globalThis.__BQ = {"dalgaBuyukluk":{"ilkokul":{"kolay":[{"q":"Şekildeki dalgada en yüksek noktaya ne ad verilir?","fig":"<svg viewBox='0 0 320 160'><rect x='0' y='0' width='320' height='160' fill='#f5f7fa'/><line x1='10' y1='80' x2='310' y2='80' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><text x='300' y='74' font-size='11' text-anchor='end' fill='#1a2b45'>denge</text><path d='M10 80 Q47 30 85 80 Q122 130 160 80 Q197 30 235 80 Q272 130 310 80' fill='none' stroke='#4aa3df' stroke-width='3'/><circle cx='47' cy='42' r='4' fill='#e0552b'/><text x='47' y='30' font-size='12' text-anchor='middle' fill='#1a2b45'>?</text><text x='122' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>çukur</text></svg>","steps":[{"t":"Yüksek noktaya bak","a":"tepe","d":"Dalganın denge çizgisinden yukarıdaki en yüksek noktasına <b>tepe</b> denir."},{"t":"Adını söyle","a":"tepe noktası","d":"Şekilde kırmızı ile işaretli yüksek nokta dalganın tepesidir."}],"ans":"Dalganın en yüksek noktasına tepe denir."},{"q":"Dalganın en alçak (en aşağı) noktasına ne ad verilir?","steps":[{"t":"Alçak noktaya bak","a":"çukur","d":"Dalganın denge çizgisinden aşağıdaki en alçak noktasına <b>çukur</b> denir."},{"t":"Adını söyle","a":"çukur noktası","d":"Su dalgasında çukur, suyun en çok çöktüğü yerdir."}],"ans":"Dalganın en alçak noktasına çukur denir."},{"q":"Bir ip dalgasında dalga ne kadar yüksek titrerse o dalga için ne söylenir?","steps":[{"t":"Yükseklik ne demek","a":"genlik","d":"Dalganın denge çizgisinden ne kadar yukarı çıktığına o dalganın <b>genliği</b> denir."},{"t":"Çok yüksekse","a":"genliği büyük","d":"Dalga çok yüksek titriyorsa genliği büyüktür."}],"ans":"Çok yüksek titreyen dalganın genliği büyüktür."},{"q":"İki çocuk aynı ipi sallıyor. Biri ipi azıcık, diğeri çok sallıyor. Hangisinin dalgası daha güçlüdür?","steps":[{"t":"Çok sallamak","a":"büyük genlik","d":"İpi çok sallayan çocuk daha büyük genlikli dalga oluşturur."},{"t":"Güçle ilişki","a":"büyük genlik güçlü","d":"Genliği büyük olan dalga daha çok enerji taşır, yani daha güçlüdür."}],"ans":"İpi çok sallayan çocuğun dalgası daha güçlüdür çünkü genliği büyüktür."},{"q":"Şekildeki dalgada iki tepe arasındaki uzaklığa ne denir?","fig":"<svg viewBox='0 0 320 160'><rect x='0' y='0' width='320' height='160' fill='#f5f7fa'/><line x1='10' y1='85' x2='310' y2='85' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><path d='M10 85 Q47 35 85 85 Q122 135 160 85 Q197 35 235 85 Q272 135 310 85' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='47' y1='40' x2='160' y2='40' stroke='#e0552b' stroke-width='2'/><polygon points='47,36 41,40 47,44' fill='#e0552b'/><polygon points='160,36 166,40 160,44' fill='#e0552b'/><text x='103' y='30' font-size='12' text-anchor='middle' fill='#1a2b45'>?</text></svg>","steps":[{"t":"İki tepe arası","a":"dalga boyu","d":"Ardışık iki tepe arasındaki uzaklığa <b>dalga boyu</b> denir."},{"t":"Simgesi","a":"λ","d":"Dalga boyu λ (lambda) harfiyle gösterilir."}],"ans":"Ardışık iki tepe arasındaki uzaklığa dalga boyu denir."}],"zor":[{"q":"Bir denizde küçük dalgalar varken sonra büyük dalgalar oluşuyor. Büyük dalgalar neden tekneyi daha çok sallar?","steps":[{"t":"Büyük dalga nedir","a":"genliği büyük","d":"Büyük dalgaların genliği (yüksekliği) küçük dalgalardan fazladır."},{"t":"Enerji ilişkisi","a":"çok enerji","d":"Genliği büyük dalga daha çok enerji taşır."},{"t":"Tekneye etki","a":"çok sallar","d":"Çok enerji taşıdığı için tekneyi daha güçlü sallar."}],"ans":"Büyük dalgaların genliği fazladır, bu yüzden daha çok enerji taşır ve tekneyi daha çok sallar."},{"q":"Bir ipte üst üste tepe, çukur, tepe, çukur görünüyor. Bir tam dalga için bir tepe ile bir çukur mu yoksa sadece iki tepe arası mı sayılır?","steps":[{"t":"Tam dalga nedir","a":"tepe + çukur","d":"Bir tam dalga, bir tepe ile bir çukurun birlikte oluşturduğu kısımdır."},{"t":"Dalga boyuyla eşle","a":"iki tepe arası","d":"Bu bir tam dalganın uzunluğu, ardışık iki tepe arasına eşittir."}],"ans":"Bir tam dalga, bir tepe ile bir çukurdan oluşur ve uzunluğu iki tepe arasına eşittir; yani dalga boyu kadardır."},{"q":"İki dalgadan A'nın tepeleri denge çizgisinden az yukarı, B'nin tepeleri daha yukarı çıkıyor. Hangisinin genliği daha büyüktür?","steps":[{"t":"Yükseklikleri karşılaştır","a":"B daha yüksek","d":"B dalgasının tepeleri denge çizgisinden daha yukarı çıkıyor."},{"t":"Genlik kararı","a":"B büyük","d":"Yükseklik genlik demek olduğundan B dalgasının genliği büyüktür."}],"ans":"B dalgasının genliği daha büyüktür çünkü tepeleri denge çizgisinden daha yukarı çıkar."},{"q":"Bir su dalgasında tepeler birbirine çok yakınsa dalga boyu hakkında ne söylenir?","steps":[{"t":"Tepeler arası","a":"dalga boyu","d":"İki tepe arası uzaklık dalga boyudur."},{"t":"Yakınsa","a":"küçük dalga boyu","d":"Tepeler birbirine çok yakınsa aradaki uzaklık az olur, yani dalga boyu küçüktür."}],"ans":"Tepeler birbirine çok yakınsa dalga boyu küçüktür."},{"q":"Aynı genliğe sahip iki dalgadan biri hızlı titriyor, diğeri yavaş. Hangisinin dalga boyu daha kısadır?","steps":[{"t":"Hızlı titreme","a":"çok dalga","d":"Hızlı titreyen dalga aynı sürede daha çok tepe ve çukur oluşturur."},{"t":"Dalga boyu","a":"kısa","d":"Daha çok tepe sığdığı için tepeler birbirine yakınlaşır, dalga boyu kısalır."}],"ans":"Hızlı titreyen dalganın dalga boyu daha kısadır."}]},"ortaokul":{"kolay":[{"q":"Şekildeki dalgada genlik ve dalga boyu hangi ölçülerle gösterilir? Açıklayınız.","fig":"<svg viewBox='0 0 320 170'><rect x='0' y='0' width='320' height='170' fill='#f5f7fa'/><line x1='10' y1='85' x2='310' y2='85' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><text x='300' y='100' font-size='10' text-anchor='end' fill='#1a2b45'>denge</text><path d='M10 85 Q47 35 85 85 Q122 135 160 85 Q197 35 235 85 Q272 135 310 85' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='47' y1='40' x2='47' y2='85' stroke='#e0552b' stroke-width='2'/><text x='55' y='62' font-size='11' fill='#1a2b45'>genlik</text><line x1='47' y1='30' x2='197' y2='30' stroke='#5b6b85' stroke-width='2'/><polygon points='47,26 41,30 47,34' fill='#5b6b85'/><polygon points='197,26 203,30 197,34' fill='#5b6b85'/><text x='122' y='22' font-size='11' text-anchor='middle' fill='#1a2b45'>λ (dalga boyu)</text></svg>","steps":[{"t":"Genlik","a":"denge-tepe arası","d":"Genlik, denge çizgisinden tepeye (veya çukura) olan dikey uzaklıktır."},{"t":"Dalga boyu","a":"iki tepe arası","d":"Dalga boyu λ, ardışık iki tepe (veya iki çukur) arasındaki yatay uzaklıktır."}],"ans":"Genlik dengeden tepeye olan dikey uzaklıktır; dalga boyu λ ise ardışık iki tepe arasındaki yatay uzaklıktır."},{"q":"Bir dalganın genliği ile taşıdığı enerji arasında nasıl bir ilişki vardır?","steps":[{"t":"Genlik artarsa","a":"enerji artar","d":"Dalganın genliği büyüdükçe taşıdığı enerji de artar."},{"t":"İlişki türü","a":"doğru orantılı değil, kuvvetli","d":"Enerji genlikle hızla artar; küçük bir genlik artışı bile enerjiyi belirgin biçimde yükseltir."}],"ans":"Genlik arttıkça dalganın taşıdığı enerji de artar; büyük genlikli dalga çok enerji taşır."},{"q":"Denge konumu bir dalga için ne anlama gelir?","steps":[{"t":"Denge konumu","a":"hareketsiz çizgi","d":"Denge konumu, ortamın dalga yokken bulunduğu orta çizgidir."},{"t":"Dalgadaki yeri","a":"tepe ile çukur ortası","d":"Tepe bu çizginin üstünde, çukur altında yer alır; genlik bu çizgiden ölçülür."}],"ans":"Denge konumu, dalga yokken ortamın bulunduğu orta çizgidir; tepe ve çukur bu çizgiye göre ölçülür."},{"q":"Dalga boyu λ tam olarak nereden nereye ölçülür?","steps":[{"t":"Bir referans seç","a":"bir tepe","d":"Bir tepe noktası referans alınır."},{"t":"Bir sonrakine git","a":"ardışık tepe","d":"Hemen yanındaki bir sonraki tepeye kadar olan uzaklık dalga boyudur."}],"ans":"Dalga boyu, ardışık iki tepe (veya ardışık iki çukur) arasındaki uzaklıktır."},{"q":"Aynı ortamda yayılan iki dalgadan birinin frekansı büyük. Frekans büyüdükçe dalga boyu nasıl değişir?","steps":[{"t":"Frekans büyük","a":"çok titreşim","d":"Frekans, birim zamanda oluşan dalga sayısıdır; büyükse çok dalga üretilir."},{"t":"Dalga boyu","a":"küçülür","d":"Aynı hızda çok dalga sığması için dalga boyları kısalır."}],"ans":"Aynı ortamda frekans büyüdükçe dalga boyu küçülür (ters orantı)."}],"zor":[{"q":"Şekildeki dalgada tepeden çukura olan dikey uzaklık 8 cm ölçülüyor. Bu dalganın genliği kaç cm'dir?","fig":"<svg viewBox='0 0 320 170'><rect x='0' y='0' width='320' height='170' fill='#f5f7fa'/><line x1='10' y1='85' x2='310' y2='85' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><text x='300' y='100' font-size='10' text-anchor='end' fill='#1a2b45'>denge</text><path d='M10 85 Q60 35 110 85 Q160 135 210 85 Q260 35 310 85' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='60' y1='40' x2='160' y2='130' stroke='#e0552b' stroke-width='2'/><polygon points='60,44 58,36 65,42' fill='#e0552b'/><polygon points='160,126 162,134 155,128' fill='#e0552b'/><text x='120' y='80' font-size='11' fill='#1a2b45'>8 cm</text></svg>","steps":[{"t":"Tepe-çukur uzaklığı","a":"2 genlik","d":"Tepeden çukura olan dikey uzaklık, genliğin iki katına eşittir."},{"t":"Genliği bul","a":"8 ÷ 2","d":"Genlik = 8 cm ÷ 2 = 4 cm olarak hesaplanır."}],"ans":"Dalganın genliği 4 cm'dir (tepe-çukur uzaklığının yarısı)."},{"q":"Bir dalganın dalga boyu 2 m, ortamdaki yayılma hızı 10 m/s'dir. Frekansını bulunuz.","steps":[{"t":"Bağıntıyı yaz","a":"v = f·λ","d":"Dalga hızı v, frekans f ile dalga boyu λ'nın çarpımına eşittir."},{"t":"Frekansı yalnız bırak","a":"f = v/λ","d":"f = v ÷ λ = 10 ÷ 2 = 5 Hz bulunur."}],"ans":"Dalganın frekansı 5 Hz'dir."},{"q":"Bir ip dalgasında 1 saniyede tam 3 dalga geçiyor ve bir dalganın boyu 0,5 m. Dalga hızını bulunuz.","steps":[{"t":"Frekansı belirle","a":"f = 3 Hz","d":"1 saniyede 3 tam dalga geçtiği için frekans 3 Hz'dir."},{"t":"Bağıntıyı uygula","a":"v = f·λ","d":"v = f × λ = 3 × 0,5 = 1,5 m/s bulunur."}],"ans":"Dalganın yayılma hızı 1,5 m/s'dir."},{"q":"İki dalga aynı dalga boyuna sahip ama birinin genliği iki katı. Hangi büyüklükleri aynı, hangileri farklıdır?","steps":[{"t":"Aynı olanlar","a":"dalga boyu, frekans","d":"Dalga boyları eşit olduğundan ve aynı ortamda hız sabit olduğundan frekansları da aynıdır."},{"t":"Farklı olan","a":"genlik ve enerji","d":"Genliği iki katı olan dalga daha fazla enerji taşır; genlik ve enerji farklıdır."}],"ans":"Dalga boyu ve frekans aynıdır; genlik ve taşınan enerji farklıdır (büyük genlikli dalga daha çok enerji taşır)."},{"q":"Bir kaynağın titreşim frekansı artırılırsa, ortamdaki dalga hızı değişmediğine göre tepeler arasındaki uzaklık nasıl değişir?","steps":[{"t":"Bağıntıyı yaz","a":"v = f·λ","d":"Hız v sabitse, f ile λ ters orantılıdır."},{"t":"Frekans artar","a":"λ küçülür","d":"v = f·λ'da v sabit, f arttığında λ küçülmek zorundadır."},{"t":"Tepeler","a":"yakınlaşır","d":"Dalga boyu küçüldüğü için ardışık tepeler birbirine yaklaşır."}],"ans":"Hız sabitken frekans artırılırsa dalga boyu küçülür ve tepeler birbirine yaklaşır."}]},"lise":{"kolay":[{"q":"Şekildeki ilerleyen dalgada genlik (A) ve dalga boyu (λ) etiketlenmiştir. Bu iki büyüklüğün tanımını ve birimlerini açıklayınız.","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='0' width='320' height='180' fill='#f5f7fa'/><line x1='10' y1='90' x2='310' y2='90' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><text x='300' y='105' font-size='10' text-anchor='end' fill='#1a2b45'>denge</text><path d='M10 90 Q47 40 85 90 Q122 140 160 90 Q197 40 235 90 Q272 140 310 90' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='47' y1='45' x2='47' y2='90' stroke='#e0552b' stroke-width='2'/><text x='54' y='68' font-size='11' fill='#1a2b45'>A</text><line x1='47' y1='30' x2='197' y2='30' stroke='#5b6b85' stroke-width='2'/><polygon points='47,26 41,30 47,34' fill='#5b6b85'/><polygon points='197,26 203,30 197,34' fill='#5b6b85'/><text x='122' y='22' font-size='11' text-anchor='middle' fill='#1a2b45'>λ</text></svg>","steps":[{"t":"Genlik A","a":"dengeden tepeye","d":"Genlik, denge konumundan tepeye (maksimum yer değiştirmeye) olan dikey uzaklıktır; birimi metredir."},{"t":"Dalga boyu λ","a":"bir periyodun uzunluğu","d":"Dalga boyu, ardışık iki tepe arasındaki uzaklıktır; uzaysal periyottur ve birimi metredir."}],"ans":"Genlik A, dengeden tepeye olan en büyük dikey yer değiştirmedir (m); dalga boyu λ ise ardışık iki tepe arasındaki uzaklıktır (m)."},{"q":"Bir dalganın taşıdığı enerji genliğin karesi ile orantılıdır. Genlik 3 katına çıkarsa enerji kaç katına çıkar?","steps":[{"t":"İlişkiyi yaz","a":"E ∝ A²","d":"Dalga enerjisi genliğin karesiyle doğru orantılıdır."},{"t":"Genlik 3 kat","a":"A² = 9 kat","d":"Genlik 3 katına çıkınca A² ifadesi 3² = 9 katına çıkar."}],"ans":"Genlik 3 katına çıkınca dalganın enerjisi 9 katına çıkar."},{"q":"Dalga hızı bağıntısı v = f·λ ile verilir. Aynı ortamda hız sabitken frekans ile dalga boyu arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Bağıntıyı incele","a":"v = f·λ","d":"Hız v sabit alındığında f ile λ'nın çarpımı sabit kalır."},{"t":"İlişki türü","a":"ters orantı","d":"Çarpımları sabit olduğu için frekans artarsa dalga boyu azalır; f ile λ ters orantılıdır."}],"ans":"Aynı ortamda hız sabitken frekans ile dalga boyu ters orantılıdır (f·λ = sabit)."},{"q":"Bir dalganın frekansı 50 Hz, dalga boyu 4 m'dir. Yayılma hızını ve periyodunu bulunuz.","steps":[{"t":"Hızı hesapla","a":"v = f·λ","d":"v = 50 × 4 = 200 m/s bulunur."},{"t":"Periyodu bul","a":"T = 1/f","d":"T = 1 ÷ 50 = 0,02 s olarak hesaplanır."}],"ans":"Dalganın hızı 200 m/s, periyodu 0,02 s'dir."},{"q":"Aynı eksende çizilen iki dalgadan birinin genliği büyük, diğerinin dalga boyu kısadır. Her dalga için hangi büyüklüğün farklı olduğunu belirtiniz.","steps":[{"t":"1. dalga","a":"genlik farklı","d":"Birinci dalganın tepeleri daha yüksek; genliği büyüktür."},{"t":"2. dalga","a":"dalga boyu farklı","d":"İkinci dalganın tepeleri sık; dalga boyu kısadır, dolayısıyla aynı hızda frekansı büyüktür."}],"ans":"Birinci dalganın genliği farklı (büyük); ikinci dalganın dalga boyu farklı (kısa), buna bağlı frekansı büyüktür."},{"q":"Denge konumu ile genlik kavramlarının dalga üzerindeki konumlarını açıklayınız.","steps":[{"t":"Denge konumu","a":"orta çizgi","d":"Denge konumu, ortam parçacığının dalga yokken bulunduğu konumdur; dalganın orta (sıfır) çizgisidir."},{"t":"Genlik","a":"dengeden uca","d":"Genlik bu çizgiden tepeye veya çukura olan maksimum uzaklıktır."}],"ans":"Denge konumu dalganın orta çizgisidir; genlik bu çizgiden tepeye (ya da çukura) olan en büyük yer değiştirmedir."},{"q":"Şekildeki dalgada bir tepe ile bir sonraki çukur arasındaki yatay uzaklık 6 cm ölçülüyor. Dalga boyunu bulunuz.","fig":"<svg viewBox='0 0 320 160'><rect x='0' y='0' width='320' height='160' fill='#f5f7fa'/><line x1='10' y1='80' x2='310' y2='80' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><path d='M10 80 Q55 35 100 80 Q145 125 190 80 Q235 35 280 80 Q302 102 310 80' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='55' y1='40' x2='145' y2='120' stroke='#e0552b' stroke-width='1.5'/><text x='100' y='70' font-size='11' fill='#1a2b45'>6 cm</text><circle cx='55' cy='40' r='3' fill='#e0552b'/><circle cx='145' cy='120' r='3' fill='#e0552b'/></svg>","steps":[{"t":"Tepe-çukur uzaklığı","a":"yarım dalga","d":"Bir tepe ile ardışık çukur arası, dalga boyunun yarısına (λ/2) eşittir."},{"t":"Dalga boyunu bul","a":"6 × 2","d":"λ/2 = 6 cm ise λ = 6 × 2 = 12 cm bulunur."}],"ans":"Dalga boyu 12 cm'dir (tepe-çukur uzaklığının iki katı)."},{"q":"Bir su dalgasının periyodu 0,25 s, dalga boyu 1,5 m'dir. Yayılma hızını bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 1/T","d":"f = 1 ÷ 0,25 = 4 Hz bulunur."},{"t":"Hızı hesapla","a":"v = f·λ","d":"v = 4 × 1,5 = 6 m/s olarak hesaplanır."}],"ans":"Dalganın yayılma hızı 6 m/s'dir."},{"q":"İki ses dalgasından birinin genliği diğerinin yarısıdır. Enerjileri arasındaki oran nedir?","steps":[{"t":"İlişkiyi yaz","a":"E ∝ A²","d":"Dalga enerjisi genliğin karesiyle orantılıdır."},{"t":"Oranı hesapla","a":"(1/2)² = 1/4","d":"Genlik yarıya inince enerji (1/2)² = 1/4 katına iner."}],"ans":"Genliği yarı olan dalganın enerjisi, diğerinin dörtte biridir."},{"q":"Şekildeki dalga grafiğinde yatay eksen konum (m). Grafikten dalga boyunu ve genliği okuyunuz.","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='0' width='320' height='180' fill='#f5f7fa'/><line x1='30' y1='90' x2='310' y2='90' stroke='#1a2b45' stroke-width='1.5'/><line x1='30' y1='20' x2='30' y2='160' stroke='#1a2b45' stroke-width='1.5'/><text x='305' y='105' font-size='10' fill='#1a2b45'>x (m)</text><text x='14' y='55' font-size='10' fill='#1a2b45'>y</text><path d='M30 90 Q70 40 110 90 Q150 140 190 90 Q230 40 270 90 Q290 115 310 90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='70' y1='45' x2='70' y2='90' stroke='#e0552b' stroke-width='1.5'/><text x='76' y='66' font-size='10' fill='#1a2b45'>2 cm</text><text x='110' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>4</text><text x='190' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>8</text></svg>","steps":[{"t":"Genliği oku","a":"A = 2 cm","d":"Tepe denge çizgisinden 2 cm yukarıda olduğundan genlik 2 cm'dir."},{"t":"Dalga boyunu oku","a":"λ = 8 m","d":"Ardışık iki tepe (veya iki çukur) x = 0 ile x = 8 arasında olduğundan dalga boyu 8 m'dir."}],"ans":"Genlik 2 cm, dalga boyu 8 m olarak okunur."},{"q":"Bir dalganın hızı sabit kalmak şartıyla dalga boyu iki katına çıkarılırsa frekansı nasıl değişir?","steps":[{"t":"Bağıntıyı yaz","a":"f = v/λ","d":"Frekans, hızın dalga boyuna bölümüdür."},{"t":"λ iki kat","a":"f yarıya","d":"v sabitken λ iki katına çıkınca f = v/λ ifadesi yarıya iner."}],"ans":"Dalga boyu iki katına çıkınca (hız sabit) frekans yarıya iner."},{"q":"Genliği büyüten ama frekansını değiştirmeyen bir değişiklik dalga hızını etkiler mi? Açıklayınız.","steps":[{"t":"Hızı belirleyen","a":"ortam","d":"Dalga hızı yalnızca yayıldığı ortamın özelliklerine bağlıdır, genlikten bağımsızdır."},{"t":"Genlik etkisi","a":"hız değişmez","d":"Genlik yalnızca enerjiyi etkiler; hızı ve dalga boyu-frekans ilişkisini değiştirmez."}],"ans":"Hayır; dalga hızı yalnızca ortama bağlıdır, genliğin büyütülmesi hızı etkilemez yalnızca taşınan enerjiyi artırır."},{"q":"Bir dalganın frekansı 2 Hz, hızı 6 m/s'dir. Bu dalganın bir tam dalgasının (bir tepe-bir çukur) uzunluğu kaç metredir?","steps":[{"t":"Dalga boyunu bul","a":"λ = v/f","d":"λ = 6 ÷ 2 = 3 m bulunur."},{"t":"Tam dalga","a":"bir λ","d":"Bir tam dalga (bir tepe ve bir çukur) bir dalga boyuna eşittir, yani 3 m'dir."}],"ans":"Bir tam dalganın uzunluğu bir dalga boyu kadar, yani 3 m'dir."},{"q":"Genlik-enerji ilişkisi neden basit doğru orantı değil de karesel orantıdır? Kısaca açıklayınız.","steps":[{"t":"Enerji kaynağı","a":"hareket + konum","d":"Dalga enerjisi parçacıkların kinetik ve potansiyel enerjisinden gelir; her ikisi de yer değiştirmenin karesiyle artar."},{"t":"Sonuç","a":"E ∝ A²","d":"Maksimum yer değiştirme genlik olduğundan toplam enerji genliğin karesiyle orantılı olur."}],"ans":"Parçacıkların hem kinetik hem potansiyel enerjisi yer değiştirmenin karesiyle arttığından dalga enerjisi genliğin karesiyle orantılıdır (E ∝ A²)."},{"q":"Bir dalganın periyodu T = 0,2 s ve dalga boyu λ = 1 m'dir. Frekansını ve yayılma hızını bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 1/T","d":"f = 1 ÷ 0,2 = 5 Hz olarak hesaplanır."},{"t":"Hızı bul","a":"v = f·λ","d":"v = 5 × 1 = 5 m/s bulunur."}],"ans":"Dalganın frekansı 5 Hz, yayılma hızı 5 m/s'dir."}],"zor":[{"q":"Şekildeki dalga grafiğinde ardışık iki tepe x = 2 m ile x = 6 m'de, genlik ise 3 cm'dir. Dalga ortamda 8 m/s ile ilerliyorsa frekansını bulunuz.","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='0' width='320' height='180' fill='#f5f7fa'/><line x1='20' y1='90' x2='310' y2='90' stroke='#1a2b45' stroke-width='1.5'/><text x='305' y='105' font-size='10' fill='#1a2b45'>x (m)</text><path d='M20 90 Q60 40 100 90 Q140 140 180 90 Q220 40 260 90 Q285 120 310 90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><circle cx='100' cy='45' r='3' fill='#e0552b'/><circle cx='220' cy='45' r='3' fill='#e0552b'/><line x1='100' y1='30' x2='220' y2='30' stroke='#5b6b85' stroke-width='1.5'/><polygon points='100,26 95,30 100,34' fill='#5b6b85'/><polygon points='220,26 225,30 220,34' fill='#5b6b85'/><text x='160' y='22' font-size='10' text-anchor='middle' fill='#1a2b45'>2 m → 6 m</text></svg>","steps":[{"t":"Dalga boyunu bul","a":"λ = 6 − 2","d":"Ardışık iki tepe arası dalga boyudur: λ = 6 − 2 = 4 m."},{"t":"Frekansı hesapla","a":"f = v/λ","d":"f = 8 ÷ 4 = 2 Hz bulunur (genlik frekansı etkilemez)."}],"ans":"Dalganın frekansı 2 Hz'dir."},{"q":"Aynı ortamda yayılan bir dalganın dalga boyu 0,5 m'den 0,2 m'ye düşürülürken hız sabit kalıyor. Frekans yüzde kaç değişir?","steps":[{"t":"İlk frekans","a":"f₁ = v/0,5","d":"v sabit alınırsa f₁ = v ÷ 0,5 = 2v olur."},{"t":"Son frekans","a":"f₂ = v/0,2","d":"f₂ = v ÷ 0,2 = 5v bulunur."},{"t":"Değişimi hesapla","a":"%150 artış","d":"f₂/f₁ = 5v/2v = 2,5 olduğundan frekans 2,5 katına, yani %150 artmış olur."}],"ans":"Dalga boyu küçüldüğü için frekans 2,5 katına çıkar, yani %150 artar."},{"q":"Bir dalganın genliği %20 artırılırsa taşıdığı enerji yüzde kaç değişir?","steps":[{"t":"İlişkiyi yaz","a":"E ∝ A²","d":"Enerji genliğin karesiyle orantılıdır."},{"t":"Yeni genlik","a":"1,2·A","d":"%20 artış genliği 1,2 katına çıkarır."},{"t":"Enerji oranı","a":"1,2² = 1,44","d":"Enerji 1,44 katına çıkar, yani %44 artar."}],"ans":"Genlik %20 artırılınca enerji %44 artar (1,2² = 1,44 kat)."},{"q":"İki dalga aynı ortamdadır. A dalgasının dalga boyu B'ninkinin yarısıdır. Hangisinin frekansı büyüktür ve kaç katıdır?","steps":[{"t":"Bağıntıyı yaz","a":"f = v/λ","d":"Aynı ortamda hız aynıdır; frekans dalga boyuyla ters orantılıdır."},{"t":"Karşılaştır","a":"A'nın λ'sı yarı","d":"A'nın dalga boyu B'nin yarısı olduğundan A'nın frekansı iki katıdır."}],"ans":"A dalgasının frekansı büyüktür; dalga boyu yarı olduğundan frekansı B'ninkinin iki katıdır."},{"q":"Bir dalganın hızı 12 m/s, periyodu 0,3 s'dir. Bu dalganın dalga boyunu ve 1,5 saniyede yaydığı tam dalga sayısını bulunuz.","steps":[{"t":"Dalga boyunu bul","a":"λ = v·T","d":"λ = 12 × 0,3 = 3,6 m bulunur."},{"t":"Dalga sayısını bul","a":"n = t/T","d":"n = 1,5 ÷ 0,3 = 5 tam dalga oluşur."}],"ans":"Dalga boyu 3,6 m'dir ve 1,5 saniyede 5 tam dalga yayılır."},{"q":"Şekildeki ip dalgasında genlik 4 cm, ardışık iki çukur arası 10 cm ve dalga 0,5 saniyede bir tam titreşim yapıyor. Dalga hızını bulunuz.","fig":"<svg viewBox='0 0 320 170'><rect x='0' y='0' width='320' height='170' fill='#f5f7fa'/><line x1='10' y1='85' x2='310' y2='85' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><path d='M10 85 Q35 45 60 85 Q85 125 110 85 Q135 45 160 85 Q185 125 210 85 Q235 45 260 85 Q285 125 310 85' fill='none' stroke='#4aa3df' stroke-width='2.5'/><circle cx='110' cy='123' r='3' fill='#e0552b'/><circle cx='210' cy='123' r='3' fill='#e0552b'/><line x1='110' y1='140' x2='210' y2='140' stroke='#5b6b85' stroke-width='1.5'/><polygon points='110,137 105,140 110,143' fill='#5b6b85'/><polygon points='210,137 215,140 210,143' fill='#5b6b85'/><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>10 cm</text></svg>","steps":[{"t":"Dalga boyunu belirle","a":"λ = 10 cm","d":"Ardışık iki çukur arası dalga boyudur: λ = 10 cm = 0,1 m."},{"t":"Periyot ve frekans","a":"T = 0,5 s, f = 2 Hz","d":"Bir tam titreşim 0,5 s sürdüğünden f = 1/0,5 = 2 Hz."},{"t":"Hızı hesapla","a":"v = f·λ","d":"v = 2 × 0,1 = 0,2 m/s bulunur (genlik hızı etkilemez)."}],"ans":"Dalganın yayılma hızı 0,2 m/s'dir."},{"q":"İki dalganın frekansları eşit ama birinin dalga boyu diğerinin 1,5 katı. Bu dalgalar aynı ortamda olabilir mi? Açıklayınız.","steps":[{"t":"Bağıntıyı yaz","a":"v = f·λ","d":"Frekanslar eşitse hız doğrudan dalga boyuyla orantılıdır."},{"t":"Hızları karşılaştır","a":"v farklı","d":"Dalga boyu 1,5 katı olan dalganın hızı da 1,5 katı olur."},{"t":"Sonuç","a":"farklı ortam","d":"Aynı ortamda hız aynı olacağından bu dalgalar farklı ortamlardadır."}],"ans":"Hayır; frekanslar eşitken dalga boyu farklıysa hızlar da farklı olur, bu yüzden dalgalar farklı ortamlardadır."},{"q":"Bir dalganın enerjisi 100 birimden 400 birime çıkarılmak isteniyor. Genlik kaç katına çıkarılmalıdır?","steps":[{"t":"İlişkiyi yaz","a":"E ∝ A²","d":"Enerji genliğin karesiyle orantılıdır."},{"t":"Enerji oranı","a":"400/100 = 4","d":"Enerji 4 katına çıkacaktır."},{"t":"Genlik oranı","a":"√4 = 2","d":"A² = 4 olduğundan genlik √4 = 2 katına çıkarılmalıdır."}],"ans":"Enerjiyi 4 katına çıkarmak için genlik 2 katına çıkarılmalıdır."},{"q":"Şekildeki konum-zaman türü gösterimde bir parçacık denge konumundan başlayıp tepe ve çukurdan geçiyor. Genlik 5 cm ise parçacığın bir tam titreşimde aldığı toplam yolu bulunuz.","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='0' width='320' height='180' fill='#f5f7fa'/><line x1='20' y1='90' x2='310' y2='90' stroke='#1a2b45' stroke-width='1.5'/><line x1='20' y1='20' x2='20' y2='160' stroke='#1a2b45' stroke-width='1.5'/><text x='305' y='105' font-size='10' fill='#1a2b45'>t</text><text x='8' y='40' font-size='10' fill='#1a2b45'>y</text><path d='M20 90 Q60 40 100 90 Q140 140 180 90 Q220 40 260 90 Q280 115 300 90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='100' y1='45' x2='100' y2='90' stroke='#e0552b' stroke-width='1.5'/><text x='106' y='66' font-size='10' fill='#1a2b45'>5 cm</text></svg>","steps":[{"t":"Bir titreşimde hareket","a":"4 genlik","d":"Parçacık dengeden tepeye (+A), tepeden dengeye, dengeden çukura (−A) ve çukurdan dengeye gider; toplam 4 genlik kadar yol alır."},{"t":"Toplam yolu hesapla","a":"4 × 5","d":"Toplam yol = 4 × A = 4 × 5 = 20 cm bulunur."}],"ans":"Parçacık bir tam titreşimde 4 genlik kadar, yani 20 cm yol alır."},{"q":"Bir dalga kaynağının frekansı sabit tutulup dalga, hızı iki katı olan başka bir ortama geçiyor. Dalga boyu nasıl değişir?","steps":[{"t":"Frekans korunur","a":"f sabit","d":"Ortam değişse de kaynağın belirlediği frekans korunur."},{"t":"Bağıntıyı yaz","a":"λ = v/f","d":"Dalga boyu hıza bağlıdır; f sabitken λ ile v doğru orantılıdır."},{"t":"Sonuç","a":"λ iki kat","d":"Hız iki katına çıktığından dalga boyu da iki katına çıkar."}],"ans":"Frekans sabit, hız iki katına çıktığı için dalga boyu da iki katına çıkar."},{"q":"İki dalgadan A'nın genliği 2 cm, B'nin genliği 6 cm. Diğer her şey eşitse B'nin enerjisi A'nınkinin kaç katıdır?","steps":[{"t":"İlişkiyi yaz","a":"E ∝ A²","d":"Enerji genliğin karesiyle orantılıdır."},{"t":"Genlik oranı","a":"6/2 = 3","d":"B'nin genliği A'nınkinin 3 katıdır."},{"t":"Enerji oranı","a":"3² = 9","d":"Enerji oranı genlik oranının karesidir: 3² = 9."}],"ans":"B dalgasının enerjisi A'nınkinin 9 katıdır."},{"q":"Bir dalganın dalga boyu λ, periyodu T olarak verilmiştir. Hızı bu iki büyüklükle nasıl ifade edilir ve λ = 2 m, T = 0,4 s için değeri nedir?","steps":[{"t":"İfadeyi yaz","a":"v = λ/T","d":"Hız, bir dalga boyu kadar yolu bir periyot zamanda aldığından v = λ/T olur."},{"t":"Değeri hesapla","a":"v = 2/0,4","d":"v = 2 ÷ 0,4 = 5 m/s bulunur."}],"ans":"Hız v = λ/T ile verilir; λ = 2 m ve T = 0,4 s için v = 5 m/s'dir."},{"q":"Aynı kaynaktan çıkan bir dalganın genliği zamanla azalıyor (sönümleniyor) ama dalga boyu sabit kalıyor. Bu süreçte dalganın enerjisi ve frekansı nasıl değişir?","steps":[{"t":"Genlik azalır","a":"enerji azalır","d":"E ∝ A² olduğundan genlik azaldıkça taşınan enerji azalır."},{"t":"Dalga boyu sabit","a":"frekans sabit","d":"v = f·λ'da ortam ve λ değişmediğinden frekans sabit kalır."}],"ans":"Genlik azaldığı için enerji azalır (E ∝ A²); dalga boyu sabit olduğundan frekans değişmez."},{"q":"İki dalgadan A'nın dalga boyu 4 cm ve frekansı 5 Hz, B'nin dalga boyu 8 cm'dir. İkisi de aynı ortamda olduğuna göre B'nin frekansını bulunuz.","steps":[{"t":"A'nın hızını bul","a":"v = f·λ","d":"v = 5 × 4 = 20 cm/s; aynı ortamda B için de hız aynıdır."},{"t":"B'nin frekansını bul","a":"f = v/λ","d":"f_B = 20 ÷ 8 = 2,5 Hz bulunur."}],"ans":"Aynı ortamda hız 20 cm/s'dir; B dalgasının frekansı 2,5 Hz olur."},{"q":"Bir dalganın hem genliği iki katına çıkarılıyor hem de frekansı yarıya indiriliyor (hız sabit). Enerji ve dalga boyu nasıl değişir?","steps":[{"t":"Genlik etkisi","a":"enerji 4 kat","d":"E ∝ A² olduğundan genlik iki katına çıkınca enerji 4 katına çıkar (frekanstan bağımsız bu adımda)."},{"t":"Frekans etkisi","a":"λ iki kat","d":"v sabitken f yarıya inince λ = v/f bağıntısından dalga boyu iki katına çıkar."},{"t":"Sonuç","a":"E ↑, λ ↑","d":"Genlik kaynaklı enerji 4 katına çıkar; dalga boyu frekans nedeniyle iki katına çıkar."}],"ans":"Genlik iki katına çıktığından enerji 4 katına çıkar; frekans yarıya indiğinden (hız sabit) dalga boyu iki katına çıkar."}]}},"dalgaHizi":{"ilkokul":{"kolay":[{"q":"Bir gölete taş atınca oluşan halkalar kıyıya doğru yayılıyor. Bu yayılan dalgaların bir hızı var mıdır?","fig":"<svg viewBox='0 0 320 160'><ellipse cx='160' cy='80' rx='18' ry='9' fill='none' stroke='#4aa3df' stroke-width='2'/><ellipse cx='160' cy='80' rx='40' ry='18' fill='none' stroke='#4aa3df' stroke-width='2'/><ellipse cx='160' cy='80' rx='65' ry='28' fill='none' stroke='#4aa3df' stroke-width='2'/><ellipse cx='160' cy='80' rx='92' ry='40' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='160' cy='80' r='4' fill='#5b6b85'/><text x='160' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>halkalar dışa yayılır</text></svg>","steps":[{"t":"Dalga hareket eder mi","a":"evet","d":"Su dalgaları durmaz, kıyıya doğru ilerler."},{"t":"İlerlemenin hızı","a":"var","d":"Dalga belli bir sürede belli bir yol aldığı için bir hızı vardır."}],"ans":"Evet, yayılan su dalgalarının bir ilerleme hızı vardır."},{"q":"İpin ucunu sallayınca oluşan dalga, ipin diğer ucuna anında mı yoksa biraz zaman geçtikten sonra mı varır?","steps":[{"t":"Dalga yol alır","a":"ilerler","d":"Dalga ipin bir ucundan diğerine doğru ilerleyerek gider."},{"t":"Zaman gerekir","a":"biraz zaman","d":"Hiçbir dalga anında varmaz, gitmesi için biraz zaman geçer."}],"ans":"Dalga ipin öbür ucuna biraz zaman geçtikten sonra varır."},{"q":"Şimşek çaktıktan biraz sonra gök gürültüsünü duyarız. Bunun sebebi sesin bir hızı olması mıdır?","fig":"<svg viewBox='0 0 320 160'><polygon points='60,15 50,70 70,70 55,130' fill='#ffd54a' stroke='#d9a400' stroke-width='1.5'/><text x='60' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>şimşek (ışık)</text><path d='M150 75 q15 -12 30 0 q15 -12 30 0 q15 -12 30 0' fill='none' stroke='#e0552b' stroke-width='2'/><text x='235' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>ses gecikir</text></svg>","steps":[{"t":"Işık çok hızlı","a":"hemen gelir","d":"Şimşeğin ışığı gözümüze neredeyse anında ulaşır."},{"t":"Ses daha yavaş","a":"sonra gelir","d":"Ses daha yavaş ilerlediği için gürültü biraz sonra duyulur."}],"ans":"Evet, sesin bir hızı olduğu için gök gürültüsü şimşekten biraz sonra duyulur."},{"q":"Denizde dalgalar kıyıya birbiri ardına geliyor. Dalgaların hep aynı yönde ilerlemesi onların bir hızı olduğunu gösterir mi?","steps":[{"t":"Dalgalar ilerler","a":"kıyıya doğru","d":"Dalgalar açıktan kıyıya doğru düzenli olarak ilerler."},{"t":"Hız var mı","a":"evet","d":"Belli yönde yol aldıkları için bir ilerleme hızları vardır."}],"ans":"Evet, kıyıya doğru ilerleyen dalgaların bir hızı vardır."},{"q":"Suya damlayan damlaların oluşturduğu dalgalar mı yoksa bir tavşanın koşması mı daha hızlıdır, sence?","steps":[{"t":"Hız karşılaştır","a":"hangisi hızlı","d":"Her hareketin bir hızı vardır ve bunları karşılaştırabiliriz."},{"t":"Su dalgası yavaş","a":"dalga yavaş","d":"Sudaki dalgalar oldukça yavaş ilerler, koşan bir tavşan daha hızlı olabilir."}],"ans":"Sudaki dalgalar yavaş ilerler; koşan bir tavşan onlardan daha hızlı gidebilir."}],"zor":[{"q":"Aynı ipte dalgayı bir gün yavaş bir gün hızlı sallıyoruz. İpi sallama hızımız değişse de dalga hep aynı ipte aynı hızla mı ilerler?","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q20 -30 40 0 q20 30 40 0 q20 -30 40 0 q20 30 40 0 q20 -30 40 0 q20 30 40 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><text x='160' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>aynı ip</text></svg>","steps":[{"t":"Hız neye bağlı","a":"ipe bağlı","d":"Dalganın ipteki ilerleme hızı, ipin kendisine (gerginliğine) bağlıdır."},{"t":"Sallama hızı","a":"hızı değiştirmez","d":"Biz hızlı ya da yavaş sallasak da aynı ipte dalga aynı hızla ilerler."}],"ans":"Evet, aynı ipte dalga hep aynı hızla ilerler; sallama hızı bunu değiştirmez."},{"q":"Ses havada ilerler. Aynı sesi suyun içinde de gönderebilir miyiz, yoksa ses sadece havada mı gider?","steps":[{"t":"Ses ortam ister","a":"madde gerekir","d":"Ses ilerlemek için hava, su gibi bir maddeye ihtiyaç duyar."},{"t":"Suda da gider","a":"evet","d":"Balıklar suyun içindeki sesleri duyduğu için ses suda da ilerler."}],"ans":"Ses hem havada hem suda ilerleyebilir; ilerlemek için bir maddeye ihtiyaç duyar."},{"q":"Bir koşucu ile deniz dalgası yan yana kıyıya doğru gidiyor. Hangisinin daha hızlı olduğunu nasıl anlarız?","steps":[{"t":"Aynı süreye bak","a":"alınan yol","d":"İkisi aynı sürede ne kadar yol aldığına bakarız."},{"t":"Çok yol alan","a":"daha hızlı","d":"Aynı sürede daha çok yol alan daha hızlıdır."}],"ans":"Aynı sürede daha çok yol alan daha hızlıdır; bunu yol ve süreyi karşılaştırarak anlarız."},{"q":"Boş bir uzayda (havasız ortamda) çıkardığımız bir sesi arkadaşımız duyabilir mi?","steps":[{"t":"Ses ne ile gider","a":"hava ile","d":"Ses ilerlemek için havaya ya da başka bir maddeye ihtiyaç duyar."},{"t":"Havasızsa","a":"gidemez","d":"Hiç madde yoksa sesin ilerleyeceği bir yol kalmaz."}],"ans":"Hayır, havasız ortamda ses ilerleyemediği için arkadaşımız sesi duyamaz."},{"q":"Aynı havuzda dalgalar bir gün, derin bölgede ve sığ bölgede aynı hızla mı ilerler dersin?","fig":"<svg viewBox='0 0 320 150'><rect x='20' y='40' width='130' height='90' fill='#4aa3df' opacity='0.5'/><rect x='150' y='90' width='150' height='40' fill='#4aa3df' opacity='0.5'/><path d='M20 50 q12 -10 24 0 q12 10 24 0 q12 -10 24 0 q12 10 24 0' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='85' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>derin</text><text x='225' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>sığ</text></svg>","steps":[{"t":"Ortam aynı mı","a":"derinlik farklı","d":"Derin ve sığ su, dalga için biraz farklı ortamlar gibidir."},{"t":"Hız değişir","a":"farklı olabilir","d":"Ortam değişince dalganın ilerleme hızı da değişebilir."}],"ans":"Hayır; derin ve sığ bölge farklı olduğu için dalga hızı değişebilir."}]},"ortaokul":{"kolay":[{"q":"Dalga hızı, dalganın belli bir sürede aldığı yol ile nasıl bir ilişki içindedir?","steps":[{"t":"Hız tanımı","a":"yol / zaman","d":"Hız, alınan yolun geçen zamana bölünmesiyle bulunur."},{"t":"Dalgaya uygula","a":"aynı mantık","d":"Dalga hızı da dalganın aldığı yolun, bu yolu alma süresine bölünmesidir."}],"ans":"Dalga hızı, dalganın aldığı yolun geçen zamana bölünmesiyle bulunur."},{"q":"Bir dalganın hızı, dalga boyu ile frekansı arasında hangi temel bağıntıyla ilişkilidir?","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='80' x2='300' y2='80' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 80 q35 -40 70 0 q35 40 70 0 q35 -40 70 0 q35 40 70 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='115' x2='160' y2='115' stroke='#e0552b' stroke-width='1.5'/><text x='90' y='133' font-size='12' text-anchor='middle' fill='#e0552b'>λ (dalga boyu)</text></svg>","steps":[{"t":"Büyüklükleri tanı","a":"λ ve f","d":"Dalga boyu λ bir dalganın uzunluğu, frekans f saniyedeki dalga sayısıdır."},{"t":"Bağıntı","a":"v = λ × f","d":"Dalga hızı, dalga boyu ile frekansın çarpımına eşittir."}],"ans":"Dalga hızı v = λ × f bağıntısıyla bulunur; yani dalga boyu çarpı frekanstır."},{"q":"Bir dalganın frekansı, dalgayı oluşturan kaynağa mı yoksa içinde ilerlediği ortama mı bağlıdır?","steps":[{"t":"Frekans nereden gelir","a":"kaynaktan","d":"Frekans, dalgayı üreten kaynağın saniyede kaç titreşim yaptığına bağlıdır."},{"t":"Ortam etkisi","a":"değiştirmez","d":"Dalga başka bir ortama geçse de kaynağın belirlediği frekans değişmez."}],"ans":"Frekans kaynağa bağlıdır; ortam değişse bile frekans değişmez."},{"q":"Bir dalga sudan başka bir ortama geçtiğinde frekansı sabit kalıyorsa, hızı değişince dalga boyu nasıl davranır?","steps":[{"t":"Bağıntıyı yaz","a":"v = λ × f","d":"Hız, dalga boyu ile frekansın çarpımıdır."},{"t":"f sabit, v değişir","a":"λ değişir","d":"Frekans sabitken hız değişirse, eşitliğin korunması için dalga boyu da değişmek zorundadır."}],"ans":"Frekans sabit kaldığı için hız değişince dalga boyu da değişir."},{"q":"Sesin havadaki hızı yaklaşık 340 m/s, ışığın boşluktaki hızı ise çok daha büyüktür. Hangisi daha hızlıdır?","steps":[{"t":"Değerleri kıyasla","a":"ışık çok büyük","d":"Işığın hızı saniyede yaklaşık 300.000 km iken ses saniyede sadece 340 metre gider."},{"t":"Sonuç","a":"ışık","d":"Çok daha büyük olduğu için ışık sesten kat kat hızlıdır."}],"ans":"Işık sesten çok daha hızlıdır; bu yüzden şimşeği gök gürültüsünden önce görürüz."}],"zor":[{"q":"Dalga boyu 2 m ve frekansı 3 Hz olan bir dalganın hızını hesaplayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q35 -35 70 0 q35 35 70 0 q35 -35 70 0 q35 35 70 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='110' x2='90' y2='110' stroke='#e0552b' stroke-width='1.5'/><text x='55' y='128' font-size='11' text-anchor='middle' fill='#e0552b'>λ = 2 m</text></svg>","steps":[{"t":"Bağıntı","a":"v = λ × f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Yerine koy","a":"2 × 3","d":"Dalga boyu 2 m ve frekans 3 Hz değerleri yerine konur."},{"t":"Sonuç","a":"6 m/s","d":"2 ile 3'ün çarpımı 6 olduğundan hız 6 m/s'dir."}],"ans":"Dalganın hızı 6 m/s'dir."},{"q":"Hızı 12 m/s ve frekansı 4 Hz olan bir dalganın dalga boyunu bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"λ = v / f","d":"v = λ × f ifadesinden dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"12 ÷ 4","d":"Hız 12 m/s ve frekans 4 Hz değerleri yerine konur."},{"t":"Sonuç","a":"3 m","d":"12'yi 4'e bölünce dalga boyu 3 m bulunur."}],"ans":"Dalganın dalga boyu 3 m'dir."},{"q":"Bir dalga 5 saniyede 40 m yol alıyor. Bu dalganın ilerleme hızını hesaplayınız.","steps":[{"t":"Hız bağıntısı","a":"v = yol / zaman","d":"İlerleme hızı, alınan yolun geçen zamana bölünmesiyle bulunur."},{"t":"Yerine koy","a":"40 ÷ 5","d":"Yol 40 m, zaman 5 s değerleri yerine konur."},{"t":"Sonuç","a":"8 m/s","d":"40'ı 5'e bölünce hız 8 m/s bulunur."}],"ans":"Dalganın ilerleme hızı 8 m/s'dir."},{"q":"Bir dalganın periyodu 0,5 s ve dalga boyu 4 m ise hızını bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q35 -35 70 0 q35 35 70 0 q35 -35 70 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='110' x2='90' y2='110' stroke='#e0552b' stroke-width='1.5'/><text x='55' y='128' font-size='11' text-anchor='middle' fill='#e0552b'>λ = 4 m</text><text x='210' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>T = 0,5 s</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"v = λ / T","d":"Dalga hızı, dalga boyunun periyoda bölünmesiyle de bulunabilir."},{"t":"Yerine koy","a":"4 ÷ 0,5","d":"Dalga boyu 4 m, periyot 0,5 s değerleri yerine konur."},{"t":"Sonuç","a":"8 m/s","d":"4'ü 0,5'e bölmek 8 verdiğinden hız 8 m/s'dir."}],"ans":"Dalganın hızı 8 m/s'dir."},{"q":"Frekansı 2 Hz olan bir dalga, hızı 10 m/s olan bir ortamda ilerliyor. Dalga boyunu bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"10 ÷ 2","d":"Hız 10 m/s ve frekans 2 Hz değerleri yerine konur."},{"t":"Sonuç","a":"5 m","d":"10'u 2'ye bölünce dalga boyu 5 m bulunur."}],"ans":"Dalganın dalga boyu 5 m'dir."}]},"lise":{"kolay":[{"q":"Dalga hızı v = λ · f bağıntısındaki λ, f ve v sembolleri sırasıyla neyi temsil eder?","steps":[{"t":"λ ve f'yi tanımla","a":"dalga boyu ve frekans","d":"λ bir tam dalganın uzunluğu (m), f saniyedeki dalga sayısı (Hz)'dir."},{"t":"v'yi tanımla","a":"dalga hızı","d":"v, dalganın ortamdaki ilerleme hızıdır (m/s)."}],"ans":"λ dalga boyu (m), f frekans (Hz), v ise dalga hızıdır (m/s); v = λ · f."},{"q":"Periyot T ile frekans f arasındaki ilişki kullanılarak v = λ · f bağıntısı v = λ / T biçiminde nasıl yazılır?","steps":[{"t":"f ile T ilişkisi","a":"f = 1 / T","d":"Frekans, periyodun tersidir; saniyedeki dalga sayısı 1/T'dir."},{"t":"Yerine yaz","a":"v = λ / T","d":"v = λ · f ifadesinde f yerine 1/T yazılınca v = λ / T elde edilir."}],"ans":"f = 1/T olduğundan v = λ · f ifadesi v = λ / T biçiminde yazılır."},{"q":"Dalga boyu 0,5 m ve frekansı 200 Hz olan bir sesin yayılma hızını hesaplayınız.","steps":[{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Yerine koy","a":"0,5 × 200","d":"λ = 0,5 m ve f = 200 Hz değerleri yerine konur."},{"t":"Sonuç","a":"100 m/s","d":"0,5 ile 200'ün çarpımı 100 olduğundan hız 100 m/s'dir."}],"ans":"Sesin yayılma hızı 100 m/s'dir."},{"q":"Şekildeki dalganın dalga boyu 4 m ve frekansı 5 Hz olarak veriliyor. Dalga hızını bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q35 -38 70 0 q35 38 70 0 q35 -38 70 0 q35 38 70 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='112' x2='160' y2='112' stroke='#e0552b' stroke-width='1.5'/><polygon points='20,112 26,109 26,115' fill='#e0552b'/><polygon points='160,112 154,109 154,115' fill='#e0552b'/><text x='90' y='130' font-size='12' text-anchor='middle' fill='#e0552b'>λ = 4 m</text></svg>","steps":[{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Yerine koy","a":"4 × 5","d":"λ = 4 m ve f = 5 Hz değerleri yerine konur."},{"t":"Sonuç","a":"20 m/s","d":"4 ile 5'in çarpımı 20 olduğundan hız 20 m/s'dir."}],"ans":"Dalganın hızı 20 m/s'dir."},{"q":"Hızı 30 m/s ve dalga boyu 6 m olan bir dalganın frekansını bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"f = v / λ","d":"v = λ · f ifadesinden frekans, hızın dalga boyuna bölünmesiyle bulunur."},{"t":"Yerine koy","a":"30 ÷ 6","d":"v = 30 m/s ve λ = 6 m değerleri yerine konur."},{"t":"Sonuç","a":"5 Hz","d":"30'u 6'ya bölünce frekans 5 Hz bulunur."}],"ans":"Dalganın frekansı 5 Hz'dir."},{"q":"Frekansı 50 Hz ve hızı 100 m/s olan bir dalganın dalga boyunu hesaplayınız.","steps":[{"t":"Bağıntıyı düzenle","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"100 ÷ 50","d":"v = 100 m/s ve f = 50 Hz değerleri yerine konur."},{"t":"Sonuç","a":"2 m","d":"100'ü 50'ye bölünce dalga boyu 2 m bulunur."}],"ans":"Dalganın dalga boyu 2 m'dir."},{"q":"Bir dalganın hızı kaynağın belirlediği frekansa mı yoksa içinde ilerlediği ortamın özelliklerine mi bağlıdır?","steps":[{"t":"Frekans nereden","a":"kaynaktan","d":"Frekans dalgayı üreten kaynak tarafından belirlenir, ortamla değişmez."},{"t":"Hız nereden","a":"ortamdan","d":"İlerleme hızı, ortamın türü ve özelliklerine (örn. esneklik, yoğunluk) bağlıdır."}],"ans":"Dalga hızı içinde ilerlediği ortamın özelliklerine bağlıdır; frekans ise kaynağa bağlıdır."},{"q":"Periyodu 0,2 s ve dalga boyu 10 m olan bir dalganın hızını bulunuz.","steps":[{"t":"Bağıntı","a":"v = λ / T","d":"Dalga hızı, dalga boyunun periyoda bölünmesiyle bulunur."},{"t":"Yerine koy","a":"10 ÷ 0,2","d":"λ = 10 m ve T = 0,2 s değerleri yerine konur."},{"t":"Sonuç","a":"50 m/s","d":"10'u 0,2'ye bölmek 50 verdiğinden hız 50 m/s'dir."}],"ans":"Dalganın hızı 50 m/s'dir."},{"q":"Bir dalga, hızının daha büyük olduğu bir ortama geçtiğinde frekansı sabit kalır. Dalga boyu nasıl değişir?","fig":"<svg viewBox='0 0 320 150'><line x1='160' y1='20' x2='160' y2='130' stroke='#1a2b45' stroke-width='1.5' stroke-dasharray='5 4'/><path d='M20 75 q15 -25 30 0 q15 25 30 0 q15 -25 30 0 q15 25 30 0 q15 -25 30 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><path d='M160 75 q30 -25 60 0 q30 25 60 0 q30 -25 60 0' fill='none' stroke='#e0552b' stroke-width='2.5'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>yavaş ortam</text><text x='235' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>hızlı ortam</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"v = λ · f","d":"Hız, dalga boyu ile frekansın çarpımıdır."},{"t":"f sabit, v artar","a":"λ artar","d":"Frekans sabitken hız büyürse, eşitlik için dalga boyu da büyümek zorundadır."}],"ans":"Frekans sabit kaldığından hız artınca dalga boyu da artar (dalgalar açılır)."},{"q":"Dalga boyu 0,02 m olan bir ses dalgasının havadaki hızı 340 m/s ise frekansını bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"f = v / λ","d":"Frekans, hızın dalga boyuna bölünmesiyle bulunur."},{"t":"Yerine koy","a":"340 ÷ 0,02","d":"v = 340 m/s ve λ = 0,02 m değerleri yerine konur."},{"t":"Sonuç","a":"17000 Hz","d":"340'ı 0,02'ye bölünce frekans 17000 Hz bulunur."}],"ans":"Ses dalgasının frekansı 17000 Hz'dir."},{"q":"Işığın boşluktaki hızı yaklaşık 3 × 10⁸ m/s, sesin havadaki hızı ise yaklaşık 340 m/s'dir. Işık sesin yaklaşık kaç katı hızlıdır?","steps":[{"t":"Oranı kur","a":"ışık / ses","d":"Kat sayısı, ışık hızının ses hızına bölünmesiyle bulunur."},{"t":"Hesapla","a":"3 × 10⁸ ÷ 340","d":"300.000.000'ı 340'a böleriz."},{"t":"Sonuç","a":"≈ 882000","d":"Sonuç yaklaşık 882 bin çıkar."}],"ans":"Işık, sesten yaklaşık 882 bin kat daha hızlıdır."},{"q":"Bir dalga kaynağı saniyede 4 tam dalga üretiyor ve her dalganın boyu 3 m. Dalga hızını bulunuz.","steps":[{"t":"Frekansı belirle","a":"f = 4 Hz","d":"Saniyede 4 tam dalga üretildiği için frekans 4 Hz'dir."},{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Hesapla","a":"3 × 4 = 12 m/s","d":"λ = 3 m ile f = 4 Hz çarpılınca hız 12 m/s bulunur."}],"ans":"Dalganın hızı 12 m/s'dir."},{"q":"Suda ses yaklaşık 1500 m/s, havada ise yaklaşık 340 m/s hızla yayılır. Aynı ses kaynağı için ses suda mı yoksa havada mı daha hızlı ilerler?","steps":[{"t":"Hızları kıyasla","a":"1500 > 340","d":"Suyun ses hızı, havanınkinden çok daha büyüktür."},{"t":"Sonuç","a":"suda","d":"Ortam değiştiği için hız değişir; ses suda daha hızlı ilerler."}],"ans":"Ses suda daha hızlı ilerler; çünkü dalga hızı ortamın özelliklerine bağlıdır."},{"q":"Dalga boyu 0,25 m olan bir dalga, hızı 5 m/s olan bir ortamda ilerliyor. Periyodunu bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"Önce frekans, hızın dalga boyuna bölünmesiyle bulunur: 5 ÷ 0,25 = 20 Hz."},{"t":"Periyoda geç","a":"T = 1 / f","d":"Periyot, frekansın tersidir."},{"t":"Sonuç","a":"1 ÷ 20 = 0,05 s","d":"1'i 20'ye bölünce periyot 0,05 s bulunur."}],"ans":"Dalganın periyodu 0,05 s'dir."},{"q":"Aynı kaynaktan çıkan bir dalga A ortamında 6 m/s, B ortamında 9 m/s hızla ilerliyor. A'daki dalga boyu 2 m ise B'deki dalga boyunu bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"A ortamında frekans = 6 ÷ 2 = 3 Hz'dir ve kaynak aynı olduğu için B'de de 3 Hz'dir."},{"t":"B'ye uygula","a":"λ = v / f","d":"B ortamında dalga boyu = 9 ÷ 3 biçiminde bulunur."},{"t":"Sonuç","a":"3 m","d":"9'u 3'e bölünce B'deki dalga boyu 3 m bulunur."}],"ans":"B ortamındaki dalga boyu 3 m'dir."}],"zor":[{"q":"Bir su dalgasının periyodu 0,4 s ve dalga boyu 1,2 m'dir. Dalganın hızını hesaplayınız.","steps":[{"t":"Bağıntı","a":"v = λ / T","d":"Dalga hızı, dalga boyunun periyoda bölünmesiyle bulunur."},{"t":"Yerine koy","a":"1,2 ÷ 0,4","d":"λ = 1,2 m ve T = 0,4 s değerleri yerine konur."},{"t":"Sonuç","a":"3 m/s","d":"1,2'yi 0,4'e bölünce hız 3 m/s bulunur."}],"ans":"Dalganın hızı 3 m/s'dir."},{"q":"Şekildeki dalga 2 m dalga boyuna sahip ve 0,25 s'de bir tam dalga tamamlıyor. Hızını bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q35 -36 70 0 q35 36 70 0 q35 -36 70 0 q35 36 70 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='112' x2='160' y2='112' stroke='#e0552b' stroke-width='1.5'/><polygon points='20,112 26,109 26,115' fill='#e0552b'/><polygon points='160,112 154,109 154,115' fill='#e0552b'/><text x='90' y='130' font-size='12' text-anchor='middle' fill='#e0552b'>λ = 2 m</text></svg>","steps":[{"t":"Periyodu belirle","a":"T = 0,25 s","d":"Bir tam dalganın oluşma süresi periyottur, burada 0,25 s'dir."},{"t":"Bağıntı","a":"v = λ / T","d":"Dalga hızı, dalga boyunun periyoda bölünmesidir."},{"t":"Hesapla","a":"2 ÷ 0,25 = 8 m/s","d":"2'yi 0,25'e bölünce hız 8 m/s bulunur."}],"ans":"Dalganın hızı 8 m/s'dir."},{"q":"Aynı kaynaktan çıkan bir dalga havada 340 m/s, suda 1360 m/s ile ilerliyor. Havadaki dalga boyu 0,5 m ise sudaki dalga boyunu bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"Havada frekans = 340 ÷ 0,5 = 680 Hz'dir; kaynak aynı olduğu için suda da 680 Hz'dir."},{"t":"Suya uygula","a":"λ = v / f","d":"Suda dalga boyu = 1360 ÷ 680 biçiminde bulunur."},{"t":"Sonuç","a":"2 m","d":"1360'ı 680'e bölünce sudaki dalga boyu 2 m bulunur."}],"ans":"Sudaki dalga boyu 2 m'dir; hız arttığı için dalga boyu büyümüştür."},{"q":"Bir dalga 8 s'de toplam 6 tam dalga üretiyor ve dalga boyu 1,5 m. Dalganın hızını bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 6 / 8","d":"Frekans, dalga sayısının toplam süreye bölünmesidir: 6 ÷ 8 = 0,75 Hz."},{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Hesapla","a":"1,5 × 0,75","d":"λ = 1,5 m ile f = 0,75 Hz çarpılır."}],"ans":"Dalganın hızı 1,125 m/s'dir."},{"q":"Bir dalganın frekansı sabit tutulurken hızı 2 katına çıkarılırsa dalga boyu nasıl değişir? Bağıntı ile açıklayınız.","steps":[{"t":"Bağıntı","a":"v = λ · f","d":"Hız, dalga boyu ile frekansın çarpımıdır."},{"t":"f sabit","a":"v ∝ λ","d":"Frekans sabitken hız ile dalga boyu doğru orantılıdır."},{"t":"Sonuç","a":"λ 2 katı","d":"Hız 2 katına çıkınca dalga boyu da 2 katına çıkar."}],"ans":"Frekans sabitken hız 2 katına çıkarsa dalga boyu da 2 katına çıkar."},{"q":"Periyodu 0,05 s olan bir dalga, dalga boyu 0,8 m olan bir ortamda ilerliyor. Hızını ve frekansını bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 1 / T","d":"Frekans periyodun tersidir: 1 ÷ 0,05 = 20 Hz."},{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Hesapla","a":"0,8 × 20 = 16 m/s","d":"λ = 0,8 m ile f = 20 Hz çarpılınca hız 16 m/s bulunur."}],"ans":"Dalganın frekansı 20 Hz, hızı ise 16 m/s'dir."},{"q":"Şekilde A ortamından B ortamına geçen bir dalga görülüyor. A'da hız 4 m/s, B'de hız 6 m/s ve A'daki dalga boyu 2 m ise B'deki dalga boyunu bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='160' y1='20' x2='160' y2='130' stroke='#1a2b45' stroke-width='1.5' stroke-dasharray='5 4'/><path d='M20 75 q20 -28 40 0 q20 28 40 0 q20 -28 40 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><path d='M160 75 q30 -28 60 0 q30 28 60 0' fill='none' stroke='#e0552b' stroke-width='2.5'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>A: 4 m/s, λ=2 m</text><text x='235' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>B: 6 m/s</text></svg>","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"A ortamında frekans = 4 ÷ 2 = 2 Hz'dir; geçişte frekans değişmez."},{"t":"B'ye uygula","a":"λ = v / f","d":"B ortamında dalga boyu = 6 ÷ 2 biçiminde bulunur."},{"t":"Sonuç","a":"3 m","d":"6'yı 2'ye bölünce B'deki dalga boyu 3 m bulunur."}],"ans":"B ortamındaki dalga boyu 3 m'dir."},{"q":"Bir dalga kaynağı 4 Hz frekansla titreşiyor. Dalga, hızının 2 m/s olduğu A ortamından hızının 5 m/s olduğu B ortamına geçiyor. İki ortamdaki dalga boylarının farkını bulunuz.","steps":[{"t":"A'daki λ","a":"λ = v / f","d":"A ortamında dalga boyu = 2 ÷ 4 = 0,5 m'dir."},{"t":"B'deki λ","a":"λ = v / f","d":"Frekans sabit (4 Hz) olduğundan B'de dalga boyu = 5 ÷ 4 = 1,25 m'dir."},{"t":"Farkı bul","a":"1,25 − 0,5","d":"İki dalga boyunun farkı hesaplanır."}],"ans":"İki ortamdaki dalga boylarının farkı 0,75 m'dir."},{"q":"Bir dalganın hızı 20 m/s, frekansı 8 Hz iken ortam değişip hız 30 m/s oluyor. Frekans sabitken yeni dalga boyunun, eski dalga boyuna oranını bulunuz.","steps":[{"t":"Eski λ","a":"20 ÷ 8 = 2,5 m","d":"Eski dalga boyu, hızın frekansa bölünmesiyle 2,5 m bulunur."},{"t":"Yeni λ","a":"30 ÷ 8 = 3,75 m","d":"Frekans sabit kaldığından yeni dalga boyu 3,75 m'dir."},{"t":"Oranı bul","a":"3,75 ÷ 2,5","d":"Yeni dalga boyunu eskiye böleriz."}],"ans":"Yeni dalga boyu, eski dalga boyunun 1,5 katıdır."},{"q":"Bir su dalgası 10 s'de 5 tepe (5 tam dalga) üretiyor ve her tepe arası 0,8 m. Dalganın hızını bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='75' x2='300' y2='75' stroke='#9aa6b8' stroke-width='1' stroke-dasharray='4 4'/><path d='M20 75 q22 -30 44 0 q22 30 44 0 q22 -30 44 0 q22 30 44 0 q22 -30 44 0 q22 30 44 0' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='42' y1='45' x2='86' y2='45' stroke='#e0552b' stroke-width='1.5'/><text x='64' y='38' font-size='11' text-anchor='middle' fill='#e0552b'>0,8 m</text></svg>","steps":[{"t":"Frekansı bul","a":"f = 5 / 10","d":"Frekans, dalga sayısının süreye bölünmesidir: 5 ÷ 10 = 0,5 Hz."},{"t":"Bağıntı","a":"v = λ · f","d":"Dalga hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Hesapla","a":"0,8 × 0,5","d":"λ = 0,8 m ile f = 0,5 Hz çarpılır."}],"ans":"Dalganın hızı 0,4 m/s'dir."},{"q":"Frekansı 2,5 Hz olan bir dalganın hızı 7,5 m/s'dir. Bu dalganın bir tam dalga boyu kadar yol alması için geçen süreyi (periyodu) bulunuz.","steps":[{"t":"Periyot tanımı","a":"T = 1 / f","d":"Bir tam dalga boyu kadar yol alma süresi periyottur ve periyot frekansın tersidir."},{"t":"Yerine koy","a":"1 ÷ 2,5","d":"Frekans 2,5 Hz değeri yerine konur."},{"t":"Sonuç","a":"0,4 s","d":"1'i 2,5'e bölünce periyot 0,4 s bulunur."}],"ans":"Dalganın periyodu 0,4 s'dir; yani bir tam dalga boyu kadar yolu 0,4 s'de alır."},{"q":"Bir dalganın hızı, dalga boyu 5 m iken 15 m/s ölçülüyor. Aynı ortamda dalga boyu 3 m'ye düşürülürse yeni frekans kaç olur (hız ortama bağlı, sabit)?","steps":[{"t":"Hız sabit","a":"v = 15 m/s","d":"Hız ortama bağlı olduğundan aynı ortamda değişmez, 15 m/s kalır."},{"t":"Yeni frekans","a":"f = v / λ","d":"Frekans, hızın yeni dalga boyuna bölünmesidir: 15 ÷ 3."},{"t":"Sonuç","a":"5 Hz","d":"15'i 3'e bölünce yeni frekans 5 Hz bulunur."}],"ans":"Yeni frekans 5 Hz'dir; aynı ortamda hız sabit kaldığı için dalga boyu küçülünce frekans artmıştır."},{"q":"Bir ses dalgasının havadaki hızı 340 m/s, frekansı 1700 Hz'dir. Bu ses dalgasının dalga boyunu bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"340 ÷ 1700","d":"v = 340 m/s ve f = 1700 Hz değerleri yerine konur."},{"t":"Sonuç","a":"0,2 m","d":"340'ı 1700'e bölünce dalga boyu 0,2 m bulunur."}],"ans":"Ses dalgasının dalga boyu 0,2 m'dir."},{"q":"Bir dalga, hızının 4 m/s olduğu A ortamında 1 m dalga boyuna sahip. B ortamına geçince dalga boyu 1,75 m oluyor. B ortamındaki hızı bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"A ortamında frekans = 4 ÷ 1 = 4 Hz'dir ve geçişte değişmez."},{"t":"B'ye uygula","a":"v = λ · f","d":"B ortamında hız = 1,75 × 4 biçiminde bulunur."},{"t":"Sonuç","a":"7 m/s","d":"1,75 ile 4 çarpılınca B'deki hız 7 m/s bulunur."}],"ans":"B ortamındaki dalga hızı 7 m/s'dir."},{"q":"Işık boşlukta 3 × 10⁸ m/s hızla ilerler. Frekansı 5 × 10¹⁴ Hz olan görünür ışığın boşluktaki dalga boyunu bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"3 × 10⁸ ÷ 5 × 10¹⁴","d":"v = 3 × 10⁸ m/s ve f = 5 × 10¹⁴ Hz değerleri yerine konur."},{"t":"Sonuç","a":"6 × 10⁻⁷ m","d":"Bölme sonucu 6 × 10⁻⁷ m, yani 600 nm bulunur."}],"ans":"Işığın boşluktaki dalga boyu 6 × 10⁻⁷ m (600 nm)'dir."}]}},"dalgaNedir":{"ilkokul":{"kolay":[{"q":"Bir gölete taş attığımızda suyun üstünde halkalar oluşup dışarı doğru yayılır. Bu yayılan harekete ne ad verilir?","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='80' r='14' fill='#4aa3df' stroke='#1a2b45'/><circle cx='160' cy='80' r='34' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='160' cy='80' r='54' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='160' cy='80' r='74' fill='none' stroke='#4aa3df' stroke-width='1.5'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>su halkaları</text></svg>","steps":[{"t":"Olayı izle","a":"halkalar yayılıyor","d":"Taşın düştüğü yerden başlayan halkalar dışarı doğru gider."},{"t":"Adını söyle","a":"dalga","d":"Suda yayılan bu titreşim hareketine dalga denir."}],"ans":"Suda dışarı doğru yayılan bu harekete dalga denir."},{"q":"Bir ipi bir ucundan tutup hızlıca yukarı aşağı sallarsak ip boyunca ilerleyen bir kıvrım oluşur. Bu kıvrıma ne denir?","fig":"<svg viewBox='0 0 320 130'><path d='M20 80 Q70 30 120 80 T220 80 T320 80' fill='none' stroke='#e0552b' stroke-width='3'/><circle cx='20' cy='80' r='6' fill='#1a2b45'/><text x='160' y='115' font-size='12' text-anchor='middle' fill='#1a2b45'>ipte ilerleyen dalga</text></svg>","steps":[{"t":"İpi salla","a":"kıvrım ilerler","d":"El titreşince ipte bir kıvrım oluşup öbür uca doğru ilerler."},{"t":"Adlandır","a":"dalga","d":"İp boyunca ilerleyen bu kıvrıma dalga denir."}],"ans":"İp boyunca ilerleyen bu kıvrıma dalga denir."},{"q":"Suda oluşan bir dalga, suyun üstündeki yaprağı kıyıya taşır mı yoksa sadece olduğu yerde aşağı yukarı mı oynatır?","steps":[{"t":"Yaprağı izle","a":"yerinde oynar","d":"Dalga geçerken yaprak aşağı yukarı oynar ama yerinden uzağa gitmez."},{"t":"Sonuç","a":"madde gitmez","d":"Dalga suyu kıyıya taşımaz, sadece hareketi iletir."}],"ans":"Dalga yaprağı taşımaz; yaprak sadece olduğu yerde aşağı yukarı oynar."},{"q":"Bir dalganın oluşması için en başta ne gerekir: hareket eden (titreşen) bir şey mi yoksa duran bir şey mi?","steps":[{"t":"Başlangıcı düşün","a":"titreşim","d":"Su dalgası taşla, ip dalgası elin sallanmasıyla başlar."},{"t":"Sonuç","a":"titreşen kaynak","d":"Dalgayı başlatan, titreşen (hareket eden) bir kaynaktır."}],"ans":"Bir dalganın oluşması için titreşen (hareket eden) bir kaynak gerekir."},{"q":"Bir davula vurduğumuzda ses çıkar ve kulağımıza ulaşır. Sesin kulağımıza ulaşması neye örnektir?","steps":[{"t":"Olayı düşün","a":"ses yayılır","d":"Davulun titreşimi havada yayılarak kulağımıza ulaşır."},{"t":"Adlandır","a":"ses dalgası","d":"Havada yayılan bu titreşim bir ses dalgasıdır."}],"ans":"Sesin kulağımıza ulaşması ses dalgasının yayılmasına örnektir."}],"zor":[{"q":"Şekilde bir dalga geçerken şamandıra olduğu yerde yukarı aşağı oynuyor. Buna göre dalga ilerlerken suyun kendisi de şamandırayla birlikte ilerler mi?","fig":"<svg viewBox='0 0 320 150'><path d='M10 90 Q50 55 90 90 T170 90 T250 90 T320 90' fill='none' stroke='#4aa3df' stroke-width='3'/><circle cx='90' cy='62' r='8' fill='#e0552b' stroke='#1a2b45'/><line x1='90' y1='40' x2='90' y2='100' stroke='#1a2b45' stroke-width='1' stroke-dasharray='3 3'/><text x='110' y='45' font-size='11' fill='#1a2b45'>şamandıra</text></svg>","steps":[{"t":"Şamandırayı izle","a":"yerinde oynar","d":"Şamandıra dalga geçerken yukarı aşağı oynar, yan tarafa gitmez."},{"t":"Suyu düşün","a":"ilerlemez","d":"Su da yerinde titreşir; ilerleyen şey dalganın kendisidir."}],"ans":"Hayır; su ve şamandıra yerinde titreşir, sadece dalga ilerler."},{"q":"Bir ipi tek bir kez hızlıca sallarsak ipte tek bir kıvrım gider; sürekli sallarsak art arda kıvrımlar gider. Bu iki duruma sırasıyla ne ad verilir?","steps":[{"t":"Tek sallama","a":"darbe","d":"Bir kez sallayınca oluşan tek kıvrıma darbe (atma) denir."},{"t":"Sürekli sallama","a":"periyodik dalga","d":"Sürekli sallayınca art arda kıvrımlar oluşur, buna periyodik dalga denir."}],"ans":"Tek kıvrım darbe (atma), art arda gelen kıvrımlar ise periyodik dalgadır."},{"q":"Bir arkadaşın uzaktan sana sesleniyor ve sesi duyuyorsun. Onun sesi sana ulaşırken aradaki hava kütlesi de sana doğru sürüklenir mi?","steps":[{"t":"Sesi düşün","a":"titreşim yayılır","d":"Arkadaşının sesi havadaki titreşimin yayılmasıyla gelir."},{"t":"Havayı düşün","a":"yer değiştirmez","d":"Hava parçacıkları yerinde titreşir, toptan sana doğru akmaz."}],"ans":"Hayır; hava yerinde titreşir, sana ulaşan şey ses dalgasının taşıdığı enerjidir."},{"q":"Bir taş gölete düştüğünde halkalar yayılırken, suyun yüzeyinden alınan enerji nereden gelir ve nereye taşınır?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='10' fill='#4aa3df' stroke='#1a2b45'/><circle cx='90' cy='75' r='28' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='90' cy='75' r='46' fill='none' stroke='#4aa3df' stroke-width='1.5'/><text x='90' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>kaynak</text><polygon points='150,75 250,75 250,68 270,78 250,88 250,81 150,81' fill='#e0552b'/><text x='215' y='60' font-size='11' fill='#1a2b45'>enerji</text></svg>","steps":[{"t":"Enerjinin kaynağı","a":"taş","d":"Taşın düşmesiyle suya enerji verilir, halkalar burada başlar."},{"t":"Nereye gider","a":"dışarı","d":"Bu enerji dalgalarla dışarıya, kıyıya doğru taşınır."}],"ans":"Enerji taştan suya geçer ve dalgalarla dışarı doğru taşınır; su yer değiştirmez."},{"q":"Bir öğrenci 'dalga geçince su öne doğru gider' diyor. Bu doğru mu? Bir tahta parçasını suya koyarak nasıl test ederiz?","steps":[{"t":"Deneyi kur","a":"tahtayı izle","d":"Suya bir tahta koyup dalga gönderir, tahtanın ne yaptığına bakarız."},{"t":"Gözlemi yorumla","a":"yerinde oynar","d":"Tahta öne gitmez, olduğu yerde aşağı yukarı oynar."}],"ans":"Öğrenci yanılıyor; tahta yerinde oynar, su öne gitmez, sadece dalga ilerler."}]},"ortaokul":{"kolay":[{"q":"Dalga, bir ortamda ilerlerken neyi taşır?","steps":[{"t":"Maddeyi incele","a":"taşımaz","d":"Ortamın parçacıkları yerinde titreşir, dalgayla birlikte gitmez."},{"t":"Taşınanı belirle","a":"enerji","d":"Dalga, kaynaktaki titreşimin enerjisini bir yerden başka yere taşır."}],"ans":"Dalga madde taşımaz; kaynaktan aldığı enerjiyi taşır."},{"q":"Bir dalganın oluşabilmesi için bir kaynak gereklidir. Bu kaynağın temel özelliği nedir?","steps":[{"t":"Kaynağı düşün","a":"titreşir","d":"Su dalgasında taş, ses dalgasında titreşen tel kaynaktır."},{"t":"Özelliği belirle","a":"titreşim","d":"Tüm dalgaları başlatan kaynak titreşim yapar."}],"ans":"Dalga kaynağının temel özelliği titreşim yapmasıdır; titreşim dalgayı başlatır."},{"q":"Yalnızca bir kez yapılan titreşimle oluşan ve ortamda ilerleyen tek kıvrıma ne ad verilir?","fig":"<svg viewBox='0 0 320 120'><path d='M10 70 Q70 25 130 70 L320 70' fill='none' stroke='#e0552b' stroke-width='3'/><circle cx='10' cy='70' r='5' fill='#1a2b45'/><text x='100' y='105' font-size='12' text-anchor='middle' fill='#1a2b45'>tek darbe (atma)</text></svg>","steps":[{"t":"Titreşim sayısı","a":"tek","d":"Kaynak bir kez titreşirse ortamda yalnız bir kıvrım oluşur."},{"t":"Adlandır","a":"darbe","d":"Bu tek kıvrıma darbe ya da atma dalgası denir."}],"ans":"Bir kez titreşimle oluşan tek kıvrıma darbe (atma) dalgası denir."},{"q":"Kaynak sürekli ve düzenli titreştiğinde art arda gelen ve aralıkları eşit olan dalgalar oluşur. Bu tür dalgaya ne denir?","steps":[{"t":"Titreşimi düşün","a":"sürekli","d":"Kaynak durmadan, düzenli titreşirse art arda dalgalar üretir."},{"t":"Adlandır","a":"periyodik dalga","d":"Eşit aralıklarla tekrar eden bu dalgalara periyodik dalga denir."}],"ans":"Kaynağın sürekli ve düzenli titreşmesiyle oluşan dalgalara periyodik dalga denir."},{"q":"Ses, su ve yay dalgalarının yayılabilmesi için ortak olarak neye ihtiyaç vardır?","steps":[{"t":"Örnekleri incele","a":"hava, su, yay","d":"Ses havada, su dalgası suda, yay dalgası yayda yayılır."},{"t":"Ortak gerekliliği bul","a":"ortam","d":"Bu dalgaların ilerlemesi için bir maddesel ortam gereklidir."}],"ans":"Bu dalgaların yayılabilmesi için maddesel bir ortama ihtiyaç vardır."}],"zor":[{"q":"Bir yayda dalga ilerlerken yay üzerindeki işaretli halkanın yerinde kalıp sadece titreştiği gözlenir. Bu durum dalganın hangi temel özelliğini gösterir?","steps":[{"t":"Halkayı izle","a":"yerinde titreşir","d":"İşaretli halka dalga geçerken titreşir ama ileriye gitmez."},{"t":"Sonucu çıkar","a":"madde taşınmaz","d":"Bu, dalganın maddeyi değil enerjiyi taşıdığını gösterir."}],"ans":"Bu durum, dalganın madde taşımadığını, sadece enerji taşıdığını gösterir."},{"q":"İki öğrenciden biri 'dalga ilerlerken parçacıklar da onunla birlikte ilerler', diğeri 'parçacıklar yerinde titreşir' diyor. Hangisi doğrudur ve neden?","steps":[{"t":"İddiaları karşılaştır","a":"titreşim mi taşınma mı","d":"Birincisi maddenin taşındığını, ikincisi yerinde kaldığını söylüyor."},{"t":"Doğruyu seç","a":"yerinde titreşir","d":"Deneyler parçacığın yerinde titreştiğini, sadece enerjinin ilerlediğini gösterir."}],"ans":"İkinci öğrenci doğrudur; parçacıklar yerinde titreşir, dalga yalnız enerjiyi iletir."},{"q":"Ses dalgası havasız ortamda (boşlukta) yayılamazken ışık yayılabilir. Bu fark, dalgaların hangi iki türe ayrıldığını gösterir?","steps":[{"t":"Sesi incele","a":"ortam gerekli","d":"Ses gibi yayılmak için maddesel ortam gerektiren dalgalara mekanik dalga denir."},{"t":"Işığı incele","a":"ortam gereksiz","d":"Işık gibi boşlukta da yayılabilen dalgalara elektromanyetik dalga denir."}],"ans":"Bu fark dalgaların mekanik (ortam gerekli) ve elektromanyetik (ortam gereksiz) olarak ikiye ayrıldığını gösterir."},{"q":"Bir deniz dalgası kıyıya doğru ilerlerken büyük enerji taşır. Bu enerjinin kaynağı genellikle nedir ve dalga bu enerjiyi nasıl iletir?","steps":[{"t":"Kaynağı bul","a":"rüzgar","d":"Açık denizde rüzgar suya enerji aktararak dalgaları oluşturur."},{"t":"İletimi açıkla","a":"titreşimle","d":"Su parçacıkları yerinde titreşerek enerjiyi komşusuna aktarır, böylece dalga ilerler."}],"ans":"Enerji genellikle rüzgardan gelir; su parçacıkları yerinde titreşip enerjiyi komşusuna aktararak iletir."},{"q":"Bir gitar telini çekip bıraktığımızda hem tel titreşir hem de ses duyulur. Burada kaynak nedir ve oluşan dalga hangi yolla kulağımıza ulaşır?","steps":[{"t":"Kaynağı belirle","a":"titreşen tel","d":"Çekilen tel ileri geri titreşerek dalganın kaynağı olur."},{"t":"İletimi açıkla","a":"hava ile","d":"Telin titreşimi havayı titreştirir, ses dalgası hava yoluyla kulağa ulaşır."}],"ans":"Kaynak titreşen teldir; oluşan ses dalgası hava parçacıklarının titreşimiyle kulağımıza ulaşır."}]},"lise":{"kolay":[{"q":"Fizikte dalga kavramı en genel anlamda nasıl tanımlanır?","steps":[{"t":"Olayı incele","a":"titreşim yayılıyor","d":"Bir kaynaktaki titreşim, ortamda komşu noktalara aktarılarak ilerler."},{"t":"Tanımı yaz","a":"enerji yayılımı","d":"Dalga, ortamda madde taşımadan enerjinin ve titreşimin yayılmasıdır."}],"ans":"Dalga, bir ortamda madde taşımadan enerjinin (titreşimin) yayılmasıdır."},{"q":"Bir dalga ortamda ilerlerken ortam parçacıkları ile dalganın kendisi nasıl bir hareket yapar?","fig":"<svg viewBox='0 0 320 150'><path d='M10 80 Q45 40 80 80 T150 80 T220 80 T290 80 L320 80' fill='none' stroke='#4aa3df' stroke-width='3'/><circle cx='115' cy='80' r='6' fill='#e0552b' stroke='#1a2b45'/><line x1='115' y1='50' x2='115' y2='110' stroke='#1a2b45' stroke-width='1' stroke-dasharray='3 3'/><text x='130' y='45' font-size='11' fill='#1a2b45'>parçacık: yerinde</text><polygon points='250,120 285,120 285,114 300,122 285,130 285,124 250,124' fill='#e0552b'/><text x='265' y='112' font-size='10' fill='#1a2b45'>dalga</text></svg>","steps":[{"t":"Parçacığı incele","a":"yerinde titreşir","d":"Ortam parçacıkları denge konumu etrafında ileri geri titreşir."},{"t":"Dalgayı incele","a":"ilerler","d":"Dalga ve onun taşıdığı enerji ortam boyunca ilerler."}],"ans":"Ortam parçacıkları yerinde titreşir; dalga ve enerjisi ortam boyunca ilerler."},{"q":"Mekanik dalga ile elektromanyetik dalga arasındaki en temel fark nedir?","steps":[{"t":"Mekanik dalga","a":"ortam gerekli","d":"Ses, su, yay dalgaları gibi mekanik dalgalar yayılmak için maddesel ortam ister."},{"t":"Elektromanyetik dalga","a":"ortam gereksiz","d":"Işık, radyo dalgası gibi elektromanyetik dalgalar boşlukta da yayılır."}],"ans":"Mekanik dalga yayılmak için maddesel ortam gerektirir; elektromanyetik dalga boşlukta da yayılabilir."},{"q":"Bir kaynağın yalnızca bir kez titreşmesiyle oluşan ve ortamda ilerleyen dalgaya ne ad verilir?","steps":[{"t":"Titreşim sayısı","a":"tek","d":"Kaynak bir kez titreştiğinde ortamda tek bir bozulma oluşur."},{"t":"Adlandır","a":"darbe","d":"Bu tek bozulmaya darbe (atma) dalgası denir."}],"ans":"Kaynağın bir kez titreşmesiyle oluşan dalgaya darbe (atma) dalgası denir."},{"q":"Kaynağın sürekli ve düzenli (özdeş) titreşimleriyle oluşan dalgaya ne ad verilir?","steps":[{"t":"Titreşim biçimi","a":"sürekli ve düzenli","d":"Kaynak eşit zaman aralıklarıyla aynı titreşimi tekrarlar."},{"t":"Adlandır","a":"periyodik dalga","d":"Eşit aralıklarla tekrar eden bu dalgalara periyodik dalga denir."}],"ans":"Kaynağın düzenli ve sürekli titreşimiyle oluşan dalgaya periyodik dalga denir."},{"q":"Dalga yayılırken kaynaktan alınan enerji ne yönde ve nasıl ilerler?","steps":[{"t":"Enerjinin kaynağı","a":"titreşen kaynak","d":"Enerji, titreşen kaynaktan ortama aktarılır."},{"t":"İlerleme biçimi","a":"yayılma yönünde","d":"Enerji, parçacıklar arası titreşim aktarımıyla dalganın yayılma yönünde ilerler."}],"ans":"Enerji kaynaktan başlayıp parçacıklar arası titreşim aktarımıyla dalganın yayılma yönünde ilerler."},{"q":"Ses dalgasının Ay yüzeyinde (havasız ortamda) yayılamamasının nedeni nedir?","steps":[{"t":"Sesin türü","a":"mekanik dalga","d":"Ses, yayılmak için maddesel ortam gerektiren mekanik bir dalgadır."},{"t":"Ortamı incele","a":"boşluk","d":"Ay yüzeyinde hava yoktur; titreşimi iletecek parçacık bulunmaz."}],"ans":"Ses mekanik dalga olduğundan ve havasız ortamda titreşimi iletecek parçacık olmadığından yayılamaz."},{"q":"Bir su dalgasında suyun yüzeyindeki bir yaprak dalga geçerken nasıl hareket eder ve bu neyi kanıtlar?","fig":"<svg viewBox='0 0 320 150'><path d='M10 90 Q45 55 80 90 T150 90 T220 90 T290 90' fill='none' stroke='#4aa3df' stroke-width='3'/><ellipse cx='115' cy='63' rx='12' ry='6' fill='#7cb342' stroke='#1a2b45'/><line x1='115' y1='45' x2='115' y2='110' stroke='#1a2b45' stroke-width='1' stroke-dasharray='3 3'/><text x='130' y='42' font-size='11' fill='#1a2b45'>yaprak</text></svg>","steps":[{"t":"Yaprağı izle","a":"aşağı yukarı","d":"Yaprak dalga geçerken denge konumu etrafında aşağı yukarı oynar."},{"t":"Sonucu çıkar","a":"madde taşınmaz","d":"Yaprağın yatay olarak taşınmaması, dalganın madde değil enerji taşıdığını kanıtlar."}],"ans":"Yaprak yerinde aşağı yukarı oynar; bu, dalganın madde değil enerji taşıdığını kanıtlar."},{"q":"Ses, deprem (sismik) ve yay dalgalarının ortak özelliği nedir ve hepsi hangi dalga grubuna girer?","steps":[{"t":"Ortak özelliği bul","a":"ortam gerekli","d":"Bu dalgaların hepsi yayılmak için maddesel bir ortama gerek duyar."},{"t":"Grupla","a":"mekanik dalga","d":"Maddesel ortam gerektiren bu dalgalar mekanik dalga grubuna girer."}],"ans":"Hepsi yayılmak için maddesel ortam gerektirir ve mekanik dalga grubuna girer."},{"q":"Işık, radyo dalgası ve röntgen ışınlarının ortak özelliği nedir ve hangi dalga grubuna girerler?","steps":[{"t":"Ortak özelliği bul","a":"boşlukta yayılır","d":"Bunların hepsi maddesel ortam olmadan, boşlukta da yayılabilir."},{"t":"Grupla","a":"elektromanyetik","d":"Boşlukta yayılabilen bu dalgalar elektromanyetik dalga grubuna girer."}],"ans":"Hepsi boşlukta yayılabilir ve elektromanyetik dalga grubuna girerler."},{"q":"Bir dalganın 'kaynak', 'ortam' ve 'enerji' kavramlarıyla oluşumu nasıl açıklanır?","steps":[{"t":"Kaynak","a":"titreşim üretir","d":"Titreşen kaynak ortama enerji aktararak dalgayı başlatır."},{"t":"Ortam ve enerji","a":"iletim","d":"Ortam parçacıkları yerinde titreşip enerjiyi komşusuna iletir, dalga ilerler."}],"ans":"Titreşen kaynak ortama enerji verir; ortam parçacıkları titreşip enerjiyi ileterek dalgayı yayar."},{"q":"Aynı ortamda bir darbe dalgası ile periyodik dalga arasındaki temel fark nedir?","steps":[{"t":"Darbe","a":"tek titreşim","d":"Darbe, kaynağın tek bir titreşimiyle oluşan yalnız bir bozulmadır."},{"t":"Periyodik dalga","a":"sürekli titreşim","d":"Periyodik dalga, kaynağın düzenli ve sürekli titreşimiyle oluşan tekrarlı dalgalardır."}],"ans":"Darbe tek titreşimle oluşan tek bozulma; periyodik dalga sürekli düzenli titreşimle oluşan tekrarlı dalgalardır."},{"q":"Dalga yayılırken ortamın net olarak ileri taşınmaması, kütle korunumu açısından neden beklenen bir sonuçtur?","steps":[{"t":"Parçacık hareketi","a":"yerinde titreşir","d":"Her parçacık denge konumu çevresinde gidip geri döner, net yer değiştirmez."},{"t":"Kütle açısından","a":"madde taşınmaz","d":"Madde toptan ilerlemediği için ortamın kütlesi bir yerde birikmez; yalnız enerji iletilir."}],"ans":"Parçacıklar net yer değiştirmediğinden madde ileri taşınmaz; bu, yalnız enerjinin iletildiğini gösterir."},{"q":"Bir hoparlörün önündeki mum alevinin titreşmesi, sesin hangi temel özelliğini doğrudan gösterir?","steps":[{"t":"Olayı incele","a":"hava titreşir","d":"Hoparlör havayı titreştirir, bu titreşim alevi oynatır."},{"t":"Sonucu çıkar","a":"enerji taşır","d":"Alevin oynaması, ses dalgasının havaya enerji taşıdığını gösterir."}],"ans":"Mum alevinin titreşmesi, ses dalgasının havada ilerlerken enerji taşıdığını gösterir."},{"q":"Bir deprem sırasında oluşan sismik dalgalar yerin derinliklerinden yüzeye enerji taşır. Bu dalgalar hangi gruba girer ve yayılmaları için ne gerekir?","steps":[{"t":"Türünü belirle","a":"mekanik dalga","d":"Sismik dalgalar yer katmanları boyunca yayılan mekanik dalgalardır."},{"t":"Gerekliliği belirle","a":"maddesel ortam","d":"Yayılmaları için yer katmanları gibi maddesel bir ortam gerekir."}],"ans":"Sismik dalgalar mekanik dalgadır; yayılmaları için yer katmanları gibi maddesel ortam gerekir."}],"zor":[{"q":"Şekilde bir kaynak titreşerek ortamda dalga üretiyor; ortamdaki üç parçacık farklı konumlarda gösterilmiş. Bu modele dayanarak dalgada hem maddenin hem enerjinin nasıl davrandığını açıklayınız.","fig":"<svg viewBox='0 0 320 160'><path d='M10 85 Q45 45 80 85 T150 85 T220 85 T290 85 L320 85' fill='none' stroke='#4aa3df' stroke-width='3'/><circle cx='45' cy='65' r='6' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='85' r='6' fill='#e0552b' stroke='#1a2b45'/><circle cx='255' cy='105' r='6' fill='#e0552b' stroke='#1a2b45'/><text x='30' y='40' font-size='10' fill='#1a2b45'>P1</text><text x='150' y='115' font-size='10' fill='#1a2b45'>P2</text><text x='270' y='100' font-size='10' fill='#1a2b45'>P3</text><polygon points='270,140 300,140 300,134 314,142 300,150 300,144 270,144' fill='#e0552b'/></svg>","steps":[{"t":"Parçacıkları incele","a":"yerinde titreşir","d":"P1, P2, P3 farklı fazlarda görünse de her biri kendi denge konumu çevresinde titreşir."},{"t":"Enerjiyi incele","a":"ilerler","d":"Her parçacık enerjiyi komşusuna aktarır; böylece enerji ilerler, madde ilerlemez."},{"t":"Sonuç","a":"enerji taşınır","d":"Dalga, parçacıkları yerinde tutarak yalnız enerjiyi yayma konumundadır."}],"ans":"Parçacıklar yerinde titreşir, net yer değiştirmez; dalga ise enerjiyi komşu parçacıklara aktararak ilerletir, yani madde değil enerji taşınır."},{"q":"Bir öğrenci 'dalganın hızı yüksekse taşıdığı madde de hızlı ilerler' diyor. Bu ifadeyi madde-enerji ayrımı açısından eleştiriniz.","steps":[{"t":"İddiayı çözümle","a":"madde taşınmıyor","d":"Dalga madde taşımadığı için 'taşınan madde' kavramı zaten hatalıdır."},{"t":"Hızı yorumla","a":"enerji hızı","d":"Dalga hızı, enerjinin (faz bozulmasının) ortamda yayılma hızıdır, maddenin değil."}],"ans":"İfade hatalıdır; dalga madde taşımaz, dalga hızı yalnızca enerjinin ortamda yayılma hızıdır."},{"q":"Ses dalgası ile ışık dalgasının boşluktaki (uzaydaki) davranışlarını karşılaştırarak mekanik ve elektromanyetik dalga ayrımını gerekçelendiriniz.","steps":[{"t":"Sesi incele","a":"yayılamaz","d":"Ses mekanik dalgadır; boşlukta titreşimi iletecek parçacık olmadığından yayılamaz."},{"t":"Işığı incele","a":"yayılır","d":"Işık elektromanyetik dalgadır; elektrik ve manyetik alan titreşimleriyle boşlukta da yayılır."},{"t":"Sonucu çıkar","a":"ortam koşulu","d":"Ortam gerektiren ses mekanik, gerektirmeyen ışık elektromanyetik dalgadır."}],"ans":"Ses boşlukta yayılamadığı için mekanik, ışık boşlukta yayılabildiği için elektromanyetik dalgadır; ayrımın ölçütü maddesel ortam gerekliliğidir."},{"q":"Bir dalga kaynağının frekansı değiştirildiğinde 'kaynak titreşimi' ile 'ortam parçacıklarının titreşimi' arasındaki ilişki nasıl etkilenir?","steps":[{"t":"Kaynağı düşün","a":"titreşim frekansı","d":"Dalganın frekansı, kaynağın saniyedeki titreşim sayısıyla belirlenir."},{"t":"Ortamı düşün","a":"aynı frekans","d":"Ortam parçacıkları, kaynağın frekansıyla aynı sıklıkta titreşmeye zorlanır."}],"ans":"Ortam parçacıkları kaynakla aynı frekansta titreşir; kaynağın frekansı değişince ortam parçacıklarının titreşim frekansı da aynı oranda değişir."},{"q":"Şekilde aynı yayda art arda gelen iki bozulma görülüyor. Bunların 'darbe' mi yoksa 'periyodik dalga' mı olduğunu, kaynağın titreşim biçimiyle ilişkilendirerek açıklayınız.","fig":"<svg viewBox='0 0 320 140'><path d='M10 75 Q40 45 70 75 Q100 105 130 75 Q160 45 190 75 Q220 105 250 75 L320 75' fill='none' stroke='#5b6b85' stroke-width='3'/><circle cx='10' cy='75' r='5' fill='#1a2b45'/><text x='10' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>kaynak</text><polygon points='270,110 300,110 300,104 314,112 300,120 300,114 270,114' fill='#e0552b'/></svg>","steps":[{"t":"Tekrarı incele","a":"art arda","d":"Bozulmalar eşit aralıklarla art arda geliyor, tek bir kıvrım değil."},{"t":"Kaynağı ilişkilendir","a":"sürekli titreşim","d":"Bu tekrar ancak kaynağın düzenli ve sürekli titreşimiyle oluşur."},{"t":"Sonuç","a":"periyodik","d":"Dolayısıyla bu bir periyodik dalgadır, darbe değildir."}],"ans":"Eşit aralıklarla tekrarlandığından bu bir periyodik dalgadır; bu tekrar yalnızca kaynağın sürekli ve düzenli titreşimiyle oluşur."},{"q":"'Dalga enerji taşır ama madde taşımaz' ilkesini, denizde bir teknenin dalga geçerken davranışını kullanarak açıklayınız.","steps":[{"t":"Tekneyi izle","a":"yerinde salınır","d":"Dalga geçerken tekne yukarı kalkıp aşağı iner ama kıyıya doğru toptan sürüklenmez."},{"t":"Enerjiyi yorumla","a":"iletilir","d":"Dalganın taşıdığı enerji tekneyi salındırır; su parçacıkları yerinde kalır."}],"ans":"Tekne yerinde aşağı yukarı salınır, su kıyıya akmaz; bu, dalganın madde değil yalnız enerji taşıdığını gösterir."},{"q":"Bir kaynak titreşimi durduğunda ortamda zaten ilerlemekte olan dalgaya ne olur? Enerji korunumu açısından yorumlayınız.","steps":[{"t":"Mevcut dalga","a":"ilerlemeye devam","d":"Kaynak dursa da daha önce ortama aktarılmış enerji dalga olarak ilerlemeyi sürdürür."},{"t":"Enerji açısından","a":"yutulana kadar","d":"Bu enerji, sürtünme/sönümlenmeyle ortama dağılana dek dalga taşımaya devam eder."}],"ans":"Önceden aktarılan enerji dalga olarak ilerlemeyi sürdürür; kaynak dursa da bu enerji sönümlenip ortama dağılana kadar dalga var olmaya devam eder."},{"q":"Mekanik bir dalganın hızı esas olarak neye bağlıdır: kaynağa mı yoksa ortamın özelliklerine mi? Gerekçelendiriniz.","steps":[{"t":"Kaynağı düşün","a":"frekansı belirler","d":"Kaynak dalganın frekansını belirler ama yayılma hızını doğrudan belirlemez."},{"t":"Ortamı düşün","a":"hızı belirler","d":"Dalga hızı, ortamın esneklik ve yoğunluk gibi özelliklerine bağlıdır."}],"ans":"Mekanik dalga hızı kaynağa değil, esas olarak ortamın esneklik ve yoğunluk gibi özelliklerine bağlıdır."},{"q":"Bir noktasal kaynaktan çıkan dalgalar dış çembere doğru genişledikçe genliklerinin azaldığı gözlenir. Madde-enerji ilkesiyle çelişmeden bu azalmayı açıklayınız.","steps":[{"t":"Enerjiyi düşün","a":"sabit toplam","d":"Kaynaktan çıkan toplam enerji korunur, yok olmaz."},{"t":"Alanı düşün","a":"çember büyür","d":"Aynı enerji giderek büyüyen çember boyunca dağılır."},{"t":"Sonuç","a":"genlik azalır","d":"Birim uzunluğa düşen enerji azaldığı için genlik küçülür; enerji yine korunur."}],"ans":"Toplam enerji korunur ama büyüyen çember boyunca dağıldığından birim uzunluğa düşen enerji ve dolayısıyla genlik azalır; bu ilkeyle çelişmez."},{"q":"Bir gitar telinin titreşimiyle oluşan ses dalgasını 'kaynak, ortam, taşınan büyüklük ve dalga türü' başlıklarına göre çözümleyiniz.","steps":[{"t":"Kaynak","a":"titreşen tel","d":"Çekilen tel ileri geri titreşerek dalgayı başlatan kaynaktır."},{"t":"Ortam ve taşınan","a":"hava, enerji","d":"Titreşim havayı titreştirir; havada madde değil enerji taşınarak ses ilerler."},{"t":"Tür","a":"mekanik dalga","d":"Hava gibi maddesel ortam gerektirdiği için bu ses dalgası mekaniktir."}],"ans":"Kaynak titreşen tel, ortam hava, taşınan büyüklük enerji, dalga türü ise maddesel ortam gerektiren mekanik dalgadır."},{"q":"İki özdeş yayda, birinde tek darbe diğerinde periyodik dalga üretiliyor. Taşınan enerji ve kaynağın yaptığı iş açısından bu iki durumu karşılaştırınız.","steps":[{"t":"Darbeyi incele","a":"tek seferlik enerji","d":"Tek darbede kaynak bir kez iş yapar, ortama bir defalık enerji aktarılır."},{"t":"Periyodik dalgayı incele","a":"sürekli enerji","d":"Periyodik dalgada kaynak sürekli iş yapar, ortama sürekli enerji aktarır."}],"ans":"Darbede kaynak bir kez iş yapıp tek seferlik enerji aktarır; periyodik dalgada ise kaynak sürekli iş yaparak ortama sürekli enerji aktarır."},{"q":"Deprem sırasında oluşan sismik dalgalar uzakta hasara yol açabilir. Bu durum, dalganın madde mi yoksa enerji mi taşıdığı sorusunu nasıl yanıtlar?","steps":[{"t":"Hasarı düşün","a":"enerji aktarımı","d":"Uzaktaki yapıların yıkılması, oraya büyük enerjinin ulaştığını gösterir."},{"t":"Maddeyi düşün","a":"yer katmanı taşınmaz","d":"Yer katmanları toptan o noktaya göç etmez, yalnız titreşim iletilir."}],"ans":"Sismik dalga maddeyi taşımaz; yer katmanları yerinde titreşip enerjiyi uzağa ileterek hasara yol açar, yani dalga enerji taşır."},{"q":"'Tüm dalgalar yayılmak için bir ortama ihtiyaç duyar' önermesini doğru/yanlış olarak değerlendirip gerekçelendiriniz.","steps":[{"t":"Mekanik dalgayı incele","a":"ortam gerekli","d":"Ses, su gibi mekanik dalgalar için bu doğrudur, ortam şarttır."},{"t":"Elektromanyetik dalgayı incele","a":"ortam gereksiz","d":"Işık gibi elektromanyetik dalgalar boşlukta da yayıldığı için önerme genel olarak yanlıştır."}],"ans":"Önerme yanlıştır; yalnız mekanik dalgalar ortam gerektirir, elektromanyetik dalgalar boşlukta da yayılabilir."},{"q":"Bir su tankında oluşturulan dalganın hızını artırmak isteyen bir öğrenci kaynağı daha hızlı sallıyor. Bu yöntemin neden dalga hızını değiştirmediğini açıklayınız.","steps":[{"t":"Sallamayı yorumla","a":"frekans artar","d":"Kaynağı hızlı sallamak dalganın frekansını artırır, hızını değil."},{"t":"Hızın bağımlılığı","a":"ortam","d":"Dalga hızı suyun derinliği gibi ortam özelliklerine bağlıdır, kaynağa değil."}],"ans":"Kaynağı hızlı sallamak yalnız frekansı artırır; dalga hızı ortamın özelliklerine bağlı olduğundan değişmez."},{"q":"Şekilde bir darbe yay boyunca ilerlerken yayın bir halkasının izlediği yol noktalı çizgiyle gösterilmiş. Bu yola dayanarak parçacığın net yer değiştirmesini ve dalganın taşıdığı büyüklüğü açıklayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='10' y1='90' x2='320' y2='90' stroke='#5b6b85' stroke-width='1' stroke-dasharray='2 4'/><path d='M10 90 Q90 90 130 50 Q150 30 170 50 Q210 90 320 90' fill='none' stroke='#e0552b' stroke-width='3'/><circle cx='150' cy='90' r='6' fill='#1a2b45'/><line x1='150' y1='40' x2='150' y2='100' stroke='#1a2b45' stroke-width='1' stroke-dasharray='3 3'/><text x='168' y='35' font-size='10' fill='#1a2b45'>halka yukarı-aşağı</text></svg>","steps":[{"t":"Halkayı izle","a":"yukarı çıkıp iner","d":"Darbe geçerken halka denge çizgisinden yukarı çıkar, sonra eski yerine döner."},{"t":"Net yer değiştirme","a":"sıfır","d":"Darbe geçtikten sonra halka başladığı yerdedir; net yer değiştirmesi sıfırdır."},{"t":"Taşınan büyüklük","a":"enerji","d":"Halka yerinde kaldığına göre dalga madde değil enerji taşımıştır."}],"ans":"Halka yukarı çıkıp eski yerine döndüğü için net yer değiştirmesi sıfırdır; dalga maddeyi taşımamış, yalnız enerjiyi iletmiştir."}]}},"depremDalgasi":{"ilkokul":{"kolay":[{"q":"Deprem olduğunda yer altından çıkıp her yöne yayılan titreşimlere ne denir?","steps":[{"t":"Deprem nedir","a":"yerin sarsılması","d":"Yer kabuğu kırılınca yer aniden sarsılır."},{"t":"Yayılan titreşim","a":"deprem dalgası","d":"Bu sarsıntı su dalgası gibi her yöne yayılır, buna deprem dalgası denir."}],"ans":"Bu titreşimlere deprem (sismik) dalgaları denir."},{"q":"Depremin yer altında ilk başladığı noktaya ne ad verilir?","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='90' width='320' height='90' fill='#caa472'/><rect x='0' y='0' width='320' height='90' fill='#dfeefb'/><circle cx='160' cy='140' r='8' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>Odak</text><circle cx='160' cy='90' r='5' fill='#1a2b45'/><text x='160' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Yer üstü</text></svg>","steps":[{"t":"Başlama yeri","a":"yer altı","d":"Deprem yerin derinliklerinde bir noktada başlar."},{"t":"Bu noktanın adı","a":"odak","d":"Yer altındaki bu başlangıç noktasına odak denir."}],"ans":"Depremin yer altında başladığı noktaya odak denir."},{"q":"Deprem dalgalarını ölçen ve kâğıda çizdiren alete ne denir?","steps":[{"t":"Ne işe yarar","a":"sarsıntıyı ölçer","d":"Bu alet yerin sarsıntısını yakalar."},{"t":"Adı","a":"sismograf","d":"Sarsıntıyı çizgi olarak kâğıda çizen alete sismograf denir."}],"ans":"Bu alete sismograf (deprem yazıcı) denir."},{"q":"Deprem dalgaları havada mı yoksa yerin içinde mi daha çok yayılır?","steps":[{"t":"Nereden çıkar","a":"yerden","d":"Deprem dalgaları yer kabuğunun içinde oluşur."},{"t":"Nasıl yayılır","a":"yerin içinde","d":"Bu dalgalar toprağın ve kayaların içinden geçerek yayılır."}],"ans":"Deprem dalgaları yerin (toprağın ve kayaların) içinde yayılır."},{"q":"Bir gölete taş atınca oluşan halkalar gibi, deprem dalgaları da odaktan nasıl yayılır?","steps":[{"t":"Taş örneği","a":"halka halka","d":"Suya taş atınca dalgalar her yöne halkalar yapar."},{"t":"Deprem dalgası","a":"her yöne","d":"Deprem dalgaları da odaktan başlayıp her yöne yayılır."}],"ans":"Deprem dalgaları odaktan her yöne yayılır."}],"zor":[{"q":"Deprem dalgalarından biri çok hızlıdır ve bir yere ilk o ulaşır. Hangisinin daha önce gelmesini bekleriz: hızlı dalga mı yavaş dalga mı?","steps":[{"t":"Kim önce varır","a":"hızlı olan","d":"Daha hızlı giden dalga bir yere daha erken ulaşır."},{"t":"Sonuç","a":"hızlı dalga","d":"Bu yüzden hızlı dalga her zaman önce hissedilir."}],"ans":"Daha hızlı olan dalga önce gelir."},{"q":"Sismografta önce küçük titreşimler, biraz sonra büyük sarsıntılar görülür. Büyük sarsıntılar neden sonra gelir?","fig":"<svg viewBox='0 0 320 120'><line x1='10' y1='60' x2='310' y2='60' stroke='#1a2b45' stroke-width='1'/><polyline points='10,60 60,60 70,54 80,66 90,55 100,65 110,60' fill='none' stroke='#4aa3df' stroke-width='1.5'/><polyline points='110,60 150,60 160,30 172,92 184,32 196,90 208,40 220,80 232,60 310,60' fill='none' stroke='#e0552b' stroke-width='1.5'/><text x='70' y='105' font-size='11' fill='#1a2b45'>önce küçük</text><text x='200' y='105' font-size='11' fill='#1a2b45'>sonra büyük</text></svg>","steps":[{"t":"Önce gelen","a":"hızlı dalga","d":"Hızlı dalga önce gelir ama titreşimi küçüktür."},{"t":"Sonra gelen","a":"yavaş dalga","d":"Daha yavaş giden dalga sonra gelir ve sarsıntısı büyüktür."}],"ans":"Büyük sarsıntı yapan dalga daha yavaş olduğu için sonra gelir."},{"q":"Yer üstünde, odağın tam üstündeki noktaya 'merkez üssü' denir. Bu nokta odağın neresindedir?","steps":[{"t":"Odak nerede","a":"yer altında","d":"Odak yerin derinliklerindedir."},{"t":"Merkez üssü","a":"tam üstünde","d":"Merkez üssü odağın tam yukarısındaki yer üstü noktasıdır."}],"ans":"Merkez üssü, odağın tam üstündeki yer üstü noktasıdır."},{"q":"Depremde en çok hasarı genellikle hangi nokta yakınında görürüz: merkez üssüne yakın yerler mi uzak yerler mi?","steps":[{"t":"Sarsıntı nerede güçlü","a":"merkeze yakın","d":"Dalgalar yol aldıkça zayıflar, merkeze yakın yerde daha güçlüdür."},{"t":"Hasar","a":"yakında çok","d":"Bu yüzden merkez üssüne yakın yerlerde hasar daha fazladır."}],"ans":"Merkez üssüne yakın yerlerde hasar daha fazladır."},{"q":"Bir deprem dalgası kayanın içinden mi yoksa boşluktan (havasız uzaydan) mı geçebilir?","steps":[{"t":"Neye ihtiyaç var","a":"madde","d":"Deprem dalgası yayılmak için kaya, toprak gibi bir maddeye ihtiyaç duyar."},{"t":"Boşluk","a":"geçemez","d":"İçinde madde olmayan boşlukta deprem dalgası yayılamaz."}],"ans":"Deprem dalgası kayanın içinden geçer; maddesiz boşlukta yayılamaz."}]},"ortaokul":{"kolay":[{"q":"Deprem dalgalarından <b>P dalgası</b> ile <b>S dalgası</b>'ndan hangisi bir yere daha önce ulaşır?","steps":[{"t":"Hız karşılaştırması","a":"P daha hızlı","d":"P dalgası (Primary) S dalgasından daha hızlıdır."},{"t":"Varış","a":"önce P","d":"Daha hızlı olduğu için P dalgası bir yere her zaman ilk ulaşır."}],"ans":"P dalgası daha hızlı olduğu için önce ulaşır."},{"q":"P dalgasında parçacıklar yayılma yönüyle nasıl titreşir: aynı doğrultuda mı dik mi? Bu nasıl bir dalgadır?","fig":"<svg viewBox='0 0 320 110'><line x1='10' y1='55' x2='300' y2='55' stroke='#1a2b45' stroke-width='1'/><polygon points='300,55 290,50 290,60' fill='#1a2b45'/><text x='270' y='80' font-size='11' fill='#1a2b45'>yayılma yönü</text><g stroke='#e0552b' stroke-width='2'><line x1='40' y1='40' x2='40' y2='70'/><line x1='52' y1='40' x2='52' y2='70'/><line x1='64' y1='40' x2='64' y2='70'/><line x1='110' y1='40' x2='110' y2='70'/><line x1='118' y1='40' x2='118' y2='70'/><line x1='180' y1='40' x2='180' y2='70'/><line x1='188' y1='40' x2='188' y2='70'/><line x1='196' y1='40' x2='196' y2='70'/></g><text x='160' y='25' font-size='12' text-anchor='middle' fill='#1a2b45'>sıkışma - gevşeme</text></svg>","steps":[{"t":"Titreşim yönü","a":"aynı doğrultuda","d":"P dalgasında parçacıklar dalganın gittiği doğrultuda ileri-geri titreşir."},{"t":"Dalga türü","a":"boyuna dalga","d":"Yayılma yönüyle aynı doğrultuda titreşen dalgaya boyuna dalga denir."}],"ans":"P dalgası boyuna dalgadır; parçacıklar yayılma yönüyle aynı doğrultuda titreşir."},{"q":"S dalgasında parçacıklar yayılma yönüne göre nasıl titreşir ve bu nasıl bir dalga türüdür?","steps":[{"t":"Titreşim yönü","a":"dik","d":"S dalgasında parçacıklar yayılma yönüne dik olarak titreşir."},{"t":"Dalga türü","a":"enine dalga","d":"Yayılma yönüne dik titreşen dalgaya enine dalga denir."}],"ans":"S dalgası enine dalgadır; parçacıklar yayılma yönüne dik titreşir."},{"q":"Deprem dalgalarından hangisi sıvı içinde (örneğin Dünya'nın sıvı dış çekirdeğinde) yayılamaz?","steps":[{"t":"S dalgası özelliği","a":"sıvıda yayılmaz","d":"S dalgası (enine) sadece katı ortamda yayılır, sıvıda yayılamaz."},{"t":"P dalgası","a":"yayılır","d":"P dalgası ise hem katıda hem sıvıda yayılabilir."}],"ans":"S dalgası sıvı içinde yayılamaz."},{"q":"Depremde en büyük yıkımı genellikle hangi dalgalar yapar: derinden geçen dalgalar mı yoksa yüzey dalgaları mı?","steps":[{"t":"Yüzey dalgaları","a":"en yıkıcı","d":"Yüzey dalgaları yer yüzeyi boyunca yavaş ama büyük genlikle ilerler."},{"t":"Sonuç","a":"yüzey dalgaları","d":"Genlikleri büyük olduğu için binalarda en çok hasarı yüzey dalgaları yapar."}],"ans":"En büyük yıkımı genellikle yüzey dalgaları yapar."}],"zor":[{"q":"Bir sismografta P dalgası saat 10.00.10'da, S dalgası 10.00.25'te kaydedilmiştir. P ile S arasındaki varış zaman farkı kaç saniyedir ve bu fark uzaklık hakkında ne söyler?","steps":[{"t":"Zaman farkı","a":"15 s","d":"25 − 10 = 15 saniye; S dalgası P'den 15 s sonra gelmiştir."},{"t":"Yorum","a":"uzaklık ölçüsü","d":"Zaman farkı büyüdükçe deprem merkezi istasyona daha uzaktır."}],"ans":"Zaman farkı 15 saniyedir; bu fark ne kadar büyükse merkez o kadar uzaktır."},{"q":"İki istasyondan biri P ve S arasında 5 s, diğeri 12 s fark ölçmüştür. Hangi istasyon deprem merkezine daha yakındır?","steps":[{"t":"Fark-uzaklık ilişkisi","a":"küçük fark yakın","d":"P-S zaman farkı küçükse istasyon merkeze daha yakındır."},{"t":"Karşılaştırma","a":"5 s olan","d":"5 s ölçen istasyon, 12 s ölçenden merkeze daha yakındır."}],"ans":"5 saniye fark ölçen istasyon deprem merkezine daha yakındır."},{"q":"Deprem merkezinin yerini doğru belirlemek için en az kaç sismograf istasyonu gerekir ve neden?","fig":"<svg viewBox='0 0 320 180'><circle cx='90' cy='70' r='55' fill='none' stroke='#4aa3df' stroke-width='1.5'/><circle cx='220' cy='60' r='60' fill='none' stroke='#4aa3df' stroke-width='1.5'/><circle cx='160' cy='150' r='65' fill='none' stroke='#4aa3df' stroke-width='1.5'/><circle cx='90' cy='70' r='3' fill='#1a2b45'/><circle cx='220' cy='60' r='3' fill='#1a2b45'/><circle cx='160' cy='150' r='3' fill='#1a2b45'/><circle cx='149' cy='95' r='5' fill='#e0552b' stroke='#1a2b45'/><text x='149' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>merkez</text></svg>","steps":[{"t":"Tek istasyon","a":"sadece uzaklık","d":"Bir istasyon yalnızca merkeze olan uzaklığı (bir çember) verir, yönü vermez."},{"t":"Üç istasyon","a":"3 çember kesişir","d":"Üç istasyonun çemberleri tek noktada kesişerek merkezi belirler."}],"ans":"En az üç istasyon gerekir; üç çemberin kesişimi merkezi tam belirler."},{"q":"P dalgası katı ve sıvıdan geçtiği, S dalgası ise sıvıdan geçemediği için bilim insanları Dünya'nın iç yapısı hakkında neyi anlamıştır?","steps":[{"t":"Gözlem","a":"S kayboluyor","d":"S dalgaları belli bölgede istasyonlara ulaşmaz (S gölge bölgesi)."},{"t":"Çıkarım","a":"sıvı dış çekirdek","d":"S dalgası sıvıdan geçemediği için dış çekirdeğin sıvı olduğu anlaşılmıştır."}],"ans":"Dünya'nın dış çekirdeğinin sıvı olduğu anlaşılmıştır."},{"q":"Bir bölgede P dalgasının hızı yaklaşık 6 km/s, S dalgasının hızı 3,5 km/s'dir. Aynı odaktan çıkan bu dalgalardan hangisi sismografa önce ulaşır ve neden zamanla aralarındaki fark açılır?","steps":[{"t":"Hız karşılaştırması","a":"P hızlı","d":"6 km/s > 3,5 km/s olduğu için P dalgası daha hızlıdır."},{"t":"Fark neden açılır","a":"uzaklıkla artar","d":"Hız farkı sabit olduğundan yol uzadıkça varış zaman farkı da büyür."}],"ans":"P dalgası önce ulaşır; uzaklık arttıkça P-S zaman farkı büyür."}]},"lise":{"kolay":[{"q":"<b>P dalgası</b> (boyuna) ile <b>S dalgası</b> (enine) arasındaki temel titreşim farkı nedir?","steps":[{"t":"P dalgası","a":"boyuna","d":"P dalgasında ortam parçacıkları yayılma doğrultusunda ileri-geri (sıkışma-gevşeme) titreşir."},{"t":"S dalgası","a":"enine","d":"S dalgasında parçacıklar yayılma doğrultusuna dik titreşir."}],"ans":"P boyuna (yayılma yönünde), S enine (yayılma yönüne dik) titreşir."},{"q":"P dalgasının katı, sıvı ve gazda yayılabilmesinin nedeni hangi dalga türü özelliğidir?","steps":[{"t":"Yayılma mekanizması","a":"sıkışma","d":"Boyuna dalga ortamın hacimsel sıkışıp gevşemesiyle ilerler."},{"t":"Ortam","a":"hepsinde var","d":"Katı, sıvı ve gaz hepsi sıkıştırılabildiğinden P dalgası hepsinde yayılır."}],"ans":"P boyuna dalga olduğu için (hacimsel sıkışma) katı, sıvı ve gazda yayılır."},{"q":"S dalgasının yalnızca katı ortamda yayılabilmesinin fiziksel nedeni nedir?","steps":[{"t":"Enine dalga gereksinimi","a":"kayma direnci","d":"Enine dalga ortamın kayma (makaslama) gerilmesine direnç göstermesini gerektirir."},{"t":"Sıvı/gaz","a":"kayma direnci yok","d":"Sıvı ve gaz kayma gerilmesine direnemediği için S dalgasını taşıyamaz."}],"ans":"S dalgası kayma gerilmesi gerektirir; sıvı ve gazda bu olmadığından yalnız katıda yayılır."},{"q":"Deprem terminolojisinde <b>odak (hiposantr)</b> ile <b>merkez üssü (episantr)</b> arasındaki fark nedir?","fig":"<svg viewBox='0 0 320 180'><rect x='0' y='70' width='320' height='110' fill='#caa472'/><rect x='0' y='0' width='320' height='70' fill='#dfeefb'/><line x1='0' y1='70' x2='320' y2='70' stroke='#1a2b45' stroke-width='1'/><circle cx='160' cy='130' r='7' fill='#e0552b' stroke='#1a2b45'/><text x='205' y='133' font-size='11' fill='#1a2b45'>odak (hiposantr)</text><line x1='160' y1='130' x2='160' y2='70' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 3'/><circle cx='160' cy='70' r='5' fill='#1a2b45'/><text x='160' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>merkez üssü</text></svg>","steps":[{"t":"Odak","a":"yer altı","d":"Odak, kırılmanın başladığı yer altındaki gerçek noktadır."},{"t":"Merkez üssü","a":"yüzey izdüşümü","d":"Merkez üssü odağın yer yüzeyindeki dik izdüşümüdür."}],"ans":"Odak yer altındaki kaynak noktasıdır; merkez üssü onun yüzeydeki dik izdüşümüdür."},{"q":"Sismografta kaydedilen dalgalar genelde hangi sırayla görülür?","steps":[{"t":"En hızlı","a":"P","d":"İlk kaydedilen, en hızlı olan P dalgasıdır."},{"t":"Sonraki","a":"S, sonra yüzey","d":"Sonra S dalgası, en son ve en büyük genlikle yüzey dalgaları gelir."}],"ans":"Önce P, sonra S, en son yüzey dalgaları kaydedilir."},{"q":"Yüzey dalgalarının (Love ve Rayleigh) en yıkıcı olmasının nedeni nedir?","steps":[{"t":"Yayıldıkları yer","a":"yüzey","d":"Yüzey dalgaları enerjilerini yer yüzeyi boyunca taşır, derine dağılmaz."},{"t":"Genlik","a":"büyük","d":"Yüzeyde genlikleri büyük olduğundan binalarda en fazla hasarı yaparlar."}],"ans":"Enerjileri yüzeyde yoğunlaşıp genlikleri büyük olduğu için en yıkıcıdırlar."},{"q":"P dalgasının ve S dalgasının ortalama hızları (yer kabuğunda) hangisi daha büyüktür ve oransal olarak yaklaşık ne kadardır?","steps":[{"t":"Hız sıralaması","a":"P > S","d":"P dalgası S dalgasından daha hızlıdır."},{"t":"Oran","a":"yaklaşık 1,7 kat","d":"Tipik kabukta P hızı S hızının yaklaşık 1,7 katıdır (örn. 6 ve 3,5 km/s)."}],"ans":"P dalgası S'den daha hızlıdır; hızı yaklaşık 1,7 katı kadardır."},{"q":"S dalgalarının ulaşamadığı, Dünya'nın belirli bir açı aralığındaki bölgeye ne ad verilir ve neyi kanıtlar?","steps":[{"t":"Adı","a":"S gölge bölgesi","d":"S dalgalarının istasyonlara hiç ulaşmadığı geniş bölgeye S gölge bölgesi denir."},{"t":"Kanıtı","a":"sıvı dış çekirdek","d":"S sıvıdan geçemediği için bu bölge dış çekirdeğin sıvı olduğunu kanıtlar."}],"ans":"S gölge bölgesidir ve dış çekirdeğin sıvı olduğunu kanıtlar."},{"q":"Bir sismografta P dalgasının varış saati 14.30.20, S dalgasının 14.30.32 ise P-S zaman farkı kaç saniyedir?","steps":[{"t":"Çıkarma","a":"32 − 20","d":"İki varış saatinin saniye değerleri çıkarılır."},{"t":"Sonuç","a":"12 s","d":"32 − 20 = 12 saniye."}],"ans":"P-S zaman farkı 12 saniyedir."},{"q":"P-S zaman farkı (Δt) ile deprem merkezine olan uzaklık arasında nasıl bir ilişki vardır?","steps":[{"t":"İlişki türü","a":"doğru orantılı","d":"Δt büyüdükçe istasyonun merkeze uzaklığı da artar."},{"t":"Neden","a":"hız farkı sabit","d":"P ve S hız farkı yaklaşık sabit olduğundan fark, yola doğru orantılı büyür."}],"ans":"P-S zaman farkı arttıkça merkeze uzaklık doğru orantılı olarak artar."},{"q":"Şekildeki sismogramda P ve S dalgalarının başlangıçları işaretlenmiştir. P-S aralığının genişliği neyi gösterir?","fig":"<svg viewBox='0 0 320 120'><line x1='10' y1='60' x2='310' y2='60' stroke='#1a2b45' stroke-width='1'/><polyline points='10,60 80,60 88,50 96,70 104,56 112,60 310,60' fill='none' stroke='#1a2b45' stroke-width='0' /><line x1='90' y1='25' x2='90' y2='95' stroke='#4aa3df' stroke-width='1.5' stroke-dasharray='4 3'/><text x='90' y='18' font-size='11' text-anchor='middle' fill='#1a2b45'>P</text><line x1='200' y1='25' x2='200' y2='95' stroke='#e0552b' stroke-width='1.5' stroke-dasharray='4 3'/><text x='200' y='18' font-size='11' text-anchor='middle' fill='#1a2b45'>S</text><polyline points='200,60 210,40 220,82 230,38 240,84 250,45 260,75 270,60 310,60' fill='none' stroke='#e0552b' stroke-width='1.5'/><line x1='90' y1='105' x2='200' y2='105' stroke='#1a2b45' stroke-width='1'/><text x='145' y='118' font-size='11' text-anchor='middle' fill='#1a2b45'>Δt (P-S aralığı)</text></svg>","steps":[{"t":"Aralık nedir","a":"varış farkı","d":"İşaretli aralık P ve S dalgalarının varış zaman farkıdır."},{"t":"Ne gösterir","a":"uzaklık","d":"Bu aralık genişledikçe istasyonun deprem merkezine uzaklığı artar."}],"ans":"P-S aralığı varış zaman farkıdır ve istasyonun merkeze uzaklığını gösterir."},{"q":"Deprem büyüklüğü (magnitüd) ile depremin şiddeti (yapılarda hissedilen etki) arasındaki fark nedir?","steps":[{"t":"Büyüklük","a":"açığa çıkan enerji","d":"Magnitüd, kaynakta açığa çıkan enerjinin tek bir sayısal ölçüsüdür."},{"t":"Şiddet","a":"yere göre değişir","d":"Şiddet, bir yerdeki sarsıntı etkisidir ve merkeze uzaklık/zemine göre değişir."}],"ans":"Büyüklük kaynaktaki enerjidir (tek değer); şiddet ise yere göre değişen etkidir."},{"q":"Tek bir sismograf istasyonu deprem merkezinin hangi bilgisini verebilir, hangisini veremez?","steps":[{"t":"Verebileceği","a":"uzaklık","d":"P-S zaman farkından merkeze olan uzaklık bulunur."},{"t":"Veremeyeceği","a":"yön","d":"Tek istasyon yönü belirleyemez; yalnız bir çember (uzaklık) verir."}],"ans":"Tek istasyon merkeze uzaklığı verir ama yönünü/tam yerini veremez."},{"q":"P dalgasına neden 'Primary (birincil)', S dalgasına 'Secondary (ikincil)' denmiştir?","steps":[{"t":"P","a":"ilk gelen","d":"P en hızlı dalga olduğu için istasyona ilk (primary) ulaşır."},{"t":"S","a":"ikinci gelen","d":"S daha yavaş olup ikinci (secondary) sırada kaydedilir."}],"ans":"P ilk geldiği için 'birincil', S ikinci geldiği için 'ikincil' adını alır."},{"q":"Yüzey dalgaları cisim dalgalarından (P ve S) hız ve genlik bakımından nasıl ayrılır?","steps":[{"t":"Hız","a":"daha yavaş","d":"Yüzey dalgaları P ve S'den daha yavaştır, en son ulaşır."},{"t":"Genlik","a":"daha büyük","d":"Genlikleri büyüktür, bu yüzden hasar potansiyelleri yüksektir."}],"ans":"Yüzey dalgaları cisim dalgalarından daha yavaş ama daha büyük genliklidir."}],"zor":[{"q":"Bir istasyonda P dalgası saat 09.15.05'te, S dalgası 09.15.25'te kaydedildi. P hızı 8 km/s, S hızı 4 km/s ise depremin merkez üssüne uzaklığı yaklaşık kaç km'dir?","steps":[{"t":"Zaman farkı","a":"Δt = 20 s","d":"25 − 5 = 20 saniye varış zaman farkı bulunur."},{"t":"Δt formülü","a":"Δt = d/Vs − d/Vp","d":"d(1/4 − 1/8) = d·(1/8) = 20 → çünkü 1/4 − 1/8 = 1/8 s/km."},{"t":"Uzaklık","a":"d = 160 km","d":"d = 20 ÷ (1/8) = 20 × 8 = 160 km."}],"ans":"Deprem merkezi istasyona yaklaşık 160 km uzaktadır."},{"q":"P hızı 6 km/s, S hızı 3 km/s olan bir bölgede P-S zaman farkı 15 s ölçülmüştür. Merkez uzaklığı kaç km'dir?","steps":[{"t":"Katsayı","a":"1/Vs − 1/Vp","d":"1/3 − 1/6 = 2/6 − 1/6 = 1/6 s/km."},{"t":"Denklem","a":"d·(1/6) = 15","d":"Δt = d × (1/6) = 15 saniye."},{"t":"Uzaklık","a":"d = 90 km","d":"d = 15 × 6 = 90 km."}],"ans":"Deprem merkezi yaklaşık 90 km uzaktadır."},{"q":"İki istasyondan A'da P-S farkı 8 s, B'de 20 s ölçülmüştür (her ikisinde Vp=8, Vs=4 km/s). İki istasyonun merkeze uzaklıklarını ve oranlarını bulunuz.","steps":[{"t":"Katsayı","a":"1/4 − 1/8 = 1/8","d":"Her iki istasyon için d = Δt ÷ (1/8) = Δt × 8."},{"t":"A uzaklığı","a":"64 km","d":"d(A) = 8 × 8 = 64 km."},{"t":"B uzaklığı ve oran","a":"160 km, 1:2,5","d":"d(B) = 20 × 8 = 160 km; oran 64:160 = 1:2,5."}],"ans":"A 64 km, B 160 km uzaktadır; uzaklık oranı 1:2,5'tir."},{"q":"Bir sismografta P 10.00.00, S 10.00.30'da kaydedildi. Vp=8, Vs=5 km/s ise merkez uzaklığı kaç km'dir?","steps":[{"t":"Zaman farkı","a":"Δt = 30 s","d":"30 − 0 = 30 saniye."},{"t":"Katsayı","a":"1/5 − 1/8","d":"1/5 − 1/8 = 8/40 − 5/40 = 3/40 s/km."},{"t":"Uzaklık","a":"d = 400 km","d":"d = 30 ÷ (3/40) = 30 × 40/3 = 400 km."}],"ans":"Deprem merkezi yaklaşık 400 km uzaktadır."},{"q":"Üç istasyon için bulunan merkez uzaklıkları sırasıyla 100 km, 150 km ve 200 km'dir. Bu verilerle deprem merkezi nasıl belirlenir? Yöntemin adı nedir?","fig":"<svg viewBox='0 0 320 180'><circle cx='80' cy='60' r='50' fill='none' stroke='#4aa3df' stroke-width='1.5'/><text x='80' y='55' font-size='10' text-anchor='middle' fill='#1a2b45'>100 km</text><circle cx='230' cy='55' r='62' fill='none' stroke='#4aa3df' stroke-width='1.5'/><text x='230' y='50' font-size='10' text-anchor='middle' fill='#1a2b45'>150 km</text><circle cx='150' cy='150' r='70' fill='none' stroke='#4aa3df' stroke-width='1.5'/><text x='150' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>200 km</text><circle cx='128' cy='92' r='5' fill='#e0552b' stroke='#1a2b45'/></svg>","steps":[{"t":"Her uzaklık","a":"bir çember","d":"Her istasyon, merkeze uzaklığı yarıçap olan bir çember tanımlar."},{"t":"Kesişim","a":"tek nokta","d":"Üç çemberin ortak kesişim noktası deprem merkezini verir."},{"t":"Yöntem","a":"üçleme","d":"Bu yönteme üçleme (triangülasyon) denir."}],"ans":"Üç çemberin kesiştiği nokta merkezdir; yönteme üçleme (triangülasyon) denir."},{"q":"Vp=7 km/s, Vs=3,5 km/s olan bir ortamda merkeze uzaklık 140 km ise P ile S dalgaları arasındaki varış zaman farkı kaç saniyedir?","steps":[{"t":"P süresi","a":"20 s","d":"t(P) = 140 ÷ 7 = 20 saniye."},{"t":"S süresi","a":"40 s","d":"t(S) = 140 ÷ 3,5 = 40 saniye."},{"t":"Fark","a":"20 s","d":"Δt = 40 − 20 = 20 saniye."}],"ans":"P-S varış zaman farkı 20 saniyedir."},{"q":"Aynı depremde Vp=8 km/s ve Vs=4 km/s'dir. 240 km uzaklıktaki bir istasyona P dalgasının ulaşma süresi ile S dalgasının ulaşma süresini ve farkını bulunuz.","steps":[{"t":"P süresi","a":"30 s","d":"t(P) = 240 ÷ 8 = 30 saniye."},{"t":"S süresi","a":"60 s","d":"t(S) = 240 ÷ 4 = 60 saniye."},{"t":"Fark","a":"30 s","d":"Δt = 60 − 30 = 30 saniye."}],"ans":"P 30 s, S 60 s'de ulaşır; varış zaman farkı 30 saniyedir."},{"q":"S dalgaları yerin merkezi çevresinde yaklaşık 105°'den sonra istasyonlara ulaşmaz. Bu gözlem Dünya'nın iç yapısı hakkında hangi iki sonucu verir?","steps":[{"t":"S gölge bölgesi","a":"sıvı engel","d":"S dalgasının kaybolması, yolu üzerinde sıvı bir katman olduğunu gösterir."},{"t":"Sonuç 1","a":"sıvı dış çekirdek","d":"S sıvıdan geçemediğinden dış çekirdeğin sıvı olduğu sonucuna varılır."},{"t":"Sonuç 2","a":"çekirdek-manto sınırı","d":"P dalgalarının kırılmasıyla birlikte çekirdek ile manto arasında keskin bir sınır olduğu anlaşılır."}],"ans":"Dış çekirdeğin sıvı olduğu ve çekirdek-manto sınırının bulunduğu anlaşılır."},{"q":"Şekildeki sismogramda P dalgası t=10 s, S dalgası t=22 s'de başlamaktadır. Vp=6, Vs=3 km/s ise merkez uzaklığını hesaplayınız.","fig":"<svg viewBox='0 0 320 120'><line x1='10' y1='60' x2='310' y2='60' stroke='#1a2b45' stroke-width='1'/><line x1='10' y1='60' x2='310' y2='60' stroke='#1a2b45' stroke-width='1'/><line x1='90' y1='25' x2='90' y2='95' stroke='#4aa3df' stroke-width='1.5' stroke-dasharray='4 3'/><text x='90' y='18' font-size='11' text-anchor='middle' fill='#1a2b45'>P (10 s)</text><line x1='210' y1='25' x2='210' y2='95' stroke='#e0552b' stroke-width='1.5' stroke-dasharray='4 3'/><text x='212' y='18' font-size='11' text-anchor='middle' fill='#1a2b45'>S (22 s)</text><polyline points='90,60 98,48 106,72 114,54 122,60 310,60' fill='none' stroke='#1a2b45' stroke-width='1'/><polyline points='210,60 220,38 230,84 240,40 250,82 260,55 310,60' fill='none' stroke='#e0552b' stroke-width='1.5'/></svg>","steps":[{"t":"Zaman farkı","a":"Δt = 12 s","d":"22 − 10 = 12 saniye."},{"t":"Katsayı","a":"1/3 − 1/6 = 1/6","d":"1/3 − 1/6 = 1/6 s/km."},{"t":"Uzaklık","a":"d = 72 km","d":"d = 12 ÷ (1/6) = 12 × 6 = 72 km."}],"ans":"Deprem merkezi yaklaşık 72 km uzaktadır."},{"q":"Bir depremin enerjisi başka bir depremden 1000 kat fazladır. Richter ölçeği logaritmik olduğundan (her 1 birim ≈ 10 kat enerji oranı yaklaşımıyla) magnitüd farkı kaçtır?","steps":[{"t":"Logaritma","a":"10^x = 1000","d":"Verilen yaklaşımla her 1 magnitüd ≈ 10 kat enerji; 1000 = 10³."},{"t":"Üs","a":"x = 3","d":"10³ = 1000 olduğundan üs 3'tür."},{"t":"Fark","a":"3 birim","d":"Magnitüd farkı 3 birimdir."}],"ans":"Magnitüd farkı yaklaşık 3 birimdir."},{"q":"İki istasyonun aynı depreme uzaklıkları 120 km ve 180 km'dir. Vp=8, Vs=4 km/s ise her iki istasyonda ölçülen P-S zaman farklarını ve farkların oranını bulunuz.","steps":[{"t":"Birim Δt","a":"1/4 − 1/8 = 1/8","d":"Δt = d × (1/8) saniye (km başına 0,125 s)."},{"t":"İlk istasyon","a":"15 s","d":"120 × 1/8 = 15 saniye."},{"t":"İkinci ve oran","a":"22,5 s, 2:3","d":"180 × 1/8 = 22,5 s; oran 15:22,5 = 2:3."}],"ans":"Δt değerleri 15 s ve 22,5 s'dir; oranları 2:3'tür (uzaklık oranıyla aynı)."},{"q":"Vp=8 km/s, Vs=4,8 km/s olan bir ortamda P-S zaman farkı 24 s ölçülmüştür. Merkez uzaklığı kaç km'dir?","steps":[{"t":"Katsayı","a":"1/4,8 − 1/8","d":"1/4,8 ≈ 0,2083; 1/8 = 0,125; fark ≈ 0,0833 s/km."},{"t":"Denklem","a":"d×0,0833 = 24","d":"Δt = d × 0,0833 = 24 saniye."},{"t":"Uzaklık","a":"d ≈ 288 km","d":"d = 24 ÷ 0,0833 ≈ 288 km."}],"ans":"Deprem merkezi yaklaşık 288 km uzaktadır."},{"q":"Neden büyük (uzak) depremlerde sismogramda P, S ve yüzey dalgaları net olarak ayrı ayrı görülürken, çok yakın depremlerde bu ayrım zorlaşır?","steps":[{"t":"Uzakta","a":"fark büyük","d":"Uzaklık arttıkça hız farkından dolayı P, S ve yüzey dalgaları arasındaki zaman aralıkları büyür."},{"t":"Yakında","a":"fark küçük","d":"Merkez yakınsa varış zamanları birbirine çok yaklaşır, dalga grupları üst üste biner."},{"t":"Sonuç","a":"ayrım zorlaşır","d":"Bu nedenle yakın depremlerde dalga türlerini ayırmak güçleşir."}],"ans":"Uzaklık arttıkça dalgalar arası zaman açıldığından uzak depremlerde ayrım nettir; yakında zamanlar üst üste biner."},{"q":"Bir bölgede P ve S hızları derinlikle artar (kayaçlar sıkılaşır). Bu durum, derinden geçen dalga ışınlarının yolunu nasıl etkiler ve neden iç içe katmanların tespitine yardım eder?","steps":[{"t":"Hız-derinlik","a":"artar","d":"Derinlik arttıkça basınç artar, kayaçlar sıkılaşır ve dalga hızı yükselir."},{"t":"Kırılma","a":"ışın büküm","d":"Hız değiştikçe dalga ışınları (Snell yasasına benzer) kırılarak yukarı doğru bükülür."},{"t":"Tespit","a":"katman haritası","d":"Farklı uzaklıklardaki varış zamanlarından hız-derinlik profili ve katmanlar belirlenir."}],"ans":"Hız artışı ışınları büker; farklı uzaklıklardaki varışlardan iç katmanların hız profili çıkarılır."},{"q":"Vp=8 km/s, Vs=4 km/s olan ortamda bir istasyonda Δt=45 s, başka istasyonda Δt=15 s ölçüldü. Hangi istasyon merkeze daha yakındır ve uzaklıkları nedir?","steps":[{"t":"Birim Δt","a":"1/4 − 1/8 = 1/8","d":"d = Δt × 8 (çünkü 1/(1/8) = 8)."},{"t":"Uzaklıklar","a":"360 km ve 120 km","d":"45 × 8 = 360 km; 15 × 8 = 120 km."},{"t":"Karşılaştırma","a":"15 s yakın","d":"Δt küçük olan (15 s, 120 km) istasyon merkeze daha yakındır."}],"ans":"Δt=15 s ölçen istasyon (120 km) daha yakındır; diğeri 360 km uzaktadır."}]}},"doppler":{"ilkokul":{"kolay":[{"q":"Ambulans sana yaklaşırken sireninin sesi sana doğru gelir. Bu durumda ses sana nasıl gelir?","steps":[{"t":"Yaklaşan ambulans","a":"ses tizleşir","d":"Ambulans sana yaklaşırken siren sesi daha ince (tiz) duyulur."},{"t":"Sonuç","a":"daha ince ses","d":"Yaklaşan bir <b>ses kaynağının</b> sesi her zaman daha ince (tiz) gelir."}],"ans":"Yaklaşan ambulansın siren sesi daha ince (tiz) duyulur."},{"q":"Şekilde bir ambulans sana doğru geliyor. Yaklaşırken sirenin sesi nasıl olur?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='70' width='60' height='30' rx='6' fill='#e0552b' stroke='#1a2b45'/><circle cx='55' cy='104' r='8' fill='#1a2b45'/><circle cx='90' cy='104' r='8' fill='#1a2b45'/><text x='70' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>Ambulans</text><circle cx='150' cy='85' r='18' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='150' cy='85' r='34' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='150' cy='85' r='52' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='270' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>Sen</text><circle cx='270' cy='70' r='8' fill='#5b6b85'/></svg>","steps":[{"t":"Yaklaşıyor","a":"sıkışan dalgalar","d":"Ambulans sana doğru gelince ses dalgaları senin önünde sıkışır."},{"t":"Sonuç","a":"tiz ses","d":"Sıkışan dalgalar yüzünden sesi daha <b>ince (tiz)</b> duyarsın."}],"ans":"Yaklaşırken ses dalgaları sıkışır ve sesi daha ince (tiz) duyarsın."},{"q":"Ambulans yanından geçip uzaklaşmaya başlayınca sireninin sesi nasıl değişir?","steps":[{"t":"Uzaklaşan ambulans","a":"ses pesleşir","d":"Ambulans senden uzaklaşırken siren sesi daha kalın (pes) duyulur."},{"t":"Sonuç","a":"daha kalın ses","d":"Uzaklaşan bir kaynağın sesi her zaman daha <b>kalın (pes)</b> gelir."}],"ans":"Uzaklaşan ambulansın siren sesi daha kalın (pes) duyulur."},{"q":"Bir ambulans sana yaklaşırken mi yoksa uzaklaşırken mi sesini daha ince duyarsın?","steps":[{"t":"İki durumu karşılaştır","a":"yaklaşırken ince","d":"Yaklaşırken ses ince, uzaklaşırken ses kalın olur."},{"t":"Sonuç","a":"yaklaşırken","d":"Sesi en ince, ambulans sana <b>yaklaşırken</b> duyarsın."}],"ans":"Ambulans sana yaklaşırken sesini daha ince duyarsın."},{"q":"Hareket etmeyen, bir yerde duran bir zilin sesi sen de dururken değişir mi?","steps":[{"t":"İkisi de duruyor","a":"hareket yok","d":"Zil de sen de hareket etmiyorsanız ses ne yaklaşır ne uzaklaşır."},{"t":"Sonuç","a":"değişmez","d":"Hareket olmadığı için sesin inceliği kalınlığı <b>değişmez</b>, hep aynı duyulur."}],"ans":"İkisi de durduğu için zilin sesi değişmez, hep aynı duyulur."}],"zor":[{"q":"Bir tren düdüğünü çalarak sana doğru geliyor, sonra yanından geçip uzaklaşıyor. Sesi baştan sona nasıl değişir?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='60' width='70' height='34' rx='5' fill='#5b6b85' stroke='#1a2b45'/><circle cx='48' cy='98' r='7' fill='#1a2b45'/><circle cx='82' cy='98' r='7' fill='#1a2b45'/><text x='65' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>Tren</text><circle cx='130' cy='77' r='14' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='130' cy='77' r='26' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='130' cy='77' r='40' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='280' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Sen</text><circle cx='280' cy='62' r='7' fill='#5b6b85'/></svg>","steps":[{"t":"Yaklaşırken","a":"ince","d":"Tren sana gelirken ses dalgaları sıkışır, düdük sesi ince (tiz) duyulur."},{"t":"Uzaklaşırken","a":"kalın","d":"Tren geçip uzaklaşınca ses dalgaları açılır, düdük sesi kalın (pes) duyulur."},{"t":"Sonuç","a":"ince → kalın","d":"Yani ses önce <b>ince</b>, geçtikten sonra birden <b>kalın</b> olur."}],"ans":"Tren yaklaşırken ses ince, uzaklaşırken kalın duyulur; ses inceden kalına döner."},{"q":"Yarış arabaları yanından geçip giderken çıkardıkları sesin neden 'viiiiyyyuuum' diye değiştiğini açıkla.","steps":[{"t":"Yaklaşan araba","a":"ince ses","d":"Araba sana doğru gelirken motor sesi ince (tiz) duyulur, bu 'viiii' kısmıdır."},{"t":"Uzaklaşan araba","a":"kalın ses","d":"Araba geçip uzaklaşınca ses kalınlaşır, bu da 'yuuum' kısmıdır."},{"t":"Sonuç","a":"ses değişimi","d":"Bu ses değişiminin nedeni arabanın çok hızlı <b>yaklaşıp uzaklaşmasıdır</b>."}],"ans":"Araba yaklaşırken ses ince, uzaklaşırken kalın olduğu için 'viiiyyuuum' diye değişir."},{"q":"İki çocuk düşünelim: biri yaklaşan ambulansı, diğeri uzaklaşan ambulansı dinliyor. Hangisi daha ince ses duyar?","steps":[{"t":"Yaklaşanı dinleyen","a":"ince ses","d":"Ambulans ona doğru geldiği için dalgalar sıkışır, sesi ince duyar."},{"t":"Uzaklaşanı dinleyen","a":"kalın ses","d":"Ambulans ondan uzaklaştığı için dalgalar açılır, sesi kalın duyar."},{"t":"Sonuç","a":"yaklaşanı dinleyen","d":"Daha <b>ince</b> sesi, yaklaşan ambulansı dinleyen çocuk duyar."}],"ans":"Daha ince sesi, ambulansın kendisine yaklaştığı çocuk duyar."},{"q":"Sen koşarak duran bir zile doğru gidersen zilin sesini nasıl duyarsın?","steps":[{"t":"Sen hareket ediyorsun","a":"zile yaklaşıyorsun","d":"Zil dursa da sen ona doğru koştuğun için aranızdaki mesafe azalır."},{"t":"Dalgalar","a":"daha sık ulaşır","d":"Zile yaklaştıkça ses dalgaları kulağına daha sık gelir."},{"t":"Sonuç","a":"ince ses","d":"Bu yüzden zilin sesini biraz daha <b>ince (tiz)</b> duyarsın."}],"ans":"Zile doğru koştuğunda sesini biraz daha ince (tiz) duyarsın."},{"q":"Gökyüzünde uçan bir uçağın sesi, tependen geçtikten sonra neden daha kalın duyulur?","steps":[{"t":"Tepene gelirken","a":"yaklaşıyor","d":"Uçak sana doğru yaklaşırken sesi daha ince duyulur."},{"t":"Tependen geçince","a":"uzaklaşıyor","d":"Uçak senden uzaklaşmaya başlayınca ses dalgaları açılır."},{"t":"Sonuç","a":"kalın ses","d":"Uzaklaştığı için uçağın sesi artık daha <b>kalın (pes)</b> duyulur."}],"ans":"Uçak tependen geçip uzaklaştığı için sesi daha kalın (pes) duyulur."}]},"ortaokul":{"kolay":[{"q":"Hareket eden bir ses kaynağı yaklaşırken algılanan sesin inceliği (frekansı) neden artar?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='75' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>Kaynak</text><line x1='100' y1='75' x2='130' y2='75' stroke='#1a2b45' stroke-width='1.5'/><polygon points='130,71 138,75 130,79' fill='#1a2b45'/><circle cx='90' cy='75' r='22' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='90' cy='75' r='40' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='180' y='40' font-size='10' fill='#1a2b45'>önde dalgalar sık</text><text x='270' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Gözlemci</text><circle cx='270' cy='65' r='7' fill='#5b6b85'/></svg>","steps":[{"t":"Kaynak ilerliyor","a":"dalgalar sıkışır","d":"Kaynak hareket yönünde ilerlerken önündeki ses dalgaları birbirine yaklaşır (dalga boyu kısalır)."},{"t":"Sonuç","a":"frekans artar","d":"Dalga boyu kısaldığı için gözlemciye birim zamanda daha çok dalga ulaşır, yani <b>frekans</b> artar ve ses tizleşir."}],"ans":"Kaynak yaklaşırken önündeki dalgalar sıkışır, dalga boyu kısalır ve algılanan frekans (incelik) artar."},{"q":"Bir kaynak gözlemciden uzaklaşırken algılanan ses neden pesleşir (frekansı azalır)?","steps":[{"t":"Kaynak uzaklaşıyor","a":"dalgalar açılır","d":"Kaynak ters yöne gittiği için arkasında kalan dalgalar birbirinden uzaklaşır (dalga boyu uzar)."},{"t":"Sonuç","a":"frekans azalır","d":"Dalga boyu uzadığı için gözlemciye daha seyrek dalga ulaşır; <b>frekans</b> azalır ve ses pesleşir."}],"ans":"Uzaklaşan kaynağın arkasındaki dalgalar açılır, dalga boyu uzar ve algılanan frekans azalır (ses pesleşir)."},{"q":"Kaynak-gözlemci arasındaki göreli harekete bağlı olarak algılanan frekansın değişmesi olayına ne ad verilir?","steps":[{"t":"Olayın tanımı","a":"göreli hareket","d":"Kaynak ile gözlemci birbirine göre hareket ettiğinde algılanan frekans değişir."},{"t":"Sonuç","a":"Doppler olayı","d":"Bu olaya <b>Doppler olayı</b> denir; hem seste hem ışıkta görülür."}],"ans":"Kaynak ile gözlemcinin göreli hareketine bağlı frekans değişmesine Doppler olayı denir."},{"q":"Polislerin kullandığı radarlı hız ölçer (radar) hangi olaydan yararlanır?","steps":[{"t":"Çalışma ilkesi","a":"yansıyan dalga","d":"Radar arabaya bir dalga gönderir; araba hareket ettiği için yansıyan dalganın frekansı değişir."},{"t":"Sonuç","a":"Doppler olayı","d":"Frekanstaki bu değişimden arabanın hızı bulunur; bu yöntem <b>Doppler olayına</b> dayanır."}],"ans":"Radarlı hız ölçerler, hareketli araçtan yansıyan dalganın frekans değişimini ölçen Doppler olayından yararlanır."},{"q":"Sen sabit dururken bir ses kaynağı sana yaklaşıyor. Sesi tiz mi pes mi duyarsın?","fig":"<svg viewBox='0 0 320 140'><circle cx='70' cy='70' r='10' fill='#e0552b' stroke='#1a2b45'/><line x1='80' y1='70' x2='115' y2='70' stroke='#1a2b45' stroke-width='1.5'/><polygon points='115,66 124,70 115,74' fill='#1a2b45'/><text x='70' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>Kaynak</text><circle cx='70' cy='70' r='24' fill='none' stroke='#4aa3df' stroke-width='2'/><circle cx='70' cy='70' r='42' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='265' y='75' font-size='11' text-anchor='middle' fill='#1a2b45'>Sen (sabit)</text><circle cx='265' cy='60' r='7' fill='#5b6b85'/></svg>","steps":[{"t":"Yaklaşan kaynak","a":"dalgalar sıkışır","d":"Kaynak sana doğru geldiği için sana ulaşan dalgalar sıklaşır."},{"t":"Sonuç","a":"tiz","d":"Frekans arttığı için sesi <b>tiz</b> (ince) duyarsın."}],"ans":"Kaynak sana yaklaştığı için frekans artar ve sesi tiz (ince) duyarsın."}],"zor":[{"q":"Bir ambulans sabit hızla sana yaklaşıp yanından geçerek uzaklaşıyor. Algıladığın frekansın zamanla değişimini açıklayınız.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='130' x2='300' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='20' y1='130' x2='20' y2='20' stroke='#1a2b45' stroke-width='1.5'/><text x='12' y='30' font-size='10' fill='#1a2b45'>f</text><text x='295' y='148' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='55' x2='150' y2='55' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='55' x2='150' y2='105' stroke='#e0552b' stroke-width='2' stroke-dasharray='4 3'/><line x1='150' y1='105' x2='300' y2='105' stroke='#e0552b' stroke-width='2'/><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1' stroke-dasharray='3 3'/><text x='60' y='48' font-size='10' fill='#1a2b45'>yaklaşırken (yüksek f)</text><text x='200' y='120' font-size='10' fill='#1a2b45'>uzaklaşırken (düşük f)</text><text x='305' y='84' font-size='9' fill='#1a2b45'>f₀</text></svg>","steps":[{"t":"Yaklaşma evresi","a":"f > f₀","d":"Ambulans yaklaşırken dalgalar sıkışır; algılanan frekans, gerçek frekanstan (f₀) yüksektir ve ses tizdir."},{"t":"Geçiş anı","a":"ani düşüş","d":"Ambulans tam yanından geçerken frekans hızla yüksek değerden düşük değere iner."},{"t":"Uzaklaşma evresi","a":"f < f₀","d":"Uzaklaşırken dalgalar açılır; algılanan frekans f₀'dan düşüktür ve ses pestir."}],"ans":"Yaklaşırken algılanan frekans gerçek frekanstan yüksek (tiz), geçiş anında aniden düşer, uzaklaşırken gerçek frekanstan düşük (pes) olur."},{"q":"Bir yıldızdan gelen ışığın renginin kırmızıya doğru kayması (kırmızıya kayma) o yıldız hakkında ne söyler?","steps":[{"t":"Işıkta Doppler","a":"frekans azalması","d":"Kaynak uzaklaşırken ışığın frekansı azalır, dalga boyu uzar; renk kırmızı uca kayar."},{"t":"Yorum","a":"uzaklaşıyor","d":"Bu nedenle kırmızıya kayma, yıldızın bizden <b>uzaklaştığını</b> gösterir."},{"t":"Sonuç","a":"evren genişliyor","d":"Uzak galaksilerin çoğunda kırmızıya kayma görülmesi, evrenin <b>genişlediğinin</b> kanıtıdır."}],"ans":"Kırmızıya kayma yıldızın bizden uzaklaştığını gösterir; galaksilerde yaygın görülmesi evrenin genişlediğine işaret eder."},{"q":"Bir yarasanın avını yakalamak için kullandığı ses (yankı) sisteminde Doppler olayı nasıl işe yarar?","steps":[{"t":"Ses gönderme","a":"yüksek frekans","d":"Yarasa ağzından yüksek frekanslı sesler çıkarır ve cisimlerden yansımasını dinler."},{"t":"Hareketli av","a":"frekans değişir","d":"Av hareket ediyorsa yansıyan sesin frekansı değişir (yaklaşırsa artar, uzaklaşırsa azalır)."},{"t":"Sonuç","a":"hız belirleme","d":"Yarasa bu Doppler kaymasından avının <b>yönünü ve hızını</b> anlar."}],"ans":"Yansıyan sesteki Doppler kayması sayesinde yarasa avının yaklaşıp uzaklaştığını ve hızını belirler."},{"q":"İki özdeş ambulanstan biri sana yaklaşırken çalışıyor, diğeri uzaklaşırken çalışıyor. Sirenlerinin gerçek frekansı aynı olduğu hâlde neden farklı duyarsın?","steps":[{"t":"Gerçek frekans","a":"eşit","d":"Her iki sirenin kaynaktaki gerçek frekansı (f₀) birbirine eşittir."},{"t":"Algılanan frekans","a":"farklı","d":"Yaklaşan ambulansta dalgalar sıkıştığı için f > f₀, uzaklaşanda dalgalar açıldığı için f < f₀ olur."},{"t":"Sonuç","a":"biri tiz biri pes","d":"Bu nedenle yaklaşanı daha <b>tiz</b>, uzaklaşanı daha <b>pes</b> duyarsın."}],"ans":"Gerçek frekansları aynı olsa da yaklaşanın algılanan frekansı yüksek (tiz), uzaklaşanın düşük (pes) olduğundan farklı duyarsın."},{"q":"Hastanede bebeğin kalp atışını ölçen Doppler cihazı hangi ilkeyle çalışır?","steps":[{"t":"Dalga gönderme","a":"ses dalgası","d":"Cihaz vücuda ses (ultrason) dalgaları gönderir."},{"t":"Hareketli kan","a":"frekans değişir","d":"Akan kandan ve hareket eden kalp duvarından yansıyan dalganın frekansı, hareket nedeniyle değişir."},{"t":"Sonuç","a":"Doppler ölçümü","d":"Bu frekans değişiminden kanın hızı ve kalp atışı belirlenir; bu bir <b>Doppler</b> uygulamasıdır."}],"ans":"Cihaz, hareketli kandan yansıyan ultrason dalgasının frekans değişimini ölçer; bu Doppler olayına dayanır."}]},"lise":{"kolay":[{"q":"Doppler olayında, kaynak gözlemciye yaklaşırken algılanan dalga boyu (λ) ve frekans (f) gerçek değerlere göre nasıl değişir?","steps":[{"t":"Yaklaşma","a":"dalga boyu kısalır","d":"Kaynak yaklaşırken önündeki dalgalar sıkışır, algılanan dalga boyu gerçek değerden küçük olur."},{"t":"Frekans","a":"artar","d":"Dalga hızı sabitken (v = f·λ) dalga boyu kısaldığında <b>frekans artar</b>."}],"ans":"Yaklaşırken algılanan dalga boyu kısalır, frekans artar (ses tizleşir)."},{"q":"Kaynağın hareketli, gözlemcinin sabit olduğu Doppler durumunda algılanan dalga boyunu değiştiren temel neden nedir?","fig":"<svg viewBox='0 0 320 150'><circle cx='150' cy='75' r='9' fill='#e0552b' stroke='#1a2b45'/><line x1='159' y1='75' x2='190' y2='75' stroke='#1a2b45' stroke-width='1.5'/><polygon points='190,71 198,75 190,79' fill='#1a2b45'/><text x='150' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>kaynak (hızlı)</text><circle cx='150' cy='75' r='18' fill='none' stroke='#4aa3df' stroke-width='1.8'/><circle cx='150' cy='75' r='34' fill='none' stroke='#4aa3df' stroke-width='1.8'/><circle cx='150' cy='75' r='50' fill='none' stroke='#4aa3df' stroke-width='1.8'/><text x='250' y='40' font-size='9' fill='#1a2b45'>önde sık (kısa λ)</text><text x='30' y='40' font-size='9' fill='#1a2b45'>arkada seyrek</text></svg>","steps":[{"t":"Kaynak hareketi","a":"dalga merkezi kayar","d":"Kaynak her yeni dalgayı bir önceki dalga cephesinin biraz ilerisinden yayar; dalga cepheleri öne sıkışır, arkaya açılır."},{"t":"Sonuç","a":"λ değişir","d":"Bu nedenle önde dalga boyu kısalır (frekans artar), arkada uzar (frekans azalır)."}],"ans":"Kaynağın yer değiştirmesiyle dalga cepheleri önde sıkışıp arkada açıldığı için algılanan dalga boyu değişir."},{"q":"Bir ses kaynağı sabit gözlemciye 340 m/s ses hızıyla, kaynak hızı 34 m/s ve gerçek frekansı 660 Hz ise yaklaşırken algılanan frekansın gerçek frekanstan büyük olacağını gösteriniz.","steps":[{"t":"Bağıntı","a":"f' = f·v/(v−vₖ)","d":"Kaynak yaklaşırken algılanan frekans f' = f · v/(v − vₖ) ile bulunur (v: ses hızı, vₖ: kaynak hızı)."},{"t":"Değerleri yerleştir","a":"660·340/306","d":"f' = 660 · 340/(340 − 34) = 660 · 340/306 ≈ 733 Hz."},{"t":"Karşılaştır","a":"733 > 660","d":"Algılanan 733 Hz, gerçek 660 Hz'ten büyüktür; yani ses <b>tizleşmiştir</b>."}],"ans":"f' ≈ 733 Hz olup gerçek 660 Hz'ten büyüktür; yaklaşan kaynağın sesi tizleşir."},{"q":"Yıldız ışığında 'maviye kayma' gözlenmesi o yıldızın hareketi hakkında ne söyler?","steps":[{"t":"Maviye kayma","a":"frekans artar","d":"Mavi uca kayma, ışığın frekansının artması (dalga boyunun kısalması) demektir."},{"t":"Doppler yorumu","a":"yaklaşıyor","d":"Frekans artışı, kaynağın gözlemciye <b>yaklaştığını</b> gösterir."}],"ans":"Maviye kayma, yıldızın bize doğru yaklaştığını gösterir."},{"q":"Ses hızı 340 m/s iken, gözlemci sabit ses kaynağına 20 m/s hızla yaklaşıyorsa algılanan frekansın değiştiğini, gerçek frekans 500 Hz için hesaplayınız.","steps":[{"t":"Bağıntı","a":"f' = f·(v+vₒ)/v","d":"Gözlemci kaynağa yaklaşırken f' = f·(v + vₒ)/v (vₒ: gözlemci hızı)."},{"t":"Hesap","a":"500·360/340","d":"f' = 500 · (340 + 20)/340 = 500 · 360/340 ≈ 529 Hz."},{"t":"Sonuç","a":"529 > 500","d":"Algılanan frekans 529 Hz, gerçek 500 Hz'ten büyüktür; ses tizleşmiştir."}],"ans":"f' ≈ 529 Hz olup gerçek frekanstan büyüktür; gözlemci yaklaştığı için ses tizleşir."},{"q":"Doppler olayında dalganın yayılma hızı (v) kaynağın hareketinden etkilenir mi?","steps":[{"t":"Dalga hızı","a":"ortama bağlı","d":"Ses dalgasının hızı yalnızca ortamın özelliklerine (sıcaklık, yoğunluk) bağlıdır."},{"t":"Sonuç","a":"değişmez","d":"Kaynak hareket etse de dalga hızı <b>değişmez</b>; değişen dalga boyu ve frekanstır."}],"ans":"Hayır; dalga hızı ortama bağlıdır, kaynağın hareketiyle değişmez, yalnızca λ ve f değişir."},{"q":"Bir radarla hız ölçümünde, hareketli araçtan yansıyan dalganın frekansı gönderilen dalgadan yüksek ölçülüyorsa araç ne yapmaktadır?","steps":[{"t":"Frekans artışı","a":"yaklaşma","d":"Doppler olayına göre frekans artışı, kaynak-gözlemci arasındaki mesafenin azalması demektir."},{"t":"Sonuç","a":"yaklaşıyor","d":"Araç radara doğru <b>yaklaşmaktadır</b>; frekans ne kadar çok artarsa hız o kadar büyüktür."}],"ans":"Yansıyan dalganın frekansı yüksekse araç radara yaklaşmaktadır."},{"q":"Kaynak ve gözlemci aynı hızla, aynı yönde, aralarındaki mesafe sabit kalacak şekilde hareket ederse Doppler etkisi gözlenir mi?","steps":[{"t":"Göreli hareket","a":"sıfır","d":"İkisi arasındaki mesafe değişmediği için kaynak-gözlemci göreli hızı sıfırdır."},{"t":"Sonuç","a":"etki yok","d":"Göreli hareket olmadığından algılanan frekans gerçek frekansa eşittir; <b>Doppler etkisi gözlenmez</b>."}],"ans":"Mesafe sabit kaldığı için göreli hareket yoktur; Doppler etkisi gözlenmez, frekans değişmez."},{"q":"Aynı frekansta çalışan iki siren düşünelim. Biri sana 30 m/s ile yaklaşıyor, biri 60 m/s ile yaklaşıyor. Hangisinin sesini daha tiz duyarsın?","steps":[{"t":"Bağıntı","a":"f' = f·v/(v−vₖ)","d":"Kaynak hızı vₖ büyüdükçe payda (v − vₖ) küçülür, algılanan frekans büyür."},{"t":"Sonuç","a":"60 m/s olan","d":"Daha hızlı yaklaşan (60 m/s) sirenin algılanan frekansı daha yüksektir; sesini daha <b>tiz</b> duyarsın."}],"ans":"Daha hızlı yaklaşan (60 m/s) sirenin sesini daha tiz duyarsın."},{"q":"Uzaklaşan bir galaksinin ışığındaki kırmızıya kaymanın büyüklüğü neyi gösterir?","steps":[{"t":"Kırmızıya kayma","a":"uzaklaşma hızı","d":"Kayma ne kadar büyükse, dalga boyundaki uzama o kadar fazladır."},{"t":"Sonuç","a":"daha hızlı uzaklaşma","d":"Büyük kırmızıya kayma, galaksinin bizden daha <b>hızlı uzaklaştığını</b> gösterir."}],"ans":"Kırmızıya kayma ne kadar büyükse galaksi bizden o kadar hızlı uzaklaşıyordur."},{"q":"Ses hızı 340 m/s iken bir kaynak 340 m/s (ses hızıyla aynı) hızla gözlemciye yaklaşsa algılanan frekans için ne söylenir?","steps":[{"t":"Bağıntı","a":"payda → 0","d":"f' = f·v/(v − vₖ) bağıntısında vₖ = v olunca payda sıfıra gider."},{"t":"Sonuç","a":"çok büyük f'","d":"Dalga cepheleri kaynağın önünde üst üste yığılır; bu durum <b>ses duvarı</b> (şok dalgası) ile ilişkilidir."}],"ans":"Kaynak hızı ses hızına eşit olunca dalgalar önde yığılır, frekans çok büyür; bu ses duvarı (şok dalgası) durumudur."},{"q":"Doppler olayı yalnızca ses dalgalarında mı görülür?","steps":[{"t":"Dalga türü","a":"tüm dalgalar","d":"Doppler olayı dalgalara özgü genel bir olaydır."},{"t":"Sonuç","a":"ışıkta da var","d":"Ses dalgaları yanında ışık ve diğer elektromanyetik dalgalarda da görülür (kırmızıya/maviye kayma)."}],"ans":"Hayır; Doppler olayı ışık dahil tüm dalga türlerinde görülür."},{"q":"Bir gözlemci, sabit duran bir kaynaktan 17 m/s ile uzaklaşıyor. Ses hızı 340 m/s, gerçek frekans 1000 Hz ise algılanan frekansın azaldığını gösteriniz.","steps":[{"t":"Bağıntı","a":"f' = f·(v−vₒ)/v","d":"Gözlemci uzaklaşırken f' = f·(v − vₒ)/v."},{"t":"Hesap","a":"1000·323/340","d":"f' = 1000 · (340 − 17)/340 = 1000 · 323/340 = 950 Hz."},{"t":"Sonuç","a":"950 < 1000","d":"Algılanan frekans 950 Hz, gerçek 1000 Hz'ten küçüktür; ses <b>pesleşmiştir</b>."}],"ans":"f' = 950 Hz olup gerçek frekanstan küçüktür; gözlemci uzaklaştığı için ses pesleşir."},{"q":"Şekildeki gibi hareketli bir kaynağın yaydığı dalga cephelerine bakarak gözlemcinin tiz mi pes mi ses duyacağını belirleyiniz.","fig":"<svg viewBox='0 0 320 150'><circle cx='130' cy='75' r='9' fill='#e0552b' stroke='#1a2b45'/><line x1='139' y1='75' x2='175' y2='75' stroke='#1a2b45' stroke-width='1.5'/><polygon points='175,71 184,75 175,79' fill='#1a2b45'/><circle cx='130' cy='75' r='20' fill='none' stroke='#4aa3df' stroke-width='1.8'/><circle cx='130' cy='75' r='38' fill='none' stroke='#4aa3df' stroke-width='1.8'/><circle cx='130' cy='75' r='56' fill='none' stroke='#4aa3df' stroke-width='1.8'/><text x='265' y='78' font-size='11' text-anchor='middle' fill='#1a2b45'>Gözlemci</text><circle cx='265' cy='62' r='7' fill='#5b6b85'/><text x='250' y='40' font-size='9' fill='#1a2b45'>sık cepheler</text></svg>","steps":[{"t":"Cepheleri oku","a":"sağ tarafta sık","d":"Gözlemcinin bulunduğu sağ tarafta dalga cepheleri sıkışmıştır (dalga boyu kısa)."},{"t":"Frekans","a":"yüksek","d":"Kısa dalga boyu yüksek frekans demektir; kaynak gözlemciye yaklaşıyordur."},{"t":"Sonuç","a":"tiz","d":"Gözlemci sesi <b>tiz</b> (yüksek frekans) duyar."}],"ans":"Gözlemci tarafında cepheler sıkışık olduğundan kaynak yaklaşıyordur; gözlemci sesi tiz duyar."},{"q":"Hız ölçümü için gönderilen radar dalgasıyla yansıyan dalga arasındaki frekans farkı (Doppler kayması) ne işe yarar?","steps":[{"t":"Frekans farkı","a":"hıza bağlı","d":"Aracın hızı arttıkça yansıyan dalganın frekans kayması da büyür."},{"t":"Sonuç","a":"hız hesabı","d":"Cihaz bu frekans farkından aracın hızını hesaplar; fark büyükse araç <b>hızlıdır</b>."}],"ans":"Doppler frekans kaymasının büyüklüğünden aracın hızı hesaplanır; fark ne kadar büyükse araç o kadar hızlıdır."}],"zor":[{"q":"Ses hızı 340 m/s, kaynak frekansı 680 Hz olan bir siren gözlemciye 20 m/s ile yaklaşıyor. (a) Yaklaşırken (b) yanından geçip aynı hızla uzaklaşırken algılanan frekansları bulunuz ve karşılaştırınız.","steps":[{"t":"Yaklaşırken","a":"f₁ = f·v/(v−vₖ)","d":"f₁ = 680 · 340/(340 − 20) = 680 · 340/320 ≈ 722,5 Hz."},{"t":"Uzaklaşırken","a":"f₂ = f·v/(v+vₖ)","d":"f₂ = 680 · 340/(340 + 20) = 680 · 340/360 ≈ 642,2 Hz."},{"t":"Karşılaştırma","a":"f₁ > f₀ > f₂","d":"722,5 Hz > 680 Hz > 642,2 Hz; yaklaşırken tiz, uzaklaşırken pes duyulur."}],"ans":"Yaklaşırken f₁ ≈ 722,5 Hz (tiz), uzaklaşırken f₂ ≈ 642,2 Hz (pes); gerçek 680 Hz ortadadır."},{"q":"Bir galaksinin tayfındaki bir çizgi 500 nm yerine 525 nm dalga boyunda gözleniyor. Bu galaksi yaklaşıyor mu uzaklaşıyor mu, neden?","steps":[{"t":"Dalga boyu değişimi","a":"uzamış","d":"Gözlenen dalga boyu (525 nm), gerçek değerden (500 nm) daha büyüktür, yani dalga boyu uzamıştır."},{"t":"Kayma yönü","a":"kırmızıya kayma","d":"Dalga boyunun uzaması frekansın azalması (kırmızıya kayma) demektir."},{"t":"Sonuç","a":"uzaklaşıyor","d":"Doppler olayına göre kırmızıya kayma, galaksinin bizden <b>uzaklaştığını</b> gösterir."}],"ans":"Dalga boyu 500 nm'den 525 nm'ye uzamış (kırmızıya kayma) olduğundan galaksi bizden uzaklaşmaktadır."},{"q":"Sabit duran bir gözlemciye, ses hızının (340 m/s) yarısı hızla yaklaşan kaynak için algılanan frekansın gerçek frekansın kaç katı olduğunu bulunuz.","steps":[{"t":"Veriler","a":"vₖ = 170 m/s","d":"Kaynak hızı vₖ = 340/2 = 170 m/s, gözlemci sabit."},{"t":"Bağıntı","a":"f' = f·v/(v−vₖ)","d":"f' = f · 340/(340 − 170) = f · 340/170 = 2f."},{"t":"Sonuç","a":"2 katı","d":"Algılanan frekans gerçek frekansın <b>2 katıdır</b>; ses çok belirgin şekilde tizleşir."}],"ans":"Algılanan frekans gerçek frekansın 2 katıdır (f' = 2f)."},{"q":"Bir tren 30 m/s hızla istasyondaki gözlemciye yaklaşırken düdüğünü 600 Hz frekansta çalıyor. Ses hızı 330 m/s. (a) Yaklaşırken (b) tam istasyondan geçerken (tam yanından) algılanan frekanslar nelerdir?","steps":[{"t":"Yaklaşırken","a":"f' = 600·330/300","d":"f' = 600 · 330/(330 − 30) = 600 · 330/300 = 660 Hz."},{"t":"Tam yanından geçerken","a":"göreli hız bileşeni ≈ 0","d":"Tren tam gözlemcinin hizasındayken hareketi gözlemciye ne yaklaşma ne uzaklaşma yönündedir; o anki radyal hız sıfırdır."},{"t":"Sonuç","a":"660 Hz → 600 Hz","d":"O anda algılanan frekans gerçek değere (600 Hz) yaklaşır; sonra uzaklaşmaya geçince 600 Hz'in altına iner."}],"ans":"Yaklaşırken 660 Hz duyulur; tam hizadan geçerken radyal hız sıfır olduğundan frekans gerçek değer 600 Hz'e iner."},{"q":"Hubble'ın gözlemine göre uzak galaksilerin neredeyse tamamı kırmızıya kayma gösterir. Bu gözlem Doppler olayıyla nasıl yorumlanır?","steps":[{"t":"Kırmızıya kayma","a":"uzaklaşma","d":"Her galaksinin ışığındaki kırmızıya kayma, o galaksinin bizden uzaklaştığını gösterir."},{"t":"Hepsi uzaklaşıyor","a":"genel uzaklaşma","d":"Galaksilerin hemen hepsinin uzaklaşması, uzaydaki her noktanın birbirinden uzaklaştığı anlamına gelir."},{"t":"Sonuç","a":"evren genişliyor","d":"Bu, evrenin <b>genişlediğinin</b> (Big Bang modelinin) en güçlü kanıtlarından biridir."}],"ans":"Galaksilerin kırmızıya kayması hepsinin uzaklaştığını gösterir; bu da evrenin genişlediğine kanıttır."},{"q":"Hem kaynak hem gözlemci birbirine doğru hareket ediyorsa (kaynak vₖ, gözlemci vₒ ile, ses hızı v) algılanan frekansı veren bağıntıyı kurun ve frekansın neden en çok arttığını açıklayın.","steps":[{"t":"Pay (gözlemci yaklaşıyor)","a":"v + vₒ","d":"Gözlemci kaynağa doğru gittiği için ona ulaşan etkin dalga hızı artar; payda (v + vₒ) yazılır."},{"t":"Payda (kaynak yaklaşıyor)","a":"v − vₖ","d":"Kaynak yaklaşırken dalga boyu kısaldığı için paydada (v − vₖ) bulunur."},{"t":"Bağıntı ve sonuç","a":"f' = f·(v+vₒ)/(v−vₖ)","d":"f' = f · (v + vₒ)/(v − vₖ). Pay büyür, payda küçülür; bu yüzden frekans <b>en çok</b> bu durumda artar."}],"ans":"f' = f·(v + vₒ)/(v − vₖ); pay büyüyüp payda küçüldüğü için iki yaklaşmada frekans en çok artar."},{"q":"Bir polis radarı 100 km/h hızla yaklaşan ve 100 km/h hızla uzaklaşan iki araca aynı dalgayı gönderiyor. Yansıyan dalgaların frekanslarını niteliksel olarak karşılaştırınız.","steps":[{"t":"Yaklaşan araç","a":"frekans artar","d":"Yaklaşan araçtan yansıyan dalganın frekansı gönderilenden yüksektir (pozitif kayma)."},{"t":"Uzaklaşan araç","a":"frekans azalır","d":"Uzaklaşan araçtan yansıyan dalganın frekansı gönderilenden düşüktür (negatif kayma)."},{"t":"Sonuç","a":"zıt yönde kayma","d":"Kayma miktarları (hızlar eşit olduğu için) yaklaşık eşit büyüklükte ama <b>zıt</b> yöndedir; işaret yönü belirler."}],"ans":"Yaklaşan araçtan yansıyan dalga yüksek, uzaklaşandan düşük frekanslıdır; kayma büyüklükleri eşit, yönleri zıttır."},{"q":"Şekildeki dalga cephesi diyagramında kaynak hızı arttıkça önde dalga boyunun nasıl değiştiğini ve algılanan frekansa etkisini açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='80' r='8' fill='#e0552b' stroke='#1a2b45'/><line x1='98' y1='80' x2='140' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='140,75 150,80 140,85' fill='#e0552b'/><circle cx='90' cy='80' r='16' fill='none' stroke='#4aa3df' stroke-width='1.6'/><circle cx='84' cy='80' r='30' fill='none' stroke='#4aa3df' stroke-width='1.6'/><circle cx='78' cy='80' r='46' fill='none' stroke='#4aa3df' stroke-width='1.6'/><text x='150' y='50' font-size='9' fill='#1a2b45'>önde λ küçük</text><text x='20' y='50' font-size='9' fill='#1a2b45'>arkada λ büyük</text><text x='90' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>kaynak hareket yönü →</text></svg>","steps":[{"t":"Hız artışı","a":"cepheler daha sık","d":"Kaynak ne kadar hızlı ilerlerse her yeni dalga cephesini bir öncekine o kadar yakın yayar; önde dalga boyu daha da kısalır."},{"t":"Frekans","a":"daha çok artar","d":"Önde dalga boyu küçüldükçe (v = f·λ, v sabit) algılanan frekans büyür."},{"t":"Sonuç","a":"daha tiz","d":"Kaynak hızı arttıkça yaklaşan gözlemci sesi giderek daha <b>tiz</b> duyar."}],"ans":"Kaynak hızı arttıkça öndeki dalga boyu daha çok kısalır, algılanan frekans büyür ve ses daha tiz duyulur."},{"q":"Ses hızı 340 m/s. Kaynak gözlemciye doğru 40 m/s ile giderken gözlemci de kaynağa doğru 10 m/s ile gidiyor. Gerçek frekans 700 Hz ise algılanan frekansı bulunuz.","steps":[{"t":"Bağıntı","a":"f' = f·(v+vₒ)/(v−vₖ)","d":"İkisi de birbirine yaklaştığından f' = 700·(340 + 10)/(340 − 40)."},{"t":"Sayıları yerleştir","a":"700·350/300","d":"f' = 700 · 350/300 = 700 · 1,1667 ≈ 816,7 Hz."},{"t":"Sonuç","a":"816,7 > 700","d":"Algılanan frekans 700 Hz'ten oldukça büyüktür; iki yaklaşma birlikte etkiyi büyütmüştür."}],"ans":"f' ≈ 816,7 Hz; her ikisi de yaklaştığı için algılanan frekans gerçek değerden belirgin yüksektir."},{"q":"Yıldızın tayf çizgisi laboratuvar değeri 600 nm iken 594 nm'de gözleniyor. Bu yıldız ne yapıyordur ve neden?","steps":[{"t":"Dalga boyu değişimi","a":"kısalmış","d":"Gözlenen 594 nm, gerçek 600 nm'den küçüktür; dalga boyu kısalmıştır."},{"t":"Kayma yönü","a":"maviye kayma","d":"Dalga boyu kısalması frekans artışı, yani maviye kayma demektir."},{"t":"Sonuç","a":"yaklaşıyor","d":"Doppler olayına göre maviye kayma, yıldızın bize doğru <b>yaklaştığını</b> gösterir."}],"ans":"Dalga boyu 600 nm'den 594 nm'ye kısalmış (maviye kayma) olduğundan yıldız bize yaklaşmaktadır."},{"q":"Bir gözlemci, hem önündeki bir sireni hem de arkasındaki özdeş başka bir sireni aynı anda dinliyor. Gözlemci öne doğru v hızıyla gidiyorsa iki sirenin sesini nasıl duyar?","steps":[{"t":"Öndeki siren","a":"yaklaşma","d":"Gözlemci ona doğru gittiği için öndeki sirene yaklaşır; algılanan frekans artar (tiz)."},{"t":"Arkadaki siren","a":"uzaklaşma","d":"Gözlemci ondan uzaklaştığı için arkadaki sirenin algılanan frekansı azalır (pes)."},{"t":"Sonuç","a":"öndeki tiz, arkadaki pes","d":"Aynı gerçek frekansta olsalar da gözlemci öndekini <b>tiz</b>, arkadakini <b>pes</b> duyar."}],"ans":"Gözlemci öne gittiğinden öndeki sirenin sesini tiz, arkadakinin sesini pes duyar."},{"q":"Doppler etkisini gözlemlemek için kaynağın ille de gözlemciye doğru (radyal) hareket etmesi mi gerekir, yoksa yana (teğetsel) hareket de yeter mi?","steps":[{"t":"Radyal hareket","a":"mesafe değişir","d":"Kaynağın gözlemciye doğru veya ondan uzağa olan bileşeni mesafeyi değiştirir ve frekansı kaydırır."},{"t":"Teğetsel hareket","a":"mesafe sabit","d":"Tam yanlamasına (teğetsel) hareketin radyal bileşeni sıfırdır; o an mesafe değişmez."},{"t":"Sonuç","a":"radyal bileşen gerekir","d":"Doppler kayması yalnızca hızın <b>radyal (gözlemci doğrultusundaki) bileşenine</b> bağlıdır."}],"ans":"Yalnızca hızın radyal bileşeni Doppler kaymasına yol açar; tam teğetsel hareketin o andaki etkisi sıfırdır."},{"q":"Ses hızı 340 m/s. 850 Hz'lik bir kaynak gözlemciye yaklaşırken gözlemci 940 Hz duyuyor. Kaynağın hızını bulunuz.","steps":[{"t":"Bağıntı","a":"f' = f·v/(v−vₖ)","d":"940 = 850 · 340/(340 − vₖ)."},{"t":"Düzenle","a":"340 − vₖ = 850·340/940","d":"340 − vₖ = 289000/940 ≈ 307,4 ⇒ vₖ ≈ 340 − 307,4."},{"t":"Sonuç","a":"vₖ ≈ 32,6 m/s","d":"Kaynağın hızı yaklaşık 32,6 m/s'dir."}],"ans":"Kaynağın hızı yaklaşık 32,6 m/s'dir."},{"q":"Hareketli kaynak, gözlemciden uzaklaşırken çıkardığı dalganın hız–frekans–dalga boyu (v = f·λ) ilişkisi nasıl korunur?","steps":[{"t":"Dalga hızı sabit","a":"v değişmez","d":"Uzaklaşan kaynakta da ses hızı ortama bağlı olup sabittir."},{"t":"Dalga boyu uzar","a":"λ artar","d":"Kaynak uzaklaşırken arkasındaki dalga boyu uzar (λ büyür)."},{"t":"Frekans azalır","a":"f düşer","d":"v = f·λ ilişkisinde v sabit, λ büyüdüğü için f küçülür; ses pesleşir, ama çarpım hep v'ye eşit kalır."}],"ans":"v sabit kalır; λ uzarken f düşer ve v = f·λ ilişkisi korunur (ses pesleşir)."},{"q":"Bir polis aracı sireni çalarak (gerçek frekans f₀) sabit hızla sana yaklaşıp uzaklaşıyor. Algıladığın frekansın gerçek frekanstan ne zaman büyük, ne zaman küçük, ne zaman ona eşit olduğunu sıralayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='20' y1='120' x2='300' y2='120' stroke='#1a2b45' stroke-width='1.4'/><line x1='20' y1='120' x2='20' y2='25' stroke='#1a2b45' stroke-width='1.4'/><text x='12' y='32' font-size='9' fill='#1a2b45'>f</text><text x='296' y='138' font-size='9' fill='#1a2b45'>t</text><line x1='20' y1='75' x2='300' y2='75' stroke='#1a2b45' stroke-width='0.8' stroke-dasharray='3 3'/><text x='305' y='78' font-size='9' fill='#1a2b45'>f₀</text><line x1='20' y1='50' x2='150' y2='50' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='50' x2='160' y2='100' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='100' x2='300' y2='100' stroke='#e0552b' stroke-width='2'/><text x='75' y='44' font-size='9' fill='#1a2b45'>f > f₀</text><text x='225' y='115' font-size='9' fill='#1a2b45'>f < f₀</text></svg>","steps":[{"t":"Yaklaşırken","a":"f > f₀","d":"Araç sana yaklaştığı sürece dalgalar sıkışır; algılanan frekans gerçek frekanstan büyüktür."},{"t":"Tam hizada","a":"f ≈ f₀","d":"Araç tam yanından geçerken radyal hız sıfır olur ve algılanan frekans kısa süreliğine f₀'a eşitlenir."},{"t":"Uzaklaşırken","a":"f < f₀","d":"Araç uzaklaşırken dalgalar açılır; algılanan frekans gerçek frekanstan küçük olur."}],"ans":"Yaklaşırken f > f₀, tam hizadan geçerken f ≈ f₀, uzaklaşırken f < f₀ olur."}]}},"emDalga":{"ilkokul":{"kolay":[{"q":"Radyoyu açtığımızda sesi taşıyan radyo dalgaları gözle görülür mü?","steps":[{"t":"Radyo dalgası nedir","a":"görünmez dalga","d":"Radyo dalgaları gözümüzle göremediğimiz bir tür enerji dalgasıdır."},{"t":"Sonuç","a":"görünmez","d":"Bu yüzden havada dolaşırlar ama biz onları göremeyiz."}],"ans":"Radyo dalgaları gözle görülmez; onları sadece radyo yakalar."},{"q":"Güneşten bize gelen ışık, uzaydaki boşluğu nasıl geçip Dünya'ya ulaşır?","fig":"<svg viewBox='0 0 320 140'><circle cx='45' cy='70' r='26' fill='#ffd54a' stroke='#d9a400'/><text x='45' y='118' font-size='12' text-anchor='middle' fill='#1a2b45'>Güneş</text><circle cx='275' cy='70' r='18' fill='#4aa3df' stroke='#1a2b45'/><text x='275' y='110' font-size='12' text-anchor='middle' fill='#1a2b45'>Dünya</text><polyline points='75,62 95,62 95,78 115,78 115,62 135,62 135,78 155,78 155,62 175,62 175,78 195,78 195,62 215,62 215,78 235,78 235,62 255,62' fill='none' stroke='#e0552b' stroke-width='2'/><text x='160' y='40' font-size='11' text-anchor='middle' fill='#1a2b45'>ışık (boşlukta)</text></svg>","steps":[{"t":"Uzayda ne var","a":"boşluk","d":"Güneş ile Dünya arasında hava yoktur, boşluk vardır."},{"t":"Işık nasıl gelir","a":"boşlukta yayılır","d":"Işık, hava olmasa da boşlukta yayılabilir ve bize ulaşır."}],"ans":"Güneş ışığı boşlukta yayılabildiği için uzayı geçip Dünya'ya ulaşır."},{"q":"Işık çok mu yoksa az mı hızlıdır? Bir lambayı açtığında ışık odaya hemen mi dolar?","steps":[{"t":"Işığın hızı","a":"çok hızlı","d":"Işık her şeyden daha hızlıdır."},{"t":"Sonuç","a":"hemen dolar","d":"Lambayı açar açmaz oda anında aydınlanır, çünkü ışık çok hızlıdır."}],"ans":"Işık çok hızlıdır; lambayı açınca oda hemen aydınlanır."},{"q":"Televizyon kumandasının ucundan çıkıp televizyonu açan görünmez ışına ne ad verebiliriz?","steps":[{"t":"Kumanda ne yollar","a":"görünmez ışın","d":"Kumanda, ucundan görünmez bir ışın gönderir."},{"t":"Adı","a":"kızılötesi","d":"Bu görünmez ışına kızılötesi denir; gözle görülmez ama televizyona ulaşır."}],"ans":"Kumandadan çıkan bu görünmez ışına kızılötesi denir."},{"q":"Güneşin ışığı bizi hem aydınlatır hem ısıtır. Bu enerji bize nasıl ulaşır?","steps":[{"t":"Enerji nereden","a":"Güneşten","d":"Işık ve sıcaklık enerjisi Güneşten gelir."},{"t":"Nasıl gelir","a":"dalgalarla","d":"Bu enerji, boşlukta yayılan ışık dalgalarıyla bize ulaşır."}],"ans":"Güneşin enerjisi, boşlukta yayılan ışık dalgalarıyla bize ulaşır."}],"zor":[{"q":"Cep telefonu, ses ve mesajları havada nasıl gönderir? Telleri olmadan nasıl konuşabiliriz?","steps":[{"t":"Telefon ne kullanır","a":"görünmez dalga","d":"Telefon, görünmeyen dalgalar gönderir."},{"t":"Sonuç","a":"telsiz iletişim","d":"Bu dalgalar havada yayıldığı için tellere gerek olmadan konuşabiliriz."}],"ans":"Telefon, görünmez dalgalar gönderir; bu dalgalar havada yayıldığı için telsiz konuşabiliriz."},{"q":"Karanlık bir odada elimizi sıcak bir sobaya yaklaştırınca onu görmesek de sıcaklığını hissederiz. Bu sıcaklık bize nasıl gelir?","steps":[{"t":"Soba ne yayar","a":"görünmez ışın","d":"Sıcak cisimler kızılötesi denilen görünmez ışınlar yayar."},{"t":"Hissetme","a":"ısı dalgası","d":"Bu ışınlar elimize ulaşınca sıcaklığı hissederiz."}],"ans":"Sıcak soba kızılötesi ışınlar yayar; bu görünmez ışınlar bize ulaşınca sıcaklığı hissederiz."},{"q":"Gökkuşağında gördüğümüz renkler aslında neyin parçasıdır?","fig":"<svg viewBox='0 0 320 110'><rect x='30' y='30' width='40' height='40' fill='#e53935'/><rect x='70' y='30' width='40' height='40' fill='#fb8c00'/><rect x='110' y='30' width='40' height='40' fill='#fdd835'/><rect x='150' y='30' width='40' height='40' fill='#43a047'/><rect x='190' y='30' width='40' height='40' fill='#1e88e5'/><rect x='230' y='30' width='40' height='40' fill='#5e35b1'/><text x='160' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>görünür ışığın renkleri</text></svg>","steps":[{"t":"Renkler nereden","a":"ışıktan","d":"Gökkuşağı renkleri, güneş ışığının içindeki renklerdir."},{"t":"Sonuç","a":"görünür ışık","d":"Bu renklerin hepsi birleşince gözümüzün gördüğü beyaz ışığı oluşturur."}],"ans":"Gökkuşağı renkleri, gözümüzün gördüğü ışığın (görünür ışığın) parçalarıdır."},{"q":"Bir radyo dalgası ile lambadan çıkan ışık aynı boşlukta yan yana yarışsa hangisi daha hızlı gider?","steps":[{"t":"İkisi de ne","a":"ışık ailesinden","d":"Radyo dalgası da ışık da aynı dalga ailesindendir."},{"t":"Hızları","a":"aynı","d":"İkisi de boşlukta tıpatıp aynı hızla, yani ışık hızıyla gider."}],"ans":"İkisi de aynı hızla gider; çünkü hepsi boşlukta ışık hızıyla yayılır."},{"q":"Doktorlar kemiğin kırılıp kırılmadığını, kesmeden vücudun içini gösteren bir ışınla bakar. Bu görünmez ışının adı nedir?","steps":[{"t":"Ne işe yarar","a":"içi gösterir","d":"Bu ışın vücudun içinden geçebilir ve kemikleri gösterir."},{"t":"Adı","a":"X ışını","d":"Bu görünmez ışına X ışını (röntgen) denir."}],"ans":"Vücudun içini gösteren bu görünmez ışına X ışını (röntgen) denir."}]},"ortaokul":{"kolay":[{"q":"Elektromanyetik dalgaların yayılması için havaya veya başka bir maddeye ihtiyaç var mıdır?","steps":[{"t":"Ses ile karşılaştır","a":"ses maddeye muhtaç","d":"Ses dalgaları yayılmak için hava gibi bir maddeye ihtiyaç duyar."},{"t":"EM dalga farkı","a":"boşlukta yayılır","d":"Elektromanyetik dalgalar ise boşlukta da yayılabilir, maddeye ihtiyaç duymaz."}],"ans":"Hayır; elektromanyetik dalgalar boşlukta da yayıldığı için herhangi bir maddeye ihtiyaç duymaz."},{"q":"Tüm elektromanyetik dalgaların boşluktaki hızı için ne söylenebilir?","steps":[{"t":"Hız değeri","a":"ışık hızı","d":"Bütün elektromanyetik dalgalar boşlukta ışık hızıyla yayılır."},{"t":"Sayısal değer","a":"c ≈ 3·10⁸ m/s","d":"Bu hız yaklaşık 300.000 km/s, yani 3·10⁸ m/s'dir."}],"ans":"Hepsi boşlukta aynı hızla, yani ışık hızı c ≈ 3·10⁸ m/s ile yayılır."},{"q":"Elektromanyetik spektrumda radyo dalgaları, görünür ışık ve X ışınları enerjilerine göre nasıl sıralanır?","fig":"<svg viewBox='0 0 320 120'><rect x='20' y='40' width='90' height='30' fill='#4aa3df'/><text x='65' y='60' font-size='11' text-anchor='middle' fill='#fff'>Radyo</text><rect x='110' y='40' width='90' height='30' fill='#43a047'/><text x='155' y='60' font-size='11' text-anchor='middle' fill='#fff'>Görünür</text><rect x='200' y='40' width='100' height='30' fill='#5e35b1'/><text x='250' y='60' font-size='11' text-anchor='middle' fill='#fff'>X ışını</text><polygon points='20,90 300,90 300,86 20,86' fill='#1a2b45'/><polygon points='300,88 290,82 290,94' fill='#1a2b45'/><text x='35' y='105' font-size='10' fill='#1a2b45'>düşük enerji</text><text x='265' y='105' font-size='10' fill='#1a2b45'>yüksek enerji</text></svg>","steps":[{"t":"Enerji yönü","a":"radyo en düşük","d":"Radyo dalgalarının enerjisi en düşüktür."},{"t":"Sıralama","a":"radyo < görünür < X","d":"Enerji radyodan görünür ışığa, oradan X ışınına doğru artar."}],"ans":"Enerji küçükten büyüğe: radyo dalgaları < görünür ışık < X ışınları biçiminde sıralanır."},{"q":"Bir elektromanyetik dalganın hızı (c), frekansı (f) ve dalga boyu (λ) arasındaki temel bağıntı nedir?","steps":[{"t":"Bağıntıyı yaz","a":"c = f · λ","d":"Hız, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Anlamı","a":"hız sabit","d":"Boşlukta c sabit olduğundan, frekans artarsa dalga boyu azalır."}],"ans":"Temel bağıntı c = f · λ'dır; hız, frekans ile dalga boyunun çarpımıdır."},{"q":"Bir elektromanyetik dalga, titreşim yönü ile yayılma yönü bakımından enine mi yoksa boyuna dalga mıdır?","steps":[{"t":"Titreşim yönü","a":"yayılmaya dik","d":"Elektrik ve manyetik alanlar, dalganın ilerleme yönüne dik titreşir."},{"t":"Tür","a":"enine dalga","d":"Titreşim ilerleme yönüne dik olduğu için bu bir enine dalgadır."}],"ans":"Elektromanyetik dalga enine bir dalgadır; alanları yayılma yönüne dik titreşir."}],"zor":[{"q":"Boşlukta dalga boyu artarken frekansın nasıl değiştiğini c = f · λ bağıntısıyla açıklayınız.","steps":[{"t":"Bağıntıyı düzenle","a":"f = c / λ","d":"c = f · λ ifadesinden frekans, ışık hızının dalga boyuna bölümüdür."},{"t":"İlişki","a":"ters orantı","d":"c sabit olduğundan dalga boyu büyürse frekans küçülür."}],"ans":"Boşlukta c sabit olduğu için dalga boyu arttıkça frekans azalır; ikisi ters orantılıdır."},{"q":"Frekansı 2·10⁸ Hz olan bir radyo dalgasının boşluktaki dalga boyu kaç metredir? (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntıyı seç","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"3·10⁸ ÷ 2·10⁸","d":"c = 3·10⁸ m/s ve f = 2·10⁸ Hz değerleri yerine konur."},{"t":"Sonuç","a":"1,5 m","d":"Bölme sonucu dalga boyu 1,5 m bulunur."}],"ans":"Radyo dalgasının dalga boyu 1,5 metredir."},{"q":"Elektromanyetik spektrum, dalga boyu küçükten büyüğe doğru nasıl sıralanır? Birkaç bölgeyi örnek vererek belirtiniz.","fig":"<svg viewBox='0 0 320 130'><rect x='15' y='45' width='50' height='28' fill='#7b1fa2'/><text x='40' y='64' font-size='9' text-anchor='middle' fill='#fff'>Gama</text><rect x='65' y='45' width='45' height='28' fill='#5e35b1'/><text x='87' y='64' font-size='9' text-anchor='middle' fill='#fff'>X</text><rect x='110' y='45' width='50' height='28' fill='#3949ab'/><text x='135' y='64' font-size='9' text-anchor='middle' fill='#fff'>Morötesi</text><rect x='160' y='45' width='50' height='28' fill='#43a047'/><text x='185' y='64' font-size='9' text-anchor='middle' fill='#fff'>Görünür</text><rect x='210' y='45' width='45' height='28' fill='#e53935'/><text x='232' y='64' font-size='9' text-anchor='middle' fill='#fff'>Kızılötesi</text><rect x='255' y='45' width='50' height='28' fill='#4aa3df'/><text x='280' y='64' font-size='9' text-anchor='middle' fill='#fff'>Radyo</text><text x='40' y='95' font-size='9' fill='#1a2b45'>küçük λ</text><text x='255' y='95' font-size='9' fill='#1a2b45'>büyük λ</text></svg>","steps":[{"t":"Yön belirle","a":"λ artıyor","d":"Dalga boyu en küçük olan gama ışınlarından başlanır."},{"t":"Sırala","a":"gama → radyo","d":"Dalga boyu artarken sıra: gama, X, morötesi, görünür, kızılötesi, radyo olur."}],"ans":"Dalga boyu küçükten büyüğe: gama, X ışını, morötesi, görünür ışık, kızılötesi, radyo biçiminde sıralanır."},{"q":"Dalga boyu 600 nm olan kırmızı bir ışığın boşluktaki frekansını yaklaşık olarak bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Birim çevir","a":"600 nm = 6·10⁻⁷ m","d":"600 nanometre, metre cinsinden 6·10⁻⁷ m'dir."},{"t":"Bağıntıyı kur","a":"f = c / λ","d":"Frekans, ışık hızının dalga boyuna bölümüdür."},{"t":"Sonuç","a":"5·10¹⁴ Hz","d":"3·10⁸ ÷ 6·10⁻⁷ = 5·10¹⁴ Hz bulunur."}],"ans":"Kırmızı ışığın frekansı yaklaşık 5·10¹⁴ Hz'dir."},{"q":"İki elektromanyetik dalgadan birinin frekansı diğerinden büyükse, enerjileri ve dalga boyları nasıl karşılaştırılır?","steps":[{"t":"Enerji-frekans","a":"doğru orantı","d":"Bir EM dalganın enerjisi frekansıyla doğru orantılıdır; frekans büyükse enerji de büyüktür."},{"t":"Frekans-dalga boyu","a":"ters orantı","d":"c sabit olduğundan frekansı büyük olanın dalga boyu küçüktür."}],"ans":"Frekansı büyük olan dalganın enerjisi daha yüksek, dalga boyu ise daha küçüktür."}]},"lise":{"kolay":[{"q":"Elektromanyetik dalgaların mekanik dalgalardan en temel farkı nedir?","steps":[{"t":"Mekanik dalga","a":"ortam gerekir","d":"Ses gibi mekanik dalgalar yayılmak için maddesel bir ortama ihtiyaç duyar."},{"t":"EM dalga","a":"ortam gerekmez","d":"Elektromanyetik dalgalar boşlukta da yayılabildiği için maddesel ortam gerektirmez."}],"ans":"En temel fark, elektromanyetik dalgaların yayılmak için maddesel bir ortama ihtiyaç duymamasıdır."},{"q":"Tüm elektromanyetik dalgaların boşluktaki yayılma hızı nedir ve neye bağlıdır?","steps":[{"t":"Hız değeri","a":"c ≈ 3·10⁸ m/s","d":"Bütün EM dalgalar boşlukta ışık hızı c ile yayılır."},{"t":"Bağımlılık","a":"frekanstan bağımsız","d":"Bu hız frekanstan veya dalga boyundan bağımsızdır; boşlukta hepsi için aynıdır."}],"ans":"Hepsi boşlukta c ≈ 3·10⁸ m/s ile yayılır; bu hız frekans ve dalga boyundan bağımsızdır."},{"q":"c = f · λ bağıntısında ışık hızı sabitken frekans ile dalga boyu arasındaki ilişki nasıldır?","steps":[{"t":"Bağıntı","a":"c = f · λ","d":"Işık hızı, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Sonuç","a":"ters orantı","d":"c sabit olduğundan frekans artarsa dalga boyu azalır, biri büyürse diğeri küçülür."}],"ans":"Işık hızı sabit olduğu için frekans ile dalga boyu ters orantılıdır."},{"q":"Frekansı 6·10¹⁴ Hz olan bir ışığın boşluktaki dalga boyunu bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntıyı seç","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Yerine koy","a":"3·10⁸ ÷ 6·10¹⁴","d":"c ve f değerleri yerine konur."},{"t":"Sonuç","a":"5·10⁻⁷ m","d":"Bölme sonucu 5·10⁻⁷ m, yani 500 nm bulunur."}],"ans":"Işığın dalga boyu 5·10⁻⁷ m'dir (500 nm)."},{"q":"Elektromanyetik spektrumda bölgeler artan frekans yönünde nasıl sıralanır?","fig":"<svg viewBox='0 0 320 130'><rect x='15' y='45' width='48' height='28' fill='#4aa3df'/><text x='39' y='64' font-size='9' text-anchor='middle' fill='#fff'>Radyo</text><rect x='63' y='45' width='52' height='28' fill='#26a69a'/><text x='89' y='64' font-size='8' text-anchor='middle' fill='#fff'>Mikrodalga</text><rect x='115' y='45' width='48' height='28' fill='#e53935'/><text x='139' y='64' font-size='8' text-anchor='middle' fill='#fff'>Kızılötesi</text><rect x='163' y='45' width='42' height='28' fill='#43a047'/><text x='184' y='64' font-size='8' text-anchor='middle' fill='#fff'>Görünür</text><rect x='205' y='45' width='44' height='28' fill='#3949ab'/><text x='227' y='64' font-size='8' text-anchor='middle' fill='#fff'>Morötesi</text><rect x='249' y='45' width='28' height='28' fill='#5e35b1'/><text x='263' y='64' font-size='9' text-anchor='middle' fill='#fff'>X</text><rect x='277' y='45' width='28' height='28' fill='#7b1fa2'/><text x='291' y='64' font-size='9' text-anchor='middle' fill='#fff'>γ</text><text x='35' y='95' font-size='9' fill='#1a2b45'>düşük f</text><text x='270' y='95' font-size='9' fill='#1a2b45'>yüksek f</text></svg>","steps":[{"t":"Düşük frekanstan başla","a":"radyo","d":"En düşük frekanslı bölge radyo dalgalarıdır."},{"t":"Sırala","a":"radyo → gama","d":"Frekans artarken: radyo, mikrodalga, kızılötesi, görünür, morötesi, X, gama olur."}],"ans":"Artan frekans yönünde: radyo, mikrodalga, kızılötesi, görünür ışık, morötesi, X ışını, gama ışını biçiminde sıralanır."},{"q":"Bir elektromanyetik dalganın enine dalga olduğunu hangi özelliği gösterir?","steps":[{"t":"Alanların yönü","a":"yayılmaya dik","d":"Elektrik ve manyetik alanlar, dalganın ilerleme yönüne diktir."},{"t":"Tanım","a":"enine dalga","d":"Titreşim yayılma yönüne dik olan dalgalara enine dalga denir."}],"ans":"Elektrik ve manyetik alanların yayılma yönüne dik titreşmesi, EM dalganın enine dalga olduğunu gösterir."},{"q":"Bir dalganın dalga boyu 3 m ise boşluktaki frekansını bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"f = c / λ","d":"Frekans, ışık hızının dalga boyuna bölümüdür."},{"t":"Yerine koy","a":"3·10⁸ ÷ 3","d":"c = 3·10⁸ m/s ve λ = 3 m yerine konur."},{"t":"Sonuç","a":"10⁸ Hz","d":"Bölme sonucu 1·10⁸ Hz bulunur."}],"ans":"Dalganın frekansı 10⁸ Hz'dir (100 MHz)."},{"q":"Görünür ışık spektrumunda kırmızı ve mor ışığın dalga boyu ve frekansı nasıl karşılaştırılır?","fig":"<svg viewBox='0 0 320 110'><rect x='30' y='35' width='240' height='28' fill='url(#g)'/><defs><marker id='m' markerWidth='8' markerHeight='8' refX='4' refY='4' orient='auto'><polygon points='0,0 8,4 0,8' fill='#1a2b45'/></marker></defs><rect x='30' y='35' width='40' height='28' fill='#e53935'/><rect x='70' y='35' width='40' height='28' fill='#fb8c00'/><rect x='110' y='35' width='40' height='28' fill='#fdd835'/><rect x='150' y='35' width='40' height='28' fill='#43a047'/><rect x='190' y='35' width='40' height='28' fill='#1e88e5'/><rect x='230' y='35' width='40' height='28' fill='#5e35b1'/><text x='50' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>kırmızı</text><text x='250' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>mor</text><text x='50' y='95' font-size='9' text-anchor='middle' fill='#1a2b45'>büyük λ</text><text x='250' y='95' font-size='9' text-anchor='middle' fill='#1a2b45'>küçük λ</text></svg>","steps":[{"t":"Dalga boyu","a":"kırmızı > mor","d":"Görünür ışıkta kırmızının dalga boyu en büyük, morun en küçüktür."},{"t":"Frekans","a":"mor > kırmızı","d":"c sabit olduğundan dalga boyu küçük olan morun frekansı daha büyüktür."}],"ans":"Kırmızı ışığın dalga boyu büyük, frekansı küçük; mor ışığın dalga boyu küçük, frekansı büyüktür."},{"q":"Elektromanyetik bir dalganın enerjisi frekansa ve dalga boyuna nasıl bağlıdır?","steps":[{"t":"Enerji-frekans","a":"doğru orantı","d":"EM dalganın enerjisi frekansıyla doğru orantılıdır; frekans arttıkça enerji artar."},{"t":"Enerji-dalga boyu","a":"ters orantı","d":"Frekans ile dalga boyu ters orantılı olduğundan, dalga boyu büyüdükçe enerji azalır."}],"ans":"Enerji frekansla doğru, dalga boyuyla ters orantılıdır; yüksek frekanslı (kısa dalga boylu) dalgalar daha enerjiktir."},{"q":"Gama ışınları ile radyo dalgalarının enerji ve dalga boylarını karşılaştırınız.","steps":[{"t":"Frekans karşılaştır","a":"gama en yüksek","d":"Gama ışınlarının frekansı en yüksek, radyo dalgalarınınki en düşüktür."},{"t":"Enerji ve dalga boyu","a":"gama enerjik","d":"Yüksek frekans nedeniyle gama en enerjik ve en küçük dalga boyludur; radyo ise en az enerjik ve en büyük dalga boyludur."}],"ans":"Gama ışınları en yüksek enerjili ve en kısa dalga boylu; radyo dalgaları en düşük enerjili ve en uzun dalga boyludur."},{"q":"Bir radyo istasyonu 100 MHz frekansta yayın yapıyor. Bu yayının boşluktaki dalga boyu kaç metredir? (c = 3·10⁸ m/s)","steps":[{"t":"Birim çevir","a":"100 MHz = 10⁸ Hz","d":"100 MHz, 100·10⁶ = 1·10⁸ Hz'dir."},{"t":"Bağıntı","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Sonuç","a":"3 m","d":"3·10⁸ ÷ 10⁸ = 3 m bulunur."}],"ans":"Yayının dalga boyu 3 metredir."},{"q":"Boşlukta yayılan bir EM dalganın dalga boyu camda yavaşlayınca hangi büyüklüğü değişmez?","steps":[{"t":"Ortam değişimi","a":"hız ve λ değişir","d":"Cama girince dalganın hızı azalır ve dalga boyu küçülür."},{"t":"Değişmeyen","a":"frekans","d":"Frekans kaynağa bağlı olduğundan ortam değişse de aynı kalır."}],"ans":"Dalga camda yavaşlasa da frekansı değişmez; değişen hız ve dalga boyudur."},{"q":"Mikrodalga fırınların kullandığı dalga, elektromanyetik spektrumda hangi bölgede yer alır ve enerjisi görünür ışığa göre nasıldır?","steps":[{"t":"Bölge","a":"mikrodalga","d":"Bu dalgalar radyo ile kızılötesi arasında, mikrodalga bölgesinde yer alır."},{"t":"Enerji","a":"görünürden düşük","d":"Frekansı görünür ışıktan küçük olduğundan enerjisi de daha düşüktür."}],"ans":"Mikrodalga bölgesinde yer alır; frekansı görünür ışıktan küçük olduğu için enerjisi de daha düşüktür."},{"q":"İki EM dalgadan birinin dalga boyu diğerinin yarısı kadarsa, frekansları boşlukta nasıl karşılaştırılır?","steps":[{"t":"Bağıntı","a":"f = c / λ","d":"Boşlukta c sabit olduğundan frekans, dalga boyuyla ters orantılıdır."},{"t":"Sonuç","a":"iki katı","d":"Dalga boyu yarıya inerse frekans iki katına çıkar."}],"ans":"Dalga boyu yarı olan dalganın frekansı, diğerinin iki katıdır."},{"q":"Bir EM dalganın frekansı 1,5·10¹⁰ Hz ise boşluktaki dalga boyunu bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Yerine koy","a":"3·10⁸ ÷ 1,5·10¹⁰","d":"c ve f değerleri yerine konur."},{"t":"Sonuç","a":"0,02 m","d":"Bölme sonucu 2·10⁻² m, yani 0,02 m bulunur."}],"ans":"Dalganın dalga boyu 0,02 m'dir (2 cm)."}],"zor":[{"q":"Dalga boyu 500 nm olan yeşil ışığın boşluktaki frekansını bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Birim çevir","a":"500 nm = 5·10⁻⁷ m","d":"500 nanometre metre cinsinden 5·10⁻⁷ m'dir."},{"t":"Bağıntı","a":"f = c / λ","d":"Frekans, ışık hızının dalga boyuna bölümüdür."},{"t":"Sonuç","a":"6·10¹⁴ Hz","d":"3·10⁸ ÷ 5·10⁻⁷ = 6·10¹⁴ Hz bulunur."}],"ans":"Yeşil ışığın frekansı 6·10¹⁴ Hz'dir."},{"q":"Bir radyo dalgasının frekansı 1,2·10⁸ Hz, bir gama ışınınınki 3·10²⁰ Hz'dir. Dalga boylarının oranını bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"λ = c / f","d":"Her dalga için dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Oranı kur","a":"λ_radyo/λ_gama = f_gama/f_radyo","d":"c sabit olduğundan dalga boyları oranı, frekansların ters oranına eşittir."},{"t":"Hesapla","a":"3·10²⁰ ÷ 1,2·10⁸","d":"Frekanslar oranı 2,5·10¹² bulunur."}],"ans":"Radyo dalgasının dalga boyu, gama ışınının dalga boyunun 2,5·10¹² katıdır."},{"q":"Boşlukta dalga boyu 4 m olan bir dalga, kırılma indisi 2 olan bir ortama giriyor. Bu ortamdaki dalga boyunu bulunuz.","steps":[{"t":"Ortamda hız","a":"v = c / n","d":"Ortamdaki hız, ışık hızının kırılma indisine bölümüyle bulunur; v = c/2'dir."},{"t":"Frekans sabit","a":"f değişmez","d":"Frekans değişmediğinden dalga boyu hızla aynı oranda küçülür: λ' = λ/n."},{"t":"Sonuç","a":"4 ÷ 2 = 2 m","d":"Ortamdaki dalga boyu, boşluktakinin kırılma indisine bölümüdür."}],"ans":"Ortamdaki dalga boyu 2 metredir; frekans aynı kalır, dalga boyu yarıya iner."},{"q":"Bir uydudan Dünya'ya gönderilen sinyalin yolu 3,6·10⁷ m ise sinyal boşlukta kaç saniyede ulaşır? (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"t = yol / c","d":"EM dalga boşlukta ışık hızıyla gittiğinden süre, yolun hıza bölümüdür."},{"t":"Yerine koy","a":"3,6·10⁷ ÷ 3·10⁸","d":"Yol ve hız değerleri yerine konur."},{"t":"Sonuç","a":"0,12 s","d":"Bölme sonucu 0,12 saniye bulunur."}],"ans":"Sinyal boşlukta 0,12 saniyede Dünya'ya ulaşır."},{"q":"Dalga boyları sırasıyla 700 nm (kırmızı) ve 400 nm (mor) olan iki ışığın frekanslarını bulup hangisinin daha enerjik olduğunu belirleyiniz. (c = 3·10⁸ m/s)","fig":"<svg viewBox='0 0 320 120'><rect x='20' y='40' width='130' height='30' fill='#e53935'/><text x='85' y='60' font-size='11' text-anchor='middle' fill='#fff'>kırmızı 700 nm</text><rect x='160' y='40' width='130' height='30' fill='#5e35b1'/><text x='225' y='60' font-size='11' text-anchor='middle' fill='#fff'>mor 400 nm</text><text x='85' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>büyük λ, küçük f</text><text x='225' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>küçük λ, büyük f</text></svg>","steps":[{"t":"Kırmızının frekansı","a":"≈4,3·10¹⁴ Hz","d":"f = c/λ = 3·10⁸ ÷ 7·10⁻⁷ ≈ 4,3·10¹⁴ Hz'dir."},{"t":"Morun frekansı","a":"7,5·10¹⁴ Hz","d":"f = 3·10⁸ ÷ 4·10⁻⁷ = 7,5·10¹⁴ Hz'dir."},{"t":"Karşılaştır","a":"mor daha enerjik","d":"Frekansı büyük olan mor ışık daha enerjiktir."}],"ans":"Kırmızı ≈4,3·10¹⁴ Hz, mor 7,5·10¹⁴ Hz; frekansı büyük olduğu için mor ışık daha enerjiktir."},{"q":"Frekansı 5·10¹⁴ Hz olan bir fotonun enerjisini bulunuz. (h = 6,63·10⁻³⁴ J·s)","steps":[{"t":"Bağıntı","a":"E = h · f","d":"Bir fotonun enerjisi, Planck sabiti ile frekansın çarpımıdır."},{"t":"Yerine koy","a":"6,63·10⁻³⁴ × 5·10¹⁴","d":"h ve f değerleri yerine konur."},{"t":"Sonuç","a":"≈3,3·10⁻¹⁹ J","d":"Çarpım sonucu yaklaşık 3,315·10⁻¹⁹ J bulunur."}],"ans":"Fotonun enerjisi yaklaşık 3,3·10⁻¹⁹ J'dir."},{"q":"Bir AM radyo 600 kHz, bir FM radyo 100 MHz'de yayın yapıyor. İki yayının boşluktaki dalga boylarını bulup karşılaştırınız. (c = 3·10⁸ m/s)","steps":[{"t":"AM dalga boyu","a":"500 m","d":"λ = c/f = 3·10⁸ ÷ 6·10⁵ = 500 m'dir."},{"t":"FM dalga boyu","a":"3 m","d":"λ = 3·10⁸ ÷ 10⁸ = 3 m'dir."},{"t":"Karşılaştır","a":"AM çok büyük","d":"AM dalga boyu 500 m, FM ise 3 m; AM dalga boyu FM'in yaklaşık 167 katıdır."}],"ans":"AM yayının dalga boyu 500 m, FM'inki 3 m'dir; düşük frekanslı AM çok daha büyük dalga boyludur."},{"q":"Boşlukta yan yana giden iki EM dalganın frekansları 2·10¹⁴ Hz ve 6·10¹⁴ Hz'dir. Aynı uzaklığı kat etme süreleri için ne söylenir?","steps":[{"t":"Hızları karşılaştır","a":"ikisi de c","d":"Frekansları farklı olsa da boşlukta her ikisi de ışık hızıyla yayılır."},{"t":"Süreyi yaz","a":"t = yol / c","d":"Aynı yol için süre yalnızca hıza bağlıdır, hız ikisinde de eşittir."},{"t":"Sonuç","a":"eşit süre","d":"Bu yüzden aynı uzaklığı eşit sürede kat ederler."}],"ans":"Frekansları farklı olsa da boşlukta hızları eşit (c) olduğundan aynı uzaklığı aynı sürede kat ederler."},{"q":"Dalga boyu 0,03 m olan bir mikrodalganın frekansını bulup bu dalganın görünür ışıktan daha mı az enerjik olduğunu açıklayınız. (c = 3·10⁸ m/s)","steps":[{"t":"Frekansı bul","a":"f = c/λ","d":"f = 3·10⁸ ÷ 0,03 = 1·10¹⁰ Hz'dir."},{"t":"Görünürle karşılaştır","a":"görünür ≈10¹⁴","d":"Görünür ışığın frekansı yaklaşık 10¹⁴ Hz mertebesindedir, mikrodalganınkinden çok büyüktür."},{"t":"Enerji yorumu","a":"daha az enerjik","d":"Enerji frekansla doğru orantılı olduğundan, düşük frekanslı mikrodalga daha az enerjiktir."}],"ans":"Mikrodalganın frekansı 10¹⁰ Hz'dir; görünür ışığa göre çok düşük frekanslı olduğundan daha az enerjiktir."},{"q":"Bir lazer 4,74·10¹⁴ Hz frekansta ışık üretiyor. Boşluktaki dalga boyunu nanometre cinsinden bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Hesapla","a":"3·10⁸ ÷ 4,74·10¹⁴","d":"Bölme sonucu yaklaşık 6,33·10⁻⁷ m bulunur."},{"t":"Birim çevir","a":"≈633 nm","d":"6,33·10⁻⁷ m, nanometre cinsinden yaklaşık 633 nm'dir."}],"ans":"Lazerin dalga boyu yaklaşık 633 nm'dir (kırmızı ışık)."},{"q":"EM spektrumda kızılötesi ile morötesi bölgelerini görünür ışığa göre konumlandırıp frekans-enerji ilişkisini açıklayınız.","fig":"<svg viewBox='0 0 320 120'><rect x='30' y='40' width='80' height='30' fill='#e53935'/><text x='70' y='60' font-size='9' text-anchor='middle' fill='#fff'>Kızılötesi</text><rect x='110' y='40' width='90' height='30' fill='#43a047'/><text x='155' y='60' font-size='9' text-anchor='middle' fill='#fff'>Görünür</text><rect x='200' y='40' width='90' height='30' fill='#3949ab'/><text x='245' y='60' font-size='9' text-anchor='middle' fill='#fff'>Morötesi</text><polygon points='30,90 290,90 290,86 30,86' fill='#1a2b45'/><polygon points='290,88 280,82 280,94' fill='#1a2b45'/><text x='45' y='105' font-size='9' fill='#1a2b45'>düşük f</text><text x='250' y='105' font-size='9' fill='#1a2b45'>yüksek f</text></svg>","steps":[{"t":"Konum","a":"görünürün iki yanı","d":"Kızılötesi görünür ışığın kırmızı tarafında (daha düşük frekans), morötesi ise mor tarafında (daha yüksek frekans) yer alır."},{"t":"Frekans-enerji","a":"morötesi enerjik","d":"Enerji frekansla doğru orantılı olduğundan morötesi, kızılötesinden daha enerjiktir."}],"ans":"Kızılötesi görünür ışıktan düşük, morötesi yüksek frekanslıdır; bu yüzden morötesi daha enerjiklidir, kızılötesi daha az."},{"q":"Frekansı 3·10⁹ Hz olan bir dalga ile frekansı 3·10¹⁵ Hz olan bir dalganın enerji oranını bulup hangi spektrum bölgelerinde olduklarını belirtiniz.","steps":[{"t":"Enerji oranı","a":"E ∝ f","d":"Enerji frekansla doğru orantılı olduğundan enerji oranı frekans oranına eşittir."},{"t":"Oranı hesapla","a":"3·10¹⁵ ÷ 3·10⁹ = 10⁶","d":"İkinci dalganın enerjisi birincinin 1 milyon (10⁶) katıdır."},{"t":"Bölgeler","a":"mikrodalga ve morötesi","d":"3·10⁹ Hz mikrodalga bölgesinde, 3·10¹⁵ Hz ise morötesi bölgesinde yer alır."}],"ans":"İkinci dalganın enerjisi birincinin 10⁶ katıdır; ilki mikrodalga, ikincisi morötesi bölgesindedir."},{"q":"Bir EM dalganın periyodu 2·10⁻⁹ s ise boşluktaki dalga boyunu bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Frekansı bul","a":"f = 1 / T","d":"Frekans, periyodun tersidir: f = 1 ÷ 2·10⁻⁹ = 5·10⁸ Hz'dir."},{"t":"Bağıntı","a":"λ = c / f","d":"Dalga boyu, ışık hızının frekansa bölümüdür."},{"t":"Sonuç","a":"0,6 m","d":"3·10⁸ ÷ 5·10⁸ = 0,6 m bulunur."}],"ans":"Dalganın dalga boyu 0,6 metredir."},{"q":"Güneş ışığının Dünya'ya ulaşması yaklaşık 500 saniye sürüyor. Buradan Güneş–Dünya uzaklığını yaklaşık olarak bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Bağıntı","a":"yol = c · t","d":"EM dalga boşlukta ışık hızıyla gittiğinden yol, hız ile sürenin çarpımıdır."},{"t":"Yerine koy","a":"3·10⁸ × 500","d":"c = 3·10⁸ m/s ve t = 500 s değerleri yerine konur."},{"t":"Sonuç","a":"1,5·10¹¹ m","d":"Çarpım sonucu 1,5·10¹¹ m bulunur."}],"ans":"Güneş–Dünya uzaklığı yaklaşık 1,5·10¹¹ m'dir (150 milyon km)."},{"q":"Bir radarın gönderdiği EM sinyal, bir uçağa çarpıp geri dönene kadar 4·10⁻⁵ s geçiyor. Uçağın radara uzaklığını bulunuz. (c = 3·10⁸ m/s)","steps":[{"t":"Tek yön süresi","a":"t = 4·10⁻⁵ ÷ 2","d":"Sinyal gidip geldiği için uçağa ulaşma süresi toplam sürenin yarısıdır: 2·10⁻⁵ s."},{"t":"Bağıntı","a":"yol = c · t","d":"Uzaklık, ışık hızı ile tek yön süresinin çarpımıdır."},{"t":"Sonuç","a":"3·10⁸ × 2·10⁻⁵","d":"Çarpım sonucu 6·10³ m, yani 6 km bulunur."}],"ans":"Uçağın radara uzaklığı 6·10³ m'dir (6 km)."}]}},"enineBoyuna":{"ilkokul":{"kolay":[{"q":"Bir ipin ucunu yukarı aşağı sallayınca oluşan dalgada el yukarı aşağı, dalga ise ileri gider. Buna ne tür dalga denir?","fig":"<svg viewBox='0 0 320 150'><polyline points='20,75 50,40 80,110 110,40 140,110 170,40 200,110 230,40 260,110 290,75' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='30' y1='30' x2='30' y2='120' stroke='#e0552b' stroke-width='2'/><polygon points='30,28 26,38 34,38' fill='#e0552b'/><polygon points='30,122 26,112 34,112' fill='#e0552b'/><text x='44' y='20' font-size='11' fill='#1a2b45'>titreşim yukarı-aşağı</text><line x1='200' y1='130' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><polygon points='292,130 282,126 282,134' fill='#1a2b45'/><text x='235' y='145' font-size='11' fill='#1a2b45'>yayılma</text></svg>","steps":[{"t":"Titreşim yönü","a":"yukarı-aşağı","d":"El, dalganın gittiği yöne dik biçimde yukarı aşağı hareket eder."},{"t":"Dalga tipi","a":"enine dalga","d":"Titreşim, yayılma yönüne dik olduğu için bu bir enine dalgadır."}],"ans":"Bu bir enine dalgadır; çünkü titreşim, yayılma yönüne diktir."},{"q":"Suya bir taş atınca oluşan halkalar yana yana açılırken su damlası yukarı aşağı oynar. Bu hangi dalga tipine örnektir?","steps":[{"t":"Suyun hareketi","a":"yukarı-aşağı","d":"Su yüzeyindeki bir yaprak, dalga geçerken sadece yukarı aşağı sallanır."},{"t":"Dalga tipi","a":"enine","d":"Su hareketi dalganın yayıldığı yöne dik olduğundan bu enine dalgadır."}],"ans":"Su yüzeyi dalgaları enine dalgaya örnektir."},{"q":"Bir yayı (zembereği) ileri geri itip çekince sıkışan ve gevşeyen bölgeler oluşur. Bu hangi dalga tipidir?","fig":"<svg viewBox='0 0 320 130'><line x1='40' y1='65' x2='50' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='52' y1='50' x2='52' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='58' y1='50' x2='58' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='64' y1='50' x2='64' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='90' y1='50' x2='90' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='50' x2='120' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='148' y1='50' x2='148' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='154' y1='50' x2='154' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='50' x2='160' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='190' y1='50' x2='190' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='220' y1='50' x2='220' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='246' y1='50' x2='246' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='252' y1='50' x2='252' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='258' y1='50' x2='258' y2='80' stroke='#1a2b45' stroke-width='2'/><text x='55' y='100' font-size='11' fill='#e0552b' text-anchor='middle'>sıkışma</text><text x='120' y='100' font-size='11' fill='#1a2b45' text-anchor='middle'>seyrelme</text><line x1='90' y1='115' x2='200' y2='115' stroke='#1a2b45' stroke-width='2'/><polygon points='202,115 192,111 192,119' fill='#1a2b45'/><text x='145' y='128' font-size='10' fill='#1a2b45' text-anchor='middle'>yayılma</text></svg>","steps":[{"t":"Hareket yönü","a":"ileri-geri","d":"Yayı ileri geri ittiğimizde halkalar dalga yönünde sıkışıp gevşer."},{"t":"Dalga tipi","a":"boyuna","d":"Titreşim, dalganın yayıldığı yönle aynı doğrultuda olduğundan boyuna dalgadır."}],"ans":"Bu bir boyuna dalgadır; sıkışma ve seyrelme bölgeleri oluşur."},{"q":"Ses dalgaları havada ilerlerken hava ileri geri sıkışır. Ses enine mi yoksa boyuna dalga mıdır?","steps":[{"t":"Havanın hareketi","a":"ileri-geri","d":"Ses geçerken havadaki parçacıklar dalga yönünde ileri geri titreşir."},{"t":"Dalga tipi","a":"boyuna","d":"Titreşim yayılma yönüyle aynı olduğu için ses boyuna dalgadır."}],"ans":"Ses bir boyuna dalgadır."},{"q":"Halatı yere koyup ucunu sağa sola değil yukarı aşağı sallarsak dalga hangi tip olur?","steps":[{"t":"El nasıl oynuyor","a":"yukarı-aşağı","d":"El, dalganın gideceği yöne dik biçimde yukarı aşağı hareket eder."},{"t":"Sonuç","a":"enine","d":"Titreşim yayılma yönüne dik olduğu için enine dalga oluşur."}],"ans":"Yukarı aşağı sallanan halatta enine dalga oluşur."}],"zor":[{"q":"Bir gölde yüzen bir mantar, dalga geçerken yerinden ileri gitmiyor sadece yukarı aşağı zıplıyor. Bu durum dalganın enine olduğunu nasıl gösterir?","steps":[{"t":"Mantarın hareketi","a":"yerinde, yukarı-aşağı","d":"Mantar dalgayla birlikte ileri taşınmaz, olduğu yerde yukarı aşağı oynar."},{"t":"Yön karşılaştırması","a":"dik","d":"Dalga yana doğru ilerlerken mantarın titreşimi buna dik yöndedir."},{"t":"Sonuç","a":"enine dalga","d":"Titreşim yayılmaya dik olduğu için bu enine bir dalgadır."}],"ans":"Mantar yerinde yukarı aşağı oynayıp dalga yana ilerlediği için bu enine dalgadır."},{"q":"Enine ve boyuna dalgayı ayırt etmek için temel olarak neye bakarız?","steps":[{"t":"İki yöne bak","a":"titreşim ve yayılma","d":"Bir dalgada parçacığın titreşim yönü ile dalganın ilerleme yönü vardır."},{"t":"Karar kuralı","a":"dik mi aynı mı","d":"Titreşim yayılmaya dikse enine, aynı doğrultudaysa boyunadır."}],"ans":"Titreşim yönü ile yayılma yönünü karşılaştırırız: dikse enine, aynıysa boyuna dalgadır."},{"q":"Şekildeki yayda sıkışma ve seyrelme bölgeleri var. Bu dalga enine mi boyuna mı, açıklayınız.","fig":"<svg viewBox='0 0 320 130'><line x1='40' y1='50' x2='40' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='46' y1='50' x2='46' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='52' y1='50' x2='52' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='80' y1='50' x2='80' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='115' y1='50' x2='115' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='50' x2='150' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='156' y1='50' x2='156' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='162' y1='50' x2='162' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='190' y1='50' x2='190' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='225' y1='50' x2='225' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='258' y1='50' x2='258' y2='80' stroke='#1a2b45' stroke-width='2'/><line x1='264' y1='50' x2='264' y2='80' stroke='#1a2b45' stroke-width='2'/><text x='46' y='100' font-size='11' fill='#e0552b' text-anchor='middle'>sıkışma</text><text x='262' y='100' font-size='11' fill='#e0552b' text-anchor='middle'>sıkışma</text><text x='150' y='42' font-size='10' fill='#1a2b45' text-anchor='middle'>↔ titreşim ve yayılma aynı yön</text></svg>","steps":[{"t":"Sıkışma ne demek","a":"boyuna işaret","d":"Sıkışma ve seyrelme, parçacıkların yayılma yönünde itilip çekilmesiyle oluşur."},{"t":"Yön ilişkisi","a":"aynı doğrultu","d":"Titreşim, dalganın ilerleme yönüyle aynı çizgi üzerindedir."},{"t":"Sonuç","a":"boyuna","d":"Bu yüzden sıkışma-seyrelme gösteren dalga boyunadır."}],"ans":"Sıkışma ve seyrelme gösterdiği için bu bir boyuna dalgadır."},{"q":"Su yüzeyi dalgası, ip dalgası ve ses dalgası veriliyor. Hangisi boyuna dalgadır?","steps":[{"t":"Su ve ip","a":"enine","d":"Su yüzeyi ve sallanan ip dalgaları enine dalgalardır, titreşim dike düşer."},{"t":"Ses","a":"boyuna","d":"Sesde hava ileri geri sıkışır, titreşim yayılma yönündedir."}],"ans":"Ses dalgası boyunadır; su ve ip dalgaları enine dalgadır."},{"q":"Ses neden boşlukta (havasız ortamda) yayılamaz, ama ışık yayılabilir?","steps":[{"t":"Sesin türü","a":"boyuna, madde gerekir","d":"Ses boyuna bir dalgadır; ilerlemek için sıkışıp gevşeyecek havaya (maddeye) ihtiyaç duyar."},{"t":"Işığın türü","a":"madde gerekmez","d":"Işık enine bir dalgadır ve yayılmak için maddeye ihtiyaç duymaz, boşlukta da gider."}],"ans":"Ses boyuna dalga olup yayılmak için maddeye muhtaçtır; bu yüzden boşlukta yayılamaz, oysa ışık boşlukta da yayılır."}]},"ortaokul":{"kolay":[{"q":"Enine dalgada parçacıkların titreşim yönü ile dalganın yayılma yönü arasındaki ilişki nedir?","fig":"<svg viewBox='0 0 320 150'><polyline points='15,75 45,40 75,110 105,40 135,110 165,40 195,110 225,40 255,110 285,75' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='30' y1='35' x2='30' y2='115' stroke='#e0552b' stroke-width='2'/><polygon points='30,33 26,43 34,43' fill='#e0552b'/><polygon points='30,117 26,107 34,107' fill='#e0552b'/><text x='40' y='28' font-size='11' fill='#e0552b'>titreşim</text><line x1='200' y1='132' x2='285' y2='132' stroke='#1a2b45' stroke-width='2'/><polygon points='287,132 277,128 277,136' fill='#1a2b45'/><text x='235' y='146' font-size='11' fill='#1a2b45'>yayılma</text></svg>","steps":[{"t":"İki yönü belirle","a":"titreşim ve yayılma","d":"Parçacıklar bir yönde titreşir, dalga başka bir yönde ilerler."},{"t":"İlişki","a":"birbirine dik","d":"Enine dalgada titreşim yönü, yayılma yönüne diktir."}],"ans":"Enine dalgada titreşim yönü ile yayılma yönü birbirine diktir."},{"q":"Boyuna dalgada sıkışma ve seyrelme bölgeleri nasıl oluşur?","steps":[{"t":"Parçacık hareketi","a":"ileri-geri","d":"Parçacıklar dalganın ilerleme yönünde ileri geri itilip çekilir."},{"t":"Bölgeler","a":"sıkışma-seyrelme","d":"İtildikleri yerde toplanıp sıkışma, çekildikleri yerde aralanıp seyrelme oluşur."}],"ans":"Parçacıkların yayılma yönünde ileri geri hareketiyle sıkışma ve seyrelme bölgeleri oluşur."},{"q":"Ses, ışık ve deprem S dalgalarından hangileri enine dalgadır?","steps":[{"t":"Sesi ele al","a":"boyuna","d":"Ses bir boyuna dalgadır, sıkışma-seyrelme ile ilerler."},{"t":"Işık ve S dalgası","a":"enine","d":"Işık ve deprem S (ikincil) dalgaları enine dalgalardır."}],"ans":"Işık ve deprem S dalgaları enine, ses ise boyunadır."},{"q":"Enine dalganın bir tam tepe ve bir tam çukurunu gösteren bölgeye ne ad verilir?","fig":"<svg viewBox='0 0 320 150'><polyline points='20,80 60,35 100,80 140,125 180,80 220,35 260,80 300,80' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='60' y1='35' x2='60' y2='80' stroke='#e0552b' stroke-width='1' stroke-dasharray='3,3'/><text x='60' y='28' font-size='10' fill='#1a2b45' text-anchor='middle'>tepe</text><text x='140' y='140' font-size='10' fill='#1a2b45' text-anchor='middle'>çukur</text><line x1='60' y1='15' x2='220' y2='15' stroke='#1a2b45' stroke-width='1'/><text x='140' y='12' font-size='10' fill='#1a2b45' text-anchor='middle'>1 dalga boyu</text></svg>","steps":[{"t":"Tekrar eden parça","a":"tepe + çukur","d":"Dalga, bir tepe ve bir çukurdan oluşan biçimi sürekli tekrarlar."},{"t":"Adı","a":"dalga boyu","d":"Bir tam tepe ile bir tam çukurun kapsadığı uzunluğa dalga boyu denir."}],"ans":"Bu bölgeye bir dalga boyu denir."},{"q":"Bir yayda iki sıkışma arasındaki uzaklık boyuna dalganın hangi büyüklüğüne karşılık gelir?","steps":[{"t":"Tekrar mesafesi","a":"sıkışmadan sıkışmaya","d":"Boyuna dalgada art arda gelen iki sıkışma arasındaki mesafe bir tam tekrardır."},{"t":"Adı","a":"dalga boyu","d":"Bu tam tekrar uzunluğu, dalganın dalga boyudur."}],"ans":"İki ardışık sıkışma arasındaki uzaklık, boyuna dalganın dalga boyudur."}],"zor":[{"q":"Bir dalganın enine mi boyuna mı olduğunu, parçacık hareketini gözlemleyerek nasıl belirlersiniz?","steps":[{"t":"Tek parçacığı izle","a":"titreşim yönü","d":"Ortamdaki bir parçacığın hangi yönde gidip geldiğini belirleriz."},{"t":"Yayılmayı belirle","a":"dalga yönü","d":"Dalganın ilerlediği yönü saptarız."},{"t":"Karşılaştır","a":"dik mi aynı mı","d":"Titreşim yayılmaya dikse enine, aynı doğrultudaysa boyuna deriz."}],"ans":"Parçacığın titreşim yönü yayılmaya dikse dalga enine, yayılma ile aynı doğrultudaysa boyunadır."},{"q":"Deprem sırasında P dalgaları S dalgalarından önce hissedilir. Bu iki dalganın tipi nedir ve neden P daha hızlıdır?","steps":[{"t":"P dalgası","a":"boyuna","d":"P (birincil) dalgalar sıkışma-seyrelme ile ilerleyen boyuna dalgalardır."},{"t":"S dalgası","a":"enine","d":"S (ikincil) dalgalar yayılmaya dik titreşen enine dalgalardır."},{"t":"Hız farkı","a":"P daha hızlı","d":"Boyuna P dalgaları katı ortamda enine S dalgalarından daha hızlı yayılır, bu yüzden önce gelir."}],"ans":"P dalgaları boyuna, S dalgaları eninedir; boyuna P dalgaları daha hızlı yayıldığı için önce hissedilir."},{"q":"Ses katı, sıvı ve gazda yayılabilirken neden boşlukta yayılamaz?","steps":[{"t":"Sesin tipi","a":"boyuna","d":"Ses, parçacıkların ileri geri sıkışmasıyla ilerleyen boyuna bir dalgadır."},{"t":"Madde gerekliliği","a":"taşıyıcı ortam","d":"Sıkışma-seyrelme için titreşecek parçacık (katı, sıvı, gaz) gerekir."},{"t":"Boşluk","a":"parçacık yok","d":"Boşlukta titreşecek parçacık bulunmadığından ses yayılamaz."}],"ans":"Ses boyuna dalga olarak yayılmak için maddeye ihtiyaç duyar; boşlukta parçacık olmadığından yayılamaz."},{"q":"Enine dalgada genlik neyi gösterir ve şekildeki dalgada nasıl ölçülür?","fig":"<svg viewBox='0 0 320 150'><line x1='15' y1='75' x2='305' y2='75' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4,4'/><text x='305' y='72' font-size='9' fill='#1a2b45' text-anchor='end'>denge</text><polyline points='20,75 55,35 90,75 125,115 160,75 195,35 230,75 265,115 300,75' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='55' y1='75' x2='55' y2='35' stroke='#e0552b' stroke-width='2'/><polygon points='55,33 51,43 59,43' fill='#e0552b'/><text x='70' y='50' font-size='11' fill='#e0552b'>genlik</text></svg>","steps":[{"t":"Genlik tanımı","a":"en büyük sapma","d":"Genlik, parçacığın denge konumundan ulaştığı en büyük uzaklıktır."},{"t":"Şekilde ölçüm","a":"orta çizgi-tepe","d":"Orta (denge) çizgisi ile tepe arasındaki dikey uzaklık genliği verir."}],"ans":"Genlik, denge çizgisinden tepeye (veya çukura) olan dikey uzaklıktır ve dalganın enerjisini yansıtır."},{"q":"Bir ipte oluşan enine dalganın frekansı artırılırsa hız sabitken dalga boyu nasıl değişir?","steps":[{"t":"Temel bağıntı","a":"v = f × λ","d":"Dalga hızı, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Hız sabit","a":"f ile λ ters","d":"Aynı ipte hız sabit olduğundan frekans artarsa dalga boyu küçülmelidir."},{"t":"Sonuç","a":"dalga boyu azalır","d":"Frekans arttıkça dalga boyu ters orantılı olarak kısalır."}],"ans":"Hız sabitken frekans artırılırsa dalga boyu kısalır; çünkü v = f × λ bağıntısında f ile λ ters orantılıdır."}]},"lise":{"kolay":[{"q":"Enine dalga nasıl tanımlanır ve tipik üç örneği nedir?","steps":[{"t":"Tanım","a":"titreşim ⊥ yayılma","d":"Enine dalgada ortam parçacıkları, dalganın yayılma yönüne dik titreşir."},{"t":"Örnekler","a":"ışık, su, ip","d":"Elektromanyetik dalgalar (ışık), su yüzeyi dalgaları ve gergin ipteki dalgalar enine dalgalardır."}],"ans":"Enine dalga, parçacık titreşiminin yayılmaya dik olduğu dalgadır; ışık, su yüzeyi ve ip dalgaları örnektir."},{"q":"Boyuna dalga nasıl tanımlanır ve en yaygın örneği nedir?","steps":[{"t":"Tanım","a":"titreşim ∥ yayılma","d":"Boyuna dalgada parçacıklar, dalganın yayılma yönü ile aynı doğrultuda ileri geri titreşir."},{"t":"Örnek","a":"ses","d":"Ses dalgası, havada sıkışma ve seyrelmelerle ilerleyen tipik bir boyuna dalgadır."}],"ans":"Boyuna dalga, titreşimin yayılma yönüyle aynı doğrultuda olduğu dalgadır; en yaygın örneği sestir."},{"q":"Şekildeki dalgada titreşim yönü oklarla gösterilmiş. Bu dalga enine mi boyuna mıdır?","fig":"<svg viewBox='0 0 320 150'><polyline points='15,75 45,38 75,112 105,38 135,112 165,38 195,112 225,38 255,112 285,75' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='105' y1='30' x2='105' y2='120' stroke='#e0552b' stroke-width='2'/><polygon points='105,28 101,38 109,38' fill='#e0552b'/><polygon points='105,122 101,112 109,112' fill='#e0552b'/><line x1='200' y1='133' x2='285' y2='133' stroke='#1a2b45' stroke-width='2'/><polygon points='287,133 277,129 277,137' fill='#1a2b45'/><text x='118' y='25' font-size='11' fill='#e0552b'>titreşim</text><text x='235' y='147' font-size='11' fill='#1a2b45'>yayılma</text></svg>","steps":[{"t":"Yönleri oku","a":"titreşim dikey, yayılma yatay","d":"Ok, parçacığın yukarı aşağı titreştiğini; alttaki ok dalganın yatay ilerlediğini gösterir."},{"t":"Karar","a":"dik → enine","d":"Titreşim yayılmaya dik olduğundan dalga eninedir."}],"ans":"Titreşim yayılmaya dik olduğu için bu bir enine dalgadır."},{"q":"Sıkışma ve seyrelme kavramları hangi dalga tipine özgüdür ve neyi ifade eder?","steps":[{"t":"Hangi tip","a":"boyuna","d":"Sıkışma ve seyrelme yalnızca boyuna dalgalarda görülür."},{"t":"Anlamları","a":"yoğun/seyrek bölge","d":"Sıkışma parçacıkların toplandığı yoğun, seyrelme ise aralandığı seyrek bölgedir."}],"ans":"Sıkışma ve seyrelme boyuna dalgalara özgüdür; sırasıyla parçacıkların yoğunlaştığı ve seyrekleştiği bölgeleri ifade eder."},{"q":"Bir enine dalgada tepe ile çukur, bir boyuna dalgada sıkışma ile seyrelme hangi bakımdan birbirine karşılık gelir?","steps":[{"t":"Enine eşleştir","a":"tepe-çukur","d":"Enine dalgada en yüksek nokta tepe, en alçak nokta çukurdur."},{"t":"Boyuna eşleştir","a":"sıkışma-seyrelme","d":"Boyuna dalgada en yoğun bölge sıkışma, en seyrek bölge seyrelmedir."},{"t":"Karşılık","a":"tepe↔sıkışma","d":"Tepe sıkışmaya, çukur seyrelmeye karşılık gelir; ikisi de dalga biçiminin uç durumlarıdır."}],"ans":"Enine dalgadaki tepe boyunadaki sıkışmaya, çukur ise seyrelmeye karşılık gelir."},{"q":"Işık ve ses kaynağı aynı odada. Işığı görüp sesi sonra duymamızın dalga tipiyle ilgisi nedir?","steps":[{"t":"Işığın tipi","a":"enine, çok hızlı","d":"Işık enine elektromanyetik dalgadır ve havada çok büyük hızla yayılır."},{"t":"Sesin tipi","a":"boyuna, yavaş","d":"Ses boyuna mekanik dalgadır ve havada görece çok yavaş yayılır."}],"ans":"Işık enine ve çok hızlı, ses ise boyuna ve yavaş yayıldığı için ışığı önce görür, sesi sonra duyarız."},{"q":"Elektromanyetik dalgaların enine olması, onların boşlukta yayılabilmesini nasıl açıklar?","steps":[{"t":"EM dalga yapısı","a":"alanların titreşimi","d":"Elektromanyetik dalgada titreşen şey elektrik ve manyetik alanlardır, maddesel parçacık değil."},{"t":"Boşlukta yayılma","a":"madde gerekmez","d":"Alanlar yayılma yönüne dik titreştiği ve maddeye ihtiyaç duymadığı için EM dalga boşlukta da ilerler."}],"ans":"EM dalgalarda titreşen, yayılmaya dik elektrik-manyetik alanlardır; madde gerekmediğinden boşlukta yayılabilirler."},{"q":"Mekanik dalgalar arasında bir ortamın hem enine hem boyuna dalga taşıyabilmesi neye bağlıdır?","steps":[{"t":"Boyuna koşulu","a":"sıkışabilirlik","d":"Her ortam (katı, sıvı, gaz) sıkışıp gevşeyebildiği için boyuna dalga taşıyabilir."},{"t":"Enine koşulu","a":"kayma direnci","d":"Enine dalga için ortamın kayma (şekil) direnci olması gerekir; bu yalnızca katılarda belirgindir."}],"ans":"Tüm ortamlar boyuna dalga taşır; enine dalga için kayma direnci gerektiğinden bunu esas olarak katılar taşır."},{"q":"Bir su yüzeyi dalgasında bir su parçacığının izlediği yörünge neden tam enine sayılmaz?","steps":[{"t":"Gözlem","a":"dairesel hareket","d":"Su yüzeyindeki parçacık yalnız yukarı aşağı değil, dairesel bir yörünge çizer."},{"t":"Yorum","a":"karışık","d":"Bu harekette hem dik hem yayılma yönünde bileşen olduğundan tam saf enine değildir."}],"ans":"Su yüzeyi parçacıkları dairesel hareket yaptığından, su dalgası saf enine olmayıp enine-boyuna karışık özellik gösterir."},{"q":"v = f × λ bağıntısı hem enine hem boyuna dalgalar için geçerli midir?","steps":[{"t":"Bağıntının kapsamı","a":"tüm dalgalar","d":"Hız = frekans × dalga boyu ilişkisi dalga tipinden bağımsızdır."},{"t":"Uygulama","a":"ses ve ışık","d":"Hem boyuna ses dalgası hem enine ışık dalgası bu bağıntıya uyar."}],"ans":"Evet; v = f × λ bağıntısı dalga tipinden bağımsız olarak hem enine hem boyuna dalgalar için geçerlidir."},{"q":"340 m/s hızla yayılan bir ses dalgasının frekansı 170 Hz ise dalga boyu kaç metredir?","steps":[{"t":"Bağıntı","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"340 ÷ 170","d":"Hız 340 m/s, frekans 170 Hz değerleri yerine yazılır."},{"t":"Sonuç","a":"2 m","d":"Bölme sonucu 2 m bulunur."}],"ans":"Ses dalgasının dalga boyu 2 metredir."},{"q":"Dalga boyu 0,5 m olan bir enine dalganın hızı 20 m/s ise frekansı kaç Hz'dir?","steps":[{"t":"Bağıntı","a":"f = v / λ","d":"Frekans, hızın dalga boyuna bölünmesiyle bulunur."},{"t":"Yerine koy","a":"20 ÷ 0,5","d":"Hız 20 m/s, dalga boyu 0,5 m değerleri yerine konur."},{"t":"Sonuç","a":"40 Hz","d":"Bölme sonucu 40 Hz bulunur."}],"ans":"Dalganın frekansı 40 Hz'dir."},{"q":"Şekildeki boyuna dalgada ardışık iki sıkışma arası 4 cm ölçüldü. Bu uzunluk neye karşılık gelir?","fig":"<svg viewBox='0 0 320 130'><line x1='30' y1='45' x2='30' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='36' y1='45' x2='36' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='42' y1='45' x2='42' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='75' y1='45' x2='75' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='115' y1='45' x2='115' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='155' y1='45' x2='155' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='161' y1='45' x2='161' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='167' y1='45' x2='167' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='205' y1='45' x2='205' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='245' y1='45' x2='245' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='285' y1='45' x2='285' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='291' y1='45' x2='291' y2='75' stroke='#1a2b45' stroke-width='2'/><text x='36' y='38' font-size='10' fill='#e0552b' text-anchor='middle'>sıkışma</text><text x='287' y='38' font-size='10' fill='#e0552b' text-anchor='middle'>sıkışma</text><line x1='36' y1='95' x2='287' y2='95' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='112' font-size='11' fill='#1a2b45' text-anchor='middle'>4 cm</text></svg>","steps":[{"t":"Tekrar mesafesi","a":"sıkışmadan sıkışmaya","d":"Boyuna dalgada ardışık iki sıkışma arası bir tam tekrar uzunluğudur."},{"t":"Adı","a":"dalga boyu","d":"Bu tam tekrar uzunluğu dalga boyu (λ) olarak adlandırılır."}],"ans":"Ardışık iki sıkışma arasındaki 4 cm, boyuna dalganın dalga boyuna (λ) karşılık gelir."},{"q":"Bir gitar telinde oluşan dalga ile bu telin çıkardığı ses dalgası hangi dalga tiplerindendir?","steps":[{"t":"Telin dalgası","a":"enine","d":"Gergin telde parçacıklar yayılmaya dik titreştiği için teldeki dalga eninedir."},{"t":"Ses dalgası","a":"boyuna","d":"Telin titreşimi havayı ileri geri sıkıştırır, bu yüzden çıkan ses boyunadır."}],"ans":"Gitar telindeki dalga enine, bu telin havada oluşturduğu ses dalgası ise boyunadır."},{"q":"Aynı frekansta titreşen iki kaynaktan biri ipte enine, diğeri yayda boyuna dalga üretiyor. Frekans eşitse hangi büyüklük kesinlikle eşit olur?","steps":[{"t":"Frekansın anlamı","a":"saniyedeki tekrar","d":"Frekans, kaynağın saniyede yaptığı titreşim sayısıdır ve dalga tipinden bağımsızdır."},{"t":"Sonuç","a":"frekans eşit","d":"Hız ve dalga boyu ortama göre değişebilir, ama kaynak frekansı her iki dalgada da aynıdır."}],"ans":"Frekans eşitse iki dalganın frekansı kesinlikle eşittir; hız ve dalga boyu ortama göre farklı olabilir."}],"zor":[{"q":"Bir enine dalganın denklem benzeri tanımında titreşim doğrultusu yayılmaya dik, boyunada ise paralel olur. Bu farkın deprem dalgalarının yer içinde yayılmasına etkisini açıklayınız.","steps":[{"t":"P dalgası (boyuna)","a":"her ortamda","d":"Boyuna P dalgaları sıkışma gerektirdiğinden katı, sıvı ve gazda (çekirdeğin sıvısında bile) yayılır."},{"t":"S dalgası (enine)","a":"yalnız katıda","d":"Enine S dalgaları kayma direnci gerektirdiği için sıvıda yayılamaz."},{"t":"Çıkarım","a":"sıvı çekirdek","d":"S dalgalarının dünyanın dış çekirdeğinden geçememesi, bu bölgenin sıvı olduğunu gösterir."}],"ans":"Boyuna P dalgaları her ortamda yayılırken enine S dalgaları sıvıda yayılamaz; S dalgalarının dış çekirdekten geçememesi onun sıvı olduğunu kanıtlar."},{"q":"Hızı 1500 m/s olan sesin suda dalga boyu, havadaki (340 m/s) aynı frekanslı sese göre nasıl değişir? Frekans 500 Hz alınız.","steps":[{"t":"Havadaki λ","a":"340 ÷ 500 = 0,68 m","d":"Havada dalga boyu, hızın frekansa bölünmesiyle 0,68 m bulunur."},{"t":"Sudaki λ","a":"1500 ÷ 500 = 3 m","d":"Suda aynı frekansla dalga boyu 3 m olur."},{"t":"Karşılaştır","a":"yaklaşık 4,4 kat","d":"Suda dalga boyu havadakinden büyüktür; 3 ÷ 0,68 ≈ 4,4 kat."}],"ans":"Suda dalga boyu 3 m, havada 0,68 m olup ses suda yaklaşık 4,4 kat daha uzun dalga boyuna sahiptir; çünkü frekans sabitken hız arttıkça λ büyür."},{"q":"Şekildeki enine dalgada genlik 3 cm, dalga boyu 8 cm. Parçacığın bir periyotta aldığı toplam yol kaç cm'dir?","fig":"<svg viewBox='0 0 320 150'><line x1='15' y1='75' x2='305' y2='75' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4,4'/><polyline points='20,75 60,35 100,75 140,115 180,75 220,35 260,75 300,115' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='60' y1='75' x2='60' y2='35' stroke='#e0552b' stroke-width='2'/><text x='72' y='50' font-size='11' fill='#e0552b'>3 cm</text><line x1='60' y1='20' x2='220' y2='20' stroke='#1a2b45' stroke-width='1'/><text x='140' y='16' font-size='10' fill='#1a2b45' text-anchor='middle'>λ = 8 cm</text></svg>","steps":[{"t":"Bir periyotta hareket","a":"4 genlik","d":"Bir parçacık bir periyotta dengeden tepeye, tepeden çukura, çukurdan dengeye gider; bu 4 genliklik yoldur."},{"t":"Yerine koy","a":"4 × 3 cm","d":"Genlik 3 cm olduğundan toplam yol 4 ile 3 cm çarpılır."},{"t":"Sonuç","a":"12 cm","d":"Çarpım sonucu 12 cm bulunur."}],"ans":"Parçacığın bir periyotta aldığı toplam yol 12 cm'dir (dalga boyu bu hesapta kullanılmaz)."},{"q":"Bir boyuna ses dalgasında basıncın en yüksek olduğu yer sıkışma, en düşük olduğu yer seyrelmedir. Parçacığın yer değiştirmesi ile basınç arasındaki faz ilişkisini yorumlayınız.","steps":[{"t":"Sıkışma noktası","a":"yer değiştirme sıfır","d":"Sıkışmanın tam ortasında parçacıkların net yer değiştirmesi sıfırdır ama basınç maksimumdur."},{"t":"Maksimum yer değiştirme","a":"basınç dengede","d":"Parçacıkların en çok yer değiştirdiği noktada ise basınç normal (denge) değerindedir."},{"t":"Sonuç","a":"çeyrek dalga faz farkı","d":"Basınç dalgası ile yer değiştirme dalgası arasında çeyrek dalga boyu (90°) faz farkı vardır."}],"ans":"Boyuna ses dalgasında basınç ile yer değiştirme arasında 90°'lik faz farkı vardır; basınç maksimumken yer değiştirme sıfır, yer değiştirme maksimumken basınç dengededir."},{"q":"Bir enine dalga 2 saniyede 10 m ilerliyor ve bu sürede bir parçacık 8 tam titreşim yapıyorsa dalganın hızını, frekansını ve dalga boyunu bulunuz.","steps":[{"t":"Hızı bul","a":"v = 10 / 2 = 5 m/s","d":"Hız, alınan yolun geçen süreye bölünmesiyle 5 m/s bulunur."},{"t":"Frekansı bul","a":"f = 8 / 2 = 4 Hz","d":"Frekans, titreşim sayısının süreye bölünmesiyle 4 Hz olur."},{"t":"Dalga boyunu bul","a":"λ = v / f = 5 / 4","d":"Dalga boyu, hızın frekansa bölünmesiyle 1,25 m bulunur."}],"ans":"Dalganın hızı 5 m/s, frekansı 4 Hz ve dalga boyu 1,25 metredir."},{"q":"Su yüzeyi dalgasında parçacıkların dairesel hareketi göz önüne alındığında, derin suda bu dalga neden saf enine dalga gibi görünür?","steps":[{"t":"Dairesel hareket","a":"yarıçap derinle azalır","d":"Su parçacıkları yüzeyde geniş daireler çizerken derine inildikçe dairelerin yarıçapı hızla küçülür."},{"t":"Yüzeydeki baskın bileşen","a":"düşey","d":"Gözlemci yüzeyde çoğunlukla yukarı aşağı (düşey) bileşeni fark eder."},{"t":"Sonuç","a":"enine gibi","d":"Yatay bileşen küçük kaldığından dalga pratikte enine dalga gibi algılanır."}],"ans":"Su parçacıklarının dairesel hareketinde düşey bileşen baskın, yatay bileşen küçük olduğundan derin suda dalga saf enineye yakın görünür."},{"q":"Şekilde bir ipin aynı anda iki bölümü gösteriliyor: solda enine dalga, sağda yay üzerinde boyuna dalga. İki dalga için ortak ve farklı olan birer özellik yazınız.","fig":"<svg viewBox='0 0 320 160'><polyline points='15,45 40,25 65,65 90,25 115,65 140,45' fill='none' stroke='#4aa3df' stroke-width='3'/><text x='78' y='15' font-size='10' fill='#1a2b45' text-anchor='middle'>enine</text><line x1='180' y1='40' x2='180' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='185' y1='40' x2='185' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='190' y1='40' x2='190' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='215' y1='40' x2='215' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='245' y1='40' x2='245' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='270' y1='40' x2='270' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='275' y1='40' x2='275' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='280' y1='40' x2='280' y2='65' stroke='#1a2b45' stroke-width='2'/><text x='235' y='15' font-size='10' fill='#1a2b45' text-anchor='middle'>boyuna</text><text x='160' y='110' font-size='10' fill='#1a2b45' text-anchor='middle'>ortak: enerji taşır, v=f·λ uyar</text><text x='160' y='130' font-size='10' fill='#1a2b45' text-anchor='middle'>fark: titreşim yönü</text></svg>","steps":[{"t":"Ortak özellik","a":"enerji taşıma","d":"İki dalga da madde taşımadan enerji aktarır ve v = f × λ bağıntısına uyar."},{"t":"Farklı özellik","a":"titreşim doğrultusu","d":"Enine dalgada titreşim yayılmaya dik, boyuna dalgada yayılma ile aynı doğrultudadır."}],"ans":"Ortak yön: ikisi de madde taşımadan enerji aktarır ve v = f × λ'ya uyar; fark: titreşim doğrultusu enine dalgada dik, boyuna dalgada paraleldir."},{"q":"Bir boyuna dalgada ardışık iki seyrelme arası 6 cm, dalga 0,3 saniyede bir bölgeden diğerine geçiyorsa dalganın hızını bulunuz.","steps":[{"t":"Dalga boyunu belirle","a":"λ = 6 cm = 0,06 m","d":"Ardışık iki seyrelme arası bir dalga boyu olup 6 cm yani 0,06 m'dir."},{"t":"Periyodu belirle","a":"T = 0,3 s","d":"Dalganın bir dalga boyu yol alma süresi periyottur, 0,3 s verilmiştir."},{"t":"Hızı bul","a":"v = λ / T = 0,06 / 0,3","d":"Hız, dalga boyunun periyoda bölünmesiyle 0,2 m/s bulunur."}],"ans":"Dalganın hızı 0,2 m/s'dir."},{"q":"Polarizasyon (kutuplanma) yalnızca enine dalgalarda gözlenir, boyuna dalgalarda gözlenmez. Bu durumu titreşim doğrultusuyla açıklayınız.","steps":[{"t":"Enine dalgada yön seçeneği","a":"sonsuz dik yön","d":"Enine dalgada titreşim yayılmaya dik düzlemde herhangi bir yönde olabilir; bir yön seçmek polarizasyondur."},{"t":"Boyuna dalgada","a":"tek doğrultu","d":"Boyuna dalgada titreşim yalnızca yayılma doğrultusunda olduğundan seçilecek başka yön yoktur."},{"t":"Sonuç","a":"sadece enine","d":"Tek titreşim doğrultusu olan boyuna dalga kutuplanamaz; bu yüzden polarizasyon enine dalga kanıtıdır."}],"ans":"Polarizasyon, yayılmaya dik düzlemde bir titreşim yönü seçmektir; boyuna dalgada titreşim tek doğrultuda olduğundan kutuplanma yalnızca enine dalgalarda görülür."},{"q":"Aynı ipte hız 12 m/s sabittir. Frekans 3 Hz'den 6 Hz'e çıkarılırsa dalga boyu nasıl değişir, sayısal olarak gösteriniz.","steps":[{"t":"İlk dalga boyu","a":"λ1 = 12 / 3 = 4 m","d":"Dalga boyu, hızın frekansa bölünmesiyle 4 m bulunur."},{"t":"Son dalga boyu","a":"λ2 = 12 / 6 = 2 m","d":"Frekans 6 Hz olunca dalga boyu 2 m olur."},{"t":"Yorum","a":"yarıya iner","d":"Hız sabitken frekans 2 katına çıkınca dalga boyu yarıya iner."}],"ans":"Dalga boyu 4 m'den 2 m'ye, yani yarıya iner; çünkü hız sabitken λ frekansla ters orantılıdır."},{"q":"Şekilde enine dalganın iki ardışık tepesi arası 10 cm, dalga sağa 5 cm/s hızla ilerliyor. Periyodu bulunuz.","fig":"<svg viewBox='0 0 320 150'><line x1='15' y1='80' x2='305' y2='80' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4,4'/><polyline points='20,80 55,45 90,80 125,115 160,80 195,45 230,80 265,115 300,80' fill='none' stroke='#4aa3df' stroke-width='3'/><line x1='55' y1='38' x2='195' y2='38' stroke='#e0552b' stroke-width='1.5'/><text x='125' y='32' font-size='10' fill='#1a2b45' text-anchor='middle'>10 cm (tepe-tepe)</text><line x1='240' y1='130' x2='300' y2='130' stroke='#1a2b45' stroke-width='2'/><polygon points='302,130 292,126 292,134' fill='#1a2b45'/><text x='265' y='145' font-size='10' fill='#1a2b45'>5 cm/s</text></svg>","steps":[{"t":"Dalga boyunu belirle","a":"λ = 10 cm","d":"Ardışık iki tepe arası bir dalga boyudur, yani 10 cm."},{"t":"Bağıntı","a":"T = λ / v","d":"Periyot, dalga boyunun hıza bölünmesiyle bulunur."},{"t":"Sonuç","a":"10 ÷ 5 = 2 s","d":"10 cm'yi 5 cm/s'ye bölünce periyot 2 saniye bulunur."}],"ans":"Dalganın periyodu 2 saniyedir."},{"q":"Bir öğrenci 'tüm mekanik dalgalar boyunadır' diyor. Bu ifadeyi enine mekanik dalga örnekleriyle çürütünüz.","steps":[{"t":"İddiayı incele","a":"yanlış genelleme","d":"Mekanik dalgalar hem enine hem boyuna olabilir; iddia eksiktir."},{"t":"Enine mekanik örnek","a":"ip ve su dalgası","d":"Gergin ipteki dalga ve su yüzeyi dalgası mekanik olduğu halde eninedir."},{"t":"Sonuç","a":"çürütüldü","d":"Bu örnekler mekanik dalgaların boyuna olmak zorunda olmadığını gösterir."}],"ans":"İfade yanlıştır; ip dalgası ve su yüzeyi dalgası gibi mekanik dalgalar enine de olabilir, dolayısıyla tüm mekanik dalgalar boyuna değildir."},{"q":"Deprem istasyonunda P dalgası 8 s, S dalgası 14 s sonra kaydedildi. P hızı 6 km/s ise odak uzaklığını ve bu dalgaların tiplerini belirtiniz.","steps":[{"t":"Dalga tipleri","a":"P boyuna, S enine","d":"P (birincil) boyuna, S (ikincil) enine dalgadır; boyuna hızlı olduğu için önce gelir."},{"t":"Uzaklığı bul","a":"x = v × t","d":"Odak uzaklığı, P hızı ile P varış süresinin çarpımıdır: 6 km/s × 8 s."},{"t":"Sonuç","a":"48 km","d":"Çarpım sonucu odak uzaklığı 48 km bulunur."}],"ans":"P dalgası boyuna, S dalgası eninedir; P varış verilerine göre odak uzaklığı 48 km'dir."},{"q":"Bir hoparlör 680 Hz ses üretiyor, ses havada 340 m/s ile yayılıyor. Bu ses dalgasının iki ardışık sıkışması arasındaki uzaklık nedir ve dalga tipi nedir?","fig":"<svg viewBox='0 0 320 130'><circle cx='35' cy='60' r='14' fill='#5b6b85' stroke='#1a2b45'/><text x='35' y='95' font-size='9' fill='#1a2b45' text-anchor='middle'>hoparlör</text><line x1='80' y1='45' x2='80' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='85' y1='45' x2='85' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='115' y1='45' x2='115' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='45' x2='150' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='155' y1='45' x2='155' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='185' y1='45' x2='185' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='220' y1='45' x2='220' y2='75' stroke='#1a2b45' stroke-width='2'/><line x1='225' y1='45' x2='225' y2='75' stroke='#1a2b45' stroke-width='2'/><text x='82' y='38' font-size='9' fill='#e0552b' text-anchor='middle'>sıkışma</text><text x='223' y='38' font-size='9' fill='#e0552b' text-anchor='middle'>sıkışma</text><line x1='82' y1='100' x2='223' y2='100' stroke='#e0552b' stroke-width='1.5'/><text x='152' y='118' font-size='10' fill='#1a2b45' text-anchor='middle'>λ = ?</text></svg>","steps":[{"t":"Dalga boyunu bul","a":"λ = v / f","d":"İki ardışık sıkışma arası bir dalga boyu olup λ = hız ÷ frekanstır."},{"t":"Yerine koy","a":"340 ÷ 680","d":"Hız 340 m/s, frekans 680 Hz değerleri yerine yazılır."},{"t":"Sonuç ve tip","a":"0,5 m, boyuna","d":"Bölme sonucu 0,5 m bulunur; ses sıkışma-seyrelmeyle ilerleyen boyuna dalgadır."}],"ans":"İki ardışık sıkışma arası 0,5 metredir; ses bir boyuna dalgadır."},{"q":"Bir enine dalganın belirli bir andaki görünümü, parçacıkların aynı anda farklı konumlarda olmasından kaynaklanır. Bu durumu 'faz' kavramıyla açıklayınız.","steps":[{"t":"Faz nedir","a":"titreşim aşaması","d":"Faz, bir parçacığın titreşim çevriminde bulunduğu aşamayı (konum ve yön) belirtir."},{"t":"Komşu parçacıklar","a":"farklı faz","d":"Dalga ilerlerken komşu parçacıklar birbirinden biraz gecikmeli titreştiği için farklı fazlardadır."},{"t":"Bir dalga boyu","a":"aynı faz","d":"Tam bir dalga boyu uzaktaki iki parçacık ise aynı fazda olup tepe ve çukur dizilimi bu faz farklarından doğar."}],"ans":"Enine dalganın anlık biçimi, ardışık parçacıkların farklı fazlarda olmasından doğar; bir dalga boyu arayla parçacıklar yeniden aynı faza gelir."}]}},"girisim":{"ilkokul":{"kolay":[{"q":"İki su dalgası karşılaşınca ne olur? Kısaca açıkla.","steps":[{"t":"Dalgalar buluşur","a":"üst üste biner","d":"İki dalga aynı yerde karşılaşınca birbirinin üstüne biner."},{"t":"Sonuç","a":"yeni dalga","d":"Birleştikleri anda bazen daha büyük, bazen daha küçük bir dalga görünür."}],"ans":"İki dalga karşılaşınca üst üste biner ve birleşerek yeni bir dalga oluşturur; buna girişim denir."},{"q":"Şekildeki gibi iki tepe (yüksek kısım) üst üste gelirse dalga nasıl olur?","fig":"<svg viewBox='0 0 320 180'><polyline points='20,90 60,50 100,90 140,50 180,90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><text x='90' y='40' font-size='11' text-anchor='middle' fill='#1a2b45'>tepe + tepe</text><polyline points='200,90 240,30 280,90' fill='none' stroke='#e0552b' stroke-width='3'/><text x='240' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>daha yüksek dalga</text></svg>","steps":[{"t":"İki tepe buluşur","a":"yükseklikler toplanır","d":"İki dalganın yüksek kısımları (tepeleri) aynı yere gelince yükseklikler toplanır."},{"t":"Sonuç","a":"daha büyük tepe","d":"Bu yüzden daha yüksek ve büyük bir dalga oluşur."}],"ans":"İki tepe üst üste gelince yükseklikleri toplanır ve daha büyük bir dalga oluşur."},{"q":"Şekildeki gibi bir tepe ile bir çukur üst üste gelirse ne olur?","fig":"<svg viewBox='0 0 320 180'><polyline points='20,90 50,55 80,90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><text x='50' y='45' font-size='10' text-anchor='middle' fill='#1a2b45'>tepe</text><polyline points='110,90 140,125 170,90' fill='none' stroke='#5b6b85' stroke-width='2.5'/><text x='140' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>çukur</text><line x1='200' y1='90' x2='300' y2='90' stroke='#e0552b' stroke-width='3'/><text x='250' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>düz su</text></svg>","steps":[{"t":"Tepe ve çukur buluşur","a":"birbirini götürür","d":"Bir dalganın yüksek kısmı, diğerinin alçak kısmıyla buluşunca birbirini yok eder."},{"t":"Sonuç","a":"su düzleşir","d":"O anda su neredeyse düz olur, dalga kaybolur gibi görünür."}],"ans":"Bir tepe ile bir çukur üst üste gelince birbirini yok eder ve su o anda düzleşir."},{"q":"İki dalga karşılaştıktan sonra birbirinden ayrılınca ne olur?","steps":[{"t":"Karşılaşma anı","a":"birlikte görünür","d":"İki dalga karşılaştığı anda tek dalga gibi görünür."},{"t":"Ayrılma","a":"eski hâline döner","d":"Ayrıldıktan sonra her dalga eski şekline dönüp yoluna devam eder."}],"ans":"İki dalga karşılaşıp ayrıldıktan sonra hiç değişmemiş gibi eski şekilleriyle yollarına devam eder."},{"q":"Bir göletteki iki taşı aynı anda atınca su yüzeyinde ne görürsün?","steps":[{"t":"İki halka","a":"iki dalga","d":"Her taş suda halka halka dalgalar oluşturur."},{"t":"Buluşma","a":"desen oluşur","d":"İki dalga halkası karşılaşınca yer yer büyük, yer yer küçük dalgalar olan bir desen görünür."}],"ans":"İki taş atınca dalgalar karşılaşır ve suda yer yer kabaran yer yer düzleşen bir desen oluşur."}],"zor":[{"q":"Şekildeki gibi iki dalganın tepeleri tam üst üste gelirse oluşan dalga neden daha büyük olur?","fig":"<svg viewBox='0 0 320 180'><polyline points='20,95 70,45 120,95' fill='none' stroke='#4aa3df' stroke-width='2.5'/><polyline points='20,95 70,55 120,95' fill='none' stroke='#7cc4ef' stroke-width='2' stroke-dasharray='3 2'/><text x='70' y='35' font-size='10' text-anchor='middle' fill='#1a2b45'>iki tepe</text><polyline points='180,95 240,25 300,95' fill='none' stroke='#e0552b' stroke-width='3'/><text x='240' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>toplam</text></svg>","steps":[{"t":"Yükseklikler eklenir","a":"toplama","d":"İki tepe aynı yerde olunca yükseklikleri birbirine eklenir."},{"t":"Daha yüksek dalga","a":"yapıcı girişim","d":"Toplam yükseklik arttığı için daha büyük bir dalga oluşur, buna yapıcı girişim denir."}],"ans":"İki tepe üst üste gelince yükseklikleri toplandığı için daha büyük dalga oluşur; bu olaya yapıcı girişim denir."},{"q":"İki dalga birbirini tam yok ederse buna ne ad verilir ve neden olur?","steps":[{"t":"Tepe + çukur","a":"zıt yönler","d":"Bir dalganın tepesi, diğerinin çukuruyla aynı yere gelirse zıt yönde itişirler."},{"t":"Yok olma","a":"yıkıcı girişim","d":"Yükseklik ve derinlik birbirini götürür, su düzleşir; buna yıkıcı girişim denir."}],"ans":"Tepe ile çukur üst üste gelip birbirini yok ederse buna yıkıcı girişim denir; çünkü zıt hareketler birbirini götürür."},{"q":"İki özdeş dalga aynı tepe ve çukurlarla yan yana yürürse hangi girişimi yapar?","steps":[{"t":"Tepeler aynı yerde","a":"birlikte yükselir","d":"İki dalganın tepeleri ve çukurları hep aynı anda aynı yerdedir."},{"t":"Sonuç","a":"yapıcı girişim","d":"Sürekli toplandıkları için daha büyük dalga oluşur, bu yapıcı girişimdir."}],"ans":"Tepe ve çukurları hep çakışan iki dalga sürekli toplanır; bu yüzden yapıcı girişim yaparlar."},{"q":"İki ipte oluşturulan zıt darbeler (biri yukarı, biri aşağı) karşılaşınca ne olur?","steps":[{"t":"Zıt darbeler","a":"yukarı + aşağı","d":"Biri ipi yukarı, diğeri aşağı iten iki darbe karşılaşır."},{"t":"Karşılaşma anı","a":"ip düzleşir","d":"Karşılaştıkları anda ip neredeyse düz olur, sonra darbeler ayrılıp devam eder."}],"ans":"Zıt yönlü iki darbe karşılaştığı anda ipi düzleştirir (yıkıcı girişim), sonra ayrılıp eski yönlerinde devam eder."},{"q":"Şekildeki desende su neden bazı yerlerde çok dalgalı, bazı yerlerde düz görünür?","fig":"<svg viewBox='0 0 320 180'><circle cx='90' cy='90' r='9' fill='#4aa3df' stroke='#1a2b45'/><circle cx='90' cy='90' r='28' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='90' cy='90' r='48' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='200' cy='90' r='9' fill='#4aa3df' stroke='#1a2b45'/><circle cx='200' cy='90' r='28' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='200' cy='90' r='48' fill='none' stroke='#4aa3df' stroke-width='1'/><text x='145' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>iki kaynak</text><text x='145' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>desen oluşur</text></svg>","steps":[{"t":"İki kaynak","a":"dalgalar karışır","d":"İki kaynaktan çıkan dalgalar suda her yerde karşılaşır."},{"t":"Toplanma / yok olma","a":"farklı bölgeler","d":"Bazı yerlerde tepeler toplanıp çok dalgalanır, bazı yerlerde tepe ile çukur birbirini götürüp düzleşir."}],"ans":"İki kaynağın dalgaları bazı yerlerde toplanıp suyu çok dalgalı yapar, bazı yerlerde birbirini yok edip düzleştirir; bu yüzden desen oluşur."}]},"ortaokul":{"kolay":[{"q":"Süperpozisyon (üst üste binme) ilkesi neyi söyler?","steps":[{"t":"Dalgalar buluşur","a":"toplanırlar","d":"Aynı noktada bulunan dalgaların etkileri o noktada toplanır."},{"t":"Toplam yer değiştirme","a":"ayrı ayrı eklenir","d":"Suyun veya ipin o noktadaki konumu, her dalganın etkisinin toplamına eşittir."}],"ans":"Süperpozisyon ilkesine göre bir noktada karşılaşan dalgaların yer değiştirmeleri toplanır; toplam dalga bu toplamla bulunur."},{"q":"Şekildeki gibi tepe ile tepe üst üste gelince oluşan girişimin adı nedir?","fig":"<svg viewBox='0 0 320 180'><polyline points='20,100 60,55 100,100 140,55 180,100' fill='none' stroke='#4aa3df' stroke-width='2'/><polyline points='20,100 60,60 100,100 140,60 180,100' fill='none' stroke='#7cc4ef' stroke-width='2' stroke-dasharray='3 2'/><text x='100' y='42' font-size='10' text-anchor='middle' fill='#1a2b45'>tepe+tepe</text><polyline points='210,100 250,25 290,100' fill='none' stroke='#e0552b' stroke-width='3'/><text x='250' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>genlik artar</text></svg>","steps":[{"t":"Aynı yönlü","a":"genlikler toplanır","d":"Tepe ile tepe aynı yöne baktığı için genlikleri (yükseklikleri) toplanır."},{"t":"Adı","a":"yapıcı girişim","d":"Genlik arttığı için bu olaya yapıcı girişim denir."}],"ans":"Tepe ile tepe üst üste gelince genlikler toplanır ve genliği büyük bir dalga oluşur; buna yapıcı girişim denir."},{"q":"Yıkıcı girişim ne zaman oluşur? Kısaca açıkla.","steps":[{"t":"Zıt yönler buluşur","a":"tepe ile çukur","d":"Bir dalganın tepesi diğerinin çukuruyla aynı yere geldiğinde oluşur."},{"t":"Genlik azalır","a":"sönümleme","d":"Yer değiştirmeler ters işaretli olduğu için toplam genlik azalır veya sıfırlanır."}],"ans":"Yıkıcı girişim, tepe ile çukur üst üste geldiğinde oluşur; ters yönlü yer değiştirmeler birbirini azaltır (sönümleme)."},{"q":"Yapıcı ve yıkıcı girişim arasındaki temel fark nedir?","steps":[{"t":"Yapıcı","a":"genlik artar","d":"Yapıcı girişimde dalgalar aynı yönlü olup genlikleri toplanır."},{"t":"Yıkıcı","a":"genlik azalır","d":"Yıkıcı girişimde dalgalar zıt yönlü olup genlikleri birbirini azaltır."}],"ans":"Yapıcı girişimde genlikler toplanıp büyür, yıkıcı girişimde ise zıt genlikler birbirini azaltır (söndürür)."},{"q":"İki kaynaktan çıkan özdeş dalgalar bir noktada hep tepe-tepe karşılaşıyorsa o noktada ne gözlenir?","steps":[{"t":"Tepe-tepe","a":"aynı anda yüksek","d":"İki dalga o noktaya hep tepeleriyle aynı anda ulaşır."},{"t":"Sonuç","a":"sürekli yapıcı","d":"Genlikler hep toplandığı için orada büyük genlikli güçlü titreşim olur."}],"ans":"O noktada dalgalar sürekli yapıcı girişim yapar; genlik en büyük değerini alır ve güçlü bir titreşim gözlenir."}],"zor":[{"q":"Genliği 3 cm olan iki dalga aynı noktada tepe-tepe karşılaşıyor. Oluşan dalganın genliği kaç cm olur?","steps":[{"t":"Girişim türü","a":"yapıcı","d":"Tepe-tepe karşılaşma yapıcı girişimdir, genlikler toplanır."},{"t":"Genlikleri topla","a":"3 cm + 3 cm","d":"İki genlik aynı yönlü olduğu için toplanır: 3 + 3 = 6 cm."}],"ans":"Yapıcı girişim olduğundan genlikler toplanır ve oluşan dalganın genliği 6 cm olur."},{"q":"Genliği 5 cm ve 5 cm olan iki dalga tepe-çukur (zıt) karşılaşırsa toplam genlik kaç cm olur?","steps":[{"t":"Girişim türü","a":"yıkıcı","d":"Tepe-çukur karşılaşma yıkıcı girişimdir, genlikler birbirini götürür."},{"t":"Farkı al","a":"5 cm − 5 cm","d":"Eşit ve zıt genlikler birbirini sıfırlar: 5 − 5 = 0 cm."}],"ans":"Yıkıcı girişimde eşit zıt genlikler birbirini götürür; toplam genlik 0 cm olur (su o noktada düzleşir)."},{"q":"Genliği 6 cm ve 4 cm olan iki dalga tepe-çukur karşılaşırsa oluşan dalganın genliği kaç cm olur?","steps":[{"t":"Zıt yönler","a":"genlik farkı","d":"Tepe-çukur karşılaşmada büyük genlikten küçük genlik çıkarılır."},{"t":"Hesap","a":"6 cm − 4 cm","d":"6 − 4 = 2 cm; sonuç büyük genliğin yönünde olur."}],"ans":"Yıkıcı girişim olduğundan genlik farkı alınır: 6 − 4 = 2 cm genlikli bir dalga oluşur."},{"q":"Şekildeki gibi iki kaynaklı su tankında bazı çizgilerde su hiç hareket etmiyor. Bu çizgiler ne ifade eder?","fig":"<svg viewBox='0 0 320 180'><circle cx='80' cy='90' r='7' fill='#4aa3df' stroke='#1a2b45'/><circle cx='80' cy='90' r='24' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='80' cy='90' r='44' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='180' cy='90' r='7' fill='#4aa3df' stroke='#1a2b45'/><circle cx='180' cy='90' r='24' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='180' cy='90' r='44' fill='none' stroke='#4aa3df' stroke-width='1'/><line x1='130' y1='20' x2='130' y2='160' stroke='#e0552b' stroke-width='2' stroke-dasharray='4 3'/><text x='250' y='95' font-size='10' fill='#1a2b45'>durgun çizgi</text></svg>","steps":[{"t":"Hareketsiz çizgi","a":"yıkıcı girişim","d":"Suyun hiç hareket etmediği çizgilerde tepe ile çukur hep karşılaşır."},{"t":"Adı","a":"düğüm çizgisi","d":"Genliğin sıfır olduğu bu hareketsiz çizgilere düğüm (sönümleme) çizgisi denir."}],"ans":"Suyun hiç hareket etmediği çizgiler yıkıcı girişimin olduğu düğüm çizgileridir; orada dalgalar birbirini söndürür."},{"q":"İki özdeş dalga kaynağının ürettiği dalgalar bir noktaya tam yarım dalga boyu farkla geliyor. O noktada hangi girişim olur?","steps":[{"t":"Yol farkı","a":"yarım dalga boyu","d":"Yarım dalga boyu fark, bir dalga tepeyle gelirken diğerinin çukurla gelmesi demektir."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Tepe ile çukur karşılaştığı için genlikler birbirini söndürür."}],"ans":"Yarım dalga boyu yol farkı tepe-çukur karşılaşması demektir; o noktada yıkıcı girişim olur ve genlik en küçük olur."}]},"lise":{"kolay":[{"q":"Süperpozisyon ilkesini ve girişim olayını tanımlayınız.","steps":[{"t":"Süperpozisyon","a":"yer değiştirmeler toplanır","d":"Aynı ortamda karşılaşan dalgaların bir noktadaki yer değiştirmeleri cebirsel olarak toplanır."},{"t":"Girişim","a":"bileşke dalga","d":"Bu toplanma sonucu bölgeye göre genliğin arttığı veya azaldığı bileşke dalga oluşur; bu olaya girişim denir."}],"ans":"Süperpozisyon ilkesine göre karşılaşan dalgaların yer değiştirmeleri toplanır; bunun sonucu genliğin yer yer arttığı veya azaldığı dalgaya girişim deseni denir."},{"q":"Şekildeki gibi aynı fazda (tepe-tepe) karşılaşan iki dalganın oluşturduğu girişimi açıklayınız.","fig":"<svg viewBox='0 0 320 180'><polyline points='20,100 60,55 100,100 140,55 180,100' fill='none' stroke='#4aa3df' stroke-width='2'/><polyline points='20,100 60,58 100,100 140,58 180,100' fill='none' stroke='#7cc4ef' stroke-width='2' stroke-dasharray='3 2'/><text x='100' y='42' font-size='10' text-anchor='middle' fill='#1a2b45'>aynı faz</text><polyline points='210,100 250,22 290,100' fill='none' stroke='#e0552b' stroke-width='3'/><text x='250' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>A=A₁+A₂</text></svg>","steps":[{"t":"Faz durumu","a":"aynı faz","d":"İki dalga aynı fazda olduğundan tepeleri ve çukurları çakışır."},{"t":"Genlik","a":"toplanır","d":"Bileşke genlik A = A₁ + A₂ olur; bu maksimum genliktir."}],"ans":"Aynı fazda karşılaşan dalgalarda yapıcı girişim olur; bileşke genlik A = A₁ + A₂ ile en büyük değerini alır."},{"q":"Şekildeki gibi zıt fazda (tepe-çukur) karşılaşan iki özdeş dalganın bileşkesini açıklayınız.","fig":"<svg viewBox='0 0 320 180'><polyline points='20,100 55,60 90,100 125,60 160,100' fill='none' stroke='#4aa3df' stroke-width='2'/><polyline points='20,100 55,140 90,100 125,140 160,100' fill='none' stroke='#5b6b85' stroke-width='2'/><text x='90' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>zıt faz</text><line x1='190' y1='100' x2='300' y2='100' stroke='#e0552b' stroke-width='3'/><text x='245' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>A=0</text></svg>","steps":[{"t":"Faz farkı","a":"180° (zıt faz)","d":"Dalgalar zıt fazda olduğundan birinin tepesi diğerinin çukuruyla çakışır."},{"t":"Genlik","a":"A₁ − A₂ = 0","d":"Genlikler eşit ve zıt olduğundan bileşke genlik sıfır olur; tam sönümleme görülür."}],"ans":"Zıt fazda karşılaşan eşit genlikli dalgalarda yıkıcı girişim olur; bileşke genlik A = A₁ − A₂ = 0 olur (tam sönümleme)."},{"q":"İki kaynaklı girişimde yapıcı girişim (maksimum) koşulunu yol farkıyla yazınız.","steps":[{"t":"Yol farkı","a":"Δx = nλ","d":"İki kaynaktan gelen dalgaların yol farkı dalga boyunun tam katıysa dalgalar aynı fazda ulaşır."},{"t":"Sonuç","a":"yapıcı girişim","d":"Tepe-tepe çakışma olduğundan genlik maksimumdur (n = 0, 1, 2, ...)."}],"ans":"Yapıcı girişim koşulu Δx = nλ'dır; yol farkı dalga boyunun tam katı olduğunda dalgalar aynı fazda gelir ve genlik maksimum olur."},{"q":"İki kaynaklı girişimde yıkıcı girişim (minimum) koşulunu yol farkıyla yazınız.","steps":[{"t":"Yol farkı","a":"Δx = (n + ½)λ","d":"Yol farkı dalga boyunun yarım tek katıysa dalgalar zıt fazda ulaşır."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Tepe-çukur çakışma olduğundan genlik minimumdur (n = 0, 1, 2, ...)."}],"ans":"Yıkıcı girişim koşulu Δx = (n + ½)λ'dır; yol farkı dalga boyunun yarım tek katı olduğunda dalgalar zıt fazda gelir ve genlik minimum (sıfır) olur."},{"q":"İki dalganın bir noktaya yol farkı Δx = 2λ ile ulaştığı biliniyor. O noktada hangi girişim oluşur?","steps":[{"t":"Koşulu kontrol et","a":"nλ biçiminde mi?","d":"Δx = 2λ, nλ biçimindedir (n = 2), yani tam katıdır."},{"t":"Sonuç","a":"yapıcı girişim","d":"Tam dalga boyu katı yol farkı dalgaları aynı fazda buluşturur."}],"ans":"Δx = 2λ = 2·λ tam katı olduğundan dalgalar aynı fazda gelir ve o noktada yapıcı girişim (maksimum) oluşur."},{"q":"Bir noktada iki dalga arasındaki yol farkı Δx = 1,5λ ise hangi girişim görülür?","steps":[{"t":"Koşulu kontrol et","a":"(n+½)λ biçiminde mi?","d":"1,5λ = (1 + ½)λ olduğundan yarım tek katı biçimindedir."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Yarım dalga boyu tek katı yol farkı dalgaları zıt fazda buluşturur."}],"ans":"Δx = 1,5λ = (1 + ½)λ olduğundan dalgalar zıt fazda gelir; o noktada yıkıcı girişim (minimum) görülür."},{"q":"Şekildeki iki kaynaklı su tankı deseninde maksimum ve minimum çizgilerini açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='90' cy='90' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='90' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>K1</text><circle cx='90' cy='90' r='22' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='90' cy='90' r='42' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='200' cy='90' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='200' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>K2</text><circle cx='200' cy='90' r='22' fill='none' stroke='#4aa3df' stroke-width='1'/><circle cx='200' cy='90' r='42' fill='none' stroke='#4aa3df' stroke-width='1'/><line x1='145' y1='25' x2='145' y2='155' stroke='#e0552b' stroke-width='2'/><text x='270' y='90' font-size='9' fill='#1a2b45'>maksimum</text></svg>","steps":[{"t":"Maksimum çizgi","a":"Δx = nλ","d":"Yol farkı tam dalga boyu katı olan noktalarda su en çok dalgalanır (yapıcı)."},{"t":"Minimum çizgi","a":"Δx = (n+½)λ","d":"Yol farkı yarım tek katı olan çizgilerde su hareketsizdir (yıkıcı, düğüm çizgisi)."}],"ans":"Maksimum (yapıcı) çizgilerde Δx = nλ olup su en çok dalgalanır; minimum (yıkıcı/düğüm) çizgilerde Δx = (n+½)λ olup su hareketsizdir."},{"q":"İki kaynak arasındaki tam ortada bulunan noktada her zaman hangi girişim görülür? Neden?","steps":[{"t":"Yol farkı","a":"Δx = 0","d":"Tam orta noktaya iki kaynaktan gelen dalgaların yolları eşittir, fark sıfırdır."},{"t":"Sonuç","a":"yapıcı girişim","d":"Δx = 0 = 0·λ olduğundan dalgalar aynı fazda buluşur, genlik maksimumdur."}],"ans":"İki özdeş kaynağın tam ortasında yol farkı sıfırdır (Δx = 0); dalgalar aynı fazda buluştuğundan her zaman yapıcı girişim (maksimum) görülür."},{"q":"Faz farkı ile yol farkı arasındaki ilişkiyi yazınız.","steps":[{"t":"Bir dalga boyu","a":"360° faz","d":"Bir dalga boyu λ kadar yol farkı 360° (2π) faz farkına karşılıktır."},{"t":"Orantı","a":"Δφ = (2π/λ)·Δx","d":"Faz farkı, yol farkıyla doğru orantılıdır: Δφ = (2π/λ)·Δx."}],"ans":"Faz farkı yol farkıyla orantılıdır: Δφ = (2π/λ)·Δx; bir dalga boyu yol farkı 360° (2π) faz farkına eşittir."},{"q":"İki dalga arasındaki faz farkı 180° ise oluşan girişim türünü ve nedenini açıklayınız.","steps":[{"t":"180° faz","a":"zıt faz","d":"180° faz farkı, birinin tepesi diğerinin çukuruna denk gelmesi demektir."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Zıt fazda yer değiştirmeler ters işaretli olduğundan genlik en küçük olur."}],"ans":"180° faz farkı zıt faz demektir; tepe ile çukur çakıştığından yıkıcı girişim oluşur ve eşit genliklerde bileşke sıfırlanır."},{"q":"Girişim olayının gözlenebilmesi için kaynakların hangi koşulu (uyumluluk) sağlaması gerekir?","steps":[{"t":"Koşul","a":"aynı frekans, sabit faz","d":"Kaynaklar aynı frekansta olmalı ve aralarındaki faz farkı zamanla değişmemelidir."},{"t":"Adı","a":"uyumlu (koherent) kaynak","d":"Bu koşulu sağlayan kaynaklara uyumlu kaynaklar denir; ancak böyle kaynaklarda kararlı desen görülür."}],"ans":"Kararlı girişim deseni için kaynaklar aynı frekanslı ve aralarındaki faz farkı sabit (uyumlu/koherent) olmalıdır; aksi hâlde desen kararlı kalmaz."},{"q":"Şekildeki gibi genlikleri eşit iki dalganın yapıcı girişiminde bileşke genlik tek bir dalganınkinin kaç katı olur?","fig":"<svg viewBox='0 0 320 180'><polyline points='20,95 55,60 90,95 125,60 160,95' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='90' y='48' font-size='10' text-anchor='middle' fill='#1a2b45'>A ve A</text><polyline points='190,95 230,25 270,95' fill='none' stroke='#e0552b' stroke-width='3'/><text x='245' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>2A</text></svg>","steps":[{"t":"Yapıcı girişim","a":"genlikler toplanır","d":"Aynı fazda eşit genlikli dalgaların genlikleri toplanır: A + A."},{"t":"Sonuç","a":"2A","d":"Bileşke genlik 2A olur, yani tek dalganın 2 katıdır."}],"ans":"Eşit genlikli (A) iki dalganın yapıcı girişiminde bileşke genlik 2A olur; tek dalganın genliğinin 2 katıdır."},{"q":"Dalga girişiminde enerji yok olmaz ilkesi yıkıcı girişimle nasıl bağdaşır?","steps":[{"t":"Düğümde enerji yok","a":"yer değiştirir","d":"Yıkıcı girişimin olduğu düğüm bölgelerinde genlik sıfırdır, ama enerji kaybolmaz."},{"t":"Karın bölgesine aktarılır","a":"korunum","d":"Düğümlerde azalan enerji, yapıcı girişimin olduğu karın bölgelerine aktarılır."}],"ans":"Yıkıcı girişimde enerji yok olmaz; düğüm bölgelerinde azalan enerji yapıcı girişimin olduğu karın bölgelerine aktarılarak toplam enerji korunur."},{"q":"İki kaynak arası uzaklık artırılırsa girişim deseninde maksimum (yapıcı) çizgilerin sıklığı nasıl değişir?","steps":[{"t":"Kaynak ayrımı artar","a":"yol farkı hızlı değişir","d":"Kaynaklar uzaklaştıkça gözlem doğrultusunda yol farkı daha hızlı değişir."},{"t":"Sonuç","a":"çizgiler sıklaşır","d":"Δx = nλ koşulu daha sık sağlandığından maksimum çizgiler birbirine yaklaşır."}],"ans":"Kaynaklar arası uzaklık arttıkça yol farkı daha hızlı değiştiğinden maksimum (yapıcı) çizgiler sıklaşır, birbirlerine yaklaşır."}],"zor":[{"q":"İki uyumlu kaynaktan çıkan dalgalar bir P noktasına sırasıyla 30 cm ve 42 cm yol alarak ulaşıyor. Dalga boyu λ = 4 cm ise P'de hangi girişim oluşur?","steps":[{"t":"Yol farkını bul","a":"Δx = 12 cm","d":"Yol farkı Δx = 42 − 30 = 12 cm'dir."},{"t":"λ cinsinden yaz","a":"Δx = 3λ","d":"12 / 4 = 3, yani Δx = 3λ; tam dalga boyu katıdır."},{"t":"Karar","a":"yapıcı girişim","d":"Δx = nλ (n = 3) koşulu sağlandığından dalgalar aynı fazda gelir."}],"ans":"Yol farkı Δx = 12 cm = 3λ (tam kat) olduğundan P noktasında yapıcı girişim (maksimum) oluşur."},{"q":"İki uyumlu kaynaktan bir noktaya gelen dalgaların yol farkı 18 cm, dalga boyu λ = 12 cm ise bu noktada hangi girişim görülür?","steps":[{"t":"λ cinsinden yaz","a":"Δx = 1,5λ","d":"18 / 12 = 1,5, yani Δx = 1,5λ = (1 + ½)λ'dır."},{"t":"Koşulu belirle","a":"yarım tek katı","d":"Yol farkı yarım dalga boyunun tek katı olduğundan dalgalar zıt fazdadır."},{"t":"Karar","a":"yıkıcı girişim","d":"Δx = (n + ½)λ koşulu sağlandığı için genlik minimumdur."}],"ans":"Δx = 18 cm = 1,5λ = (1 + ½)λ olduğundan dalgalar zıt fazda gelir; bu noktada yıkıcı girişim (minimum) görülür."},{"q":"Şekildeki P noktasına iki kaynaktan gelen yollar r₁ = 25 cm, r₂ = 35 cm. Dalga boyu λ = 5 cm ise P'deki girişim türünü ve maksimum sıra numarasını bulunuz.","fig":"<svg viewBox='0 0 320 180'><circle cx='40' cy='130' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='40' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>K1</text><circle cx='40' cy='60' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='40' y='45' font-size='10' text-anchor='middle' fill='#1a2b45'>K2</text><circle cx='270' cy='95' r='6' fill='#e0552b'/><text x='270' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>P</text><line x1='47' y1='130' x2='264' y2='95' stroke='#1a2b45' stroke-width='1'/><text x='150' y='125' font-size='9' fill='#1a2b45'>r₁</text><line x1='47' y1='60' x2='264' y2='95' stroke='#1a2b45' stroke-width='1'/><text x='150' y='65' font-size='9' fill='#1a2b45'>r₂</text></svg>","steps":[{"t":"Yol farkı","a":"Δx = 10 cm","d":"Δx = r₂ − r₁ = 35 − 25 = 10 cm."},{"t":"λ cinsinden","a":"Δx = 2λ","d":"10 / 5 = 2, yani Δx = 2λ; tam katı olduğundan yapıcıdır."},{"t":"Sıra numarası","a":"n = 2","d":"Δx = nλ'da n = 2 olduğundan bu 2. dereceden (2. sıra) maksimumdur."}],"ans":"Yol farkı Δx = 10 cm = 2λ olduğundan P'de yapıcı girişim oluşur ve bu 2. sıra (n = 2) maksimumdur."},{"q":"İki kaynak aynı fazda titreşmiyor; aralarında 180° (yarım dalga boyu) faz farkı var. Tam ortadaki noktada hangi girişim oluşur?","steps":[{"t":"Geometrik yol farkı","a":"Δx = 0","d":"Orta noktaya iki kaynaktan gelen yollar eşit olduğundan geometrik yol farkı sıfırdır."},{"t":"Kaynak faz farkını ekle","a":"½λ ek fark","d":"Kaynaklar 180° (½λ) faz farklıysa etkin fark ½λ olur."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Etkin yol farkı (n + ½)λ biçiminde olduğundan zıt faz; genlik minimumdur."}],"ans":"Kaynaklar 180° faz farklıyken geometrik yol farkı sıfır olsa da etkin fark ½λ olur; orta noktada yıkıcı girişim (minimum) görülür."},{"q":"Şekildeki gibi genlikleri 4 cm ve 3 cm olan iki dalga aynı fazda (tepe-tepe) bir noktada karşılaşıyor. Bileşke genliği bulunuz ve girişim türünü belirtiniz.","fig":"<svg viewBox='0 0 320 180'><polyline points='20,100 55,55 90,100 125,55 160,100' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='90' y='42' font-size='10' text-anchor='middle' fill='#1a2b45'>A₁=4 cm</text><polyline points='20,100 55,68 90,100 125,68 160,100' fill='none' stroke='#7cc4ef' stroke-width='2' stroke-dasharray='3 2'/><text x='90' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>A₂=3 cm</text><polyline points='195,100 240,30 285,100' fill='none' stroke='#e0552b' stroke-width='3'/><text x='240' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>A=?</text></svg>","steps":[{"t":"Faz durumu","a":"aynı faz","d":"Tepe-tepe karşılaşma aynı faz demektir, genlikler toplanır."},{"t":"Genlikleri topla","a":"4 + 3","d":"Bileşke genlik A = A₁ + A₂ = 4 + 3 = 7 cm."},{"t":"Tür","a":"yapıcı girişim","d":"Genlik tek dalgadan büyük olduğundan yapıcı girişimdir."}],"ans":"Aynı fazda olduklarından genlikler toplanır: A = 4 + 3 = 7 cm; bu bir yapıcı girişimdir."},{"q":"Genlikleri 7 cm ve 3 cm olan iki dalga zıt fazda (tepe-çukur) karşılaşıyor. Bileşke genliği ve girişim türünü bulunuz.","steps":[{"t":"Faz durumu","a":"zıt faz","d":"Tepe-çukur karşılaşma zıt faz demektir, genlikler ters işaretli toplanır."},{"t":"Farkı al","a":"7 − 3","d":"Bileşke genlik |A₁ − A₂| = |7 − 3| = 4 cm olur."},{"t":"Tür","a":"yıkıcı girişim","d":"Genlik tek dalgadan küçük olduğundan yıkıcı girişimdir (kısmi sönümleme)."}],"ans":"Zıt fazda olduklarından genlik farkı alınır: A = 7 − 3 = 4 cm; bu kısmi yıkıcı girişimdir."},{"q":"Bir noktada arka arkaya maksimum gözlenen iki yol farkı değeri Δx = 8 cm ve Δx = 12 cm ise dalga boyunu bulunuz.","steps":[{"t":"Maksimum koşulu","a":"Δx = nλ","d":"Ardışık maksimumlar nλ ve (n+1)λ değerlerine karşılık gelir."},{"t":"Fark al","a":"12 − 8 = 4 cm","d":"Ardışık maksimumların yol farkı tam bir dalga boyudur."},{"t":"Sonuç","a":"λ = 4 cm","d":"Bu fark λ'ya eşit olduğundan dalga boyu 4 cm'dir."}],"ans":"Ardışık maksimumların yol farkı bir dalga boyuna eşittir: λ = 12 − 8 = 4 cm."},{"q":"İki uyumlu kaynaktan çıkan dalgalar bir noktaya 0,40 m ve 0,55 m yol alarak geliyor. λ = 0,10 m ise hangi girişim oluşur ve neden?","steps":[{"t":"Yol farkı","a":"Δx = 0,15 m","d":"Δx = 0,55 − 0,40 = 0,15 m."},{"t":"λ cinsinden","a":"Δx = 1,5λ","d":"0,15 / 0,10 = 1,5, yani Δx = (1 + ½)λ."},{"t":"Karar","a":"yıkıcı girişim","d":"Yarım dalga boyu tek katı olduğundan dalgalar zıt fazda gelir."}],"ans":"Δx = 0,15 m = 1,5λ = (1 + ½)λ olduğundan dalgalar zıt fazda buluşur; o noktada yıkıcı girişim (minimum) oluşur."},{"q":"Şekildeki iki kaynaklı desende merkez doğrusundan dışarı doğru sırasıyla maksimum, minimum, maksimum çizgileri görülüyor. Bu sıralamanın yol farkı değerlerini açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='110' cy='130' r='6' fill='#4aa3df' stroke='#1a2b45'/><text x='110' y='152' font-size='10' text-anchor='middle' fill='#1a2b45'>K1</text><circle cx='210' cy='130' r='6' fill='#4aa3df' stroke='#1a2b45'/><text x='210' y='152' font-size='10' text-anchor='middle' fill='#1a2b45'>K2</text><line x1='160' y1='130' x2='160' y2='15' stroke='#e0552b' stroke-width='2'/><text x='160' y='12' font-size='9' text-anchor='middle' fill='#1a2b45'>maks(0)</text><line x1='160' y1='130' x2='95' y2='25' stroke='#5b6b85' stroke-width='1.5' stroke-dasharray='4 3'/><text x='80' y='22' font-size='9' fill='#1a2b45'>min</text><line x1='160' y1='130' x2='55' y2='60' stroke='#e0552b' stroke-width='1.5'/><text x='40' y='58' font-size='9' fill='#1a2b45'>maks(1)</text></svg>","steps":[{"t":"Merkez çizgi","a":"Δx = 0 (maksimum)","d":"Tam ortadaki çizgide yol farkı sıfırdır, sıfırıncı maksimumdur."},{"t":"İlk minimum","a":"Δx = ½λ","d":"Merkezden dışa ilk düğüm çizgisinde yol farkı yarım dalga boyudur."},{"t":"İlk yan maksimum","a":"Δx = λ","d":"Bir sonraki maksimum çizgide yol farkı tam bir dalga boyudur."}],"ans":"Merkezden dışa doğru yol farkları 0 (maksimum), ½λ (minimum), λ (1. maksimum) biçiminde artar; maksimumlar nλ'da, minimumlar (n+½)λ'da oluşur."},{"q":"İki dalga genliği A olan eşit dalgalar arasında 90° faz farkı varsa bileşke genliğin tek dalgadan büyük mü küçük mü olduğunu niteliksel açıklayınız.","steps":[{"t":"Ne tam yapıcı ne yıkıcı","a":"ara durum","d":"90° faz farkı, ne 0° (tam yapıcı) ne 180° (tam yıkıcı) olan bir ara durumdur."},{"t":"Bileşke","a":"A√2 ≈ 1,41A","d":"Vektörel toplamada dik bileşenler toplanır; bileşke genlik A√2 olur."},{"t":"Karar","a":"tek dalgadan büyük","d":"A√2 ≈ 1,41A olduğundan bileşke tek dalgadan büyük ama 2A'dan küçüktür."}],"ans":"90° faz farkında bileşke genlik A√2 ≈ 1,41A olur; tek dalganın genliğinden büyük fakat tam yapıcı durumun (2A) altındadır."},{"q":"Bir su tankında frekans artırılırsa (dalga boyu azalır) girişim desenindeki düğüm çizgilerinin sayısı nasıl değişir?","steps":[{"t":"Dalga boyu azalır","a":"λ küçülür","d":"Frekans artınca v sabitken λ = v/f azalır."},{"t":"Koşulları sık sağlar","a":"daha çok (n+½)λ","d":"λ küçüldüğünde (n+½)λ koşulu daha küçük yol farklarında, daha sık sağlanır."},{"t":"Sonuç","a":"düğüm çizgileri artar","d":"Aynı bölgede daha çok düğüm çizgisi oluşur, desen sıklaşır."}],"ans":"Frekans artınca dalga boyu küçülür; (n+½)λ koşulu daha sık sağlandığından düğüm (minimum) çizgilerinin sayısı artar ve desen sıklaşır."},{"q":"Şekildeki gibi bir noktaya iki kaynaktan gelen dalgalardan biri λ/2 yol farkıyla, biri de kaynakta λ/2 faz farkıyla geliyor. Bu noktada hangi girişim oluşur?","fig":"<svg viewBox='0 0 320 180'><circle cx='40' cy='55' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='40' y='40' font-size='9' text-anchor='middle' fill='#1a2b45'>K1</text><circle cx='40' cy='130' r='7' fill='#4aa3df' stroke='#1a2b45'/><text x='40' y='152' font-size='9' text-anchor='middle' fill='#1a2b45'>K2</text><text x='40' y='95' font-size='9' text-anchor='middle' fill='#e0552b'>faz ½λ</text><circle cx='270' cy='92' r='6' fill='#e0552b'/><text x='270' y='78' font-size='9' text-anchor='middle' fill='#1a2b45'>P</text><line x1='47' y1='55' x2='264' y2='92' stroke='#1a2b45' stroke-width='1'/><line x1='47' y1='130' x2='264' y2='92' stroke='#1a2b45' stroke-width='1'/></svg>","steps":[{"t":"Yol farkı katkısı","a":"½λ","d":"Geometrik yol farkı λ/2 tek başına yıkıcı (zıt faz) eğilimindedir."},{"t":"Kaynak faz farkı katkısı","a":"½λ","d":"Kaynaktaki ½λ (180°) faz farkı bir ½λ daha ekler."},{"t":"Toplam etki","a":"λ → aynı faz","d":"İki ½λ toplanır: ½λ + ½λ = λ, yani etkin fark tam dalga boyu olur, dalgalar aynı fazdadır."}],"ans":"Yol farkından ½λ ve kaynak faz farkından ½λ toplanınca etkin fark λ (tam kat) olur; dalgalar aynı fazda buluşur ve P'de yapıcı girişim oluşur."},{"q":"İki uyumlu kaynaktan gelen dalgaların bir noktadaki yol farkı 25 cm ölçülüyor. Bu noktada yıkıcı girişim gözlendiğine göre olası en büyük dalga boyu kaç cm'dir?","steps":[{"t":"Yıkıcı koşulu","a":"Δx = (n+½)λ","d":"Yıkıcı girişim için 25 = (n + ½)λ olmalıdır."},{"t":"En büyük λ için en küçük n","a":"n = 0","d":"λ'yı büyütmek için en küçük n = 0 seçilir: 25 = ½λ."},{"t":"Çöz","a":"λ = 50 cm","d":"½λ = 25 ⇒ λ = 50 cm bulunur."}],"ans":"Yıkıcı koşulu 25 = (n+½)λ'da en küçük n = 0 alınınca ½λ = 25, yani olası en büyük dalga boyu λ = 50 cm olur."},{"q":"Genlikleri eşit iki dalganın yapıcı girişiminde şiddet (enerji) tek dalganınkinin kaç katı olur? (Şiddet genliğin karesiyle orantılıdır.)","steps":[{"t":"Bileşke genlik","a":"2A","d":"Yapıcı girişimde eşit genlikli dalgaların bileşkesi 2A olur."},{"t":"Şiddet ilişkisi","a":"I ∝ A²","d":"Şiddet genliğin karesiyle orantılıdır, I ∝ A²."},{"t":"Oran","a":"(2A)²/A² = 4","d":"Bileşke şiddet (2A)² = 4A²'ye orantılı; tek dalganın 4 katıdır."}],"ans":"Bileşke genlik 2A olduğundan ve I ∝ A² olduğundan yapıcı girişimde şiddet tek dalganınkinin 4 katı olur."},{"q":"İki uyumlu kaynaktan bir P noktasına gelen yolların farkı Δx = 21 cm. P noktasında 3. dereceden (n = 3) yıkıcı girişim gözlendiğine göre dalga boyunu bulunuz.","steps":[{"t":"Yıkıcı koşulu","a":"Δx = (n+½)λ","d":"Yıkıcı girişim için yol farkı (n + ½)λ biçimindedir."},{"t":"n = 3 yerleştir","a":"21 = 3,5λ","d":"3. dereceden minimumda n = 3 olduğundan Δx = (3 + ½)λ = 3,5λ olur: 21 = 3,5λ."},{"t":"Çöz","a":"λ = 6 cm","d":"λ = 21 / 3,5 = 6 cm bulunur."}],"ans":"Yıkıcı koşulu 21 = (3 + ½)λ = 3,5λ'dan λ = 21 / 3,5 = 6 cm bulunur."}]}},"kirilma":{"ilkokul":{"kolay":[{"q":"Bir kalemi su dolu bardağa daldırınca kalem suyun yüzeyinde neden kırık gibi görünür?","fig":"<svg viewBox='0 0 320 180'><rect x='40' y='90' width='240' height='70' fill='#4aa3df'/><text x='160' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>su</text><line x1='160' y1='20' x2='160' y2='90' stroke='#5b6b85' stroke-width='6'/><line x1='160' y1='90' x2='130' y2='150' stroke='#5b6b85' stroke-width='6'/><text x='200' y='60' font-size='11' fill='#1a2b45'>kalem</text><line x1='40' y1='90' x2='280' y2='90' stroke='#1a2b45' stroke-width='1'/></svg>","steps":[{"t":"Işık ortam değiştirir","a":"hava → su","d":"Işık havadan suya geçerken yön değiştirir, buna kırılma denir."},{"t":"Göze etkisi","a":"kırık görünür","d":"Yön değiştiren ışık yüzünden kalem suyun yüzeyinde kırılmış gibi görünür."}],"ans":"Işık sudan çıkarken yön değiştirdiği için kalem kırık gibi görünür."},{"q":"Su dolu bir havuzun dibi neden olduğundan daha sığ (yakın) görünür?","steps":[{"t":"Işık sudan çıkar","a":"yön değiştirir","d":"Dipten gelen ışık sudan havaya çıkarken kırılarak yön değiştirir."},{"t":"Göze etkisi","a":"daha yakın","d":"Gözümüz ışığı düz geldi sanır, bu yüzden dip daha yakın görünür."}],"ans":"Işık su yüzeyinde kırıldığı için havuzun dibi olduğundan daha sığ görünür."},{"q":"Işık havadan suya geçerken hızı artar mı azalır mı?","steps":[{"t":"Su daha yoğun","a":"su engelli","d":"Su, havaya göre daha yoğun bir ortamdır ve ışığı yavaşlatır."},{"t":"Hıza etkisi","a":"yavaşlar","d":"Bu yüzden ışık havadan suya geçerken hızı azalır."}],"ans":"Işık havadan suya geçince hızı azalır, yani yavaşlar."},{"q":"Bir bardak suyun arkasındaki yazılar neden bazen büyümüş ya da kaymış görünür?","steps":[{"t":"Işık bükülür","a":"kırılma","d":"Yazıdan gelen ışık bardaktaki sudan geçerken kırılıp yön değiştirir."},{"t":"Göze etkisi","a":"kayar/büyür","d":"Yön değiştiren ışık yazıları kaymış ya da büyümüş gibi gösterir."}],"ans":"Işık sudan geçerken kırıldığı için yazılar kaymış ya da büyümüş görünür."},{"q":"Bir tabak suya batırılmış bozuk parayı, dışarıdan baktığımızda neden tam yerinde göremeyiz?","steps":[{"t":"Işık sudan çıkar","a":"kırılır","d":"Paradan gelen ışık sudan havaya çıkarken kırılıp yön değiştirir."},{"t":"Göze etkisi","a":"yer kayar","d":"Gözümüz ışığın geldiği yöne bakar, bu yüzden para biraz kaymış görünür."}],"ans":"Işık su yüzeyinde kırıldığı için para olduğu yerden biraz kaymış görünür."}],"zor":[{"q":"Su dolu bir bardağa daldırılan pipet yüzeyde kırık görünürken, aynı pipeti boş bardakta neden düz görürüz?","fig":"<svg viewBox='0 0 320 180'><rect x='30' y='95' width='110' height='60' fill='#4aa3df'/><text x='85' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>su</text><line x1='85' y1='30' x2='85' y2='95' stroke='#5b6b85' stroke-width='5'/><line x1='85' y1='95' x2='65' y2='150' stroke='#5b6b85' stroke-width='5'/><rect x='190' y='95' width='100' height='60' fill='none' stroke='#1a2b45' stroke-width='1'/><text x='240' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>boş</text><line x1='240' y1='30' x2='240' y2='150' stroke='#5b6b85' stroke-width='5'/></svg>","steps":[{"t":"Suda kırılma var","a":"ışık bükülür","d":"Sulu bardakta ışık sudan havaya geçerken kırılır ve pipet kırık görünür."},{"t":"Boş bardakta yok","a":"tek ortam","d":"Boş bardakta ışık hep havada gider, ortam değişmediği için kırılma olmaz."}],"ans":"Suda ışık kırıldığı için pipet kırık görünür; boş bardakta ortam değişmediğinden düz görünür."},{"q":"Bir balıkçı suyun içinde gördüğü balığa zıpkın atarken neden balığın biraz altına nişan alması gerekir?","steps":[{"t":"Balığın ışığı kırılır","a":"yukarı kayar","d":"Balıktan gelen ışık sudan çıkarken kırıldığı için balık olduğundan daha yukarıda görünür."},{"t":"Nişan düzeltmesi","a":"biraz aşağı","d":"Gerçek balık göründüğü yerden biraz aşağıda olduğu için altına nişan alınır."}],"ans":"Işık kırılınca balık olduğundan yukarıda göründüğü için balıkçı biraz altına nişan almalıdır."},{"q":"Işık camdan tekrar havaya çıkarken hızı nasıl değişir, neden?","steps":[{"t":"Cam yoğun ortam","a":"cam yavaşlatır","d":"Camda ışık havadakinden daha yavaş gider, çünkü cam daha yoğundur."},{"t":"Havaya çıkış","a":"hızlanır","d":"Daha az yoğun olan havaya geçince ışık tekrar hızlanır."}],"ans":"Işık camdan havaya çıkarken hızlanır, çünkü hava camdan daha az yoğundur."},{"q":"Kırılma sırasında ışığın rengi (titreşim sayısı) değişir mi?","steps":[{"t":"Frekans korunur","a":"renk aynı","d":"Işık ortam değiştirse de saniyedeki titreşim sayısı (frekansı) değişmez."},{"t":"Sonuç","a":"renk değişmez","d":"Frekans aynı kaldığı için ışığın rengi de aynı kalır."}],"ans":"Kırılmada ışığın frekansı korunduğu için rengi değişmez."},{"q":"Sıcak yaz gününde asfalt yolun uzağında neden su birikmiş gibi parıltı görünür?","steps":[{"t":"Hava katmanları farklı","a":"sıcak-soğuk hava","d":"Asfalta yakın hava çok sıcak, üstteki hava daha serindir; ışık bu katmanlarda kırılır."},{"t":"Göze etkisi","a":"yansıma/su gibi","d":"Kırılan gökyüzü ışığı, yolda su birikmiş gibi parıltılı görünür."}],"ans":"Sıcak ve serin hava katmanlarında ışık kırıldığı için asfaltta su varmış gibi parıltı görünür."}]},"ortaokul":{"kolay":[{"q":"Su dalgası derin bölgeden sığ bölgeye geçince hızı ve dalga boyu nasıl değişir?","fig":"<svg viewBox='0 0 320 160'><rect x='20' y='40' width='130' height='100' fill='#4aa3df'/><rect x='150' y='40' width='150' height='100' fill='#8ecbf0'/><text x='85' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>derin</text><text x='225' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>sığ</text><line x1='40' y1='40' x2='40' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='75' y1='40' x2='75' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='110' y1='40' x2='110' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='170' y1='40' x2='170' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='190' y1='40' x2='190' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='210' y1='40' x2='210' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='150' stroke='#e0552b' stroke-width='1' stroke-dasharray='4 3'/></svg>","steps":[{"t":"Sığ ortam","a":"hız azalır","d":"Su dalgası sığ bölgede daha yavaş ilerler, yani hızı azalır."},{"t":"Dalga boyu","a":"kısalır","d":"Frekans değişmediği için hız azalınca dalga boyu da kısalır."}],"ans":"Sığ bölgeye geçen su dalgasının hem hızı hem dalga boyu azalır; frekans değişmez."},{"q":"Kırılma olayında frekansın değişmediğini nasıl açıklarsın?","steps":[{"t":"Kaynak belirler","a":"frekans kaynaktan","d":"Dalganın frekansı onu üreten kaynağa bağlıdır, ortam değiştirmez."},{"t":"Sınırda süreklilik","a":"aynı sayıda dalga","d":"Birim zamanda sınıra gelen dalga sayısı, çıkan dalga sayısına eşit olmalıdır."}],"ans":"Frekans kaynak tarafından belirlendiği için kırılmada değişmez; hız ve dalga boyu değişir."},{"q":"Bir dalga hızı azalarak ortam değiştirince, gelen dalga ile normal arasındaki açı nasıl değişir?","fig":"<svg viewBox='0 0 320 180'><rect x='20' y='90' width='280' height='70' fill='#8ecbf0'/><rect x='20' y='30' width='280' height='60' fill='#f5f7fa'/><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='80' y1='40' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><polygon points='160,90 150,80 158,76' fill='#e0552b'/><text x='95' y='55' font-size='11' fill='#1a2b45'>gelen</text><line x1='160' y1='90' x2='205' y2='150' stroke='#e0552b' stroke-width='2'/><text x='210' y='140' font-size='11' fill='#1a2b45'>kırılan</text></svg>","steps":[{"t":"Hız azalır","a":"yavaş ortam","d":"Dalga daha yavaş bir ortama geçtiğinde normale doğru kırılır."},{"t":"Açıya etkisi","a":"açı küçülür","d":"Kırılma açısı, gelme açısından daha küçük olur."}],"ans":"Hız azalınca dalga normale yaklaşır, yani kırılma açısı gelme açısından küçük olur."},{"q":"Bir dalganın bir ortamdaki hızı 6 m/s, diğer ortamdaki hızı 3 m/s ise dalga boyları oranı kaçtır?","steps":[{"t":"Bağıntıyı yaz","a":"v₁/v₂ = λ₁/λ₂","d":"Frekans sabit olduğu için hızların oranı dalga boylarının oranına eşittir."},{"t":"Yerine koy","a":"6 ÷ 3","d":"Birinci ortam hızını ikinciye bölünce 6 ÷ 3 = 2 bulunur."}],"ans":"Dalga boyları oranı λ₁/λ₂ = 2'dir; birinci ortamdaki dalga boyu ikincinin 2 katıdır."},{"q":"Işık havadan cama geçerken yön değiştirir; bu olayın adı nedir ve nedeni nedir?","steps":[{"t":"Olayın adı","a":"kırılma","d":"Işığın ortam değiştirirken yön değiştirmesine kırılma denir."},{"t":"Nedeni","a":"hız değişimi","d":"Işığın hızı camda farklı olduğu için yön değiştirir."}],"ans":"Olayın adı kırılmadır; nedeni ışığın iki ortamdaki hızlarının farklı olmasıdır."}],"zor":[{"q":"Su dalgası sığ bölgeden derin bölgeye geçiyor. Hızı, dalga boyu ve normalle açısı nasıl değişir?","fig":"<svg viewBox='0 0 320 160'><rect x='20' y='40' width='130' height='100' fill='#8ecbf0'/><rect x='150' y='40' width='150' height='100' fill='#4aa3df'/><text x='85' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>sığ</text><text x='225' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>derin</text><line x1='150' y1='30' x2='150' y2='150' stroke='#e0552b' stroke-width='1' stroke-dasharray='4 3'/><line x1='50' y1='40' x2='50' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='75' y1='40' x2='75' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='100' y1='40' x2='100' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='180' y1='40' x2='180' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='220' y1='40' x2='220' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='260' y1='40' x2='260' y2='140' stroke='#1a2b45' stroke-width='2'/></svg>","steps":[{"t":"Derin ortam","a":"hız artar","d":"Su dalgası derin bölgede daha hızlı ilerler."},{"t":"Dalga boyu","a":"uzar","d":"Frekans sabitken hız arttığı için dalga boyu uzar."},{"t":"Açı","a":"normalden uzaklaşır","d":"Hız arttığı için dalga normalden uzaklaşır, kırılma açısı büyür."}],"ans":"Derin bölgede hız artar, dalga boyu uzar ve dalga normalden uzaklaşır; frekans değişmez."},{"q":"Bir dalganın birinci ortamdaki dalga boyu 8 cm, ikincide 2 cm. Birinci ortam hızı 12 m/s ise ikinci ortamdaki hızı bulunuz.","steps":[{"t":"Bağıntıyı yaz","a":"v₁/v₂ = λ₁/λ₂","d":"Frekans sabit olduğu için hızların oranı dalga boylarının oranına eşittir."},{"t":"Oranı kur","a":"12/v₂ = 8/2","d":"Bilinen değerleri yerine koyarız: λ₁=8 cm, λ₂=2 cm."},{"t":"Çöz","a":"v₂ = 12 × 2 ÷ 8","d":"İçler dışlar çarpımından v₂ = 24 ÷ 8 = 3 m/s bulunur."}],"ans":"İkinci ortamdaki hız 3 m/s'dir."},{"q":"Bir dalga normale doğru kırılıyorsa hangi ortamdan hangi ortama geçtiği hakkında ne söylenir?","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='70' y1='35' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='80' y='50' font-size='11' fill='#1a2b45'>gelen</text><line x1='160' y1='90' x2='195' y2='155' stroke='#e0552b' stroke-width='2'/><polygon points='195,155 184,148 192,143' fill='#e0552b'/><text x='200' y='145' font-size='11' fill='#1a2b45'>kırılan</text><text x='40' y='80' font-size='10' fill='#1a2b45'>hızlı</text><text x='40' y='110' font-size='10' fill='#1a2b45'>yavaş</text></svg>","steps":[{"t":"Normale yaklaşma","a":"açı küçülür","d":"Kırılan dalga normale yaklaşmışsa kırılma açısı gelme açısından küçüktür."},{"t":"Hıza yorum","a":"hız azaldı","d":"Açının küçülmesi dalganın yavaşladığını, yani daha yoğun (yavaş) ortama geçtiğini gösterir."}],"ans":"Dalga normale yaklaşıyorsa hızı azalmıştır; hızlı ortamdan yavaş ortama geçmiştir."},{"q":"Bir su dalgasının frekansı 5 Hz, derin ortamdaki dalga boyu 4 cm. Sığ ortamda dalga boyu 2 cm olduğunda her iki ortamdaki hızları bulunuz.","steps":[{"t":"Derin ortam hızı","a":"v = f × λ","d":"Hız = frekans × dalga boyu = 5 Hz × 4 cm = 20 cm/s'dir."},{"t":"Sığ ortam hızı","a":"5 × 2","d":"Frekans sabit kalır; sığ ortamda v = 5 Hz × 2 cm = 10 cm/s'dir."},{"t":"Karşılaştır","a":"20 ve 10 cm/s","d":"Sığ ortamda hız yarıya inmiştir, çünkü dalga boyu yarıya inmiştir."}],"ans":"Derin ortamda hız 20 cm/s, sığ ortamda 10 cm/s'dir."},{"q":"İki ortamın sınırına dik (normal boyunca) gelen bir dalga neden yön değiştirmeden geçer?","steps":[{"t":"Gelme açısı sıfır","a":"açı = 0","d":"Dalga sınıra dik geldiğinde normalle yaptığı açı sıfırdır."},{"t":"Kırılma açısı","a":"yine 0","d":"Açı sıfır olunca kırılma açısı da sıfır olur, yön değişmez."}],"ans":"Normal boyunca gelen dalganın gelme açısı sıfır olduğu için yön değiştirmeden geçer; yalnızca hızı ve dalga boyu değişir."}]},"lise":{"kolay":[{"q":"Kırılma olayında korunan büyüklük hangisidir ve neden?","steps":[{"t":"Frekans korunur","a":"f sabit","d":"Dalganın frekansı kaynağa bağlıdır ve ortam değiştirirken değişmez."},{"t":"Diğerleri değişir","a":"v ve λ değişir","d":"v = f·λ olduğundan frekans sabitken hız değişince dalga boyu da değişir."}],"ans":"Kırılmada frekans korunur; hız ve dalga boyu ortama göre değişir."},{"q":"Bir dalganın birinci ortamdaki hızı 10 m/s, ikincideki hızı 4 m/s ise λ₁/λ₂ oranını bulunuz.","steps":[{"t":"Bağıntı","a":"v₁/v₂ = λ₁/λ₂","d":"Frekans sabit olduğu için hız oranı dalga boyu oranına eşittir."},{"t":"Yerine koy","a":"10 ÷ 4","d":"Hızları orana koyarız: 10 m/s ve 4 m/s."},{"t":"Sonuç","a":"2,5","d":"Bölme sonucu λ₁/λ₂ = 2,5 bulunur."}],"ans":"λ₁/λ₂ oranı 2,5'tir."},{"q":"Şekildeki dalga hızlı ortamdan yavaş ortama geçiyor. Kırılma açısının gelme açısına göre durumunu açıklayınız.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='70' y1='30' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='80' y='48' font-size='11' fill='#1a2b45'>gelen</text><line x1='160' y1='90' x2='200' y2='155' stroke='#e0552b' stroke-width='2'/><polygon points='200,155 189,148 197,143' fill='#e0552b'/><text x='205' y='145' font-size='11' fill='#1a2b45'>kırılan</text><text x='30' y='75' font-size='10' fill='#1a2b45'>hızlı</text><text x='30' y='115' font-size='10' fill='#1a2b45'>yavaş</text></svg>","steps":[{"t":"Hız azalır","a":"yavaş ortam","d":"Dalga yavaş ortama geçtiğinde hızı azalır."},{"t":"Açıya etkisi","a":"normale yaklaşır","d":"Hız azaldığı için dalga normale yaklaşır, kırılma açısı küçülür."}],"ans":"Hızlı ortamdan yavaş ortama geçen dalga normale yaklaşır; kırılma açısı gelme açısından küçüktür."},{"q":"Snell bağıntısının dalga hızlarıyla yazılışı nasıldır?","steps":[{"t":"Açı-hız ilişkisi","a":"sin oranı = hız oranı","d":"Gelme açısının sinüsünün kırılma açısının sinüsüne oranı, hızların oranına eşittir."},{"t":"Bağıntı","a":"sinθ₁/sinθ₂ = v₁/v₂","d":"Bu da aynı zamanda dalga boyları oranı λ₁/λ₂'ye eşittir."}],"ans":"Snell bağıntısı sinθ₁/sinθ₂ = v₁/v₂ = λ₁/λ₂ biçiminde yazılır."},{"q":"Bir dalganın frekansı 50 Hz, birinci ortamdaki dalga boyu 0,4 m. Bu ortamdaki hızını bulunuz.","steps":[{"t":"Bağıntı","a":"v = f × λ","d":"Dalga hızı, frekans ile dalga boyunun çarpımıdır."},{"t":"Yerine koy","a":"50 × 0,4","d":"f = 50 Hz ve λ = 0,4 m değerlerini yerine koyarız."},{"t":"Sonuç","a":"20 m/s","d":"Çarpım sonucu 20 m/s bulunur."}],"ans":"Dalganın birinci ortamdaki hızı 20 m/s'dir."},{"q":"Su dalgalarında derinlik artarsa hız nasıl etkilenir ve bu kırılmayı nasıl belirler?","fig":"<svg viewBox='0 0 320 150'><rect x='20' y='30' width='130' height='110' fill='#8ecbf0'/><rect x='150' y='30' width='150' height='110' fill='#4aa3df'/><text x='85' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>az derin</text><text x='225' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>çok derin</text><line x1='150' y1='20' x2='150' y2='145' stroke='#e0552b' stroke-width='1' stroke-dasharray='4 3'/><text x='85' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>yavaş</text><text x='225' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>hızlı</text></svg>","steps":[{"t":"Derinlik-hız","a":"derinlik artınca hız artar","d":"Su dalgalarında derinlik arttıkça dalga hızı artar."},{"t":"Kırılmaya etki","a":"yön belirler","d":"Hız değişimi kırılmayı doğurur; hız artarsa dalga normalden uzaklaşır."}],"ans":"Su dalgasında derinlik artınca hız artar; hız arttığı için dalga normalden uzaklaşarak kırılır."},{"q":"Birinci ortamdaki dalga boyu 6 cm, ikincideki 9 cm. λ₁/λ₂ oranını ve hangi ortamda hızın büyük olduğunu bulunuz.","steps":[{"t":"Oranı yaz","a":"λ₁/λ₂ = 6/9","d":"Dalga boylarını orana koyarız ve sadeleştiririz."},{"t":"Sadeleştir","a":"2/3","d":"6 ÷ 9 sadeleşince 2/3 ≈ 0,67 bulunur."},{"t":"Hız yorumu","a":"ikinci ortam hızlı","d":"v₁/v₂ = λ₁/λ₂ olduğundan dalga boyu büyük olan ikinci ortamda hız daha büyüktür."}],"ans":"λ₁/λ₂ = 2/3'tür; dalga boyu daha büyük olduğu için ikinci ortamda hız daha büyüktür."},{"q":"Kırılma sırasında v, λ ve f büyüklüklerinden hangileri değişir, hangisi sabittir?","steps":[{"t":"Sabit olan","a":"frekans","d":"Frekans kaynağa bağlı olduğu için kırılmada değişmez."},{"t":"Değişenler","a":"hız ve dalga boyu","d":"v = f·λ bağıntısı gereği f sabitken hız değişince dalga boyu da değişir."}],"ans":"Kırılmada frekans sabittir; hız ve dalga boyu değişir."},{"q":"Bir dalga sınıra normalle 0° açıyla (dik) gelirse kırılma sonrası ne olur?","steps":[{"t":"Gelme açısı","a":"0°","d":"Dalga sınıra dik geldiğinde normalle yaptığı açı sıfırdır."},{"t":"Sonuç","a":"yön değişmez","d":"Kırılma açısı da sıfır olur; yalnızca hız ve dalga boyu değişir, doğrultu aynı kalır."}],"ans":"Dik gelen dalga yön değiştirmeden geçer; sadece hızı ve dalga boyu değişir."},{"q":"v₁/v₂ = λ₁/λ₂ bağıntısı kırılmada hangi temel ilkeden türetilir?","steps":[{"t":"Temel bağıntı","a":"v = f·λ","d":"Her ortamda dalga hızı, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Frekans sabit","a":"f kısalır","d":"İki ortamda f aynı olduğundan v₁ = f·λ₁ ve v₂ = f·λ₂ oranlanınca f sadeleşir."}],"ans":"Bağıntı, her ortamda v = f·λ olması ve frekansın sabit kalması ilkesinden türetilir; oranlanınca f sadeleşir."},{"q":"Bir dalga birinci ortamda 15 m/s ile yayılıyor. İkinci ortamda dalga boyu yarıya iniyorsa ikinci ortamdaki hızı bulunuz.","steps":[{"t":"Dalga boyu oranı","a":"λ₂ = λ₁/2","d":"Dalga boyu yarıya indiğinden λ₁/λ₂ = 2'dir."},{"t":"Hız oranına geç","a":"v₁/v₂ = λ₁/λ₂","d":"Hız oranı dalga boyu oranına eşittir, yani v₁/v₂ = 2'dir."},{"t":"Çöz","a":"v₂ = 15/2","d":"İkinci ortam hızı = 15 ÷ 2 = 7,5 m/s bulunur."}],"ans":"İkinci ortamdaki hız 7,5 m/s'dir."},{"q":"Gelme açısı 30°, kırılma açısı 30°'den küçükse hangi ortamda dalga daha hızlı yayılır?","steps":[{"t":"Açı yorumu","a":"normale yaklaşmış","d":"Kırılma açısı gelme açısından küçükse dalga normale yaklaşmıştır."},{"t":"Hız yorumu","a":"ikinci ortam yavaş","d":"Normale yaklaşma hızın azaldığını gösterir; ikinci ortam daha yavaştır."}],"ans":"Dalga ilk (gelinen) ortamda daha hızlı yayılır; ikinci ortamda yavaşlamıştır."},{"q":"Su dalgası derin ortamda 24 cm/s, sığ ortamda 16 cm/s ile yayılıyor. Dalga boyları oranını bulunuz.","steps":[{"t":"Bağıntı","a":"v₁/v₂ = λ₁/λ₂","d":"Frekans sabit olduğu için hız oranı dalga boyu oranına eşittir."},{"t":"Yerine koy","a":"24 ÷ 16","d":"Derin ve sığ ortam hızlarını orana koyarız."},{"t":"Sonuç","a":"3/2 = 1,5","d":"Bölme sonucu λ(derin)/λ(sığ) = 1,5 bulunur."}],"ans":"Dalga boyları oranı 1,5'tir; derin ortamdaki dalga boyu sığdakinin 1,5 katıdır."},{"q":"Şekilde gelen ve kırılan dalga gösterilmiştir. Dalga boylarının değişiminden ortamların hızları hakkında ne söylenir?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='85' x2='300' y2='85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='15' x2='160' y2='155' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='26' font-size='11' fill='#1a2b45'>normal</text><line x1='60' y1='25' x2='160' y2='85' stroke='#e0552b' stroke-width='2'/><polygon points='160,85 149,79 156,73' fill='#e0552b'/><text x='70' y='42' font-size='10' fill='#1a2b45'>geniş λ₁</text><line x1='160' y1='85' x2='220' y2='150' stroke='#e0552b' stroke-width='2'/><polygon points='220,150 209,144 217,138' fill='#e0552b'/><text x='205' y='135' font-size='10' fill='#1a2b45'>dar λ₂</text></svg>","steps":[{"t":"Dalga boyu küçülmüş","a":"λ₂ < λ₁","d":"Kırılan dalganın dalga boyu daha küçükse ikinci ortamda dalga boyu kısalmıştır."},{"t":"Hıza yorum","a":"v₂ < v₁","d":"v₁/v₂ = λ₁/λ₂ olduğundan dalga boyu küçülünce hız da azalmıştır."}],"ans":"Dalga boyu küçüldüğü için ikinci ortamda hız da küçüktür; dalga yavaş ortama geçmiştir."},{"q":"Bir ortamda dalga boyu 5 cm, frekans 8 Hz. Diğer ortamda dalga boyu 10 cm ise frekans kaç Hz olur?","steps":[{"t":"Frekans korunur","a":"f değişmez","d":"Kırılmada frekans kaynağa bağlı olduğu için ortam değiştirse de değişmez."},{"t":"Sonuç","a":"8 Hz","d":"Dalga boyu değişse de frekans her iki ortamda aynı, yani 8 Hz kalır."}],"ans":"Frekans her iki ortamda da 8 Hz'tir; kırılmada frekans değişmez."}],"zor":[{"q":"Bir su dalgasının derin ortamdaki hızı 30 cm/s, dalga boyu 6 cm. Sığ ortamda dalga boyu 4 cm ölçülüyor. Sığ ortamdaki hızı bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v/λ","d":"Derin ortamda f = 30 ÷ 6 = 5 Hz'tir; frekans her iki ortamda aynıdır."},{"t":"Sığ ortam hızı","a":"v = f × λ","d":"Sığ ortamda v = 5 Hz × 4 cm hesaplanır."},{"t":"Sonuç","a":"20 cm/s","d":"Çarpım sonucu sığ ortam hızı 20 cm/s bulunur."}],"ans":"Sığ ortamdaki hız 20 cm/s'dir."},{"q":"Gelme açısı 60°, kırılma açısı 30°. Birinci ortamdaki hız 8 m/s ise ikinci ortamdaki hızı bulunuz. (sin60° = 0,87 ; sin30° = 0,5)","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='65' y1='35' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='72' y='52' font-size='11' fill='#1a2b45'>60°</text><line x1='160' y1='90' x2='200' y2='155' stroke='#e0552b' stroke-width='2'/><polygon points='200,155 189,148 197,143' fill='#e0552b'/><text x='168' y='130' font-size='11' fill='#1a2b45'>30°</text></svg>","steps":[{"t":"Snell bağıntısı","a":"sinθ₁/sinθ₂ = v₁/v₂","d":"Gelme ve kırılma açılarının sinüs oranı, hızların oranına eşittir."},{"t":"Yerine koy","a":"0,87/0,5 = 8/v₂","d":"sin60° = 0,87, sin30° = 0,5 ve v₁ = 8 m/s değerlerini koyarız."},{"t":"Çöz","a":"v₂ = 8 × 0,5 ÷ 0,87","d":"İçler dışlar çarpımından v₂ ≈ 4,6 m/s bulunur."}],"ans":"İkinci ortamdaki hız yaklaşık 4,6 m/s'dir."},{"q":"Bir dalganın λ₁ = 12 cm, λ₂ = 8 cm. Birinci ortamda hız 60 cm/s ise frekansı ve ikinci ortamdaki hızı bulunuz.","steps":[{"t":"Frekansı bul","a":"f = v₁/λ₁","d":"Frekans = 60 ÷ 12 = 5 Hz'tir; her iki ortamda aynıdır."},{"t":"İkinci hızı bul","a":"v₂ = f × λ₂","d":"İkinci ortam hızı = 5 Hz × 8 cm = 40 cm/s'dir."},{"t":"Kontrol","a":"v₁/v₂ = λ₁/λ₂","d":"60/40 = 12/8 = 1,5 olarak bağıntıyı doğrular."}],"ans":"Frekans 5 Hz, ikinci ortamdaki hız 40 cm/s'dir."},{"q":"Gelme açısı 45°, ikinci ortamda dalga normale yaklaşarak 30° ile kırılıyor. λ₁/λ₂ oranını bulunuz. (sin45° = 0,71 ; sin30° = 0,5)","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='80' y1='30' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='88' y='48' font-size='11' fill='#1a2b45'>45°</text><line x1='160' y1='90' x2='200' y2='150' stroke='#e0552b' stroke-width='2'/><polygon points='200,150 189,143 197,138' fill='#e0552b'/><text x='168' y='130' font-size='11' fill='#1a2b45'>30°</text></svg>","steps":[{"t":"Bağıntı","a":"λ₁/λ₂ = sinθ₁/sinθ₂","d":"Dalga boyu oranı, açıların sinüs oranına eşittir."},{"t":"Yerine koy","a":"0,71 ÷ 0,5","d":"sin45° = 0,71 ve sin30° = 0,5 değerlerini koyarız."},{"t":"Sonuç","a":"1,42","d":"Bölme sonucu λ₁/λ₂ ≈ 1,42 bulunur."}],"ans":"λ₁/λ₂ oranı yaklaşık 1,42'dir; birinci ortamdaki dalga boyu daha büyüktür."},{"q":"Frekansı 4 Hz olan su dalgası, derinliği farklı iki bölgeden geçiyor. Birinci bölgede dalga boyu 5 cm, ikincide 8 cm. Hangi bölge daha derindir ve hızlar nedir?","steps":[{"t":"Hızları hesapla","a":"v = f × λ","d":"Birinci: 4 × 5 = 20 cm/s; ikinci: 4 × 8 = 32 cm/s'dir."},{"t":"Derinlik yorumu","a":"hızlı = derin","d":"Su dalgasında hız büyükse derinlik fazladır; ikinci bölge daha hızlı, yani daha derindir."}],"ans":"İkinci bölge daha derindir; hızlar 20 cm/s ve 32 cm/s'dir."},{"q":"Bir dalga normalle 0° açıyla bir sınırdan geçiyor ve hızı 18 m/s'den 12 m/s'ye düşüyor. Kırılma açısını ve dalga boyu oranını açıklayınız.","steps":[{"t":"Açı durumu","a":"yön değişmez","d":"Dik gelen dalganın gelme açısı 0° olduğundan kırılma açısı da 0°'dir, doğrultu aynı kalır."},{"t":"Dalga boyu oranı","a":"λ₁/λ₂ = v₁/v₂","d":"Frekans sabit olduğu için dalga boyu oranı hız oranına eşittir: 18/12 = 1,5."},{"t":"Sonuç","a":"oran 1,5","d":"Hız azaldığı için dalga boyu da 1,5 kat küçülür ama yön değişmez."}],"ans":"Kırılma açısı 0°'dir (yön değişmez); dalga boyu oranı λ₁/λ₂ = 1,5'tir, dalga boyu küçülür."},{"q":"İki ortam sınırında gelme açısı 53°, kırılma açısı 37°. v₁ = 10 m/s ise v₂ ve λ₂/λ₁ oranını bulunuz. (sin53° = 0,8 ; sin37° = 0,6)","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='62' y1='40' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='70' y='56' font-size='11' fill='#1a2b45'>53°</text><line x1='160' y1='90' x2='205' y2='148' stroke='#e0552b' stroke-width='2'/><polygon points='205,148 194,141 202,136' fill='#e0552b'/><text x='168' y='128' font-size='11' fill='#1a2b45'>37°</text></svg>","steps":[{"t":"Hızı bul","a":"v₂ = v₁ × sinθ₂/sinθ₁","d":"Snell'den v₂ = 10 × 0,6 ÷ 0,8 = 7,5 m/s'dir."},{"t":"Dalga boyu oranı","a":"λ₂/λ₁ = v₂/v₁","d":"Frekans sabit; λ₂/λ₁ = 7,5/10 = 0,75'tir."},{"t":"Yorum","a":"normale yaklaştı","d":"v₂ < v₁ olduğu için dalga normale yaklaşmıştır."}],"ans":"İkinci ortamdaki hız 7,5 m/s, λ₂/λ₁ oranı 0,75'tir."},{"q":"Bir su dalgası sığ bölgeden derine geçerken dalga boyu %50 artıyor. Sığ ortamdaki hız 12 cm/s ise derin ortamdaki hızı bulunuz.","steps":[{"t":"Dalga boyu oranı","a":"λ(derin) = 1,5 × λ(sığ)","d":"%50 artış, dalga boyunun 1,5 katına çıkması demektir."},{"t":"Hız oranı","a":"v oranı = λ oranı","d":"Frekans sabit olduğundan hız oranı da 1,5'tir."},{"t":"Çöz","a":"12 × 1,5","d":"Derin ortam hızı = 12 cm/s × 1,5 = 18 cm/s'dir."}],"ans":"Derin ortamdaki hız 18 cm/s'dir."},{"q":"Gelme açısı kırılma açısına eşit çıkıyorsa iki ortam için ne söylenir?","steps":[{"t":"Açı eşitliği","a":"θ₁ = θ₂","d":"Gelme ve kırılma açıları eşitse sinüsleri de eşittir."},{"t":"Hız sonucu","a":"v₁ = v₂","d":"sinθ₁/sinθ₂ = v₁/v₂ = 1 olduğundan iki ortamdaki hızlar eşittir."},{"t":"Yorum","a":"kırılma yok","d":"Hızlar eşit olduğu için dalga gerçekte yön değiştirmez."}],"ans":"Açılar eşitse iki ortamdaki hızlar (ve dalga boyları) eşittir; dalga yön değiştirmeden geçer."},{"q":"Bir dalga birinci ortamda 200 m'de 50 dalga, ikinci ortamda 200 m'de 80 dalga içeriyor. Birinci ortamda hız 40 m/s ise frekansı ve ikinci ortam hızını bulunuz.","steps":[{"t":"Dalga boylarını bul","a":"λ = uzunluk/sayı","d":"λ₁ = 200 ÷ 50 = 4 m; λ₂ = 200 ÷ 80 = 2,5 m'dir."},{"t":"Frekansı bul","a":"f = v₁/λ₁","d":"Frekans = 40 ÷ 4 = 10 Hz'tir; her iki ortamda aynıdır."},{"t":"İkinci hız","a":"v₂ = f × λ₂","d":"v₂ = 10 Hz × 2,5 m = 25 m/s bulunur."}],"ans":"Frekans 10 Hz, ikinci ortamdaki hız 25 m/s'dir."},{"q":"Şekildeki dalga ikinci ortamda normalden uzaklaşarak kırılıyor. Hız ve dalga boyu değişimini gerekçesiyle açıklayınız.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='160' y2='160' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5 4'/><text x='168' y='30' font-size='11' fill='#1a2b45'>normal</text><line x1='95' y1='40' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><text x='100' y='56' font-size='11' fill='#1a2b45'>gelen</text><line x1='160' y1='90' x2='240' y2='140' stroke='#e0552b' stroke-width='2'/><polygon points='240,140 228,137 233,130' fill='#e0552b'/><text x='220' y='130' font-size='11' fill='#1a2b45'>kırılan</text></svg>","steps":[{"t":"Açı durumu","a":"açı büyüdü","d":"Kırılan dalga normalden uzaklaşmışsa kırılma açısı gelme açısından büyüktür."},{"t":"Hıza yorum","a":"hız arttı","d":"Açının büyümesi dalganın hızlandığını, daha az yoğun (hızlı) ortama geçtiğini gösterir."},{"t":"Dalga boyu","a":"uzar","d":"Frekans sabitken hız arttığı için dalga boyu da uzar."}],"ans":"Dalga normalden uzaklaşıyorsa hızı artmıştır ve dalga boyu uzamıştır; frekans değişmez."},{"q":"v₁/v₂ = 5/3 olan iki ortamda birinci ortamdaki dalga boyu 15 cm ise ikinci ortamdaki dalga boyunu bulunuz.","steps":[{"t":"Bağıntı","a":"v₁/v₂ = λ₁/λ₂","d":"Frekans sabit olduğu için hız oranı dalga boyu oranına eşittir."},{"t":"Oranı kur","a":"5/3 = 15/λ₂","d":"v oranını ve λ₁ = 15 cm değerini yerine koyarız."},{"t":"Çöz","a":"λ₂ = 15 × 3 ÷ 5","d":"İçler dışlar çarpımından λ₂ = 45 ÷ 5 = 9 cm bulunur."}],"ans":"İkinci ortamdaki dalga boyu 9 cm'dir."},{"q":"Bir su dalgası derin bölgede 36 cm/s, sığ bölgede 27 cm/s ile yayılıyor. Gelme açısı 60° ise kırılma açısının sinüsünü bulunuz. (sin60° = 0,87)","steps":[{"t":"Snell bağıntısı","a":"sinθ₁/sinθ₂ = v₁/v₂","d":"Açıların sinüs oranı, hızların oranına eşittir."},{"t":"Düzenle","a":"sinθ₂ = sinθ₁ × v₂/v₁","d":"sinθ₂ = 0,87 × 27 ÷ 36 hesaplanır."},{"t":"Sonuç","a":"0,65","d":"Çarpım ve bölme sonucu sinθ₂ ≈ 0,65 bulunur."}],"ans":"Kırılma açısının sinüsü yaklaşık 0,65'tir; dalga sığ (yavaş) ortamda normale yaklaşmıştır."},{"q":"Bir dalganın iki ortamdaki periyotları karşılaştırıldığında ne bulunur, neden?","steps":[{"t":"Periyot-frekans","a":"T = 1/f","d":"Periyot, frekansın tersidir."},{"t":"Frekans sabit","a":"T de sabit","d":"Kırılmada frekans değişmediği için periyot da iki ortamda aynı kalır."}],"ans":"İki ortamdaki periyotlar eşittir; çünkü kırılmada frekans değişmez, periyot da değişmez."},{"q":"İki ortam sınırında dalga boyu 8 cm'den 6 cm'ye düşüyor. Birinci ortamdaki periyot 0,2 s ise her iki ortamdaki hızları bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 1/T","d":"Frekans = 1 ÷ 0,2 = 5 Hz'tir; her iki ortamda aynıdır."},{"t":"Birinci hız","a":"v₁ = f × λ₁","d":"v₁ = 5 Hz × 8 cm = 40 cm/s'dir."},{"t":"İkinci hız","a":"v₂ = f × λ₂","d":"v₂ = 5 Hz × 6 cm = 30 cm/s'dir."}],"ans":"Birinci ortamda hız 40 cm/s, ikinci ortamda 30 cm/s'dir; dalga yavaşlamıştır."}]}},"kirinim":{"ilkokul":{"kolay":[{"q":"Bir kapı aralığından gelen sesi, kapının yan tarafında durduğumuz hâlde nasıl duyabiliriz?","steps":[{"t":"Ses dalgası yayılır","a":"her yöne","d":"Ses, kapı aralığından geçtikten sonra yalnız düz gitmez, kenarlardan bükülerek de yayılır."},{"t":"Sonuç","a":"bükülerek gelir","d":"Bu bükülme sayesinde kapının yanında olsak bile sesi duyabiliriz."}],"ans":"Ses kapı aralığından geçince kenarlardan bükülerek yayıldığı için yandan da duyulur."},{"q":"Şekildeki gibi dar bir aralıktan geçen su dalgaları aralıktan sonra nasıl davranır?","fig":"<svg viewBox='0 0 320 160'><line x1='150' y1='10' x2='150' y2='62' stroke='#1a2b45' stroke-width='5'/><line x1='150' y1='98' x2='150' y2='150' stroke='#1a2b45' stroke-width='5'/><text x='90' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>Aralık</text><line x1='30' y1='30' x2='30' y2='130' stroke='#4aa3df' stroke-width='2'/><line x1='55' y1='30' x2='55' y2='130' stroke='#4aa3df' stroke-width='2'/><line x1='80' y1='30' x2='80' y2='130' stroke='#4aa3df' stroke-width='2'/><path d='M 200 80 A 50 50 0 0 1 250 30' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 200 80 A 50 50 0 0 0 250 130' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 220 80 A 70 70 0 0 1 285 35' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 220 80 A 70 70 0 0 0 285 125' fill='none' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Aralıktan geçer","a":"daralır","d":"Düz gelen su dalgaları dar aralıktan geçer."},{"t":"Sonuç","a":"yayılır (bükülür)","d":"Aralıktan sonra dalgalar yelpaze gibi açılıp her yöne <b>bükülür</b>."}],"ans":"Dalgalar dar aralıktan geçtikten sonra yelpaze gibi açılıp bükülerek yayılır."},{"q":"Bir köşenin arkasında saklanan arkadaşımız bizi görmese de sesimizi duyabilir. Bunun nedeni nedir?","steps":[{"t":"Ses köşeden döner","a":"bükülür","d":"Ses dalgaları köşe kenarından bükülüp arkaya doğru yayılabilir."},{"t":"Sonuç","a":"duyulur","d":"Bu yüzden köşenin arkasındaki arkadaşımız sesimizi duyar."}],"ans":"Ses köşe kenarından bükülerek arkaya yayıldığı için köşe arkasındaki kişi sesi duyar."},{"q":"Denizde dalgalar dar bir liman ağzından geçince liman içine doğru nasıl yayılır?","steps":[{"t":"Dar ağızdan geçer","a":"sıkışır","d":"Dalgalar limanın dar girişinden geçer."},{"t":"Sonuç","a":"içeri yayılır","d":"Girişten sonra dalgalar açılıp limanın içine doğru <b>bükülerek</b> yayılır."}],"ans":"Dalgalar dar liman ağzından geçtikten sonra açılıp liman içine bükülerek yayılır."},{"q":"Dalgaların bir engelin kenarından bükülerek arkaya yayılmasına ne ad verilir?","steps":[{"t":"Bükülme olayı","a":"kırınım","d":"Dalganın engel kenarından ya da dar aralıktan bükülmesine <b>kırınım</b> denir."},{"t":"Sonuç","a":"kırınım","d":"Bu olay sayesinde dalga engelin arkasına da ulaşabilir."}],"ans":"Bu olaya kırınım denir."}],"zor":[{"q":"Şekilde geniş bir aralıktan ve dar bir aralıktan geçen dalgalar gösterilmiştir. Hangisinde dalgalar daha çok bükülür?","fig":"<svg viewBox='0 0 320 170'><text x='80' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>Geniş aralık</text><line x1='80' y1='22' x2='80' y2='45' stroke='#1a2b45' stroke-width='4'/><line x1='80' y1='95' x2='80' y2='118' stroke='#1a2b45' stroke-width='4'/><line x1='95' y1='70' x2='150' y2='70' stroke='#4aa3df' stroke-width='2'/><line x1='95' y1='58' x2='150' y2='58' stroke='#4aa3df' stroke-width='2'/><line x1='95' y1='82' x2='150' y2='82' stroke='#4aa3df' stroke-width='2'/><text x='250' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>Dar aralık</text><line x1='250' y1='22' x2='250' y2='58' stroke='#1a2b45' stroke-width='4'/><line x1='250' y1='82' x2='250' y2='118' stroke='#1a2b45' stroke-width='4'/><path d='M 262 70 A 35 35 0 0 1 297 35' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 262 70 A 35 35 0 0 0 297 105' fill='none' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Geniş aralık","a":"az bükülür","d":"Geniş aralıktan geçen dalga çoğunlukla düz devam eder, kenarlarda az bükülür."},{"t":"Dar aralık","a":"çok bükülür","d":"Dar aralıktan geçen dalga yelpaze gibi açılır, çok daha fazla <b>bükülür</b>."},{"t":"Sonuç","a":"dar aralık","d":"Aralık daraldıkça kırınım (bükülme) daha belirgin olur."}],"ans":"Dar aralıkta dalgalar daha çok bükülür; aralık daraldıkça kırınım belirginleşir."},{"q":"Bir odada yüksek sesle müzik açıldığında, kapı açık olduğunda komşu odadan müziği neden duyabiliriz?","steps":[{"t":"Ses kapıdan geçer","a":"aralık","d":"Ses dalgaları açık kapı aralığından komşu odaya geçer."},{"t":"Kenardan bükülür","a":"kırınım","d":"Aralıktan geçen ses kenarlarda bükülerek odanın her yerine yayılır."},{"t":"Sonuç","a":"her yerde duyulur","d":"Bu kırınım sayesinde kapının tam karşısında olmasak da müziği duyarız."}],"ans":"Ses açık kapıdan geçip kenarlardan bükülerek (kırınarak) yayıldığı için komşu odanın her yerinde duyulur."},{"q":"Küçük bir taş havuza atıldığında oluşan dalgalar, su içindeki bir kazığın arkasına ulaşır mı?","steps":[{"t":"Dalga kazığa çarpar","a":"engel","d":"Halka dalgalar yayılırken su içindeki kazık (engel) önüne gelir."},{"t":"Kenardan bükülür","a":"kırınım","d":"Dalganın bir kısmı kazığın kenarından bükülüp arkaya geçer."},{"t":"Sonuç","a":"ulaşır","d":"Bu kırınım sayesinde dalga kazığın arkasına da ulaşabilir."}],"ans":"Evet; dalgalar kazığın kenarından bükülerek (kırınarak) arkasına da ulaşır."},{"q":"Ses dalgaları köşelerden rahatça bükülürken ışığın köşe arkasını aydınlatmaması neyi gösterir?","steps":[{"t":"Ses bükülür","a":"dalga boyu büyük","d":"Sesin dalga boyu büyük (kapı genişliğine yakın) olduğu için köşeden kolayca bükülür."},{"t":"Işık bükülmez gibi","a":"dalga boyu çok küçük","d":"Işığın dalga boyu çok küçük olduğundan köşeden gözle görülür biçimde bükülmez."},{"t":"Sonuç","a":"orana bağlı","d":"Kırınımın belirginliği, dalga boyunun engel/aralık boyutuna oranına bağlıdır."}],"ans":"Kırınımın belirginliği dalga boyuna bağlıdır; sesin dalga boyu büyük olduğu için bükülür, ışığınki çok küçük olduğu için belirgin bükülmez."},{"q":"Sis düdüğünün (gemi düdüğü) sesinin alçak (kalın) seçilmesinin, sesin uzaklara ve engel arkasına ulaşmasıyla ilgisi nedir?","steps":[{"t":"Alçak ses","a":"uzun dalga boyu","d":"Alçak (kalın) sesin dalga boyu uzundur."},{"t":"Uzun dalga boyu","a":"daha çok bükülür","d":"Dalga boyu büyük olan ses, engellerin ve kayalıkların kenarından daha kolay bükülür."},{"t":"Sonuç","a":"uzağa ulaşır","d":"Bu yüzden alçak ses engel arkasındaki gemilere de daha iyi ulaşır."}],"ans":"Alçak sesin dalga boyu uzun olduğundan engel kenarlarından daha çok bükülür ve engel arkasına daha iyi ulaşır."}]},"ortaokul":{"kolay":[{"q":"Kırınım olayını tanımlayınız.","steps":[{"t":"Olay","a":"bükülme","d":"Dalganın bir engel kenarından ya da dar bir aralıktan geçerken bükülerek yayılmasıdır."},{"t":"Sonuç","a":"kırınım","d":"Bu sayede dalga, engelin arkasındaki gölge bölgesine de ulaşabilir."}],"ans":"Kırınım, dalganın engel kenarından veya dar aralıktan geçerken bükülerek yayılmasıdır."},{"q":"Şekildeki gibi dar bir yarıktan geçen düz su dalgaları yarıktan sonra hangi biçimi alır?","fig":"<svg viewBox='0 0 320 160'><line x1='150' y1='10' x2='150' y2='68' stroke='#1a2b45' stroke-width='5'/><line x1='150' y1='92' x2='150' y2='150' stroke='#1a2b45' stroke-width='5'/><line x1='30' y1='25' x2='30' y2='135' stroke='#4aa3df' stroke-width='2'/><line x1='52' y1='25' x2='52' y2='135' stroke='#4aa3df' stroke-width='2'/><line x1='74' y1='25' x2='74' y2='135' stroke='#4aa3df' stroke-width='2'/><text x='80' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>düz dalga</text><path d='M 195 80 A 45 45 0 0 1 240 35' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 195 80 A 45 45 0 0 0 240 125' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 215 80 A 65 65 0 0 1 280 40' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 215 80 A 65 65 0 0 0 280 120' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='250' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>dairesel dalga</text></svg>","steps":[{"t":"Yarığa kadar","a":"düz cephe","d":"Yarığa gelen dalga cepheleri düz (doğrusal) çizgiler hâlindedir."},{"t":"Yarıktan sonra","a":"dairesel cephe","d":"Dar yarıktan geçtikten sonra dalga cepheleri dairesel (yarım daire) biçimde açılarak yayılır."}],"ans":"Düz dalga cepheleri dar yarıktan geçtikten sonra dairesel biçimde açılarak (bükülerek) yayılır."},{"q":"Kırınımın belirginliği hangi iki büyüklüğün oranına bağlıdır?","steps":[{"t":"Etkenler","a":"dalga boyu ve aralık","d":"Kırınımın belirginliği dalganın dalga boyu (λ) ile aralık/engel genişliğine bağlıdır."},{"t":"Sonuç","a":"λ ⁄ aralık oranı","d":"Dalga boyu, aralık genişliğine yaklaştıkça kırınım daha belirgin olur."}],"ans":"Kırınımın belirginliği, dalga boyunun aralık (ya da engel) genişliğine oranına bağlıdır."},{"q":"Bir dalganın dar yarıkta belirgin kırınım yapması için dalga boyu ile yarık genişliği nasıl olmalıdır?","steps":[{"t":"Koşul","a":"λ ≈ yarık","d":"Dalga boyu yarık genişliğine yaklaşık eşit ya da ondan büyük olmalıdır."},{"t":"Sonuç","a":"belirgin kırınım","d":"Bu durumda dalga yarıktan geçince geniş biçimde açılır, kırınım belirgin görülür."}],"ans":"Dalga boyu yarık genişliğine eşit veya ondan büyük olduğunda kırınım belirgin olur."},{"q":"Sesi köşe arkasından duyabilmemizin nedeni hangi dalga olayıdır?","steps":[{"t":"Olay","a":"kırınım","d":"Ses dalgaları köşe (engel) kenarından bükülerek arkaya yayılır; bu olay kırınımdır."},{"t":"Sonuç","a":"köşeden duyulur","d":"Kırınım sayesinde sesi göremesek de köşe arkasından duyabiliriz."}],"ans":"Sesi köşe arkasından duymamızı sağlayan dalga olayı kırınımdır."}],"zor":[{"q":"Aynı yarıktan önce uzun dalga boylu, sonra kısa dalga boylu bir dalga geçiriliyor. Hangisinde kırınım daha belirgindir?","steps":[{"t":"Uzun dalga boyu","a":"yarığa yakın","d":"Uzun dalga boyu, yarık genişliğine daha yakın olduğundan dalga yarıktan geçince çok açılır."},{"t":"Kısa dalga boyu","a":"yarıktan küçük","d":"Kısa dalga boyu yarıktan çok küçük kalınca dalga az açılır, çoğunlukla düz devam eder."},{"t":"Sonuç","a":"uzun dalga boyu","d":"Kırınım, dalga boyu yarık genişliğine yaklaştıkça (uzun dalga boyunda) daha belirgindir."}],"ans":"Uzun dalga boylu dalgada kırınım daha belirgindir; çünkü dalga boyu yarık genişliğine daha yakındır."},{"q":"Bir dalga leğeninde (ripple tank) yarık genişliği yavaşça daraltılırsa yarıktan çıkan dalgaların açılma miktarı nasıl değişir?","steps":[{"t":"Geniş yarık","a":"az açılma","d":"Yarık genişken dalga çoğunlukla düz geçer, kenarlarda az bükülür."},{"t":"Yarık daralınca","a":"çok açılma","d":"Yarık daraldıkça dalga boyuna yaklaşır ve çıkan dalga daha geniş açıyla yayılır."},{"t":"Sonuç","a":"açılma artar","d":"Yani yarık daraldıkça kırınım belirginleşir, dalgalar daha çok açılır."}],"ans":"Yarık daraldıkça dalgaların açılması (kırınım) artar; çünkü yarık dalga boyuna yaklaşır."},{"q":"Radyo dalgaları dağların ve binaların arkasındaki evlere ulaşırken, görünür ışık bu engellerin arkasını aydınlatamaz. Bu farkın nedeni nedir?","steps":[{"t":"Radyo dalgası","a":"çok uzun dalga boyu","d":"Radyo dalgalarının dalga boyu metrelerce uzundur, engel boyutlarına yakın ya da büyüktür."},{"t":"Işık","a":"çok kısa dalga boyu","d":"Görünür ışığın dalga boyu çok küçüktür (yaklaşık 0,0005 mm), engellerden çok küçüktür."},{"t":"Sonuç","a":"kırınım farkı","d":"Dalga boyu büyük olan radyo dalgaları engellerin arkasına kırınır; ışık ise belirgin kırınmaz."}],"ans":"Radyo dalgalarının dalga boyu büyük olduğundan engellere kırınıp arkalarına ulaşır; ışığın dalga boyu çok küçük olduğundan belirgin kırınmaz."},{"q":"Bir orkestrada bas (kalın) sesler salonun her köşesinden iyi duyulurken tiz (ince) seslerin yön etkisi daha belirgindir. Bunu kırınımla açıklayınız.","steps":[{"t":"Bas ses","a":"uzun dalga boyu","d":"Bas seslerin dalga boyu uzundur, salondaki engel ve aralıklara yakın boyuttadır."},{"t":"Tiz ses","a":"kısa dalga boyu","d":"Tiz seslerin dalga boyu kısadır, engellerden çok küçük kalır."},{"t":"Sonuç","a":"bas daha çok kırınır","d":"Uzun dalga boylu bas sesler engellerden çok kırınıp her köşeye yayılır; tiz sesler az kırınır, daha yönlüdür."}],"ans":"Uzun dalga boylu bas sesler engellerden çok kırınıp her yöne yayılır; kısa dalga boylu tiz sesler az kırındığı için daha yönlüdür."},{"q":"Şekildeki gibi bir engelin kenarına gelen su dalgaları engelin arkasındaki 'gölge bölgesi'ne ulaşabilir mi? Açıklayınız.","fig":"<svg viewBox='0 0 320 160'><rect x='150' y='80' width='14' height='75' fill='#1a2b45'/><text x='157' y='150' font-size='10' text-anchor='middle' fill='#fff'>Engel</text><line x1='30' y1='15' x2='30' y2='75' stroke='#4aa3df' stroke-width='2'/><line x1='55' y1='15' x2='55' y2='75' stroke='#4aa3df' stroke-width='2'/><line x1='80' y1='15' x2='80' y2='75' stroke='#4aa3df' stroke-width='2'/><line x1='105' y1='15' x2='105' y2='75' stroke='#4aa3df' stroke-width='2'/><path d='M 157 80 A 55 55 0 0 1 200 120' fill='none' stroke='#4aa3df' stroke-width='2' stroke-dasharray='4 3'/><path d='M 157 80 A 80 80 0 0 1 225 135' fill='none' stroke='#4aa3df' stroke-width='2' stroke-dasharray='4 3'/><text x='240' y='110' font-size='10' fill='#1a2b45'>gölge</text><text x='240' y='124' font-size='10' fill='#1a2b45'>bölgesi</text></svg>","steps":[{"t":"Engele çarpar","a":"kenar","d":"Düz dalga cepheleri engele gelir; bir kısmı engelin kenarına ulaşır."},{"t":"Kenardan bükülür","a":"kırınım","d":"Dalga, engelin keskin kenarından bükülüp arkaya doğru dairesel olarak yayılır."},{"t":"Sonuç","a":"kısmen ulaşır","d":"Kırınım sayesinde dalga, engelin arkasındaki gölge bölgesine kısmen ulaşır."}],"ans":"Evet; dalga engelin kenarından bükülerek (kırınarak) gölge bölgesine kısmen ulaşır."}]},"lise":{"kolay":[{"q":"Kırınım olayını dalga cephesi kavramıyla açıklayınız.","steps":[{"t":"Tanım","a":"bükülme","d":"Kırınım, bir dalganın engel kenarından ya da dar aralıktan geçerken doğrultusundan saparak (bükülerek) yayılmasıdır."},{"t":"Dalga cephesi","a":"yeniden şekillenir","d":"Aralıktan geçen dalga cephesinin kenarları, çevreye dairesel cepheler olarak yayılır."},{"t":"Sonuç","a":"gölge bölgesine ulaşır","d":"Bu nedenle dalga, doğrusal yayılmayla ulaşamayacağı gölge bölgesine de erişir."}],"ans":"Kırınım, dalganın engel kenarı veya dar aralıktan geçerken bükülerek gölge bölgesine de yayılması olayıdır."},{"q":"Kırınımın belirginliğini belirleyen oran nedir ve bu oran ne zaman kırınımı artırır?","steps":[{"t":"Belirleyici oran","a":"λ ⁄ d","d":"Belirginlik, dalga boyu λ ile yarık (ya da engel) genişliği d'nin oranına bağlıdır."},{"t":"Oran büyüdükçe","a":"kırınım artar","d":"λ ⁄ d oranı büyüdükçe, yani λ, d'ye yaklaştıkça veya geçtikçe kırınım belirginleşir."},{"t":"Sonuç","a":"λ ≈ d ideal","d":"Dalga boyu yarık genişliğine eşit ya da büyük olduğunda en belirgin kırınım gözlenir."}],"ans":"Kırınımın belirginliği λ ⁄ d oranına bağlıdır; bu oran büyüdükçe (λ ≈ d veya λ > d) kırınım belirginleşir."},{"q":"Huygens ilkesi kırınımı nasıl açıklar?","steps":[{"t":"Huygens ilkesi","a":"her nokta yeni kaynak","d":"Bir dalga cephesinin üzerindeki her nokta, yeni dairesel dalgacıklar yayan bir kaynak gibi davranır."},{"t":"Yarıkta","a":"kenar dalgacıkları","d":"Dar yarıkta yalnız sınırlı sayıda nokta kaynak kaldığından, kenardaki dalgacıklar yana doğru da yayılır."},{"t":"Sonuç","a":"dalga açılır","d":"Bu dalgacıkların üst üste binmesiyle dalga yarık arkasında açılarak yayılır; kırınım budur."}],"ans":"Huygens ilkesine göre dalga cephesindeki her nokta dairesel dalgacık yayar; yarıkta kenar dalgacıkları yana yayıldığından dalga açılır (kırınır)."},{"q":"Sesin kırınımı ışığın kırınımından neden günlük yaşamda daha kolay gözlenir?","steps":[{"t":"Sesin dalga boyu","a":"büyük (m mertebesi)","d":"Sesin dalga boyu santimetre-metre mertebesindedir, kapı ve engellerle kıyaslanabilir."},{"t":"Işığın dalga boyu","a":"çok küçük (nm)","d":"Görünür ışığın dalga boyu yaklaşık 400-700 nm'dir, sıradan engellerden çok küçüktür."},{"t":"Sonuç","a":"λ ⁄ d farkı","d":"Sesin λ ⁄ d oranı büyük olduğundan kırınımı belirgin; ışığın oranı çok küçük olduğundan kırınımı gözle fark edilmez."}],"ans":"Sesin dalga boyu engel boyutlarına yakın olduğundan λ ⁄ d oranı büyük ve kırınımı belirgindir; ışığın dalga boyu çok küçük olduğundan kırınımı günlük gözlemde fark edilmez."},{"q":"Şekildeki gibi dar bir yarığa düz dalga cepheleriyle gelen bir dalga, yarıktan sonra hangi cephe biçimini alır ve neden?","fig":"<svg viewBox='0 0 320 170'><line x1='150' y1='10' x2='150' y2='72' stroke='#1a2b45' stroke-width='5'/><line x1='150' y1='98' x2='150' y2='160' stroke='#1a2b45' stroke-width='5'/><text x='80' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>düz cepheler</text><line x1='28' y1='25' x2='28' y2='145' stroke='#4aa3df' stroke-width='2'/><line x1='50' y1='25' x2='50' y2='145' stroke='#4aa3df' stroke-width='2'/><line x1='72' y1='25' x2='72' y2='145' stroke='#4aa3df' stroke-width='2'/><line x1='94' y1='25' x2='94' y2='145' stroke='#4aa3df' stroke-width='2'/><circle cx='150' cy='85' r='3' fill='#e0552b'/><path d='M 153 85 A 40 40 0 0 1 193 45' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 153 85 A 40 40 0 0 0 193 125' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 153 85 A 62 62 0 0 1 213 50' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 153 85 A 62 62 0 0 0 213 120' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='250' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>dairesel cepheler</text></svg>","steps":[{"t":"Yarık dalga boyu mertebesinde","a":"tek kaynak gibi","d":"Yarık genişliği dalga boyuna yakın olduğunda yarık, neredeyse noktasal bir kaynak gibi davranır."},{"t":"Huygens","a":"dairesel dalgacık","d":"Bu noktasal kaynaktan dairesel dalgacıklar yayılır."},{"t":"Sonuç","a":"dairesel cephe","d":"Bu yüzden yarıktan sonra cepheler dairesel (yarım daire) biçimde açılarak yayılır."}],"ans":"Yarık dalga boyu mertebesinde olduğundan noktasal kaynak gibi davranır; yarıktan sonra dalga dairesel cepheler hâlinde açılarak yayılır."},{"q":"Bir engelin (örneğin bir duvarın) arkasındaki gölge bölgesinin tam karanlık (sessiz) olmamasının nedeni nedir?","steps":[{"t":"Doğrusal yayılma beklentisi","a":"keskin gölge","d":"Yalnız doğrusal yayılma olsaydı engel arkasında keskin sınırlı, tam boş bir gölge bölgesi olurdu."},{"t":"Kırınım","a":"kenardan bükülme","d":"Ancak dalga, engel kenarından bükülerek gölge bölgesine kısmen girer."},{"t":"Sonuç","a":"yumuşak sınır","d":"Bu yüzden gölge sınırı keskin değildir; gölge bölgesine de bir miktar dalga ulaşır."}],"ans":"Dalga engel kenarından kırındığı için gölge bölgesine kısmen ulaşır; bu nedenle gölge sınırı keskin değil, yumuşaktır."},{"q":"Su dalgalarıyla yapılan dalga leğeni deneyinde kırınımın belirginleştiğini gözlemek için hangi değişiklikler yapılabilir?","steps":[{"t":"Yarığı daraltma","a":"d küçülür","d":"Yarık genişliği azaltılarak yarık dalga boyuna yaklaştırılır, kırınım belirginleşir."},{"t":"Dalga boyunu artırma","a":"λ büyür","d":"Dalga üretecinin frekansı düşürülerek dalga boyu büyütülür, λ ⁄ d oranı artar."},{"t":"Sonuç","a":"açılma artar","d":"Her iki değişiklik de λ ⁄ d oranını büyüterek dalganın yarıktan sonra daha geniş açılmasını sağlar."}],"ans":"Yarık genişliği azaltılarak veya dalga boyu (frekans düşürülerek) artırılarak λ ⁄ d oranı büyütülür; böylece kırınım belirginleşir."},{"q":"AM radyo yayınlarının (uzun dalga boyu) dağlık bölgelerde FM yayınlarından (kısa dalga boyu) daha iyi alınmasını kırınımla açıklayınız.","steps":[{"t":"AM dalga boyu","a":"yüzlerce metre","d":"AM dalgalarının dalga boyu yüzlerce metredir, dağ ve tepe boyutlarına yakındır."},{"t":"FM dalga boyu","a":"birkaç metre","d":"FM dalgalarının dalga boyu birkaç metredir, dağlardan çok küçük kalır."},{"t":"Sonuç","a":"AM daha çok kırınır","d":"Uzun dalga boylu AM dalgaları dağların kenarından çok kırınıp arkaya ulaşır; FM az kırındığından arkadaki vadilerde zayıflar."}],"ans":"AM dalgalarının dalga boyu dağ boyutlarına yakın olduğundan kenardan çok kırınıp arkaya ulaşır; FM dalgaları az kırındığından dağ arkasında zayıf alınır."},{"q":"Kırınım olayında dalganın frekansı, dalga boyu ve hızı yarıktan geçerken değişir mi?","steps":[{"t":"Frekans","a":"değişmez","d":"Kırınımda kaynak aynı kaldığından dalganın frekansı değişmez."},{"t":"Ortam aynı","a":"hız değişmez","d":"Dalga aynı ortamda yayılmaya devam ettiği için hızı ve dolayısıyla dalga boyu da değişmez."},{"t":"Sonuç","a":"yalnız doğrultu/biçim değişir","d":"Kırınımda yalnız dalganın yayılma doğrultusu ve cephe biçimi değişir; frekans, hız ve dalga boyu sabit kalır."}],"ans":"Hayır; kırınımda frekans, hız ve dalga boyu değişmez, yalnız dalganın yayılma doğrultusu ve cephe biçimi değişir."},{"q":"Çok küçük cisimleri optik mikroskopla görmenin bir sınırı vardır. Bu sınırın kırınımla ilgisi nedir?","steps":[{"t":"Ayırt etme","a":"dalga boyu sınırı","d":"Bir mikroskop, ışığın dalga boyu mertebesinden çok küçük ayrıntıları ayırt edemez."},{"t":"Kırınım etkisi","a":"görüntü bulanır","d":"Cisim ışığın dalga boyuna yaklaştıkça ışık cisim kenarlarından kırınır ve görüntü bulanıklaşır."},{"t":"Sonuç","a":"çözünürlük sınırı","d":"Bu yüzden optik mikroskobun ayırt edebileceği en küçük ayrıntı, kullanılan ışığın dalga boyuyla sınırlıdır."}],"ans":"Işık, dalga boyu mertebesindeki cisim kenarlarından kırındığından optik mikroskobun çözünürlüğü ışığın dalga boyuyla sınırlıdır."},{"q":"Bir dar yarıktan geçen tek renkli (monokromatik) ışık perdede merkezde geniş aydınlık bir bant oluşturur. Bu olayı kırınımla açıklayınız.","steps":[{"t":"Yarık çok dar","a":"ışık kırınır","d":"Yarık ışığın dalga boyu mertebesine yaklaştığında ışık yarıktan geçerken kırınır."},{"t":"Kenar dalgacıkları","a":"yayılır","d":"Yarık kenarlarından çıkan dalgacıklar perdeye doğru açılarak yayılır."},{"t":"Sonuç","a":"merkezde geniş aydınlık","d":"Bu kırınım, ışığı düz bir nokta yerine perdede geniş bir aydınlık bant (kırınım deseni merkezi) hâlinde yayar."},{"t":"Not","a":"dalga doğası","d":"Bu olay ışığın dalga olduğunun kanıtlarından biridir."}],"ans":"Dar yarıktan geçen ışık kırınıma uğrayıp açıldığından, perdede tek nokta yerine merkezde geniş bir aydınlık bant oluşturur."},{"q":"Aynı yarıktan geçen kırmızı ışık ile mavi ışıktan hangisinin kırınımı daha belirgindir?","steps":[{"t":"Kırmızı ışık","a":"uzun dalga boyu","d":"Kırmızı ışığın dalga boyu yaklaşık 700 nm ile görünür bölgenin en uzunlarındandır."},{"t":"Mavi ışık","a":"kısa dalga boyu","d":"Mavi ışığın dalga boyu yaklaşık 450 nm ile daha kısadır."},{"t":"Sonuç","a":"kırmızı daha çok kırınır","d":"λ ⁄ d oranı kırmızıda daha büyük olduğundan kırmızı ışığın kırınımı daha belirgindir, daha geniş açılır."}],"ans":"Kırmızı ışığın kırınımı daha belirgindir; çünkü dalga boyu mavi ışıktan büyüktür ve λ ⁄ d oranı daha yüksektir."},{"q":"Şekildeki gibi bir limanın dar ağzından geçen deniz dalgaları liman içine yayılırken kırınım nasıl rol oynar?","fig":"<svg viewBox='0 0 320 160'><rect x='140' y='10' width='20' height='55' fill='#1a2b45'/><rect x='140' y='100' width='20' height='55' fill='#1a2b45'/><text x='80' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>açık deniz</text><line x1='25' y1='20' x2='25' y2='150' stroke='#4aa3df' stroke-width='2'/><line x1='50' y1='20' x2='50' y2='150' stroke='#4aa3df' stroke-width='2'/><line x1='75' y1='20' x2='75' y2='150' stroke='#4aa3df' stroke-width='2'/><line x1='100' y1='20' x2='100' y2='150' stroke='#4aa3df' stroke-width='2'/><path d='M 163 82 A 50 50 0 0 1 213 32' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 163 82 A 50 50 0 0 0 213 132' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 163 82 A 75 75 0 0 1 238 40' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 163 82 A 75 75 0 0 0 238 124' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='255' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>liman içi</text></svg>","steps":[{"t":"Dar ağız","a":"yarık gibi","d":"Limanın dar ağzı, dalga için dar bir yarık gibi davranır."},{"t":"Kırınım","a":"dairesel yayılma","d":"Ağızdan geçen dalga kırınıma uğrayıp dairesel cepheler hâlinde liman içine açılır."},{"t":"Sonuç","a":"kıyıları döver","d":"Bu kırınım nedeniyle dalgalar yalnız karşı kıyıya değil, ağzın doğrudan karşısında olmayan iç kıyılara da ulaşır."}],"ans":"Limanın dar ağzı yarık gibi davranır; dalgalar kırınarak dairesel biçimde liman içine yayılır ve doğrudan karşıda olmayan kıyılara da ulaşır."},{"q":"İki farklı engel düşünelim: biri dalga boyundan çok büyük, diğeri dalga boyuyla karşılaştırılabilir. Hangi engelin arkasında kırınım daha belirgindir?","steps":[{"t":"Büyük engel","a":"λ ≪ engel","d":"Dalga boyu engelden çok küçükse, dalga engelin yalnız kenarından az miktarda kırınır."},{"t":"Karşılaştırılabilir engel","a":"λ ≈ engel","d":"Engel dalga boyuyla aynı mertebede ise, dalga engeli neredeyse sarmalayacak kadar kırınır."},{"t":"Sonuç","a":"küçük engelde belirgin","d":"Kırınım, engel boyutu dalga boyuna yaklaştıkça (küçük engelde) daha belirgindir."}],"ans":"Dalga boyuyla karşılaştırılabilir boyuttaki engelin arkasında kırınım daha belirgindir; engel boyutu dalga boyuna yaklaştıkça kırınım artar."},{"q":"Deniz dalgalarının açık denizden gelirken bir adanın arkasındaki koruma altındaki koya da bir miktar ulaşması hangi olayla açıklanır?","steps":[{"t":"Ada engeldir","a":"dalgayı keser","d":"Ada, gelen deniz dalgalarının önünü kesen bir engel gibi davranır."},{"t":"Kenardan bükülme","a":"kırınım","d":"Dalganın bir kısmı adanın kenarlarından bükülerek adanın arkasındaki koya doğru yayılır."},{"t":"Sonuç","a":"koya ulaşır","d":"Bu kırınım sayesinde, doğrudan dalgaya açık olmasa da koy bir miktar dalga alır."}],"ans":"Olay kırınımdır; dalgalar adanın kenarlarından bükülerek (kırınarak) arkadaki koya da kısmen ulaşır."}],"zor":[{"q":"Bir dalga leğeninde dalga boyu 2 cm olan su dalgaları, genişliği 2 cm olan bir yarığa gönderiliyor. Bu durumda kırınım belirgin midir, açıklayınız.","steps":[{"t":"Verileri karşılaştır","a":"λ = d = 2 cm","d":"Dalga boyu (λ = 2 cm) ile yarık genişliği (d = 2 cm) eşittir."},{"t":"Belirginlik ölçütü","a":"λ ⁄ d ≈ 1","d":"λ ⁄ d oranı yaklaşık 1 olduğunda kırınım belirgin olur."},{"t":"Sonuç","a":"belirgin","d":"Dalga boyu yarık genişliğine eşit olduğundan kırınım belirgindir; dalga yarıktan sonra geniş açıyla yayılır."}],"ans":"Evet, belirgindir; çünkü λ = d olduğundan λ ⁄ d ≈ 1'dir ve dalga yarıktan sonra geniş açıyla yayılır."},{"q":"Aynı yarığa önce dalga boyu 1 cm, sonra dalga boyu 4 cm olan su dalgaları gönderiliyor (yarık genişliği 3 cm). Hangi durumda dalga yarıktan sonra daha geniş açılır?","steps":[{"t":"İlk durum","a":"λ ⁄ d = 1 ⁄ 3","d":"λ = 1 cm, d = 3 cm için λ ⁄ d ≈ 0,33; oran küçük, dalga az açılır."},{"t":"İkinci durum","a":"λ ⁄ d = 4 ⁄ 3","d":"λ = 4 cm, d = 3 cm için λ ⁄ d ≈ 1,33; oran büyük, dalga çok açılır."},{"t":"Sonuç","a":"4 cm'lik dalga","d":"λ ⁄ d oranı daha büyük olan 4 cm dalga boyunda dalga yarıktan sonra daha geniş açılır."}],"ans":"Dalga boyu 4 cm olan dalga daha geniş açılır; çünkü λ ⁄ d oranı (≈ 1,33) diğerinden (≈ 0,33) büyüktür."},{"q":"Bir dalga leğeninde dalga üretecinin frekansı artırıldığında (ortam aynı), aynı yarıktaki kırınımın belirginliği nasıl değişir?","steps":[{"t":"Frekans artar","a":"λ azalır","d":"Ortam aynı kalıp hız sabit olduğundan, λ = v ⁄ f bağıntısı gereği frekans artınca dalga boyu küçülür."},{"t":"Oran küçülür","a":"λ ⁄ d düşer","d":"Yarık genişliği d sabit olduğundan, λ küçülünce λ ⁄ d oranı azalır."},{"t":"Sonuç","a":"kırınım azalır","d":"λ ⁄ d küçüldüğü için dalga yarıktan sonra daha az açılır; kırınım belirginliği azalır."}],"ans":"Frekans artınca dalga boyu küçülür, λ ⁄ d oranı azalır ve kırınımın belirginliği azalır (dalga daha az açılır)."},{"q":"Şekildeki gibi dalga leğeninde aynı dalga aynı anda iki farklı genişlikteki (d₁ < d₂) yarığa gönderiliyor. Yarıklardan çıkan dalgaların açılma açılarını karşılaştırınız.","fig":"<svg viewBox='0 0 320 180'><text x='80' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>dar yarık d₁</text><line x1='80' y1='22' x2='80' y2='62' stroke='#1a2b45' stroke-width='4'/><line x1='80' y1='78' x2='80' y2='118' stroke='#1a2b45' stroke-width='4'/><path d='M 80 70 A 30 30 0 0 1 110 40' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 80 70 A 30 30 0 0 0 110 100' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 80 70 A 48 48 0 0 1 128 45' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 80 70 A 48 48 0 0 0 128 95' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='245' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>geniş yarık d₂</text><line x1='245' y1='22' x2='245' y2='52' stroke='#1a2b45' stroke-width='4'/><line x1='245' y1='88' x2='245' y2='118' stroke='#1a2b45' stroke-width='4'/><line x1='247' y1='60' x2='305' y2='52' stroke='#4aa3df' stroke-width='2'/><line x1='247' y1='70' x2='305' y2='70' stroke='#4aa3df' stroke-width='2'/><line x1='247' y1='80' x2='305' y2='88' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Aynı dalga boyu","a":"λ sabit","d":"İki yarığa da aynı dalga gönderildiği için dalga boyu λ aynıdır."},{"t":"Dar yarık","a":"λ ⁄ d₁ büyük","d":"d₁ küçük olduğundan λ ⁄ d₁ oranı büyüktür; dar yarıktan çıkan dalga daha geniş açıyla yayılır."},{"t":"Geniş yarık","a":"λ ⁄ d₂ küçük","d":"d₂ büyük olduğundan λ ⁄ d₂ oranı küçüktür; geniş yarıktan çıkan dalga daha düz, dar açıyla devam eder."},{"t":"Sonuç","a":"dar yarık çok açılır","d":"Dar yarıkta açılma açısı, geniş yarıktakinden daha büyüktür."}],"ans":"Dar yarıkta (d₁) açılma açısı daha büyüktür; λ ⁄ d oranı büyük olduğundan dar yarıktan çıkan dalga daha geniş açıyla yayılır."},{"q":"Bir gemi düdüğü 170 Hz frekansında çalışıyor ve sesin havadaki hızı 340 m/s'dir. Bu sesin dalga boyu kaç metredir ve yaklaşık bu boyutlardaki bir engel (örneğin 2 m'lik direk) sesi belirgin kırınıma uğratır mı?","steps":[{"t":"Dalga boyu hesabı","a":"λ = v ⁄ f","d":"λ = 340 ⁄ 170 = 2 m bulunur."},{"t":"Engelle karşılaştır","a":"λ ≈ engel","d":"Dalga boyu (2 m) direğin boyutuyla (2 m) aynı mertebededir."},{"t":"Sonuç","a":"belirgin kırınır","d":"λ engel boyutuna yakın olduğundan ses bu engelin kenarından belirgin biçimde kırınır."}],"ans":"Sesin dalga boyu 2 m'dir; engel boyutuyla aynı mertebede olduğundan ses bu engelden belirgin biçimde kırınır."},{"q":"Görünür ışığın dalga boyu yaklaşık 500 nm'dir. Sıradan bir kapı aralığında (örneğin 80 cm) ışığın belirgin kırınmamasını λ ⁄ d oranıyla açıklayınız.","steps":[{"t":"Büyüklükleri yaz","a":"λ = 5·10⁻⁷ m, d = 0,8 m","d":"Işığın dalga boyu 500 nm = 5·10⁻⁷ m, aralık 0,8 m'dir."},{"t":"Oranı bul","a":"λ ⁄ d ≈ 6·10⁻⁷","d":"λ ⁄ d = (5·10⁻⁷) ⁄ 0,8 ≈ 6·10⁻⁷ gibi çok küçük bir değerdir."},{"t":"Sonuç","a":"kırınım ihmal edilir","d":"Oran neredeyse sıfır olduğundan ışık aralıktan geçerken belirgin kırınmaz, düz gider gibi görünür."}],"ans":"λ ⁄ d oranı (≈ 6·10⁻⁷) son derece küçük olduğundan ışık kapı aralığında belirgin kırınmaz; bu yüzden ışıkta kırınım ancak çok dar yarıklarda gözlenir."},{"q":"Dalga boyu 3 cm olan su dalgaları için kırınımın belirgin gözlenebilmesi açısından yarık genişliği nasıl seçilmelidir? Üç farklı yarık (1 cm, 3 cm, 12 cm) için değerlendiriniz.","steps":[{"t":"1 cm yarık","a":"λ ⁄ d = 3","d":"λ ⁄ d = 3 ⁄ 1 = 3; oran 1'den büyük, kırınım çok belirgin, dalga çok geniş açılır."},{"t":"3 cm yarık","a":"λ ⁄ d = 1","d":"λ ⁄ d = 3 ⁄ 3 = 1; oran yaklaşık 1, kırınım belirgindir."},{"t":"12 cm yarık","a":"λ ⁄ d = 0,25","d":"λ ⁄ d = 3 ⁄ 12 = 0,25; oran küçük, kırınım az, dalga çoğunlukla düz devam eder."},{"t":"Sonuç","a":"dar yarık seçilmeli","d":"Belirgin kırınım için yarık, dalga boyuna eşit ya da ondan dar (≤ 3 cm) seçilmelidir."}],"ans":"Belirgin kırınım için yarık dalga boyuna eşit veya daha dar (≤ 3 cm) olmalıdır; 1 cm ve 3 cm yarıkta kırınım belirgin, 12 cm yarıkta zayıftır."},{"q":"Yarasalar avlarını bulurken çok yüksek frekanslı (kısa dalga boylu) ses kullanır. Bu seçimin küçük cisimleri 'görmek' açısından kırınımla ilgisi nedir?","steps":[{"t":"Yüksek frekans","a":"kısa dalga boyu","d":"Çok yüksek frekanslı ses çok kısa dalga boyuna sahiptir."},{"t":"Küçük cisim","a":"λ ≪ cisim","d":"Dalga boyu küçük olduğundan ses, küçük böceğin etrafından fazla kırınmaz, ona çarpıp yansır."},{"t":"Sonuç","a":"keskin yankı","d":"Az kırınım olduğundan yansıyan yankı keskin olur ve yarasa küçük avı net biçimde algılar."}],"ans":"Kısa dalga boylu ses küçük cisimden az kırındığı için ona çarpıp net yansır; böylece yarasa küçük avını ayırt edebilir."},{"q":"Şekildeki gibi bir dalga leğeninde dalga boyu sabit tutulup yarık genişliği yarıya indirildiğinde, yarıktan sonraki dalga açılma açısı nasıl değişir? Açıklayınız.","fig":"<svg viewBox='0 0 320 180'><text x='80' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>yarık d</text><line x1='80' y1='22' x2='80' y2='62' stroke='#1a2b45' stroke-width='4'/><line x1='80' y1='82' x2='80' y2='122' stroke='#1a2b45' stroke-width='4'/><path d='M 80 72 A 32 32 0 0 1 112 45' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 80 72 A 32 32 0 0 0 112 99' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='245' y='14' font-size='10' text-anchor='middle' fill='#1a2b45'>yarık d ⁄ 2</text><line x1='245' y1='22' x2='245' y2='66' stroke='#1a2b45' stroke-width='4'/><line x1='245' y1='78' x2='245' y2='122' stroke='#1a2b45' stroke-width='4'/><circle cx='245' cy='72' r='3' fill='#e0552b'/><path d='M 248 72 A 36 36 0 0 1 284 38' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 248 72 A 36 36 0 0 0 284 106' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 248 72 A 55 55 0 0 1 300 45' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 248 72 A 55 55 0 0 0 300 100' fill='none' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Oran değişimi","a":"λ ⁄ d artar","d":"λ sabit, d yarıya inerse λ ⁄ d oranı iki katına çıkar."},{"t":"Açılma","a":"açı büyür","d":"λ ⁄ d arttıkça yarıktan çıkan dalganın açılma açısı büyür."},{"t":"Sonuç","a":"daha geniş açılır","d":"Yarık daraldığında dalga yarıktan sonra daha geniş bir açıyla yayılır; kırınım belirginleşir."}],"ans":"Yarık genişliği yarıya inince λ ⁄ d oranı iki katına çıkar; dalganın açılma açısı büyür ve kırınım belirginleşir."},{"q":"Bir konser salonunda alçak frekanslı (bas) hoparlör seslerinin sütun, koltuk gibi engelleri aşıp her yere yayılması; tiz hoparlör seslerinin ise daha yönlü kalması nasıl açıklanır?","steps":[{"t":"Bas ses","a":"uzun λ","d":"Bas seslerin dalga boyu metrelerce olup salondaki sütun ve koltuk boyutlarına yakındır."},{"t":"Kırınım belirgin","a":"engeli aşar","d":"λ ⁄ d oranı büyük olduğundan bas sesler bu engellerden çok kırınıp her yöne yayılır."},{"t":"Tiz ses","a":"kısa λ","d":"Tiz seslerin dalga boyu santimetre mertebesinde olup engellerden çok küçük kalır."},{"t":"Sonuç","a":"tiz yönlü","d":"λ ⁄ d oranı çok küçük olduğundan tiz sesler az kırınır, doğrultusunda yönlü kalır."}],"ans":"Bas seslerin uzun dalga boyu salon engellerine yakın olduğundan çok kırınıp her yere yayılır; tiz seslerin kısa dalga boyu az kırındığından yönlü kalır."},{"q":"Tek yarıkta ışık kırınımında merkezî aydınlık bandın genişliği, yarık daraltıldığında nasıl değişir? Kırınım mantığıyla açıklayınız.","steps":[{"t":"Yarık daralır","a":"λ ⁄ d artar","d":"λ sabitken yarık genişliği d küçüldükçe λ ⁄ d oranı büyür."},{"t":"Açılma artar","a":"ışık daha çok kırınır","d":"Oran büyüdüğünden ışık yarıktan sonra daha geniş bir açıyla yayılır."},{"t":"Sonuç","a":"merkez bant genişler","d":"Bu nedenle perdedeki merkezî aydınlık bandın genişliği artar; yarık ne kadar dar olursa desen o kadar geniş yayılır."}],"ans":"Yarık daraldıkça λ ⁄ d oranı artar, ışık daha çok kırınır ve perdedeki merkezî aydınlık bant genişler."},{"q":"Sesin köşeden kolayca kırınması ile ışığın kırınmaması, ses ve ışığın dalga boyları arasındaki kaç kat farkla ilişkilidir? Mertebe karşılaştırması yapınız.","steps":[{"t":"Ses dalga boyu","a":"≈ 1 m mertebesi","d":"Duyulabilir sesin dalga boyu santimetre ile metre arasında, tipik olarak ≈ 1 m mertebesindedir."},{"t":"Işık dalga boyu","a":"≈ 5·10⁻⁷ m","d":"Görünür ışığın dalga boyu yaklaşık 500 nm = 5·10⁻⁷ m'dir."},{"t":"Oran","a":"≈ 10⁶ kat","d":"Sesin dalga boyu ışığınkinden yaklaşık 1 ⁄ (5·10⁻⁷) ≈ 2·10⁶, yani milyon kat büyüktür."},{"t":"Sonuç","a":"ses çok kırınır","d":"Bu devasa fark nedeniyle ses sıradan engellerden belirgin kırınırken, ışık aynı engellerde belirgin kırınmaz."}],"ans":"Sesin dalga boyu ışığınkinden yaklaşık milyon (10⁶) kat büyük olduğundan ses sıradan engellerden belirgin kırınır, ışık ise kırınmaz."},{"q":"Şekildeki gibi düz bir dalga, dalga boyundan biraz büyük genişlikte bir yarığa geliyor. Yarıktan çıkan dalganın merkezde düz, kenarlarda hafif bükük cepheler oluşturmasının nedeni nedir?","fig":"<svg viewBox='0 0 320 170'><line x1='150' y1='12' x2='150' y2='58' stroke='#1a2b45' stroke-width='5'/><line x1='150' y1='112' x2='150' y2='158' stroke='#1a2b45' stroke-width='5'/><text x='80' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>düz dalga</text><line x1='28' y1='25' x2='28' y2='145' stroke='#4aa3df' stroke-width='2'/><line x1='52' y1='25' x2='52' y2='145' stroke='#4aa3df' stroke-width='2'/><line x1='76' y1='25' x2='76' y2='145' stroke='#4aa3df' stroke-width='2'/><path d='M 195 58 Q 200 85 195 112' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 222 52 Q 232 85 222 118' fill='none' stroke='#4aa3df' stroke-width='2'/><path d='M 249 48 Q 262 85 249 122' fill='none' stroke='#4aa3df' stroke-width='2'/><text x='250' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>kenarda bükük</text></svg>","steps":[{"t":"Yarık λ'dan büyük","a":"orta kısım düz","d":"Yarık dalga boyundan büyük olduğunda, dalganın orta kısmı eski düz cephe biçimini büyük ölçüde korur."},{"t":"Kenar etkisi","a":"Huygens dalgacıkları","d":"Yarık kenarlarındaki noktalar dairesel dalgacık yaydığından cephe kenarlarda yana doğru bükülür."},{"t":"Sonuç","a":"merkez düz, kenar bükük","d":"Bu yüzden yarık geniş olduğunda kırınım yalnız kenarlarda fark edilir; merkez düz kalır."}],"ans":"Yarık dalga boyundan büyük olduğundan cephenin ortası düz kalır; yalnız kenarlardaki Huygens dalgacıkları yana yayıldığı için kenarlar hafif bükülür."},{"q":"Bir baraj kapağının dar aralığından geçen su dalgalarının, aralığın doğrudan karşısında olmayan kıyı kesimlerini de dövmesi hangi olayla açıklanır ve bu olayın belirginliği neye bağlıdır?","steps":[{"t":"Olay","a":"kırınım","d":"Dalganın dar aralıktan geçtikten sonra her yöne açılarak yayılması kırınımdır."},{"t":"Yan kıyıya ulaşma","a":"dairesel yayılma","d":"Aralık dalga boyu mertebesinde olduğundan dalga dairesel cepheler hâlinde açılır ve yan kıyılara da ulaşır."},{"t":"Belirginlik","a":"λ ⁄ d oranı","d":"Bu yayılmanın belirginliği, dalga boyunun aralık genişliğine oranına bağlıdır; oran büyüdükçe dalga daha geniş açılır."},{"t":"Sonuç","a":"kırınım, λ ⁄ d'ye bağlı","d":"Aralık dar (λ'ye yakın) oldukça dalga daha çok kırınır ve karşıda olmayan kıyıları da döver."}],"ans":"Olay kırınımdır; dar aralıktan geçen dalga dairesel açılır ve yan kıyılara ulaşır. Belirginliği λ ⁄ d oranına bağlıdır; aralık daraldıkça kırınım artar."},{"q":"Bir dalga boyu 5 cm olan su dalgası, 5 cm genişliğinde bir yarıktan geçtiğinde belirgin kırınır. Aynı yarık sabit tutulup ortam değiştirilerek dalganın hızı iki katına çıkarılırsa (frekans aynı), kırınımın belirginliği nasıl değişir?","steps":[{"t":"Hız ile dalga boyu","a":"λ = v ⁄ f","d":"Frekans sabitken hız iki katına çıkarsa, λ = v ⁄ f gereği dalga boyu da iki katına çıkar (λ = 10 cm)."},{"t":"Oranı güncelle","a":"λ ⁄ d = 10 ⁄ 5 = 2","d":"Yarık genişliği 5 cm sabit, yeni λ = 10 cm için λ ⁄ d oranı 1'den 2'ye yükselir."},{"t":"Sonuç","a":"daha belirgin","d":"λ ⁄ d oranı arttığından dalga yarıktan sonra daha geniş açılır; kırınım daha belirgin olur."}],"ans":"Dalga boyu iki katına çıkar, λ ⁄ d oranı 1'den 2'ye yükselir ve kırınım daha belirgin hâle gelir."}]}},"periyotFrekans":{"ilkokul":{"kolay":[{"q":"Bir salıncak ileri geri gidip aynı yere döndüğünde bir tam sallanma tamamlanmış olur. Buna bir <b>titreşim</b> diyebilir miyiz?","steps":[{"t":"Tam hareketi izle","a":"git ve dön","d":"Salıncak öne gidip geri gelerek başladığı yere dönerse hareketin tamamı bitmiş olur."},{"t":"İsmini söyle","a":"bir titreşim","d":"Başladığı yere dönen bu tam hareketin her birine bir titreşim denir."}],"ans":"Evet, salıncağın gidip geri dönmesi bir tam titreşimdir."},{"q":"Hızlı titreyen bir gitar teli ile yavaş sallanan bir salıncaktan hangisi saniyede daha çok hareket yapar?","fig":"<svg viewBox='0 0 320 160'><text x='80' y='25' font-size='12' text-anchor='middle' fill='#1a2b45'>Gitar teli (hızlı)</text><path d='M20 70 Q35 50 50 70 Q65 90 80 70 Q95 50 110 70 Q125 90 140 70' fill='none' stroke='#e0552b' stroke-width='2'/><text x='240' y='25' font-size='12' text-anchor='middle' fill='#1a2b45'>Salıncak (yavaş)</text><path d='M180 110 Q210 70 240 110 Q270 150 300 110' fill='none' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Hıza bak","a":"gitar teli","d":"Gitar teli çok hızlı titrer, bir saniyede pek çok kez gider gelir."},{"t":"Karşılaştır","a":"daha çok","d":"Yavaş salıncak ise saniyede ancak birkaç kez sallanır."}],"ans":"Gitar teli saniyede daha çok hareket yapar çünkü daha hızlı titrer."},{"q":"İki yayda biri çok hızlı, biri çok yavaş zıplıyor. Bir tam zıplaması daha kısa süren hangisidir?","steps":[{"t":"Süreyi düşün","a":"hızlı olan","d":"Hızlı zıplayan yay, bir tam zıplamayı çok kısa sürede bitirir."},{"t":"Sonucu söyle","a":"hızlı yay","d":"Yavaş yay ise bir zıplama için daha uzun süre bekler."}],"ans":"Hızlı zıplayan yayın bir tam hareketi daha kısa sürer."},{"q":"Sallanan bir sarkacı izliyoruz. Sarkaç ne kadar hızlı sallanırsa saniyede yaptığı tam sallanma sayısı nasıl olur?","fig":"<svg viewBox='0 0 320 160'><line x1='160' y1='20' x2='110' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='20' x2='210' y2='120' stroke='#5b6b85' stroke-width='2' stroke-dasharray='4 3'/><circle cx='110' cy='120' r='14' fill='#5b6b85' stroke='#1a2b45'/><circle cx='210' cy='120' r='14' fill='#5b6b85' stroke='#1a2b45' opacity='0.5'/><circle cx='160' cy='20' r='5' fill='#1a2b45'/><text x='160' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>git ve gel = bir titreşim</text></svg>","steps":[{"t":"Hızı düşün","a":"daha hızlı","d":"Hızlı sallanan sarkaç aynı sürede daha çok gidip gelir."},{"t":"Sayıya bak","a":"daha çok","d":"Bu yüzden saniyede yaptığı tam sallanma sayısı artar."}],"ans":"Sarkaç ne kadar hızlı sallanırsa saniyede o kadar çok tam sallanma yapar."},{"q":"Bir bayrak rüzgârda yavaş yavaş dalgalanıyor. Bunun titreşimi hızlı mı yavaş mıdır?","steps":[{"t":"Hareketi izle","a":"yavaş","d":"Bayrak büyük ve ağır olduğu için yavaş dalgalanır."},{"t":"Karar ver","a":"yavaş titreşim","d":"Yavaş dalgalandığı için saniyede az sayıda tam hareket yapar."}],"ans":"Bayrağın dalgalanması yavaş bir titreşimdir."}],"zor":[{"q":"Bir arının kanatları çok hızlı, kelebeğin kanatları ise yavaş çırpılır. Hangisinin kanat hareketi bir saniyede daha çok tekrar eder?","steps":[{"t":"Hıza bak","a":"arı","d":"Arının kanatları o kadar hızlı çırpılır ki gözle tek tek göremeyiz."},{"t":"Sonucu söyle","a":"arı daha çok","d":"Kelebek kanatlarını yavaş çırptığı için saniyede daha az tekrar yapar."}],"ans":"Arının kanat hareketi bir saniyede daha çok tekrar eder."},{"q":"Aynı ipte iki çocuk salıncak sallıyor. Biri bir gidip gelmeyi 2 saniyede, diğeri 1 saniyede yapıyor. Hangisi daha hızlı sallanıyor?","fig":"<svg viewBox='0 0 320 160'><line x1='80' y1='20' x2='80' y2='90' stroke='#1a2b45' stroke-width='1.5'/><circle cx='80' cy='100' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='80' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>2 saniye</text><line x1='240' y1='20' x2='240' y2='90' stroke='#1a2b45' stroke-width='1.5'/><circle cx='240' cy='100' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>1 saniye</text></svg>","steps":[{"t":"Süreyi karşılaştır","a":"1 saniye az","d":"Bir gidip gelmeyi daha kısa sürede yapan daha hızlıdır."},{"t":"Sonucu söyle","a":"1 saniyelik","d":"1 saniyede tamamlayan çocuk daha hızlı sallanıyor."}],"ans":"Bir gidip gelmeyi 1 saniyede yapan çocuk daha hızlı sallanıyor."},{"q":"Bir davula yavaş yavaş, sonra çok hızlı vuruyoruz. Sesin titreşimi ne zaman daha sık olur?","steps":[{"t":"Vuruş hızını düşün","a":"hızlı vuruş","d":"Hızlı vurduğumuzda davulun derisi daha sık titrer."},{"t":"Sonuç","a":"hızlıyken","d":"Yavaş vururken titreşim aralıklı, hızlı vururken sıktır."}],"ans":"Davula hızlı vurduğumuzda titreşim daha sık olur."},{"q":"İki kalbin biri saniyede bir, diğeri saniyede iki kez atıyor. Hangisi daha hızlı çalışıyor?","fig":"<svg viewBox='0 0 320 150'><path d='M20 80 L60 80 L70 50 L85 110 L100 80 L300 80' fill='none' stroke='#e0552b' stroke-width='2'/><text x='160' y='130' font-size='12' text-anchor='middle' fill='#1a2b45'>saniyede 2 atış = daha hızlı</text></svg>","steps":[{"t":"Atış sayısını say","a":"iki kez","d":"Saniyede iki kez atan kalp aynı sürede daha çok çalışır."},{"t":"Karar ver","a":"daha hızlı","d":"Aynı saniyede daha çok atış yapan kalp daha hızlıdır."}],"ans":"Saniyede iki kez atan kalp daha hızlı çalışıyor."},{"q":"Bir yelpazeyi önce yavaş, sonra hızlı salladık. Hangi durumda kolumuz bir saniyede daha çok gidip gelir?","steps":[{"t":"Hareketi izle","a":"hızlı sallama","d":"Hızlı salladığımızda kolumuz aynı sürede daha fazla gidip gelir."},{"t":"Sonuç","a":"hızlı durum","d":"Yavaş salladığımızda ise saniyede az sayıda hareket olur."}],"ans":"Yelpazeyi hızlı salladığımızda kolumuz bir saniyede daha çok gidip gelir."}]},"ortaokul":{"kolay":[{"q":"Bir tam titreşimin sürmesi için geçen süreye ne ad verilir?","steps":[{"t":"Tanımı hatırla","a":"bir tam hareket","d":"Bir cismin bir tam titreşimi tamamlaması belli bir süre alır."},{"t":"İsmini ver","a":"periyot","d":"Bu süreye periyot denir ve T harfiyle gösterilir, birimi saniyedir."}],"ans":"Bir tam titreşimin süresine periyot (T) denir; birimi saniyedir."},{"q":"Bir saniyede yapılan tam titreşim sayısına ne ad verilir ve birimi nedir?","steps":[{"t":"Tanımı düşün","a":"saniyedeki sayı","d":"Bir saniyede kaç tam titreşim olduğunu sayan büyüklüktür."},{"t":"İsmini ver","a":"frekans, Hz","d":"Buna frekans denir, f harfiyle gösterilir ve birimi hertz (Hz) tir."}],"ans":"Saniyedeki titreşim sayısına frekans (f) denir; birimi hertz (Hz) tir."},{"q":"Bir sarkaç bir tam salınımını 2 saniyede tamamlıyor. Periyodu kaç saniyedir?","fig":"<svg viewBox='0 0 320 150'><line x1='160' y1='15' x2='120' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='15' x2='200' y2='110' stroke='#5b6b85' stroke-width='2' stroke-dasharray='4 3'/><circle cx='120' cy='110' r='13' fill='#5b6b85' stroke='#1a2b45'/><circle cx='200' cy='110' r='13' fill='#5b6b85' stroke='#1a2b45' opacity='0.5'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>bir tam salınım = 2 s</text></svg>","steps":[{"t":"Periyodu tanı","a":"bir tam salınım süresi","d":"Periyot, bir tam salınımın süresidir."},{"t":"Değeri oku","a":"2 s","d":"Bir tam salınım 2 saniye sürdüğüne göre periyot doğrudan 2 saniyedir."}],"ans":"Sarkacın periyodu 2 saniyedir."},{"q":"Bir cisim saniyede 5 tam titreşim yapıyor. Frekansı kaç Hz tir?","steps":[{"t":"Frekansı tanı","a":"saniyedeki sayı","d":"Frekans, bir saniyedeki tam titreşim sayısıdır."},{"t":"Değeri yaz","a":"5 Hz","d":"Saniyede 5 titreşim olduğu için frekans 5 hertzdir."}],"ans":"Cismin frekansı 5 Hz tir."},{"q":"Bir kaynağın frekansı büyüdükçe periyodu nasıl değişir?","steps":[{"t":"İlişkiyi düşün","a":"ters orantı","d":"Frekans saniyedeki titreşim sayısı, periyot ise bir titreşimin süresidir."},{"t":"Sonuç","a":"küçülür","d":"Saniyede daha çok titreşim olursa her bir titreşim daha kısa sürer, yani periyot küçülür."}],"ans":"Frekans büyüdükçe periyot küçülür; ikisi ters orantılıdır."}],"zor":[{"q":"Bir cisim 10 saniyede 20 tam titreşim yapıyor. Frekansı kaç Hz tir?","steps":[{"t":"Frekans bağıntısı","a":"f = titreşim/süre","d":"Frekans, toplam titreşim sayısının geçen süreye bölünmesiyle bulunur."},{"t":"Yerine koy","a":"20 ÷ 10","d":"20 titreşim 10 saniyeye bölünür."},{"t":"Sonuç","a":"2 Hz","d":"Bölme sonucu 2 hertz bulunur."}],"ans":"Cismin frekansı 2 Hz tir."},{"q":"Bir sarkaç 12 saniyede 4 tam salınım yapıyor. Periyodu kaç saniyedir?","fig":"<svg viewBox='0 0 320 150'><line x1='160' y1='15' x2='118' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='15' x2='202' y2='110' stroke='#5b6b85' stroke-width='2' stroke-dasharray='4 3'/><circle cx='118' cy='110' r='13' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='140' font-size='12' text-anchor='middle' fill='#1a2b45'>12 s'de 4 salınım</text></svg>","steps":[{"t":"Periyot bağıntısı","a":"T = süre/titreşim","d":"Periyot, geçen sürenin tam titreşim sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"12 ÷ 4","d":"12 saniye 4 salınıma bölünür."},{"t":"Sonuç","a":"3 s","d":"Bölme sonucu 3 saniye bulunur."}],"ans":"Sarkacın periyodu 3 saniyedir."},{"q":"Frekansı 4 Hz olan bir kaynağın periyodu kaç saniyedir?","steps":[{"t":"İlişkiyi yaz","a":"T = 1/f","d":"Periyot, frekansın tersine eşittir."},{"t":"Yerine koy","a":"1 ÷ 4","d":"Frekans 4 Hz olduğu için 1 sayısını 4'e böleriz."},{"t":"Sonuç","a":"0,25 s","d":"Bölme sonucu 0,25 saniye bulunur."}],"ans":"Kaynağın periyodu 0,25 saniyedir."},{"q":"Periyodu 0,5 saniye olan bir titreşimin frekansı kaç Hz tir?","steps":[{"t":"İlişkiyi yaz","a":"f = 1/T","d":"Frekans, periyodun tersine eşittir."},{"t":"Yerine koy","a":"1 ÷ 0,5","d":"Periyot 0,5 s olduğu için 1 sayısını 0,5'e böleriz."},{"t":"Sonuç","a":"2 Hz","d":"Bölme sonucu 2 hertz bulunur."}],"ans":"Titreşimin frekansı 2 Hz tir."},{"q":"Şekildeki dalga grafiğinde bir tam dalga 4 saniyede oluşuyor. Bu dalganın frekansını bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1'/><text x='305' y='84' font-size='10' fill='#1a2b45'>t(s)</text><line x1='20' y1='20' x2='20' y2='140' stroke='#1a2b45' stroke-width='1'/><path d='M20 80 Q70 30 120 80 Q170 130 220 80' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='145' x2='220' y2='145' stroke='#e0552b' stroke-width='1.5'/><text x='120' y='158' font-size='11' text-anchor='middle' fill='#e0552b'>T = 4 s</text></svg>","steps":[{"t":"Periyodu oku","a":"T = 4 s","d":"Bir tam dalganın oluşma süresi periyottur, grafikte 4 saniyedir."},{"t":"Frekansı yaz","a":"f = 1/T","d":"Frekans, periyodun tersidir: 1 ÷ 4."},{"t":"Sonuç","a":"0,25 Hz","d":"Bölme sonucu 0,25 hertz bulunur."}],"ans":"Dalganın frekansı 0,25 Hz tir."}]},"lise":{"kolay":[{"q":"Periyot (T) ve frekans (f) arasındaki temel matematiksel ilişki nedir?","steps":[{"t":"Tanımları hatırla","a":"süre ve sayı","d":"Periyot bir tam titreşimin süresi, frekans ise saniyedeki titreşim sayısıdır."},{"t":"İlişkiyi kur","a":"T = 1/f","d":"İki büyüklük birbirinin tersidir: T = 1/f ve f = 1/T."}],"ans":"Periyot ile frekans birbirinin tersidir: T = 1/f (ve f = 1/T)."},{"q":"Frekansı 50 Hz olan bir kaynağın periyodunu hesaplayınız.","steps":[{"t":"Bağıntı","a":"T = 1/f","d":"Periyot, frekansın tersine eşittir."},{"t":"Yerine koy","a":"1 ÷ 50","d":"Frekans 50 Hz olduğu için 1 sayısını 50'ye böleriz."},{"t":"Sonuç","a":"0,02 s","d":"Bölme sonucu 0,02 saniye bulunur."}],"ans":"Kaynağın periyodu 0,02 saniyedir."},{"q":"Periyodu 0,01 saniye olan bir titreşimin frekansını bulunuz.","steps":[{"t":"Bağıntı","a":"f = 1/T","d":"Frekans, periyodun tersine eşittir."},{"t":"Yerine koy","a":"1 ÷ 0,01","d":"Periyot 0,01 s olduğu için 1 sayısını 0,01'e böleriz."},{"t":"Sonuç","a":"100 Hz","d":"Bölme sonucu 100 hertz bulunur."}],"ans":"Titreşimin frekansı 100 Hz tir."},{"q":"Bir kaynak 8 saniyede 32 tam titreşim üretiyor. Frekansını ve periyodunu bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 32/8 = 4 Hz","d":"Frekans, titreşim sayısının süreye bölünmesidir."},{"t":"Periyodu bul","a":"T = 1/4","d":"Periyot frekansın tersidir, 1 ÷ 4 hesaplanır."},{"t":"Sonuç","a":"0,25 s","d":"Periyot 0,25 saniye bulunur."}],"ans":"Frekans 4 Hz, periyot 0,25 saniyedir."},{"q":"Şekildeki dalga grafiğinde bir tam dalganın periyodu 0,2 saniye olarak işaretlenmiştir. Frekansını hesaplayınız.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1'/><text x='305' y='84' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='20' x2='20' y2='140' stroke='#1a2b45' stroke-width='1'/><path d='M20 80 Q60 25 100 80 Q140 135 180 80 Q220 25 260 80 Q300 135 300 80' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='148' x2='180' y2='148' stroke='#e0552b' stroke-width='1.5'/><text x='100' y='160' font-size='11' text-anchor='middle' fill='#e0552b'>T = 0,2 s</text></svg>","steps":[{"t":"Periyodu oku","a":"T = 0,2 s","d":"Grafikte bir tam dalganın süresi 0,2 saniye olarak verilmiştir."},{"t":"Frekansı yaz","a":"f = 1/T","d":"Frekans periyodun tersidir: 1 ÷ 0,2."},{"t":"Sonuç","a":"5 Hz","d":"Bölme sonucu 5 hertz bulunur."}],"ans":"Dalganın frekansı 5 Hz tir."},{"q":"Frekansı 2 kHz olan bir ses kaynağının periyodunu saniye cinsinden bulunuz.","steps":[{"t":"Birimi çevir","a":"2 kHz = 2000 Hz","d":"1 kHz 1000 Hz'e eşittir, bu yüzden 2 kHz = 2000 Hz tir."},{"t":"Bağıntı","a":"T = 1/f","d":"Periyot, frekansın tersidir: 1 ÷ 2000."},{"t":"Sonuç","a":"0,0005 s","d":"Bölme sonucu 0,0005 saniye (yani 0,5 ms) bulunur."}],"ans":"Kaynağın periyodu 0,0005 saniyedir."},{"q":"Bir titreşim kaynağının frekansı kaynağın özelliğine bağlıdır. Bu cümle ne anlama gelir?","steps":[{"t":"Frekansı kim belirler","a":"kaynak","d":"Bir dalganın frekansı, onu üreten kaynağın titreşim hızıyla belirlenir."},{"t":"Ortam etkisi","a":"değişmez","d":"Dalga başka ortama geçse de frekansı (dolayısıyla periyodu) değişmez, kaynağa bağlı kalır."}],"ans":"Frekans yalnızca kaynağın titreşim hızıyla belirlenir; ortam değişse bile frekans ve periyot sabit kalır."},{"q":"Periyodu 4 ms olan bir titreşimin frekansını Hz cinsinden bulunuz.","steps":[{"t":"Birimi çevir","a":"4 ms = 0,004 s","d":"1 ms 0,001 saniyedir, bu yüzden 4 ms = 0,004 saniyedir."},{"t":"Bağıntı","a":"f = 1/T","d":"Frekans periyodun tersidir: 1 ÷ 0,004."},{"t":"Sonuç","a":"250 Hz","d":"Bölme sonucu 250 hertz bulunur."}],"ans":"Titreşimin frekansı 250 Hz tir."},{"q":"İki kaynaktan birinin periyodu 0,1 s, diğerininki 0,5 s. Hangisinin frekansı daha büyüktür?","steps":[{"t":"İlişkiyi hatırla","a":"f = 1/T","d":"Frekans periyot ile ters orantılıdır; periyot küçükse frekans büyüktür."},{"t":"Karşılaştır","a":"0,1 s'lik","d":"Periyodu 0,1 s olan kaynağın frekansı 10 Hz, 0,5 s olanınki 2 Hz tir."}],"ans":"Periyodu 0,1 s olan kaynağın frekansı (10 Hz) daha büyüktür."},{"q":"Bir cismin frekansı 20 Hz tir. 3 saniyede kaç tam titreşim yapar?","steps":[{"t":"İlişkiyi yaz","a":"sayı = f × t","d":"Toplam titreşim sayısı, frekans ile geçen sürenin çarpımıdır."},{"t":"Yerine koy","a":"20 × 3","d":"Frekans 20 Hz, süre 3 saniye yerine konur."},{"t":"Sonuç","a":"60 titreşim","d":"Çarpım sonucu 60 tam titreşim bulunur."}],"ans":"Cisim 3 saniyede 60 tam titreşim yapar."},{"q":"Şekildeki grafikte 0,6 saniyede 3 tam dalga görülüyor. Dalganın periyodunu bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1'/><text x='305' y='84' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='20' x2='20' y2='140' stroke='#1a2b45' stroke-width='1'/><path d='M20 80 Q35 40 50 80 Q65 120 80 80 Q95 40 110 80 Q125 120 140 80 Q155 40 170 80 Q185 120 200 80' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='150' x2='200' y2='150' stroke='#e0552b' stroke-width='1.5'/><text x='110' y='160' font-size='11' text-anchor='middle' fill='#e0552b'>3 dalga = 0,6 s</text></svg>","steps":[{"t":"Periyot bağıntısı","a":"T = süre/dalga","d":"Periyot, toplam sürenin tam dalga sayısına bölünmesidir."},{"t":"Yerine koy","a":"0,6 ÷ 3","d":"0,6 saniye 3 dalgaya bölünür."},{"t":"Sonuç","a":"0,2 s","d":"Bölme sonucu 0,2 saniye bulunur."}],"ans":"Dalganın periyodu 0,2 saniyedir."},{"q":"Bir alternatif akım kaynağının frekansı 60 Hz tir. Periyodunu ms (milisaniye) cinsinden bulunuz.","steps":[{"t":"Periyodu bul","a":"T = 1/60","d":"Periyot frekansın tersidir, 1 ÷ 60 hesaplanır."},{"t":"Sonucu çevir","a":"≈ 0,0167 s","d":"Bölme sonucu yaklaşık 0,0167 saniyedir."},{"t":"ms'ye geçir","a":"× 1000","d":"Saniyeyi 1000 ile çarpınca yaklaşık 16,7 ms bulunur."}],"ans":"Kaynağın periyodu yaklaşık 16,7 milisaniyedir."},{"q":"Frekansı 5 Hz olan bir titreşim için bir tam titreşimin yarısı ne kadar sürer?","steps":[{"t":"Periyodu bul","a":"T = 1/5 = 0,2 s","d":"Önce periyot, frekansın tersi olarak 0,2 saniye bulunur."},{"t":"Yarısını al","a":"0,2 ÷ 2","d":"Tam titreşimin yarısı periyodun yarısıdır."},{"t":"Sonuç","a":"0,1 s","d":"Bölme sonucu 0,1 saniye bulunur."}],"ans":"Bir tam titreşimin yarısı 0,1 saniye sürer."},{"q":"Frekans-periyot grafiğinde frekans artarken periyot eğrisinin nasıl bir davranış gösterdiğini açıklayınız.","steps":[{"t":"İlişkiyi yaz","a":"T = 1/f","d":"Periyot frekansın tersi olduğundan f arttıkça T küçülür."},{"t":"Eğriyi tanı","a":"hiperbol","d":"Ters orantı, eksenlere yaklaşan azalan bir eğri (hiperbol) verir."}],"ans":"Frekans arttıkça periyot azalır; grafik eksenlere yaklaşan azalan bir hiperbol biçimindedir."},{"q":"Bir radyo istasyonu 100 MHz frekansta yayın yapıyor. Periyodunu bulunuz.","steps":[{"t":"Birimi çevir","a":"100 MHz = 10⁸ Hz","d":"1 MHz 10⁶ Hz olduğundan 100 MHz = 10⁸ hertzdir."},{"t":"Bağıntı","a":"T = 1/f","d":"Periyot frekansın tersidir: 1 ÷ 10⁸."},{"t":"Sonuç","a":"10⁻⁸ s","d":"Bölme sonucu 10⁻⁸ saniye (10 nanosaniye) bulunur."}],"ans":"İstasyonun periyodu 10⁻⁸ saniye (10 ns) dir."}],"zor":[{"q":"Bir cisim 2,5 saniyede 50 tam titreşim yapıyor. Frekansını ve periyodunu bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 50/2,5","d":"Frekans, titreşim sayısının süreye bölünmesidir."},{"t":"Hesapla","a":"20 Hz","d":"50 titreşim 2,5 saniyeye bölününce 20 hertz çıkar."},{"t":"Periyodu bul","a":"T = 1/20 = 0,05 s","d":"Periyot frekansın tersidir, 1 ÷ 20 = 0,05 saniyedir."}],"ans":"Frekans 20 Hz, periyot 0,05 saniyedir."},{"q":"Periyodu 0,004 saniye olan bir titreşim 1 dakikada kaç tam titreşim yapar?","steps":[{"t":"Frekansı bul","a":"f = 1/0,004","d":"Frekans periyodun tersidir: 1 ÷ 0,004 = 250 Hz."},{"t":"Süreyi çevir","a":"1 dk = 60 s","d":"Bir dakika 60 saniyeye eşittir."},{"t":"Sayıyı bul","a":"250 × 60","d":"Titreşim sayısı = frekans × süre = 250 × 60'tır."}],"ans":"Titreşim 1 dakikada 15000 tam titreşim yapar."},{"q":"Bir sarkacın periyodu 2 saniyedir. Frekansı iki katına çıkarılırsa yeni periyot kaç saniye olur?","steps":[{"t":"İlk frekansı bul","a":"f = 1/2 = 0,5 Hz","d":"İlk periyot 2 s olduğundan frekans 0,5 hertzdir."},{"t":"Yeni frekans","a":"2 × 0,5 = 1 Hz","d":"Frekans iki katına çıkınca 1 hertz olur."},{"t":"Yeni periyot","a":"T = 1/1","d":"Yeni periyot, yeni frekansın tersidir: 1 ÷ 1 = 1 saniye."}],"ans":"Yeni periyot 1 saniyedir; frekans iki katına çıkınca periyot yarıya iner."},{"q":"Şekildeki dalga grafiğinde art arda iki tam dalga toplam 0,3 saniyede oluşuyor. Bu dalganın frekansını bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1'/><text x='305' y='84' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='20' x2='20' y2='140' stroke='#1a2b45' stroke-width='1'/><path d='M20 80 Q50 30 80 80 Q110 130 140 80 Q170 30 200 80 Q230 130 260 80' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='150' x2='260' y2='150' stroke='#e0552b' stroke-width='1.5'/><text x='140' y='160' font-size='11' text-anchor='middle' fill='#e0552b'>2 dalga = 0,3 s</text></svg>","steps":[{"t":"Periyodu bul","a":"T = 0,3/2 = 0,15 s","d":"İki tam dalga 0,3 s sürdüğüne göre bir dalganın periyodu 0,15 saniyedir."},{"t":"Frekansı yaz","a":"f = 1/T","d":"Frekans periyodun tersidir: 1 ÷ 0,15."},{"t":"Sonuç","a":"≈ 6,67 Hz","d":"Bölme sonucu yaklaşık 6,67 hertz bulunur."}],"ans":"Dalganın frekansı yaklaşık 6,67 Hz tir."},{"q":"İki titreşim kaynağından A'nın periyodu 0,02 s, B'nin frekansı 100 Hz tir. Hangisinin frekansı büyüktür ve kaç kat?","steps":[{"t":"A'nın frekansı","a":"f = 1/0,02 = 50 Hz","d":"A kaynağının frekansı periyodun tersi olarak 50 hertzdir."},{"t":"Karşılaştır","a":"B büyük","d":"B'nin frekansı 100 Hz, A'nınki 50 Hz tir; B daha büyüktür."},{"t":"Kat bul","a":"100 ÷ 50","d":"Frekanslar oranlanınca B, A'nın 2 katıdır."}],"ans":"B kaynağının frekansı daha büyüktür ve A'nınkinin 2 katıdır."},{"q":"Bir titreşimin periyodu, frekansı 3 katına çıkarıldığında 0,1 saniye oluyor. İlk frekans kaç Hz idi?","steps":[{"t":"Son frekansı bul","a":"f₂ = 1/0,1 = 10 Hz","d":"Yeni periyot 0,1 s olduğundan yeni frekans 10 hertzdir."},{"t":"İlk frekansı yaz","a":"f₁ = f₂/3","d":"Yeni frekans ilkin 3 katı olduğundan ilk frekans, 10'un üçte biridir."},{"t":"Sonuç","a":"≈ 3,33 Hz","d":"10 ÷ 3 işlemiyle yaklaşık 3,33 hertz bulunur."}],"ans":"İlk frekans yaklaşık 3,33 Hz idi."},{"q":"Bir cisim önce 4 Hz, sonra 6 Hz ile titreşiyor. İki durumun periyotları farkını bulunuz.","steps":[{"t":"İlk periyot","a":"T₁ = 1/4 = 0,25 s","d":"4 Hz frekansın periyodu 0,25 saniyedir."},{"t":"İkinci periyot","a":"T₂ = 1/6 ≈ 0,167 s","d":"6 Hz frekansın periyodu yaklaşık 0,167 saniyedir."},{"t":"Farkı bul","a":"0,25 − 0,167","d":"İki periyot çıkarılır."}],"ans":"Periyotlar farkı yaklaşık 0,083 saniyedir."},{"q":"Bir alternatif akım kaynağı 50 Hz tir. 0,1 saniyede kaç tam periyot tamamlar?","steps":[{"t":"Periyodu bul","a":"T = 1/50 = 0,02 s","d":"50 Hz frekansın bir periyodu 0,02 saniyedir."},{"t":"Sayıyı kur","a":"0,1 ÷ 0,02","d":"Toplam süre bir periyoda bölünerek periyot sayısı bulunur."},{"t":"Sonuç","a":"5 periyot","d":"Bölme sonucu 5 tam periyot bulunur."}],"ans":"Kaynak 0,1 saniyede 5 tam periyot tamamlar."},{"q":"Şekildeki grafikte bir tam dalganın periyodu 0,25 saniyedir. Bu dalganın 2 saniyede kaç tam titreşim yaptığını bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='20' y1='80' x2='300' y2='80' stroke='#1a2b45' stroke-width='1'/><text x='305' y='84' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='20' x2='20' y2='140' stroke='#1a2b45' stroke-width='1'/><path d='M20 80 Q65 25 110 80 Q155 135 200 80' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='20' y1='150' x2='200' y2='150' stroke='#e0552b' stroke-width='1.5'/><text x='110' y='160' font-size='11' text-anchor='middle' fill='#e0552b'>T = 0,25 s</text></svg>","steps":[{"t":"Frekansı bul","a":"f = 1/0,25 = 4 Hz","d":"Periyot 0,25 s olduğundan frekans saniyede 4 titreşimdir."},{"t":"Sayıyı kur","a":"sayı = f × t","d":"Toplam titreşim sayısı frekans ile süre çarpımıdır: 4 × 2."},{"t":"Sonuç","a":"8 titreşim","d":"Çarpım sonucu 8 tam titreşim bulunur."}],"ans":"Dalga 2 saniyede 8 tam titreşim yapar."},{"q":"Bir kaynağın frekansı %25 artırılırsa periyodu yüzde kaç değişir?","steps":[{"t":"Yeni frekansı yaz","a":"f₂ = 1,25 f₁","d":"Frekans %25 artınca yeni frekans, eskinin 1,25 katı olur."},{"t":"Periyot oranı","a":"T₂/T₁ = 1/1,25","d":"Periyot frekansın tersi olduğundan oran 1 ÷ 1,25 = 0,8'dir."},{"t":"Değişimi bul","a":"%20 azalma","d":"Yeni periyot eskinin 0,8 katı, yani %20 daha küçüktür."}],"ans":"Periyot %20 azalır."},{"q":"İki dalganın periyotları toplamı 0,3 s, frekansları toplamı 25 Hz tir. Dalgalardan birinin periyodu 0,1 s ise diğerinin frekansını bulunuz.","steps":[{"t":"İkinci periyodu bul","a":"0,3 − 0,1 = 0,2 s","d":"Periyotlar toplamından birincisi çıkarılır, ikinci periyot 0,2 saniyedir."},{"t":"Frekansını yaz","a":"f = 1/0,2","d":"İkinci dalganın frekansı periyodunun tersidir: 1 ÷ 0,2."},{"t":"Sonuç","a":"5 Hz","d":"Bölme sonucu 5 hertz bulunur."}],"ans":"İkinci dalganın frekansı 5 Hz tir."},{"q":"Bir titreşim kaynağı 0,8 saniyede 16 tam titreşim yaparken sonra hızlanıp aynı sürede 24 titreşim yapıyor. Periyodundaki değişimi bulunuz.","steps":[{"t":"İlk periyot","a":"0,8 ÷ 16 = 0,05 s","d":"İlk durumda periyot, sürenin titreşim sayısına bölümüdür."},{"t":"Son periyot","a":"0,8 ÷ 24 ≈ 0,0333 s","d":"Son durumda periyot yaklaşık 0,0333 saniyedir."},{"t":"Farkı bul","a":"0,05 − 0,0333","d":"İki periyot çıkarılır, periyot kısalmıştır."}],"ans":"Periyot yaklaşık 0,0167 saniye kısalır (0,05 s'den ≈0,0333 s'ye iner)."},{"q":"Şekildeki grafikte iki ardışık tepe arası 0,4 saniye işaretlenmiştir. Bu dalganın frekansını ve 1 saniyedeki tepe sayısını bulunuz.","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='1'/><text x='305' y='94' font-size='10' fill='#1a2b45'>t</text><line x1='20' y1='25' x2='20' y2='150' stroke='#1a2b45' stroke-width='1'/><path d='M20 90 Q60 30 100 90 Q140 150 180 90 Q220 30 260 90' fill='none' stroke='#4aa3df' stroke-width='2.5'/><line x1='60' y1='30' x2='220' y2='30' stroke='#e0552b' stroke-width='1.5' stroke-dasharray='4 3'/><text x='140' y='22' font-size='11' text-anchor='middle' fill='#e0552b'>tepeler arası = 0,4 s</text></svg>","steps":[{"t":"Periyodu tanı","a":"T = 0,4 s","d":"İki ardışık tepe arası bir tam periyoda eşittir, yani 0,4 saniyedir."},{"t":"Frekansı bul","a":"f = 1/0,4 = 2,5 Hz","d":"Frekans periyodun tersidir, 1 ÷ 0,4 = 2,5 hertzdir."},{"t":"Tepe sayısı","a":"2,5 tepe","d":"Her periyotta bir tepe olduğundan 1 saniyede frekans kadar, yani 2,5 tepe oluşur."}],"ans":"Frekans 2,5 Hz tir ve 1 saniyede 2,5 tepe oluşur."},{"q":"Bir cismin periyodu T iken frekansı f'tir. Periyot 3 katına çıkarılırsa frekans nasıl değişir, oran vererek açıklayınız.","steps":[{"t":"İlişkiyi yaz","a":"f = 1/T","d":"Frekans periyot ile ters orantılıdır."},{"t":"Yeni periyodu koy","a":"T₂ = 3T","d":"Periyot 3 katına çıktığında yeni periyot 3T olur."},{"t":"Yeni frekans","a":"f₂ = 1/(3T) = f/3","d":"Yeni frekans, eski frekansın üçte biridir."}],"ans":"Periyot 3 katına çıkınca frekans üçte birine (f/3) iner."},{"q":"Bir titreşim 5 saniyede 200 tam titreşim yapıyor. Frekansını, periyodunu ve bir titreşim için geçen süreyi milisaniye cinsinden bulunuz.","steps":[{"t":"Frekansı bul","a":"f = 200/5 = 40 Hz","d":"Frekans, titreşim sayısının süreye bölünmesidir."},{"t":"Periyodu bul","a":"T = 1/40 = 0,025 s","d":"Periyot frekansın tersidir, 0,025 saniyedir."},{"t":"ms'ye çevir","a":"× 1000","d":"0,025 saniyeyi 1000 ile çarpınca 25 ms bulunur."}],"ans":"Frekans 40 Hz, periyot 0,025 saniye (25 milisaniye) dir."}]}},"sesDalgasi":{"ilkokul":{"kolay":[{"q":"Ses bir yerden başka yere nasıl ulaşır?","steps":[{"t":"Ses titreşimdir","a":"titreşir","d":"Bir cisim titreştiğinde çevresindeki havayı sarsar ve ses oluşur."},{"t":"Hava taşır","a":"hava ileri taşır","d":"Titreşen hava komşu havayı iterek sesi kulağımıza kadar ulaştırır."}],"ans":"Ses, titreşen cismin çevresindeki havayı sarsarak yayılır ve kulağımıza ulaşır."},{"q":"Davula vurduğumuzda ses neden çıkar?","fig":"<svg viewBox='0 0 320 160'><ellipse cx='120' cy='90' rx='55' ry='30' fill='#5b6b85' stroke='#1a2b45'/><rect x='65' y='90' width='110' height='40' fill='#8a99b5' stroke='#1a2b45'/><text x='120' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>Davul</text><path d='M185 75 q12 15 0 30' stroke='#e0552b' stroke-width='2' fill='none'/><path d='M200 68 q18 22 0 44' stroke='#e0552b' stroke-width='2' fill='none'/><path d='M215 60 q24 30 0 60' stroke='#e0552b' stroke-width='2' fill='none'/><text x='250' y='90' font-size='12' fill='#1a2b45'>Ses</text></svg>","steps":[{"t":"Yüzey titreşir","a":"deri titrer","d":"Vurunca davulun gergin derisi hızlıca titreşmeye başlar."},{"t":"Hava sarsılır","a":"ses çıkar","d":"Titreşen deri havayı sarstığı için ses çıkar."}],"ans":"Davulun gergin derisi titreştiği için ses çıkar."},{"q":"Ay'da, yani havasız bir yerde konuşan birini duyabilir miyiz?","steps":[{"t":"Ses neyle yayılır","a":"havayla","d":"Sesin yayılması için hava gibi bir taşıyıcı ortam gerekir."},{"t":"Ay'da hava yok","a":"duyamayız","d":"Ay'da hava olmadığı için ses yayılamaz, bu yüzden duyamayız."}],"ans":"Hayır, Ay'da hava olmadığı için ses yayılamaz ve duyamayız."},{"q":"Kalın bir ip ile ince bir ipi çektiğimizde hangisi daha kalın (pes) ses verir?","steps":[{"t":"Kalınlığa bak","a":"kalın olan","d":"Kalın teller yavaş titreşir."},{"t":"Sesi belirle","a":"kalın ses","d":"Yavaş titreşim kalın (pes) ses verir."}],"ans":"Kalın ip daha kalın (pes) ses verir, çünkü daha yavaş titreşir."},{"q":"Bir arkadaşımız çok uzaktan bağırınca sesini neden daha zor duyarız?","steps":[{"t":"Ses yayılır","a":"her yöne dağılır","d":"Ses kaynaktan uzaklaştıkça her yöne dağılır."},{"t":"Zayıflar","a":"daha sessiz","d":"Uzaklaştıkça ses zayıflar, bu yüzden duymak zorlaşır."}],"ans":"Ses uzaklaştıkça dağılıp zayıfladığı için uzaktan gelen sesi daha zor duyarız."}],"zor":[{"q":"Bir telefonun sesini açtığımızda (yükselttiğimizde) sesin nesi değişir?","steps":[{"t":"Ne arttı","a":"şiddeti","d":"Ses açıldığında sesin gürlüğü, yani şiddeti artar."},{"t":"Nasıl duyarız","a":"daha gür","d":"Daha şiddetli ses bize daha yüksek (gür) gelir."}],"ans":"Sesi açınca sesin şiddeti artar ve daha gür duyulur."},{"q":"Boş bir kovaya ve dolu bir kovaya vurduğumuzda neden farklı sesler çıkar?","steps":[{"t":"İçindeki ne","a":"hava ya da su","d":"Boş kovada hava, dolu kovada su vardır."},{"t":"Titreşim farkı","a":"farklı ses","d":"İçindekiler farklı titreştiği için sesler de farklı çıkar."}],"ans":"İçlerindeki madde farklı titreştiği için boş ve dolu kova farklı ses verir."},{"q":"Bir dağ eteğinde bağırınca sesimizin bize geri dönmesine ne denir?","steps":[{"t":"Ses çarpar","a":"kayaya çarpar","d":"Ses dağdaki sert kayalara çarpar."},{"t":"Geri döner","a":"yankı","d":"Çarpan ses geri döner; buna yankı denir."}],"ans":"Sesin sert bir yüzeye çarpıp geri dönmesine yankı denir."},{"q":"Kuru bir tahta çubuğa vurunca neden ince, kalın bir kütüğe vurunca kalın ses çıkar?","steps":[{"t":"Boyuta bak","a":"küçük hızlı titrer","d":"İnce çubuk hızlı, büyük kütük yavaş titreşir."},{"t":"Sesi eşleştir","a":"ince/kalın","d":"Hızlı titreşim ince ses, yavaş titreşim kalın ses verir."}],"ans":"İnce çubuk hızlı titreşip ince ses, büyük kütük yavaş titreşip kalın ses verir."},{"q":"Bir misket havuza, biri su dolu bardağa düşüyor. Sesin yayılması için ikisinde de ne ortak gerekir?","steps":[{"t":"Ses neye ihtiyaç duyar","a":"bir ortam","d":"Ses yayılmak için mutlaka bir maddeye (ortama) ihtiyaç duyar."},{"t":"Ortak olan","a":"su ve hava","d":"Her ikisinde de su ve hava gibi bir taşıyıcı ortam vardır."}],"ans":"Sesin yayılması için her durumda hava ya da su gibi bir taşıyıcı ortam gerekir."}]},"ortaokul":{"kolay":[{"q":"Ses dalgası enine mi yoksa boyuna dalga mıdır, kısaca açıklayınız.","fig":"<svg viewBox='0 0 320 120'><text x='30' y='20' font-size='12' fill='#1a2b45'>Sıkışma ve seyrelme</text><line x1='40' y1='40' x2='40' y2='100' stroke='#1a2b45'/><line x1='48' y1='40' x2='48' y2='100' stroke='#1a2b45'/><line x1='54' y1='40' x2='54' y2='100' stroke='#1a2b45'/><line x1='80' y1='40' x2='80' y2='100' stroke='#1a2b45'/><line x1='110' y1='40' x2='110' y2='100' stroke='#1a2b45'/><line x1='140' y1='40' x2='140' y2='100' stroke='#1a2b45'/><line x1='146' y1='40' x2='146' y2='100' stroke='#1a2b45'/><line x1='152' y1='40' x2='152' y2='100' stroke='#1a2b45'/><line x1='180' y1='40' x2='180' y2='100' stroke='#1a2b45'/><line x1='210' y1='40' x2='210' y2='100' stroke='#1a2b45'/><line x1='240' y1='40' x2='240' y2='100' stroke='#1a2b45'/><line x1='246' y1='40' x2='246' y2='100' stroke='#1a2b45'/><line x1='252' y1='40' x2='252' y2='100' stroke='#1a2b45'/><polygon points='290,65 300,70 290,75' fill='#e0552b'/><line x1='265' y1='70' x2='300' y2='70' stroke='#e0552b' stroke-width='1.5'/><text x='278' y='60' font-size='10' text-anchor='middle' fill='#e0552b'>yön</text></svg>","steps":[{"t":"Titreşim yönü","a":"yayılma yönünde","d":"Ses dalgasında hava molekülleri dalganın ilerlediği yönde ileri geri titreşir."},{"t":"Dalga türü","a":"boyuna","d":"Titreşim, yayılma yönüyle aynı doğrultuda olduğu için ses boyuna dalgadır."}],"ans":"Ses, titreşim yönü ile yayılma yönü aynı olan boyuna (mekanik) bir dalgadır."},{"q":"Ses neden boşlukta (vakumda) yayılamaz?","steps":[{"t":"Ses ne gerektirir","a":"madde ortamı","d":"Ses mekanik dalga olduğu için yayılmak için titreşecek bir maddeye ihtiyaç duyar."},{"t":"Boşlukta ne yok","a":"madde yok","d":"Vakumda titreşecek molekül bulunmadığı için ses ilerleyemez."}],"ans":"Ses mekanik dalgadır; boşlukta titreşecek madde olmadığı için yayılamaz."},{"q":"Ses en hızlı katıda mı, sıvıda mı, yoksa gazda mı yayılır?","steps":[{"t":"Moleküllere bak","a":"katıda sık","d":"Katıda moleküller birbirine çok yakındır, titreşimi hemen komşuya aktarır."},{"t":"Hız sırası","a":"katı > sıvı > gaz","d":"Moleküller seyrekleştikçe ses yavaşlar; bu yüzden katı > sıvı > gaz sırası olur."}],"ans":"Ses en hızlı katıda, sonra sıvıda, en yavaş gazda yayılır."},{"q":"İnce bir telin sesi tiz (ince), kalın bir telin sesi pes (kalın) çıkar. Bunu belirleyen büyüklük nedir?","steps":[{"t":"İlişkili büyüklük","a":"frekans","d":"Sesin ince ya da kalın olması titreşim sayısına, yani frekansa bağlıdır."},{"t":"İlişki","a":"yüksek/düşük frekans","d":"Yüksek frekans tiz (ince), düşük frekans pes (kalın) ses verir."}],"ans":"Sesin inceliği kalınlığı frekansa bağlıdır; yüksek frekans tiz, düşük frekans pes sestir."},{"q":"Aynı notayı çalan keman ile flütü gözümüz kapalıyken nasıl ayırt ederiz?","steps":[{"t":"Fark eden özellik","a":"tını","d":"Frekans aynı olsa bile her çalgının kendine özgü bir ses rengi vardır; buna tını denir."},{"t":"Nasıl ayırırız","a":"tınıdan","d":"Tını farklı olduğu için sesleri birbirinden ayırt ederiz."}],"ans":"Çalgıların tınısı (ses rengi) farklı olduğu için aynı notayı bile ayırt edebiliriz."}],"zor":[{"q":"Sesin havadaki hızı 340 m/s olduğuna göre 5 saniyede kaç metre yol alır?","steps":[{"t":"Bağıntı","a":"yol = hız × süre","d":"Alınan yol, hız ile sürenin çarpımıyla bulunur."},{"t":"Yerine koy","a":"340 × 5","d":"Hız 340 m/s ve süre 5 s yerine konur."},{"t":"Sonuç","a":"1700 m","d":"Çarpım sonucu 1700 m bulunur."}],"ans":"Ses 5 saniyede 1700 metre yol alır."},{"q":"Bir kişi bağırıyor; sesi 680 m uzaktaki kayadan yansıyıp geri dönüyor. Ses hızı 340 m/s ise yankıyı kaç saniye sonra duyar?","fig":"<svg viewBox='0 0 320 130'><circle cx='40' cy='80' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='40' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>Kişi</text><polygon points='250,30 290,30 290,110 250,110 260,70' fill='#8a99b5' stroke='#1a2b45'/><text x='270' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>Kaya</text><line x1='55' y1='75' x2='248' y2='75' stroke='#e0552b' stroke-width='1.5'/><polygon points='248,75 238,71 238,79' fill='#e0552b'/><line x1='248' y1='88' x2='55' y2='88' stroke='#4aa3df' stroke-width='1.5'/><polygon points='55,88 65,84 65,92' fill='#4aa3df'/><text x='150' y='68' font-size='10' text-anchor='middle' fill='#1a2b45'>680 m</text></svg>","steps":[{"t":"Toplam yol","a":"gidiş + dönüş","d":"Ses kayaya gidip geri döndüğü için toplam yol 680 m × 2 = 1360 m'dir."},{"t":"Süreyi bul","a":"yol ÷ hız","d":"Süre = toplam yol ÷ hız = 1360 ÷ 340 olarak hesaplanır."},{"t":"Sonuç","a":"4 s","d":"Bölme sonucu 4 saniye bulunur."}],"ans":"Kişi yankıyı 4 saniye sonra duyar."},{"q":"Bir ses dalgasının frekansı arttığında, sesin tizliği ve dalga boyu nasıl değişir?","steps":[{"t":"Tizlik","a":"artar","d":"Frekans arttıkça ses daha tiz (ince) duyulur."},{"t":"Dalga boyu","a":"azalır","d":"Hız sabitken frekans artarsa dalga boyu kısalır (λ = v/f)."}],"ans":"Frekans artınca ses tizleşir ve dalga boyu kısalır."},{"q":"İnsan kulağının duyabildiği ses aralığı yaklaşık nedir ve bu aralığın altı ile üstüne ne ad verilir?","fig":"<svg viewBox='0 0 320 110'><line x1='20' y1='60' x2='300' y2='60' stroke='#1a2b45' stroke-width='2'/><line x1='100' y1='50' x2='100' y2='70' stroke='#1a2b45'/><line x1='230' y1='50' x2='230' y2='70' stroke='#1a2b45'/><text x='100' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>20 Hz</text><text x='230' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>20 kHz</text><rect x='100' y='52' width='130' height='16' fill='#4aa3df'/><text x='165' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>işitilebilir</text><text x='55' y='40' font-size='10' text-anchor='middle' fill='#e0552b'>infrason</text><text x='270' y='40' font-size='10' text-anchor='middle' fill='#e0552b'>ultrason</text></svg>","steps":[{"t":"İşitme aralığı","a":"20 Hz – 20 kHz","d":"İnsan kulağı yaklaşık 20 Hz ile 20.000 Hz arasındaki sesleri duyar."},{"t":"Sınır dışı sesler","a":"infrason/ultrason","d":"20 Hz altı sesler infrason, 20 kHz üstü sesler ultrason olarak adlandırılır."}],"ans":"İnsan 20 Hz – 20 kHz arası sesleri duyar; altı infrason, üstü ultrason adını alır."},{"q":"Şimşeği gördükten 3 saniye sonra gök gürültüsünü duyuyoruz. Ses hızı 340 m/s ise şimşek yaklaşık kaç metre uzakta çakmıştır?","steps":[{"t":"Bağıntı","a":"yol = hız × süre","d":"Işık anında ulaştığı için süreyi sesin yoluna çeviririz: yol = hız × süre."},{"t":"Yerine koy","a":"340 × 3","d":"Hız 340 m/s, süre 3 s yerine konur."},{"t":"Sonuç","a":"1020 m","d":"Çarpım sonucu yaklaşık 1020 m bulunur."}],"ans":"Şimşek yaklaşık 1020 metre uzakta çakmıştır."}]},"lise":{"kolay":[{"q":"Ses dalgasının boyuna mekanik dalga olması ne anlama gelir?","steps":[{"t":"Mekanik dalga","a":"ortam gerekir","d":"Mekanik dalga yayılmak için maddesel bir ortama ihtiyaç duyar, boşlukta ilerleyemez."},{"t":"Boyuna olması","a":"titreşim yayılma yönünde","d":"Ortam molekülleri dalganın ilerleme doğrultusunda ileri geri titreşir."}],"ans":"Ses, ortam gerektiren ve moleküllerin yayılma yönünde titreştiği boyuna mekanik bir dalgadır."},{"q":"Bir ses dalgasında sıkışma ve seyrelme bölgeleri neyi ifade eder?","fig":"<svg viewBox='0 0 320 120'><line x1='35' y1='35' x2='35' y2='95' stroke='#1a2b45'/><line x1='42' y1='35' x2='42' y2='95' stroke='#1a2b45'/><line x1='48' y1='35' x2='48' y2='95' stroke='#1a2b45'/><line x1='85' y1='35' x2='85' y2='95' stroke='#1a2b45'/><line x1='130' y1='35' x2='130' y2='95' stroke='#1a2b45'/><line x1='137' y1='35' x2='137' y2='95' stroke='#1a2b45'/><line x1='143' y1='35' x2='143' y2='95' stroke='#1a2b45'/><line x1='180' y1='35' x2='180' y2='95' stroke='#1a2b45'/><line x1='225' y1='35' x2='225' y2='95' stroke='#1a2b45'/><line x1='232' y1='35' x2='232' y2='95' stroke='#1a2b45'/><line x1='238' y1='35' x2='238' y2='95' stroke='#1a2b45'/><text x='42' y='25' font-size='10' text-anchor='middle' fill='#e0552b'>sıkışma</text><text x='107' y='110' font-size='10' text-anchor='middle' fill='#4aa3df'>seyrelme</text><text x='137' y='25' font-size='10' text-anchor='middle' fill='#e0552b'>sıkışma</text></svg>","steps":[{"t":"Sıkışma","a":"yüksek basınç","d":"Sıkışma, moleküllerin sıklaştığı, basıncın arttığı bölgedir."},{"t":"Seyrelme","a":"düşük basınç","d":"Seyrelme, moleküllerin aralandığı, basıncın azaldığı bölgedir."}],"ans":"Sıkışma moleküllerin sıklaşıp basıncın arttığı, seyrelme ise aralanıp basıncın azaldığı bölgedir."},{"q":"Sesin yayılma hızının katı > sıvı > gaz sıralamasında olmasının nedeni nedir?","steps":[{"t":"Moleküller arası bağ","a":"katıda güçlü","d":"Katılarda moleküller birbirine sıkı bağlıdır, titreşimi hızla komşuya iletir."},{"t":"Hız sırası","a":"katı > sıvı > gaz","d":"Bağ zayıfladıkça (sıvı, gaz) titreşim daha yavaş aktarılır, ses yavaşlar."}],"ans":"Moleküller arası bağ katıda en güçlü olduğundan titreşim en hızlı katıda iletilir; hız katı > sıvı > gaz olur."},{"q":"Sesin yüksekliği (tizlik/peslik) hangi dalga büyüklüğüne bağlıdır?","steps":[{"t":"İlgili büyüklük","a":"frekans","d":"Sesin yüksekliği, saniyedeki titreşim sayısı olan frekansa bağlıdır."},{"t":"İlişki","a":"yüksek f → tiz","d":"Frekans büyüdükçe ses tizleşir (incelir), küçüldükçe pesleşir (kalınlaşır)."}],"ans":"Sesin yüksekliği frekansa bağlıdır; yüksek frekans tiz, düşük frekans pes ses verir."},{"q":"Sesin şiddeti (gürlüğü) hangi büyüklükle ilişkilidir ve hangi birimle ölçülür?","fig":"<svg viewBox='0 0 320 120'><line x1='20' y1='60' x2='300' y2='60' stroke='#1a2b45'/><path d='M20 60 Q35 20 50 60 T80 60' stroke='#e0552b' stroke-width='2' fill='none'/><text x='50' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>büyük genlik</text><path d='M180 60 Q188 48 196 60 T212 60' stroke='#4aa3df' stroke-width='2' fill='none'/><text x='210' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>küçük genlik</text></svg>","steps":[{"t":"İlgili büyüklük","a":"genlik","d":"Sesin şiddeti dalganın genliğiyle artar; büyük genlik gür ses verir."},{"t":"Birim","a":"desibel (dB)","d":"Ses şiddet düzeyi desibel (dB) birimiyle ifade edilir."}],"ans":"Sesin şiddeti genliğe bağlıdır ve şiddet düzeyi desibel (dB) ile ölçülür."},{"q":"Tını (ses rengi) nedir ve neden iki çalgının aynı notası farklı duyulur?","steps":[{"t":"Tını tanımı","a":"ses rengi","d":"Tını, bir sesi diğerinden ayıran, ana frekansa eşlik eden ek frekanslardan (harmoniklerden) doğan özelliktir."},{"t":"Çalgı farkı","a":"farklı harmonikler","d":"Her çalgı farklı harmonik karışımı ürettiği için aynı nota farklı tınıda duyulur."}],"ans":"Tını, harmoniklerin oluşturduğu ses rengidir; çalgıların harmonikleri farklı olduğu için aynı nota farklı duyulur."},{"q":"Yankı (eko) olayı nasıl oluşur?","steps":[{"t":"Sesin çarpması","a":"sert yüzey","d":"Ses dalgası uzak ve sert bir yüzeye çarpar."},{"t":"Geri dönüş","a":"yansıma","d":"Yüzeye çarpan ses yansıyarak kaynağa geri döner ve gecikmeli olarak tekrar duyulur."}],"ans":"Yankı, sesin sert bir yüzeye çarpıp yansıyarak gecikmeli biçimde geri dönmesiyle oluşur."},{"q":"İnsan kulağının işitme aralığı nedir; infrason ve ultrason bu aralığa göre nasıl tanımlanır?","steps":[{"t":"İşitme aralığı","a":"20 Hz – 20 kHz","d":"İnsan kulağı yaklaşık 20 Hz ile 20.000 Hz arası frekansları duyabilir."},{"t":"Sınır dışı","a":"infrason / ultrason","d":"20 Hz'in altı infrason, 20 kHz'in üstü ultrasondur ve insan tarafından duyulmaz."}],"ans":"İşitme aralığı 20 Hz – 20 kHz'tir; altı infrason, üstü ultrason olup duyulamaz."},{"q":"Sonar sistemi ultrason dalgalarını hangi amaçla kullanır?","fig":"<svg viewBox='0 0 320 140'><rect x='0' y='30' width='320' height='10' fill='#4aa3df'/><polygon points='40,30 70,30 65,45 45,45' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='25' font-size='10' text-anchor='middle' fill='#1a2b45'>Gemi</text><path d='M55 45 q15 25 0 50' stroke='#e0552b' stroke-width='1.5' fill='none'/><path d='M55 45 q28 30 0 70' stroke='#e0552b' stroke-width='1.5' fill='none'/><ellipse cx='150' cy='115' rx='40' ry='12' fill='#8a99b5' stroke='#1a2b45'/><text x='150' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>Deniz tabanı</text></svg>","steps":[{"t":"Dalga gönderir","a":"ultrason yollar","d":"Sonar, suya ultrason dalgası gönderir."},{"t":"Yankıyı ölçer","a":"süreden uzaklık","d":"Dalganın yansıyıp geri dönme süresinden hedefin uzaklığı hesaplanır."}],"ans":"Sonar, gönderdiği ultrasonun yansıma süresini ölçerek su altındaki cisimlerin ve tabanın derinliğini belirler."},{"q":"Bir ses dalgasının dalga boyu, frekansı ve hızı arasındaki temel bağıntı nedir?","steps":[{"t":"Bağıntı","a":"v = f × λ","d":"Dalga hızı, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Anlamı","a":"v sabitse ters orantı","d":"Aynı ortamda hız sabit olduğundan frekans artarsa dalga boyu kısalır."}],"ans":"Temel bağıntı v = f × λ'dır; aynı ortamda hız sabit olduğu için frekans ile dalga boyu ters orantılıdır."},{"q":"Havanın sıcaklığı artarsa sesin havadaki hızı nasıl değişir?","steps":[{"t":"Sıcaklık etkisi","a":"moleküller hızlanır","d":"Sıcaklık arttıkça hava molekülleri daha hızlı hareket eder."},{"t":"Hıza etkisi","a":"ses hızı artar","d":"Daha hızlı moleküller titreşimi daha çabuk aktardığı için ses hızı artar."}],"ans":"Sıcaklık artınca hava molekülleri hızlandığı için sesin havadaki hızı artar."},{"q":"Ses hızı 340 m/s olan havada frekansı 170 Hz olan sesin dalga boyu kaç metredir?","steps":[{"t":"Bağıntı","a":"λ = v / f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"340 ÷ 170","d":"Hız 340 m/s, frekans 170 Hz yerine konur."},{"t":"Sonuç","a":"2 m","d":"Bölme sonucu dalga boyu 2 m bulunur."}],"ans":"Sesin dalga boyu 2 metredir."},{"q":"Sesin enerjisi (şiddeti) kaynaktan uzaklaştıkça neden azalır?","steps":[{"t":"Yayılma biçimi","a":"küresel dağılım","d":"Ses enerjisi kaynaktan her yöne küresel olarak yayılır."},{"t":"Sonuç","a":"birim alana düşen azalır","d":"Yüzey büyüdükçe birim alana düşen enerji, yani şiddet azalır."}],"ans":"Ses enerjisi geniş bir yüzeye yayıldığı için kaynaktan uzaklaştıkça birim alana düşen şiddet azalır."},{"q":"Bir flüt aynı şiddette ama daha tiz bir nota çalarsa sesin frekansı ve genliği nasıl değişir?","steps":[{"t":"Tizlik","a":"frekans artar","d":"Daha tiz ses, daha yüksek frekans demektir."},{"t":"Şiddet","a":"genlik aynı","d":"Şiddet (gürlük) değişmediğine göre genlik aynı kalır."}],"ans":"Daha tiz nota frekansı artırır; şiddet sabit olduğu için genlik değişmez."},{"q":"Sesin desibel (dB) cinsinden ölçülen şiddet düzeyi neyi ifade eder?","steps":[{"t":"dB nedir","a":"şiddet düzeyi","d":"Desibel, sesin şiddetini referans bir şiddete göre logaritmik olarak ifade eden birimdir."},{"t":"Anlamı","a":"gürlük ölçüsü","d":"dB değeri büyüdükçe ses daha gür algılanır; örneğin fısıltı düşük, gürültü yüksek dB'dir."}],"ans":"Desibel, sesin şiddetini referansa göre logaritmik olarak veren, gürlük düzeyini gösteren birimdir."}],"zor":[{"q":"Ses hızı 1500 m/s olan deniz suyunda, bir sonar dalgası tabandan yansıyıp 0,4 s sonra geri dönüyor. Tabanın derinliği kaç metredir?","fig":"<svg viewBox='0 0 320 140'><rect x='0' y='25' width='320' height='8' fill='#4aa3df'/><polygon points='130,25 180,25 175,38 135,38' fill='#5b6b85' stroke='#1a2b45'/><text x='155' y='20' font-size='10' text-anchor='middle' fill='#1a2b45'>Sonar</text><line x1='155' y1='38' x2='155' y2='108' stroke='#e0552b' stroke-width='1.5'/><polygon points='155,108 151,98 159,98' fill='#e0552b'/><line x1='170' y1='108' x2='170' y2='38' stroke='#4aa3df' stroke-width='1.5'/><polygon points='170,38 166,48 174,48' fill='#4aa3df'/><ellipse cx='160' cy='118' rx='90' ry='10' fill='#8a99b5' stroke='#1a2b45'/><text x='250' y='90' font-size='10' fill='#1a2b45'>h=?</text></svg>","steps":[{"t":"Toplam yol","a":"yol = v × t","d":"Toplam yol = hız × süre = 1500 × 0,4 = 600 m'dir."},{"t":"Derinlik","a":"yol ÷ 2","d":"Dalga gidip geldiği için derinlik toplam yolun yarısıdır: 600 ÷ 2."},{"t":"Sonuç","a":"300 m","d":"Bölme sonucu derinlik 300 m bulunur."}],"ans":"Tabanın derinliği 300 metredir."},{"q":"Bir kişi ile duvar arasındaki uzaklık 510 m'dir. Ses hızı 340 m/s ise bağıran kişi yankıyı kaç saniye sonra duyar?","steps":[{"t":"Toplam yol","a":"2 × 510 = 1020 m","d":"Ses duvara gidip döndüğü için toplam yol uzaklığın iki katıdır."},{"t":"Süre","a":"t = yol ÷ v","d":"Süre = 1020 ÷ 340 olarak hesaplanır."},{"t":"Sonuç","a":"3 s","d":"Bölme sonucu yankı 3 saniye sonra duyulur."}],"ans":"Kişi yankıyı 3 saniye sonra duyar."},{"q":"Bir ses kaynağının havadaki dalga boyu 1,7 m, ses hızı 340 m/s ise frekansı kaç Hz'dir ve bu ses duyulabilir mi?","steps":[{"t":"Frekansı bul","a":"f = v / λ","d":"Frekans = hız ÷ dalga boyu = 340 ÷ 1,7 olarak hesaplanır."},{"t":"Hesapla","a":"200 Hz","d":"Bölme sonucu frekans 200 Hz bulunur."},{"t":"Duyulurluk","a":"evet","d":"200 Hz, 20 Hz – 20 kHz işitme aralığında olduğu için duyulabilir."}],"ans":"Frekans 200 Hz'tir ve işitme aralığında olduğu için duyulabilir."},{"q":"Aynı ses çubuğu önce demir çubukta (v=5000 m/s) sonra havada (v=340 m/s) yayılıyor. Frekans 1000 Hz sabit kalırsa iki ortamdaki dalga boylarının oranını bulunuz.","steps":[{"t":"Demirde dalga boyu","a":"λ = 5000/1000 = 5 m","d":"Demirdeki dalga boyu hızın frekansa bölümüdür."},{"t":"Havada dalga boyu","a":"λ = 340/1000 = 0,34 m","d":"Havadaki dalga boyu aynı yolla bulunur."},{"t":"Oranı kur","a":"5 ÷ 0,34","d":"Demirdeki dalga boyunu havadakine böleriz."}],"ans":"Demirdeki dalga boyu, havadakinin yaklaşık 14,7 katıdır (5 m'ye karşı 0,34 m)."},{"q":"Bir gözlemci şimşeği görüp 6 saniye sonra gök gürültüsünü duyuyor. Ardından şimşek yaklaşıyor ve süre 2 saniyeye düşüyor. Şimşek kaç metre yaklaşmıştır? (v=340 m/s)","fig":"<svg viewBox='0 0 320 130'><polyline points='60,15 50,45 70,45 55,80' stroke='#ffd54a' stroke-width='3' fill='none'/><polyline points='230,15 220,45 240,45 225,80' stroke='#ffd54a' stroke-width='3' fill='none'/><circle cx='150' cy='100' r='10' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='125' font-size='10' text-anchor='middle' fill='#1a2b45'>Gözlemci</text><text x='55' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>6 s</text><text x='235' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>2 s</text></svg>","steps":[{"t":"İlk uzaklık","a":"340 × 6 = 2040 m","d":"İlk uzaklık ses hızı ile ilk sürenin çarpımıdır."},{"t":"Son uzaklık","a":"340 × 2 = 680 m","d":"Son uzaklık aynı yolla 680 m bulunur."},{"t":"Yaklaşma miktarı","a":"2040 − 680","d":"İki uzaklığın farkı şimşeğin yaklaşma miktarını verir."}],"ans":"Şimşek 1360 metre yaklaşmıştır (2040 m'den 680 m'ye)."},{"q":"Sesin şiddet düzeyi 60 dB'den 90 dB'ye çıkarsa, sesin algılanan gürlüğü ve enerjisi hakkında ne söylenebilir?","steps":[{"t":"dB artışı","a":"30 dB artış","d":"Şiddet düzeyi 30 dB artmıştır; desibel logaritmik bir ölçektir."},{"t":"Enerji etkisi","a":"çok büyük artış","d":"Her 10 dB artış şiddetin 10 katına çıkması demektir; 30 dB artış şiddetin 1000 katı olması anlamına gelir."}],"ans":"60 dB'den 90 dB'ye çıkış, sesin şiddetinin (enerjisinin) yaklaşık 1000 katına çıkması ve çok daha gür algılanması demektir."},{"q":"Yarasa, çıkardığı ultrason 0,02 saniye sonra bir böcekten yansıyıp dönerse böcek kaç metre uzaktadır? (v=340 m/s)","steps":[{"t":"Toplam yol","a":"v × t = 340 × 0,02","d":"Toplam yol hız ile sürenin çarpımıdır: 6,8 m."},{"t":"Uzaklık","a":"yol ÷ 2","d":"Ses gidip geldiği için böceğin uzaklığı toplam yolun yarısıdır."},{"t":"Sonuç","a":"3,4 m","d":"6,8 m'nin yarısı 3,4 m'dir."}],"ans":"Böcek yarasadan 3,4 metre uzaktadır."},{"q":"Frekansı 680 Hz olan bir sesin havadaki (v=340 m/s) iki ardışık sıkışma bölgesi arasındaki uzaklık kaç metredir?","steps":[{"t":"Hangi büyüklük","a":"dalga boyu","d":"İki ardışık sıkışma arası uzaklık tam bir dalga boyuna eşittir."},{"t":"Hesapla","a":"λ = v/f = 340/680","d":"Dalga boyu hızın frekansa bölümüdür."},{"t":"Sonuç","a":"0,5 m","d":"Bölme sonucu 0,5 m bulunur."}],"ans":"İki ardışık sıkışma arası uzaklık 0,5 metredir (bir dalga boyu)."},{"q":"Aynı şiddette iki ses; biri 200 Hz diğeri 4000 Hz. Hangisi daha tiz duyulur ve genlikleri nasıl karşılaştırılır?","steps":[{"t":"Tizlik","a":"4000 Hz tiz","d":"Frekansı yüksek olan 4000 Hz'lik ses daha tiz duyulur."},{"t":"Genlik","a":"yaklaşık eşit","d":"Şiddetleri (gürlükleri) aynı verildiği için genlikleri de yaklaşık eşittir."}],"ans":"4000 Hz'lik ses daha tizdir; şiddetleri aynı olduğu için genlikleri yaklaşık eşittir."},{"q":"Bir denizaltı sonarı düşmandan 2,1 saniyede yankı alıyor. Deniz suyunda ses hızı 1500 m/s ise hedef kaç metre uzaktadır?","steps":[{"t":"Toplam yol","a":"v × t = 1500 × 2,1","d":"Toplam yol hız ile sürenin çarpımıdır: 3150 m."},{"t":"Uzaklık","a":"yol ÷ 2","d":"Dalga gidip döndüğü için hedef uzaklığı toplam yolun yarısıdır."},{"t":"Sonuç","a":"1575 m","d":"3150 m'nin yarısı 1575 m'dir."}],"ans":"Hedef 1575 metre uzaktadır."},{"q":"Ses havadan (v=340 m/s) suya (v=1500 m/s) geçtiğinde frekansı değişmezken dalga boyu nasıl değişir, nedeniyle açıklayınız.","steps":[{"t":"Frekans","a":"sabit kalır","d":"Bir dalga ortam değiştirdiğinde kaynağın belirlediği frekans değişmez."},{"t":"Bağıntı","a":"λ = v/f","d":"Hız arttığı (340 → 1500) ve frekans sabit kaldığı için dalga boyu artar."},{"t":"Sonuç","a":"dalga boyu artar","d":"Suda hız yaklaşık 4,4 kat fazla olduğu için dalga boyu da yaklaşık 4,4 kat uzar."}],"ans":"Frekans sabit kaldığından, su içinde hız arttığı için dalga boyu yaklaşık 4,4 kat uzar."},{"q":"Bir gözlemci, 1190 m uzaktaki bir kayaya doğru bağırıyor ve aynı anda 340 m/s hızla kayaya doğru yürümeye başlıyor. Ses hızı 340 m/s ise kişi yankıyı duyana kadar ne kadar süre geçer (kişinin hareketini ihmal ederek sesin yolunu hesaplayınız)?","steps":[{"t":"Toplam ses yolu","a":"2 × 1190 m","d":"Ses kayaya gidip döner; yaklaşık toplam yol 1190 × 2 = 2380 m'dir."},{"t":"Süreyi bul","a":"t = yol ÷ v","d":"Süre = 2380 ÷ 340 olarak hesaplanır."},{"t":"Sonuç","a":"7 s","d":"Bölme sonucu yaklaşık 7 saniye bulunur."}],"ans":"Kişi yankıyı yaklaşık 7 saniye sonra duyar."},{"q":"Bir telin titreşim frekansı 256 Hz iken tını farkı dışında, telin gerginliği artırılırsa çıkan sesin yüksekliği (tizliği) nasıl değişir?","steps":[{"t":"Gerginlik etkisi","a":"frekans artar","d":"Tel gerildikçe daha hızlı titreşir, frekansı artar."},{"t":"Sese etkisi","a":"daha tiz","d":"Frekans arttığı için ses daha tiz (ince) duyulur."}],"ans":"Telin gerginliği artınca frekans yükselir ve ses daha tiz (ince) duyulur."},{"q":"Havada 340 m/s hızla giden bir ses dalgasının periyodu 0,004 s ise frekansını ve dalga boyunu bulunuz.","steps":[{"t":"Frekans","a":"f = 1/T","d":"Frekans periyodun tersidir: 1 ÷ 0,004 = 250 Hz."},{"t":"Dalga boyu","a":"λ = v/f","d":"Dalga boyu hızın frekansa bölümüdür: 340 ÷ 250."},{"t":"Sonuç","a":"1,36 m","d":"Bölme sonucu dalga boyu 1,36 m bulunur."}],"ans":"Sesin frekansı 250 Hz, dalga boyu 1,36 metredir."},{"q":"İki ses dalgasının genlikleri eşit, biri infrason (10 Hz) diğeri ultrason (30000 Hz). İnsan kulağı bu seslerden hangilerini duyabilir, gerekçesiyle belirtiniz.","steps":[{"t":"İşitme aralığı","a":"20 Hz – 20 kHz","d":"İnsan kulağı yalnızca 20 Hz ile 20.000 Hz arasındaki frekansları duyabilir."},{"t":"Değerlendir","a":"ikisi de duyulmaz","d":"10 Hz aralığın altında (infrason), 30000 Hz aralığın üstündedir (ultrason)."}],"ans":"İkisi de duyulmaz; 10 Hz infrason olarak aralığın altında, 30000 Hz ultrason olarak aralığın üstünde kalır."}]}},"suDalgasi":{"ilkokul":{"kolay":[{"q":"Durgun bir suya küçük bir taş atınca su yüzeyinde ne oluşur?","steps":[{"t":"Suya dokunma","a":"sarsıntı","d":"Taş suya düşünce o noktada suyu titretir, suyu bir an aşağı bastırır."},{"t":"Yayılma","a":"halkalar","d":"Bu titreşim çevreye yayılarak <b>halka halka su dalgaları</b> oluşturur."}],"ans":"Suya taş atınca, dışa doğru yayılan halka şeklinde su dalgaları oluşur."},{"q":"Şekildeki gibi suya bir damla düşünce oluşan dalgalar hangi şekildedir?","fig":"<svg viewBox='0 0 320 150'><rect x='10' y='95' width='300' height='45' fill='#4aa3df'/><circle cx='160' cy='95' r='14' fill='none' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='95' r='32' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='160' cy='95' r='50' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='160' cy='95' r='68' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='160' cy='40' r='5' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='30' font-size='11' text-anchor='middle' fill='#1a2b45'>Damla</text></svg>","steps":[{"t":"Şekle bak","a":"iç içe halkalar","d":"Damlanın düştüğü noktadan dışa doğru iç içe halkalar görünür."},{"t":"Sonuç","a":"dairesel dalga","d":"Bir noktadan yayılan bu halkalara <b>dairesel su dalgası</b> denir."}],"ans":"Bir noktadan yayıldığı için daire (halka) şeklinde su dalgaları oluşur."},{"q":"Suyun yüzeyinde yüzen bir yaprak, dalga gelince ileri sürüklenir mi yoksa olduğu yerde inip kalkar mı?","steps":[{"t":"Yaprağı izle","a":"inip kalkar","d":"Dalga gelince yaprak aşağı yukarı sallanır, suyla birlikte uzağa gitmez."},{"t":"Sonuç","a":"madde taşınmaz","d":"Dalga ilerlerken suyu taşımaz; sadece <b>hareketi (enerjiyi)</b> taşır."}],"ans":"Yaprak olduğu yerde inip kalkar; dalga suyu değil, hareketi taşır."},{"q":"Denizde dalgalar genellikle hangi yöne doğru gider?","steps":[{"t":"Gözlem","a":"kıyıya doğru","d":"Denizde oluşan dalgalar sıra sıra kıyıya doğru ilerler."},{"t":"Sonuç","a":"yayılma yönü","d":"Dalgalar oluştukları yerden çevreye, kıyıya doğru <b>yayılır</b>."}],"ans":"Deniz dalgaları genellikle kıyıya doğru ilerler."},{"q":"Küvette elini suya batırıp düz bir tahtayı ileri geri sallarsan nasıl dalgalar oluşur?","steps":[{"t":"Düz engel","a":"düz titreşim","d":"Düz tahta suyu boydan boya aynı anda iter, böylece düz bir kabarık oluşur."},{"t":"Sonuç","a":"doğrusal dalga","d":"Bu düz kabarıklar arka arkaya yayılarak <b>doğrusal (düz) su dalgaları</b> oluşturur."}],"ans":"Düz tahta, düz çizgiler hâlinde ilerleyen doğrusal su dalgaları oluşturur."}],"zor":[{"q":"Şekilde bir damla noktasal dalga, bir de düz çubuk doğrusal dalga oluşturuyor. Bu iki dalganın oluşturduğu cepheler nasıl farklıdır?","fig":"<svg viewBox='0 0 320 160'><rect x='8' y='10' width='150' height='140' fill='#4aa3df'/><circle cx='80' cy='80' r='16' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='80' cy='80' r='34' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='80' cy='80' r='52' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='80' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>Nokta kaynak</text><rect x='168' y='10' width='144' height='140' fill='#4aa3df'/><line x1='176' y1='20' x2='176' y2='130' stroke='#1a2b45' stroke-width='3'/><line x1='196' y1='20' x2='196' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='216' y1='20' x2='216' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='236' y1='20' x2='236' y2='130' stroke='#1a2b45' stroke-width='1.5'/><text x='240' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>Düz kaynak</text></svg>","steps":[{"t":"Nokta kaynak","a":"dairesel cephe","d":"Tek noktadan çıkan dalga her yöne aynı uzaklıkta yayılır, daire şeklinde cepheler oluşur."},{"t":"Düz kaynak","a":"doğrusal cephe","d":"Boydan boya titreşen düz çubuk, birbirine paralel düz çizgi cepheler oluşturur."},{"t":"Sonuç","a":"cephe şekli farklı","d":"Demek ki kaynağın şekli, <b>dalga cephesinin</b> dairesel mi doğrusal mı olacağını belirler."}],"ans":"Nokta kaynak dairesel cepheler, düz kaynak ise birbirine paralel doğrusal cepheler oluşturur."},{"q":"İki çocuk havuzun iki ucundan aynı anda taş atıyor. Oluşan iki dalga halkası karşılaştığında ne olur?","steps":[{"t":"İki dalga yayılır","a":"halkalar büyür","d":"Her taş kendi noktasından dairesel dalga oluşturur, halkalar büyüyerek birbirine yaklaşır."},{"t":"Karşılaşma","a":"üst üste biner","d":"İki dalga karşılaştığında birbirinin içinden geçer, çakıştıkları yerde su daha çok kabarır ya da çukurlaşır."},{"t":"Sonuç","a":"iç içe geçer","d":"Karşılaştıktan sonra her dalga <b>bozulmadan</b> kendi yoluna devam eder."}],"ans":"İki dalga karşılaştıkları yerde üst üste biner, sonra birbirini bozmadan yoluna devam eder."},{"q":"Bir su dalgası saniyede 3 tepe oluşturuyor (frekans 3 Hz) ve ardışık iki tepe arası 4 cm ise dalga ne hızla ilerler?","steps":[{"t":"Bilinenler","a":"f=3 Hz, λ=4 cm","d":"Saniyede 3 tepe geçiyor, ardışık iki tepe arası uzaklık (dalga boyu) 4 cm'dir."},{"t":"Hız bağıntısı","a":"v = f · λ","d":"Dalga hızı, frekans ile dalga boyunun çarpımına eşittir."},{"t":"Hesap","a":"3 · 4 = 12 cm/s","d":"v = 3 Hz × 4 cm = 12 cm/s bulunur."}],"ans":"Dalga 12 cm/s hızla ilerler."},{"q":"Yüzen mantar bir dalgada 2 saniyede 4 kez aşağı yukarı inip kalkıyor. Dalganın frekansı kaç Hz'dir?","steps":[{"t":"Tanım","a":"frekans = tekrar/süre","d":"Frekans, bir saniyede yapılan tam titreşim (inip kalkma) sayısıdır."},{"t":"Hesap","a":"4 ÷ 2","d":"2 saniyede 4 titreşim olduğundan saniyedeki titreşim 4 ÷ 2 = 2'dir."},{"t":"Sonuç","a":"2 Hz","d":"Demek ki dalganın frekansı 2 Hz'dir."}],"ans":"Dalganın frekansı 2 Hz'dir."},{"q":"Dalga leğeninde oluşturulan su dalgalarını net görebilmek için altına lamba konup üstten ekrana yansıtılır. Bu düzeneğe ne ad verilir ve niçin kullanılır?","steps":[{"t":"Düzenek","a":"dalga leğeni","d":"İçinde sığ su bulunan, altından aydınlatılan cam tabanlı kaba dalga leğeni denir."},{"t":"Amaç","a":"dalgayı görünür kılmak","d":"Dalga tepeleri ışığı toplayıp çukurları farklı kırdığından, ekranda aydınlık-karanlık çizgiler olarak görünür."},{"t":"Sonuç","a":"dalga davranışı incelenir","d":"Böylece dalgaların yayılması, kırılması ve girişimi <b>kolayca gözlenir</b>."}],"ans":"Bu düzeneğe dalga leğeni denir; su dalgalarını ekranda görünür kılarak davranışlarını incelemek için kullanılır."}]},"ortaokul":{"kolay":[{"q":"Su dalgalarında 'dalga cephesi' ne demektir?","steps":[{"t":"Tanım","a":"aynı evredeki noktalar","d":"Aynı anda aynı durumda olan (örneğin hepsi tepe olan) komşu su noktalarının oluşturduğu çizgiye dalga cephesi denir."},{"t":"Yön ilişkisi","a":"yayılmaya dik","d":"Dalga cephesi, dalganın ilerleme yönüne her zaman <b>diktir</b>."}],"ans":"Dalga cephesi, aynı evrede olan komşu noktaların oluşturduğu ve yayılma yönüne dik olan çizgidir."},{"q":"Şekildeki dairesel ve doğrusal su dalgalarında cepheler hangi şekilde uzanır?","fig":"<svg viewBox='0 0 320 160'><rect x='8' y='10' width='150' height='140' fill='#4aa3df'/><circle cx='30' cy='80' r='22' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='30' cy='80' r='44' fill='none' stroke='#1a2b45' stroke-width='1.5'/><circle cx='30' cy='80' r='66' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='80' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>Dairesel</text><rect x='168' y='10' width='144' height='140' fill='#4aa3df'/><line x1='190' y1='20' x2='190' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='220' y1='20' x2='220' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='250' y1='20' x2='250' y2='130' stroke='#1a2b45' stroke-width='1.5'/><line x1='280' y1='20' x2='280' y2='130' stroke='#1a2b45' stroke-width='1.5'/><text x='240' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>Doğrusal</text></svg>","steps":[{"t":"Dairesel dalga","a":"halka cephe","d":"Nokta kaynaktan çıkan dalgada cepheler iç içe halkalar (daireler) şeklindedir."},{"t":"Doğrusal dalga","a":"düz çizgi cephe","d":"Düz kaynaktan çıkan dalgada cepheler birbirine paralel düz çizgilerdir."}],"ans":"Dairesel dalgada cepheler iç içe halkalar, doğrusal dalgada birbirine paralel düz çizgilerdir."},{"q":"Su dalgalarında frekansı belirleyen şey nedir?","steps":[{"t":"Kaynak","a":"titreşim sayısı","d":"Su dalgasını oluşturan kaynağın saniyede kaç kez titreştiği frekansı belirler."},{"t":"Sonuç","a":"kaynağa bağlı","d":"Su derinliği değişse bile frekans <b>kaynağa bağlıdır</b> ve değişmez."}],"ans":"Frekansı, dalgayı oluşturan kaynağın titreşim sayısı belirler; kaynak değişmezse frekans sabit kalır."},{"q":"Şekildeki su dalgası kesitinde dalga boyu (λ) hangi iki nokta arasıdır?","fig":"<svg viewBox='0 0 320 150'><path d='M10 80 Q40 30 70 80 T130 80 T190 80 T250 80 T310 80' fill='none' stroke='#1a2b45' stroke-width='2.5'/><line x1='40' y1='45' x2='160' y2='45' stroke='#e0552b' stroke-width='1.5'/><polygon points='40,45 50,40 50,50' fill='#e0552b'/><polygon points='160,45 150,40 150,50' fill='#e0552b'/><text x='100' y='35' font-size='12' text-anchor='middle' fill='#1a2b45'>λ</text><circle cx='40' cy='45' r='3' fill='#e0552b'/><circle cx='160' cy='45' r='3' fill='#e0552b'/><text x='100' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>ardışık iki tepe</text></svg>","steps":[{"t":"Tanım","a":"ardışık iki tepe arası","d":"Şekildeki gibi ardışık iki dalga tepesi (veya iki çukur) arasındaki uzaklığa dalga boyu denir."},{"t":"Sembol","a":"λ ile gösterilir","d":"Dalga boyu λ (lambda) sembolüyle gösterilir ve uzunluk birimiyle (cm, m) ölçülür."}],"ans":"Dalga boyu, ardışık iki tepe (ya da iki çukur) arasındaki uzaklıktır ve λ ile gösterilir."},{"q":"Su dalgasının hızı derinliğe göre değişir mi?","steps":[{"t":"Derinlik etkisi","a":"evet değişir","d":"Su dalgasının hızı suyun derinliğine bağlıdır."},{"t":"Kural","a":"derinde hızlı, sığda yavaş","d":"Dalga, <b>derin suda hızlı</b>, sığ (az derin) suda <b>yavaş</b> ilerler."}],"ans":"Evet; su dalgası derin suda hızlı, sığ suda yavaş ilerler."}],"zor":[{"q":"Şekilde su dalgası derin bölgeden sığ bölgeye geçerken cepheler sıklaşıyor. Bu sığ bölgede dalga boyu ve hız nasıl değişir? (Frekans sabit)","fig":"<svg viewBox='0 0 320 160'><rect x='10' y='20' width='150' height='120' fill='#2f7fc0'/><rect x='160' y='20' width='150' height='120' fill='#8fcdf0'/><text x='85' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Derin</text><text x='235' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Sığ</text><line x1='40' y1='25' x2='40' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='80' y1='25' x2='80' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='120' y1='25' x2='120' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='180' y1='25' x2='180' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='200' y1='25' x2='200' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='220' y1='25' x2='220' y2='135' stroke='#1a2b45' stroke-width='1.5'/><line x1='240' y1='25' x2='240' y2='135' stroke='#1a2b45' stroke-width='1.5'/></svg>","steps":[{"t":"Frekans sabit","a":"f değişmez","d":"Dalga bir ortamdan diğerine geçerken frekansı (kaynağa bağlı) değişmez, sabit kalır."},{"t":"Sığ suda hız","a":"azalır","d":"Su sığlaştığında dalga hızı azalır; şekilde cephelerin sıklaşması da bunu gösterir."},{"t":"Dalga boyu","a":"λ = v ÷ f → küçülür","d":"f sabit, v küçüldüğü için λ = v ÷ f bağıntısına göre dalga boyu da küçülür."}],"ans":"Sığ bölgede frekans sabit kalır, hız azalır ve buna bağlı olarak dalga boyu küçülür."},{"q":"Bir su dalgası derin bölgede 20 cm/s hızla ve 4 cm dalga boyuyla ilerliyor. Sığ bölgeye geçince hızı 12 cm/s'ye düşüyor. Sığ bölgedeki dalga boyu kaç cm olur?","steps":[{"t":"Frekansı bul","a":"f = v ÷ λ","d":"Derin bölgede f = 20 ÷ 4 = 5 Hz'dir."},{"t":"Frekans sabit","a":"f = 5 Hz","d":"Ortam değişse de frekans değişmez, sığ bölgede de 5 Hz'dir."},{"t":"Yeni dalga boyu","a":"λ = v ÷ f","d":"Sığ bölgede λ = 12 ÷ 5 = 2,4 cm bulunur."}],"ans":"Sığ bölgede dalga boyu 2,4 cm olur."},{"q":"Derin sudan sığ suya geçen bir dalga, sınıra eğik (dik olmayan) açıyla gelirse yön değiştirir. Bu olaya ne ad verilir ve neden olur?","steps":[{"t":"Hız değişimi","a":"sığda yavaşlar","d":"Dalga sığ bölgeye geçince hızı azalır; cephenin önce giren ucu yavaşlar."},{"t":"Yön sapması","a":"cephe döner","d":"Cephenin bir ucu diğerinden önce yavaşladığı için dalga sınırda bükülerek yön değiştirir."},{"t":"Sonuç","a":"kırılma","d":"Hız (ve dalga boyu) değişimiyle dalganın yön değiştirmesine <b>kırılma</b> denir."}],"ans":"Bu olaya kırılma denir; sığ bölgede hız azaldığından eğik gelen dalga cephesi bükülerek yön değiştirir."},{"q":"İki ucundan aynı kaynakla üretilen iki dairesel su dalgası dalga leğeninde karşılaşıyor. Bazı noktalarda su hiç hareket etmiyor (durgun), bazı noktalarda çok kabarıyor. Bu olay nedir?","steps":[{"t":"Üst üste binme","a":"dalgalar çakışır","d":"İki dalga aynı noktaya geldiğinde etkileri toplanır (üst üste binme ilkesi)."},{"t":"Kabarma noktası","a":"tepe+tepe","d":"İki tepenin (ya da iki çukurun) çakıştığı yerde su daha çok kabarır; buna yapıcı girişim denir."},{"t":"Durgun nokta","a":"tepe+çukur","d":"Bir tepe ile bir çukurun çakıştığı yerde etkiler birbirini götürür, su durgun kalır (yıkıcı girişim)."}],"ans":"Bu olay girişimdir; dalgaların üst üste binmesiyle bazı noktalar çok kabarır (yapıcı), bazıları durgun kalır (yıkıcı)."},{"q":"Bir dalga leğeninde düz dalgalar bir engelin ucundan geçtikten sonra engelin arkasına doğru yayılıp bükülüyor. Bu olayın adı nedir ve ne zaman belirgin olur?","steps":[{"t":"Gözlem","a":"engel arkasına yayılma","d":"Düz dalgalar dar bir aralık ya da engel kenarından geçince arkadaki gölge bölgeye doğru yayılır."},{"t":"Olayın adı","a":"kırınım (difraksiyon)","d":"Dalganın engel veya yarık kenarından bükülerek arkaya yayılmasına kırınım denir."},{"t":"Belirginlik","a":"aralık ≈ dalga boyu","d":"Aralığın genişliği dalga boyuna yaklaştıkça kırınım daha <b>belirgin</b> olur."}],"ans":"Bu olay kırınımdır; engel/yarık genişliği dalga boyuna yaklaştığında daha belirgin görülür."}]},"lise":{"kolay":[{"q":"Su dalgalarının yüzeysel (yüzey) dalgası olarak sınıflandırılmasının nedeni nedir?","steps":[{"t":"Yayılma yeri","a":"su yüzeyi","d":"Su dalgaları, suyun ve havanın ayrım yüzeyi boyunca, yani yüzeyde yayılır."},{"t":"Parçacık hareketi","a":"dairesel salınım","d":"Yüzeydeki su parçacıkları yaklaşık dairesel bir yörünge çizerek hem yukarı-aşağı hem ileri-geri salınır."},{"t":"Sonuç","a":"yüzey dalgası","d":"Boyuna ve enine hareketi birleştirdiğinden su dalgası bir <b>yüzey dalgası</b> kabul edilir."}],"ans":"Su dalgaları suyun yüzeyinde yayılıp parçacıklara dairesel hareket yaptırdığından yüzey dalgası sayılır."},{"q":"Bir dalga için v, f, λ ve T arasındaki temel bağıntıları yazınız.","steps":[{"t":"Periyot-frekans","a":"T = 1 ÷ f","d":"Periyot, bir tam dalganın süresidir ve frekansın tersine eşittir."},{"t":"Hız bağıntısı","a":"v = f · λ","d":"Dalga hızı, frekans ile dalga boyunun çarpımıdır."},{"t":"Eşdeğer biçim","a":"v = λ ÷ T","d":"f = 1 ÷ T olduğundan hız, dalga boyunun periyoda bölümü olarak da yazılır."}],"ans":"T = 1 ÷ f, v = f · λ ve eşdeğer olarak v = λ ÷ T bağıntıları geçerlidir."},{"q":"Şekildeki dalga leğeninde bir bölgeye plaka konarak sığ bölge oluşturulmuştur. Bu düzenek ne işe yarar?","fig":"<svg viewBox='0 0 320 160'><rect x='20' y='40' width='280' height='80' fill='#4aa3df' stroke='#1a2b45'/><rect x='180' y='95' width='120' height='25' fill='#8fcdf0' stroke='#1a2b45'/><text x='90' y='75' font-size='11' text-anchor='middle' fill='#1a2b45'>derin</text><text x='240' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>sığ (plaka)</text><circle cx='160' cy='140' r='10' fill='#ffd54a' stroke='#d9a400'/><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>lamba</text><text x='160' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>ekran (üst)</text></svg>","steps":[{"t":"Derinlik ayarı","a":"cam/plaka koyma","d":"Leğenin bir bölümüne saydam bir plaka konularak su o bölgede sığlaştırılır."},{"t":"İki bölge","a":"derin ve sığ","d":"Böylece aynı leğende biri derin, biri sığ iki farklı hızlı bölge elde edilir."},{"t":"Amaç","a":"kırılmayı gözlemek","d":"Dalga bu bölgeler arasından geçerken hız, dalga boyu ve kırılma değişimleri <b>incelenir</b>."}],"ans":"Leğen tabanına plaka konup su sığlaştırılır; iki farklı derinlikli bölge dalganın kırılmasını incelemeye yarar."},{"q":"Su dalgasının hızının derinliğe bağlı olması, hangi mekanik geri çağırıcı kuvvetle açıklanır?","steps":[{"t":"Geri çağırıcı kuvvet","a":"yerçekimi","d":"Yüzeyden yükselen suyu eski düzeyine indiren kuvvet, ağırlık (yerçekimi) kaynaklıdır."},{"t":"Derinlik etkisi","a":"derinde daha etkili","d":"Derin suda hareket eden su kütlesi daha çok olduğundan dalga daha hızlı yayılır."},{"t":"Sonuç","a":"v ↑ derinlikle","d":"Bu yüzden derin suda hız büyük, sığ suda küçüktür."}],"ans":"Su dalgaları yerçekimi geri çağırıcı kuvvetiyle yayılır; bu nedenle hız derin suda büyük, sığ suda küçüktür."},{"q":"Şekildeki dalga leğeninde nokta kaynak ve doğrusal kaynaktan üretilen dalga cephelerinin geometrisini açıklayınız.","fig":"<svg viewBox='0 0 320 160'><rect x='8' y='12' width='150' height='136' fill='#4aa3df'/><circle cx='40' cy='80' r='5' fill='#e0552b' stroke='#1a2b45'/><circle cx='40' cy='80' r='22' fill='none' stroke='#1a2b45' stroke-width='1.3'/><circle cx='40' cy='80' r='44' fill='none' stroke='#1a2b45' stroke-width='1.3'/><circle cx='40' cy='80' r='66' fill='none' stroke='#1a2b45' stroke-width='1.3'/><text x='80' y='144' font-size='10' text-anchor='middle' fill='#1a2b45'>Nokta kaynak</text><rect x='168' y='12' width='144' height='136' fill='#4aa3df'/><line x1='178' y1='20' x2='178' y2='128' stroke='#e0552b' stroke-width='3'/><line x1='200' y1='20' x2='200' y2='128' stroke='#1a2b45' stroke-width='1.3'/><line x1='222' y1='20' x2='222' y2='128' stroke='#1a2b45' stroke-width='1.3'/><line x1='244' y1='20' x2='244' y2='128' stroke='#1a2b45' stroke-width='1.3'/><line x1='266' y1='20' x2='266' y2='128' stroke='#1a2b45' stroke-width='1.3'/><text x='240' y='144' font-size='10' text-anchor='middle' fill='#1a2b45'>Doğrusal kaynak</text></svg>","steps":[{"t":"Nokta kaynak","a":"eş merkezli daireler","d":"Tek noktadan çıkan dalga her yöne aynı hızda yayıldığından cepheler eş merkezli dairelerdir."},{"t":"Doğrusal kaynak","a":"paralel doğrular","d":"Boydan boya titreşen düz çubuk, birbirine paralel düz çizgi cepheler üretir."},{"t":"Ortak özellik","a":"cepheler yayılmaya dik","d":"Her iki durumda da dalga cepheleri yayılma doğrultusuna diktir."}],"ans":"Nokta kaynak eş merkezli dairesel cepheler, doğrusal kaynak ise birbirine paralel doğrusal cepheler oluşturur; her ikisinde de cephe yayılma yönüne diktir."},{"q":"Su dalgaları bir ortamdan diğerine geçerken hangi büyüklük kesinlikle değişmez, açıklayınız.","steps":[{"t":"Kaynağa bağlı büyüklük","a":"frekans","d":"Frekans (ve periyot) yalnızca kaynağın titreşim hızına bağlıdır, ortama bağlı değildir."},{"t":"Geçişte","a":"f sabit","d":"Dalga derinden sığa veya farklı ortama geçse de saniyedeki tepe sayısı korunur."},{"t":"Değişenler","a":"v ve λ","d":"Buna karşılık hız ve dalga boyu ortama göre değişir."}],"ans":"Ortam değişiminde frekans (ve periyot) kesinlikle değişmez; değişenler hız ve dalga boyudur."},{"q":"Bir su dalgasının frekansı 5 Hz, dalga boyu 6 cm ise hızını ve periyodunu hesaplayınız.","steps":[{"t":"Hız","a":"v = f · λ","d":"v = 5 Hz × 6 cm = 30 cm/s bulunur."},{"t":"Periyot","a":"T = 1 ÷ f","d":"T = 1 ÷ 5 = 0,2 s'dir."},{"t":"Sonuç","a":"v=30 cm/s, T=0,2 s","d":"Dalga 30 cm/s hızla yayılır ve bir tam dalga 0,2 saniyede oluşur."}],"ans":"Hız 30 cm/s, periyot 0,2 saniyedir."},{"q":"Dalga cephesi ile dalga ışını (yayılma doğrultusu) arasındaki ilişki nedir?","steps":[{"t":"Dalga cephesi","a":"eş evre çizgisi","d":"Aynı anda aynı evrede olan noktaların oluşturduğu çizgi/yüzey dalga cephesidir."},{"t":"Dalga ışını","a":"yayılma yönü","d":"Dalga ışını, dalganın ilerleme doğrultusunu gösteren çizgidir."},{"t":"İlişki","a":"birbirine dik","d":"Dalga ışını her zaman dalga cephesine <b>diktir</b>."}],"ans":"Dalga ışını dalganın yayılma yönünü gösterir ve dalga cephesine her noktada diktir."},{"q":"Su dalgalarında 'derin suda hızlı, sığ suda yavaş' kuralı, dalganın sığ kıyıya yaklaşırken neden tepelerinin dikleşip kırıldığını açıklar mı?","steps":[{"t":"Tepe ve çukur hızı","a":"derinlik farkı","d":"Kıyıya yaklaşırken dalganın alt kısmı (çukuru) sığ tabandan etkilenip yavaşlar."},{"t":"Tepe geç yavaşlar","a":"öne devrilme","d":"Üstteki tepe hâlâ hızlı olduğundan yavaşlayan alt kısmın önüne geçer, dalga dikleşir."},{"t":"Sonuç","a":"kıyıda kırılma","d":"Tepe daha fazla dayanamayıp öne devrilir; kıyıdaki köpüklü kırılan dalgalar böyle oluşur."}],"ans":"Evet; sığ tabanda alt kısım yavaşlayıp tepe öne geçtiğinden dalga dikleşir ve kıyıda devrilerek kırılır."},{"q":"Bir su dalgasında periyot 0,25 s ve dalga boyu 5 cm ise hız kaç cm/s'dir?","steps":[{"t":"Frekans","a":"f = 1 ÷ T","d":"f = 1 ÷ 0,25 = 4 Hz bulunur."},{"t":"Hız","a":"v = f · λ","d":"v = 4 Hz × 5 cm = 20 cm/s'dir."},{"t":"Sonuç","a":"20 cm/s","d":"Dalga 20 cm/s hızla yayılır."}],"ans":"Dalganın hızı 20 cm/s'dir."},{"q":"Su dalgalarının doğrusal yayıldığı (cephelerin düzgün ilerlediği) hangi koşulda söylenebilir?","steps":[{"t":"Koşul","a":"homojen derinlik","d":"Suyun derinliği her yerde aynı (homojen ortam) ise dalga hızı her noktada eşittir."},{"t":"Sonuç","a":"yön sapmaz","d":"Hız her yerde eşit olduğundan dalga cephesi şeklini koruyarak yön değiştirmeden ilerler."},{"t":"Aksi durum","a":"derinlik değişince","d":"Derinlik değişirse hız değişir ve dalga kırılarak yön değiştirir."}],"ans":"Derinlik her yerde aynı (homojen) olduğunda dalga hızı sabittir ve doğrusal, yön değiştirmeden yayılır."},{"q":"Aynı dalga leğeninde frekansı artırırsak (kaynak daha hızlı titreşirse) dalga boyu nasıl değişir? (Derinlik sabit)","steps":[{"t":"Derinlik sabit","a":"v değişmez","d":"Derinlik değişmediğinden su dalgasının hızı sabit kalır."},{"t":"Bağıntı","a":"λ = v ÷ f","d":"Hız sabitken dalga boyu frekansla ters orantılıdır."},{"t":"Sonuç","a":"λ küçülür","d":"Frekans arttıkça dalga boyu küçülür; cepheler birbirine yaklaşır."}],"ans":"Derinlik sabitken hız değişmez; frekans arttıkça dalga boyu (λ = v ÷ f) küçülür."},{"q":"Bir deprem deniz tabanında oluşunca dev su dalgaları (tsunami) açık denizde fark edilmezken kıyıda neden yükselir?","steps":[{"t":"Açık deniz","a":"derin, hızlı, alçak","d":"Çok derin açık denizde dalga çok hızlı yayılır, dalga boyu büyük ama yüksekliği küçüktür, bu yüzden fark edilmez."},{"t":"Kıyıya yaklaşma","a":"sığlaşma, yavaşlama","d":"Su sığlaştıkça dalga yavaşlar, dalga boyu kısalır; enerji daha küçük bir bölgeye sıkışır."},{"t":"Sonuç","a":"yükseklik artar","d":"Enerji korunduğundan yavaşlayıp sıkışan dalganın yüksekliği kıyıda büyük ölçüde artar."}],"ans":"Açık denizde derin-hızlı-alçak olan tsunami, kıyıda sığlaşıp yavaşlayınca enerjisi sıkışır ve yüksekliği büyük oranda artar."},{"q":"Su dalgalarının enine mi boyuna mı dalga olduğu neden tam net söylenemez?","steps":[{"t":"Enine bileşen","a":"yukarı-aşağı","d":"Su parçacıkları yayılma yönüne dik olarak yukarı-aşağı oynar; bu enine dalga özelliğidir."},{"t":"Boyuna bileşen","a":"ileri-geri","d":"Aynı parçacıklar yayılma yönünde ileri-geri de hareket eder; bu boyuna dalga özelliğidir."},{"t":"Sonuç","a":"dairesel hareket","d":"İkisi birleşince parçacık yaklaşık dairesel yörünge çizer; bu yüzden su dalgası saf enine ya da boyuna değildir."}],"ans":"Su parçacıkları hem enine hem boyuna hareket edip dairesel yörünge çizdiğinden, su dalgası tek bir türe sokulamaz; bir yüzey dalgasıdır."},{"q":"Dalga leğeninde sığ bölge sınırına dik gelen doğrusal bir dalga kırılır mı, yön değiştirir mi?","steps":[{"t":"Dik geliş","a":"cephe tümü aynı anda","d":"Dalga sınıra dik geldiğinde cephenin tüm noktaları sınıra aynı anda ulaşır."},{"t":"Hız değişimi","a":"hepsi birlikte yavaşlar","d":"Bütün cephe aynı anda sığ bölgeye girip aynı oranda yavaşlar, bir uç diğerinden önce yavaşlamaz."},{"t":"Sonuç","a":"yön değişmez","d":"Yön değişmez; yalnızca hız ve dalga boyu azalır. Kırılma (yön sapması) eğik gelişte olur."}],"ans":"Dik gelişte dalga yön değiştirmez; hızı ve dalga boyu azalır, ama doğrultusu korunur."}],"zor":[{"q":"Bir su dalgası derin bölgede 40 cm/s hızla, 8 cm dalga boyuyla ilerliyor. Sığ bölgede dalga boyu 5 cm ölçülüyor. Sığ bölgedeki hızı ve dalganın frekansını bulunuz.","steps":[{"t":"Frekans (derin)","a":"f = v ÷ λ","d":"f = 40 ÷ 8 = 5 Hz bulunur."},{"t":"Frekans sabit","a":"5 Hz","d":"Ortam değişse de frekans değişmediğinden sığ bölgede de f = 5 Hz'dir."},{"t":"Sığ bölgede hız","a":"v = f · λ","d":"v = 5 Hz × 5 cm = 25 cm/s bulunur."}],"ans":"Dalganın frekansı 5 Hz, sığ bölgedeki hızı 25 cm/s'dir."},{"q":"Bir su dalgası derin bölgeden sığ bölgeye 30° lik kırılma davranışı sergiliyor. Derinde hız 24 cm/s, sığda 16 cm/s ise dalga boylarının oranı (λderin ÷ λsığ) kaçtır? (Frekans sabit)","steps":[{"t":"Frekans sabit","a":"f ortak","d":"İki bölgede de frekans aynıdır, dolayısıyla λ = v ÷ f bağıntısında f sadeleşir."},{"t":"Oran kurma","a":"λderin ÷ λsığ = vderin ÷ vsığ","d":"f sabit olduğundan dalga boyu hızla doğru orantılıdır."},{"t":"Hesap","a":"24 ÷ 16 = 1,5","d":"Oran 24 ÷ 16 = 3 ÷ 2 = 1,5 bulunur."}],"ans":"Frekans sabit olduğundan dalga boyları hızla orantılıdır; λderin ÷ λsığ = 24 ÷ 16 = 1,5'tir."},{"q":"Şekildeki gibi doğrusal bir dalga, derin (D) bölgeden sığ (S) bölgeye eğik geliyor. Geliş açısı sınır normaliyle 50° ise kırılan dalganın açısı 50° den büyük mü küçük mü olur? Nedeniyle açıklayınız.","fig":"<svg viewBox='0 0 320 170'><rect x='10' y='15' width='300' height='70' fill='#2f7fc0'/><rect x='10' y='85' width='300' height='70' fill='#8fcdf0'/><text x='30' y='35' font-size='11' fill='#1a2b45'>D (derin)</text><text x='30' y='130' font-size='11' fill='#1a2b45'>S (sığ)</text><line x1='10' y1='85' x2='310' y2='85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='35' x2='160' y2='135' stroke='#1a2b45' stroke-width='1' stroke-dasharray='5,4'/><text x='170' y='30' font-size='10' fill='#1a2b45'>normal</text><line x1='100' y1='25' x2='160' y2='85' stroke='#e0552b' stroke-width='2.5'/><polygon points='160,85 150,76 156,72' fill='#e0552b'/><line x1='160' y1='85' x2='200' y2='145' stroke='#e0552b' stroke-width='2.5'/><polygon points='200,145 190,140 196,134' fill='#e0552b'/></svg>","steps":[{"t":"Hız değişimi","a":"sığda yavaş","d":"Sığ bölgede dalga hızı azalır (derinde hızlı, sığda yavaş)."},{"t":"Kırılma kuralı","a":"yavaş ortama normale yaklaşır","d":"Dalga, hızının azaldığı (yoğun benzeri) ortama geçerken normale doğru kırılır."},{"t":"Sonuç","a":"açı küçülür","d":"Bu nedenle kırılma açısı geliş açısından (50°) küçük olur."}],"ans":"Sığ bölgede hız azaldığından dalga normale yaklaşarak kırılır; kırılma açısı 50° den küçük olur."},{"q":"Bir dalga leğeninde derin bölgede λ = 9 mm, sığ bölgede λ = 6 mm ölçülüyor. Geliş açısı (derin) 60° ise sığ bölgedeki kırılma açısının sinüsü kaçtır? (sin60° ≈ 0,87)","steps":[{"t":"Snell benzeri bağıntı","a":"sinθ₁ ÷ sinθ₂ = λ₁ ÷ λ₂","d":"Frekans sabit olduğundan açıların sinüsleri dalga boylarıyla orantılıdır."},{"t":"Oran","a":"λ₂ ÷ λ₁ = 6 ÷ 9","d":"sinθ₂ = sinθ₁ × (λ₂ ÷ λ₁) = 0,87 × (6 ÷ 9)."},{"t":"Hesap","a":"≈ 0,58","d":"sinθ₂ = 0,87 × 0,667 ≈ 0,58 bulunur (θ₂ ≈ 35°)."}],"ans":"Kırılma açısının sinüsü yaklaşık 0,58'dir (yaklaşık 35°)."},{"q":"İki noktasal kaynak aynı frekans ve aynı evrede su dalgaları üretiyor (girişim). Bir P noktasının kaynaklara uzaklık farkı tam 1 dalga boyu ise P'de su nasıl davranır?","steps":[{"t":"Yol farkı","a":"Δx = 1·λ","d":"P noktasının iki kaynağa uzaklık farkı tam bir dalga boyu (tam sayı katı) kadardır."},{"t":"Evre durumu","a":"aynı evre","d":"Tam katı yol farkında iki dalga P'ye aynı evrede ulaşır; tepe tepeyle, çukur çukurla çakışır."},{"t":"Sonuç","a":"yapıcı girişim","d":"Genlikler toplanır, P'de su en çok kabarıp en çok çukurlaşan (yapıcı girişim) noktadır."}],"ans":"Yol farkı tam dalga boyu katı olduğundan P'de yapıcı girişim olur; su en büyük genlikle salınır (tepe noktası)."},{"q":"Aynı girişim düzeneğinde Q noktasının uzaklık farkı yarım dalga boyu (λ ÷ 2) ise Q'da ne gözlenir?","steps":[{"t":"Yol farkı","a":"Δx = λ ÷ 2","d":"Q noktasının iki kaynağa uzaklık farkı yarım dalga boyunun tek katıdır."},{"t":"Evre durumu","a":"ters evre","d":"Bu durumda dalgalar Q'ya zıt evrede ulaşır; birinin tepesi diğerinin çukuruna denk gelir."},{"t":"Sonuç","a":"yıkıcı girişim","d":"Etkiler birbirini götürür; Q durgun (düğüm) noktadır, su neredeyse hiç hareket etmez."}],"ans":"Yol farkı λ ÷ 2 olduğundan Q'da yıkıcı girişim olur; su durgun kalır (düğüm noktası)."},{"q":"Şekildeki gibi düz dalgalar, genişliği dalga boyuna yakın dar bir aralıktan geçince arkada nasıl yayılır? Bu olayı ve koşulunu açıklayınız.","fig":"<svg viewBox='0 0 320 160'><rect x='10' y='12' width='300' height='136' fill='#4aa3df'/><line x1='40' y1='18' x2='40' y2='142' stroke='#1a2b45' stroke-width='1.4'/><line x1='65' y1='18' x2='65' y2='142' stroke='#1a2b45' stroke-width='1.4'/><line x1='90' y1='18' x2='90' y2='142' stroke='#1a2b45' stroke-width='1.4'/><rect x='150' y='12' width='12' height='55' fill='#1a2b45'/><rect x='150' y='93' width='12' height='55' fill='#1a2b45'/><text x='156' y='160' font-size='9' text-anchor='middle' fill='#1a2b45'>aralık</text><circle cx='156' cy='80' r='20' fill='none' stroke='#1a2b45' stroke-width='1.3'/><circle cx='156' cy='80' r='42' fill='none' stroke='#1a2b45' stroke-width='1.3'/><circle cx='156' cy='80' r='64' fill='none' stroke='#1a2b45' stroke-width='1.3'/></svg>","steps":[{"t":"Gözlem","a":"dairesel yayılma","d":"Dar aralıktan geçen düz dalga, arkada sanki aralık bir nokta kaynakmış gibi dairesel olarak yayılır."},{"t":"Olayın adı","a":"kırınım","d":"Dalganın yarık/engel kenarından bükülerek arkaya, gölge bölgeye yayılmasına kırınım denir."},{"t":"Koşul","a":"aralık ≈ λ","d":"Aralık genişliği dalga boyuna yaklaştıkça kırınım belirginleşir; aralık çok büyükse dalga düz geçer."}],"ans":"Dalga aralıktan geçince dairesel yayılır; bu kırınımdır ve aralık genişliği dalga boyuna yaklaştığında belirgin olur."},{"q":"Bir su dalgasının açık denizde periyodu 10 s, hızı 200 m/s'dir (derin su). Kıyıya yaklaşıp hızı 20 m/s'ye düştüğünde dalga boyu nasıl değişir? Sayısal olarak gösteriniz.","steps":[{"t":"Derin su dalga boyu","a":"λ = v · T","d":"λ = 200 m/s × 10 s = 2000 m bulunur."},{"t":"Frekans/periyot sabit","a":"T = 10 s","d":"Periyot kaynağa bağlı olup değişmez, sığlaşmada da 10 s kalır."},{"t":"Sığ su dalga boyu","a":"λ' = v' · T","d":"λ' = 20 m/s × 10 s = 200 m olur; dalga boyu 2000 m'den 200 m'ye düşer."}],"ans":"Periyot sabit kaldığından dalga boyu 2000 m'den 200 m'ye, yani onda birine düşer."},{"q":"Derin-sığ sınırında dalga boyu λ₁ den λ₂ ye düşerken kırınım/kırılmadan bağımsız olarak frekans neden değişmez? Fiziksel gerekçeyle açıklayınız.","steps":[{"t":"Süreklilik","a":"tepe yutulmaz","d":"Sınıra saniyede gelen dalga tepesi sayısı, sınırdan saniyede çıkan tepe sayısına eşit olmalıdır; aksi halde sınırda tepe birikir ya da yok olurdu."},{"t":"Anlamı","a":"f₁ = f₂","d":"Giren ve çıkan tepe sayısı eşit olduğundan frekans iki tarafta da aynıdır."},{"t":"Sonuç","a":"v ve λ uyum sağlar","d":"Frekans sabit kaldığından hız değişimi yalnızca dalga boyu değişimiyle (λ = v ÷ f) karşılanır."}],"ans":"Sınırda saniyede giren ve çıkan tepe sayısı eşit olmak zorunda olduğundan frekans korunur; hız değişimini dalga boyu karşılar."},{"q":"Bir dalga leğeninde derin bölgede ardışık 5 tepe arası 16 cm ölçülüyor ve kaynak saniyede 4 tam titreşim yapıyor. Bu bölgedeki dalga boyunu ve hızı bulunuz.","steps":[{"t":"Dalga boyu","a":"4 aralık = 16 cm","d":"5 tepe arasında 4 dalga boyu aralığı vardır; λ = 16 ÷ 4 = 4 cm."},{"t":"Frekans","a":"f = 4 Hz","d":"Kaynak saniyede 4 tam titreşim yaptığından f = 4 Hz'dir."},{"t":"Hız","a":"v = f · λ","d":"v = 4 Hz × 4 cm = 16 cm/s bulunur."}],"ans":"Dalga boyu 4 cm, hız 16 cm/s'dir."},{"q":"Bir tsunami açık denizde 720 km/s hızla yayılıyor ve periyodu 15 dakika. Açık denizdeki dalga boyu kaç km'dir?","steps":[{"t":"Periyodu çevir","a":"15 dk = 900 s","d":"15 dakika = 15 × 60 = 900 saniyedir."},{"t":"Hızı çevir","a":"720 km/s = 0,2 km/s","d":"720 km/s yerine 720 ÷ 3600 = 0,2 km/s kullanmak daha kolaydır (saatte 720 km)."},{"t":"Dalga boyu","a":"λ = v · T","d":"λ = 0,2 km/s × 900 s = 180 km bulunur."}],"ans":"Açık denizdeki dalga boyu yaklaşık 180 km'dir."},{"q":"İki dalga leğeni deneyinde aynı kaynak kullanılıyor; birinde su daha derin. Hangi leğende ekrandaki dalga çizgileri (cepheler) daha seyrek görünür? Açıklayınız.","steps":[{"t":"Frekans ortak","a":"aynı kaynak","d":"Aynı kaynak kullanıldığından iki leğende de frekans aynıdır."},{"t":"Derin leğende hız","a":"daha büyük","d":"Derin suda dalga hızı daha büyüktür."},{"t":"Dalga boyu","a":"λ = v ÷ f → büyük","d":"f sabit, v büyük olduğundan derin leğende dalga boyu büyüktür; cepheler arası açıklık fazladır."}],"ans":"Derin leğende dalga boyu büyük olduğundan cepheler daha seyrek (aralıklı) görünür."},{"q":"Su dalgası modeli, ışığın kırılmasını anlamada neden iyi bir benzetme kabul edilir?","steps":[{"t":"Ortak davranış","a":"hız değişimi","d":"Hem su dalgası hem ışık, farklı ortama geçince hız değiştirir ve buna bağlı yön değiştirir (kırılma)."},{"t":"Frekans korunumu","a":"ikisinde de sabit","d":"Her iki dalgada da geçişte frekans korunur, dalga boyu ve hız değişir."},{"t":"Sonuç","a":"aynı kurallar","d":"sinθ₁ ÷ sinθ₂ = v₁ ÷ v₂ = λ₁ ÷ λ₂ bağıntısı her ikisinde de geçerli olduğundan su dalgaları ışığa iyi bir modeldir."}],"ans":"Su dalgaları da ortam değişiminde frekansı koruyup hız ve dalga boyu değiştirerek aynı kırılma kurallarına uyduğundan ışık kırılmasına iyi bir benzetmedir."},{"q":"Şekilde derin bölgeden sığ bölgeye geçen doğrusal dalga gösterilmiştir. Sığ bölgede cephelerin sıklaşmasının fiziksel anlamı nedir?","fig":"<svg viewBox='0 0 320 160'><rect x='10' y='15' width='150' height='130' fill='#2f7fc0'/><rect x='160' y='15' width='150' height='130' fill='#8fcdf0'/><text x='80' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Derin (hızlı)</text><text x='235' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Sığ (yavaş)</text><line x1='35' y1='20' x2='35' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='75' y1='20' x2='75' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='115' y1='20' x2='115' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='168' y1='20' x2='168' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='186' y1='20' x2='186' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='204' y1='20' x2='204' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='222' y1='20' x2='222' y2='140' stroke='#1a2b45' stroke-width='1.5'/><line x1='240' y1='20' x2='240' y2='140' stroke='#1a2b45' stroke-width='1.5'/></svg>","steps":[{"t":"Cephe aralığı","a":"= dalga boyu","d":"Ardışık iki cephe arası uzaklık dalga boyuna eşittir; cepheler sıklaşmışsa dalga boyu küçülmüştür."},{"t":"Neden küçüldü","a":"hız azaldı","d":"Sığ bölgede hız azaldı; frekans sabit olduğundan λ = v ÷ f bağıntısıyla dalga boyu da azaldı."},{"t":"Sonuç","a":"yavaş + kısa dalga","d":"Cephelerin sıklaşması, sığ bölgede dalganın hem yavaşladığını hem de dalga boyunun kısaldığını gösterir."}],"ans":"Cephelerin sıklaşması, sığ bölgede hızın azalması nedeniyle (frekans sabit) dalga boyunun küçüldüğünü gösterir."},{"q":"Bir su dalgasının genliği iki katına çıkarılırsa hızı, frekansı ve dalga boyu değişir mi? Açıklayınız.","steps":[{"t":"Genlik nedir","a":"tepe yüksekliği","d":"Genlik, su yüzeyinin denge konumundan en çok ne kadar yükseldiğidir; dalganın taşıdığı enerjiyle ilgilidir."},{"t":"Hıza etkisi","a":"etkilemez","d":"Su dalgasının hızı yalnızca derinliğe (ortama) bağlıdır, genlikten bağımsızdır (küçük genlik yaklaşımında)."},{"t":"f ve λ","a":"değişmez","d":"Frekans kaynağa, dalga boyu da hız ve frekansa bağlıdır; genlik değişimi bunları etkilemez."}],"ans":"Genlik değişse de hız (derinliğe bağlı), frekans (kaynağa bağlı) ve dalga boyu değişmez; yalnızca taşınan enerji artar."}]}},"yansima":{"ilkokul":{"kolay":[{"q":"Bir topu duvara doğru attığında topun ne yaptığını fark edersin?","steps":[{"t":"Çarpma","a":"duvara çarpar","d":"Top ilerler ve sert duvara çarpar."},{"t":"Geri dönme","a":"geri gelir","d":"Çarpan top geri döner; işte dalganın engele çarpıp geri dönmesine yansıma denir."}],"ans":"Top duvara çarpıp geri döner; dalganın engele çarpıp geri dönmesine yansıma denir."},{"q":"Boş bir odada bağırınca sesinin biraz sonra sana geri gelmesine ne ad verilir?","steps":[{"t":"Ses gider","a":"duvara ulaşır","d":"Sesin uzak duvara doğru gider."},{"t":"Geri döner","a":"yankı","d":"Sesin duvardan yansıyıp sana geri dönmesine yankı denir."}],"ans":"Sesin duvardan yansıyıp geri dönmesine yankı denir."},{"q":"Durgun bir gölete taş attığında oluşan su dalgaları kıyıya çarpınca ne olur?","steps":[{"t":"Dalga ilerler","a":"kıyıya gider","d":"Halka halka dalgalar dışa doğru yayılıp kıyıya çarpar."},{"t":"Geri döner","a":"yansır","d":"Kıyıya çarpan dalga geri döner; buna yansıma denir."}],"ans":"Su dalgası kıyıya çarpıp geri döner, yani yansır."},{"q":"Şekildeki gibi bir ışık demeti aynaya çarpınca ne yapar?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='5'/><text x='160' y='166' font-size='12' text-anchor='middle' fill='#1a2b45'>Ayna</text><line x1='60' y1='30' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><line x1='160' y1='150' x2='260' y2='30' stroke='#ffd54a' stroke-width='3'/><text x='80' y='40' font-size='11' fill='#1a2b45'>gelen</text><text x='235' y='40' font-size='11' fill='#1a2b45'>yansıyan</text></svg>","steps":[{"t":"Aynaya çarpar","a":"durmaz","d":"Işık aynanın yüzeyine ulaşır."},{"t":"Geri seker","a":"yansır","d":"Işık aynadan yansıyıp başka yöne gider."}],"ans":"Işık aynaya çarpıp yansır, yani geri seker."},{"q":"Aynanın karşısına geçince kendini görebilmenin sebebi nedir?","steps":[{"t":"Işık gider","a":"aynaya çarpar","d":"Senden çıkan ışık aynaya ulaşır."},{"t":"Geri döner","a":"gözüne gelir","d":"Aynadan yansıyan ışık gözüne döndüğü için kendini görürsün."}],"ans":"Işık aynadan yansıyıp gözüne döndüğü için kendini aynada görürsün."}],"zor":[{"q":"Şekilde bir ışık aynaya eğik geliyor. Yansıdıktan sonra hangi yöne gider?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='5'/><text x='160' y='166' font-size='12' text-anchor='middle' fill='#1a2b45'>Ayna</text><line x1='160' y1='150' x2='160' y2='30' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 4'/><text x='168' y='40' font-size='10' fill='#1a2b45'>dik çizgi</text><line x1='50' y1='40' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><line x1='160' y1='150' x2='270' y2='40' stroke='#ffd54a' stroke-width='3'/><text x='70' y='55' font-size='11' fill='#1a2b45'>gelen</text></svg>","steps":[{"t":"Nasıl geliyor","a":"soldan eğik","d":"Işık soldan eğik bir biçimde aynaya iniyor."},{"t":"Nasıl döner","a":"diğer yana","d":"Yansıyan ışık, aynanın öbür yanına aynı eğiklikte gider."}],"ans":"Eğik gelen ışık, aynanın diğer tarafına doğru aynı eğiklikte yansır."},{"q":"Dağda 'Hooo!' diye bağırınca sesin geç gelmesinin sebebi nedir?","steps":[{"t":"Ses uzağa gider","a":"karşı dağa","d":"Sesin karşıdaki uzak dağa kadar gider."},{"t":"Geri dönüş zaman alır","a":"yol uzun","d":"Yansıyıp geri gelmesi zaman aldığı için sesi sonradan duyarsın."}],"ans":"Ses uzaktaki dağa gidip yansıyarak geri döndüğü için yankıyı sonradan duyarsın."},{"q":"Bir top duvara tam dik (karşıdan) çarparsa nereye gider?","fig":"<svg viewBox='0 0 320 160'><line x1='240' y1='20' x2='240' y2='140' stroke='#1a2b45' stroke-width='5'/><text x='258' y='80' font-size='11' fill='#1a2b45'>Duvar</text><line x1='60' y1='80' x2='235' y2='80' stroke='#e0552b' stroke-width='3'/><polygon points='235,80 222,74 222,86' fill='#e0552b'/><text x='110' y='70' font-size='11' fill='#1a2b45'>gelen</text><line x1='235' y1='95' x2='60' y2='95' stroke='#5b6b85' stroke-width='3'/><polygon points='60,95 73,89 73,101' fill='#5b6b85'/><text x='110' y='112' font-size='11' fill='#1a2b45'>geri</text></svg>","steps":[{"t":"Çarpma yönü","a":"dik","d":"Top duvara tam karşıdan, dik olarak çarpar."},{"t":"Dönüş yönü","a":"geldiği yol","d":"Dik çarpan top geldiği yoldan geri döner."}],"ans":"Duvara dik çarpan top, geldiği yoldan geri döner."},{"q":"Suya çok eğik (yatay gibi) bir taş fırlatınca taşın 'sektiğini' görürüz. Bu hangi olaya benzer?","steps":[{"t":"Suya değer","a":"yüzeye çarpar","d":"Yassı taş su yüzeyine yatık bir açıyla çarpar."},{"t":"Geri yükselir","a":"sekme","d":"Taşın yüzeyden sıçrayıp tekrar havalanması, dalganın yansımasına benzer."}],"ans":"Taşın su yüzeyinden sekmesi, dalganın yüzeye çarpıp yansımasına benzer."},{"q":"Bir aynayı eğip güneş ışığını tavana düşürebiliyoruz. Bunu nasıl yaparız?","steps":[{"t":"Işık aynaya gelir","a":"güneşten","d":"Güneş ışığı aynaya düşer."},{"t":"Yönü değiştir","a":"aynayı eğ","d":"Aynayı eğince yansıyan ışığın yönü değişir ve tavana düşer."}],"ans":"Aynayı eğince güneş ışığı farklı yöne yansıdığı için ışığı tavana düşürebiliriz."}]},"ortaokul":{"kolay":[{"q":"Yansıma olayını ve gerçekleşmesi için neyin gerektiğini kısaca açıklayınız.","steps":[{"t":"Tanım","a":"geri dönme","d":"Bir dalganın yayılırken bir engele çarpıp geri dönmesine yansıma denir."},{"t":"Gerekli koşul","a":"engel/yüzey","d":"Yansıma için dalganın çarpacağı bir yüzeye (ayna, duvar, su kıyısı) ihtiyaç vardır."}],"ans":"Yansıma, dalganın bir engele çarpıp geri dönmesidir ve bunun için bir yüzeye ihtiyaç vardır."},{"q":"Yansıma yasasında 'normal' nedir ve açılar neye göre ölçülür?","steps":[{"t":"Normal nedir","a":"dik çizgi","d":"Normal, yüzeye çarpma noktasında dik olarak çizilen doğrudur."},{"t":"Açılar","a":"normale göre","d":"Gelme ve yansıma açıları, ışınla normal arasında ölçülür."}],"ans":"Normal, yüzeye dik olan çizgidir; gelme ve yansıma açıları ışınla normal arasında ölçülür."},{"q":"Yansıma yasasına göre bir dalga 30° gelme açısıyla geliyorsa yansıma açısı kaç derecedir?","steps":[{"t":"Yasayı hatırla","a":"açılar eşit","d":"Yansıma yasasına göre gelme açısı, yansıma açısına eşittir."},{"t":"Uygula","a":"30°","d":"Gelme açısı 30° ise yansıma açısı da 30° olur."}],"ans":"Yansıma açısı 30°'dir, çünkü gelme açısı yansıma açısına eşittir."},{"q":"Bir dalga yansıdığında dalga boyu ve frekansı değişir mi?","steps":[{"t":"Ortam aynı","a":"değişmez","d":"Yansımada dalga aynı ortamda kaldığı için hızı değişmez."},{"t":"Sonuç","a":"aynı kalır","d":"Hız sabit kalınca dalga boyu ve frekans da değişmez."}],"ans":"Yansımada dalga aynı ortamda kaldığı için dalga boyu, frekansı ve hızı değişmez."},{"q":"Yankı (eko) nasıl oluşur, kısaca açıklayınız.","steps":[{"t":"Ses yayılır","a":"engele gider","d":"Çıkardığımız ses, uzaktaki bir yüzeye (duvar, kayalık) doğru yayılır."},{"t":"Geri döner","a":"yansır","d":"Ses yüzeyden yansıyıp kulağımıza geri döner; bu tekrara yankı denir."}],"ans":"Yankı, sesin uzak bir yüzeyden yansıyıp tekrar kulağımıza dönmesiyle oluşur."}],"zor":[{"q":"Bir dalga yüzeye 50° gelme açısıyla çarpıyor. Gelen ışınla yansıyan ışın arasındaki açı kaç derecedir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='4'/><line x1='160' y1='150' x2='160' y2='20' stroke='#e0552b' stroke-width='2' stroke-dasharray='5 4'/><text x='166' y='30' font-size='10' fill='#e0552b'>normal</text><line x1='70' y1='70' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><line x1='160' y1='150' x2='250' y2='70' stroke='#4aa3df' stroke-width='3'/><text x='120' y='120' font-size='11' fill='#1a2b45'>50°</text><text x='185' y='120' font-size='11' fill='#1a2b45'>50°</text></svg>","steps":[{"t":"Yansıma açısı","a":"50°","d":"Gelme açısı 50° olduğundan yansıma açısı da 50°'dir."},{"t":"İki açıyı topla","a":"50 + 50","d":"Gelen ve yansıyan ışın normalin iki yanında olduğundan açıları toplanır."}],"ans":"Gelen ve yansıyan ışın arasındaki açı 100°'dir."},{"q":"Bir dalga yüzeye tam dik (normal boyunca) gelirse gelme açısı kaçtır ve dalga ne yapar?","steps":[{"t":"Açıyı belirle","a":"0°","d":"Dalga normal boyunca geldiğinden ışınla normal arasındaki açı 0°'dir."},{"t":"Dönüş","a":"geri döner","d":"Yansıma açısı da 0° olur, dalga geldiği yoldan geri döner."}],"ans":"Gelme açısı 0°'dir ve dalga geldiği yoldan geri döner."},{"q":"Bir ses, kayalığa çarpıp 2 saniye sonra yankı olarak geri dönüyor. Sesin hızı 340 m/s ise kayalık kaç metre uzaktadır?","steps":[{"t":"Toplam yol","a":"gidiş + dönüş","d":"Ses kayalığa gidip geri döndüğü için toplam yol = hız × süre = 340 × 2 = 680 m'dir."},{"t":"Mesafeyi bul","a":"680 ÷ 2","d":"Toplam yol gidiş ve dönüşü kapsadığından mesafe yarısı, yani 340 m'dir."}],"ans":"Kayalık 340 metre uzaktadır."},{"q":"Sabit (sert) bir uçtan yansıyan bir yay darbesi, gelen darbeye göre nasıl döner?","fig":"<svg viewBox='0 0 320 160'><line x1='250' y1='20' x2='250' y2='140' stroke='#1a2b45' stroke-width='5'/><text x='266' y='80' font-size='10' fill='#1a2b45'>sabit uç</text><path d='M40 90 Q90 50 140 90' stroke='#e0552b' stroke-width='3' fill='none'/><polygon points='140,90 150,86 150,94' fill='#e0552b'/><text x='80' y='115' font-size='11' fill='#1a2b45'>gelen (üst)</text><path d='M210 90 Q160 130 110 90' stroke='#4aa3df' stroke-width='3' fill='none'/><text x='160' y='150' font-size='11' fill='#1a2b45' text-anchor='middle'>yansıyan (alt)</text></svg>","steps":[{"t":"Sabit uç koşulu","a":"ters çevirir","d":"Sabit uç darbeyi tutar ve tepki kuvveti darbeyi ters yöne iter."},{"t":"Sonuç","a":"faz değişir","d":"Gelen darbe üstteyse yansıyan darbe altta olur; yani faz ters döner."}],"ans":"Sabit uçtan yansımada darbe ters döner (faz değişir); üstteki çukur, alttaki tepe olarak yansır."},{"q":"Serbest uçtan yansıyan bir yay darbesi gelen darbeye göre nasıl döner?","steps":[{"t":"Serbest uç koşulu","a":"serbest sallanır","d":"Serbest uç engellenmediği için darbe ile aynı yönde savrulur."},{"t":"Sonuç","a":"faz değişmez","d":"Gelen darbe üstteyse yansıyan darbe de üstte kalır; yani faz değişmez."}],"ans":"Serbest uçtan yansımada darbe aynı yönde döner (faz değişmez); üstteki tepe yine tepe olarak yansır."}]},"lise":{"kolay":[{"q":"Yansıma yasasının iki temel kuralını yazınız.","steps":[{"t":"Birinci kural","a":"aynı düzlem","d":"Gelen ışın, yansıyan ışın ve normal aynı düzlemde bulunur."},{"t":"İkinci kural","a":"açılar eşit","d":"Gelme açısı, yansıma açısına eşittir; her ikisi de normale göre ölçülür."}],"ans":"Gelen ışın, yansıyan ışın ve normal aynı düzlemdedir ve gelme açısı yansıma açısına eşittir."},{"q":"Yansımada dalganın hangi büyüklükleri değişir, hangileri değişmez?","steps":[{"t":"Ortam değişmez","a":"hız sabit","d":"Yansımada dalga aynı ortamda kaldığı için yayılma hızı değişmez."},{"t":"Sonuç","a":"yalnız yön","d":"Hız sabit olduğundan dalga boyu ve frekans da değişmez; sadece yayılma yönü değişir."}],"ans":"Yansımada dalganın hızı, dalga boyu ve frekansı değişmez; yalnızca yayılma yönü değişir."},{"q":"Bir ışın yüzeye 35° gelme açısıyla geliyorsa yansıma açısı kaç derecedir?","steps":[{"t":"Yasayı yaz","a":"i = r","d":"Yansıma yasasına göre gelme açısı yansıma açısına eşittir."},{"t":"Uygula","a":"35°","d":"Gelme açısı 35° olduğundan yansıma açısı da 35°'dir."}],"ans":"Yansıma açısı 35°'dir."},{"q":"Gelme açısı 40° iken gelen ışınla yüzey arasındaki açı kaç derecedir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='4'/><text x='265' y='165' font-size='10' fill='#1a2b45'>yüzey</text><line x1='160' y1='150' x2='160' y2='20' stroke='#e0552b' stroke-width='2' stroke-dasharray='5 4'/><text x='166' y='30' font-size='10' fill='#e0552b'>normal</text><line x1='80' y1='55' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><text x='118' y='115' font-size='11' fill='#1a2b45'>40°</text></svg>","steps":[{"t":"Normal yüzeye dik","a":"90°","d":"Normal ile yüzey arasındaki açı her zaman 90°'dir."},{"t":"Çıkar","a":"90 − 40","d":"Işınla yüzey arasındaki açı, 90°'den gelme açısı çıkarılarak bulunur."}],"ans":"Gelen ışınla yüzey arasındaki açı 50°'dir."},{"q":"Gelme açısı 25° olan bir ışında, gelen ve yansıyan ışın arasındaki toplam açı kaçtır?","steps":[{"t":"Yansıma açısı","a":"25°","d":"Yansıma açısı gelme açısına eşit olduğundan 25°'dir."},{"t":"Topla","a":"25 + 25","d":"Gelen ve yansıyan ışın normalin iki yanında olduğundan açıları toplanır."}],"ans":"Gelen ve yansıyan ışın arasındaki açı 50°'dir."},{"q":"Düzlem aynaya gelen ışının gelme açısı sıfır ise (dik geliş) yansıyan ışın ne yapar?","steps":[{"t":"Açı durumu","a":"0°","d":"Işın normal boyunca geldiği için gelme açısı 0°'dir."},{"t":"Yansıma","a":"geri döner","d":"Yansıma açısı da 0° olur ve ışın kendi üzerinden geldiği yola geri döner."}],"ans":"Dik gelen ışın geldiği yoldan kendi üzerinden geri döner (yansıma açısı 0°)."},{"q":"Su dalga leğeninde (rıpıl tankı) düz bir engele çarpan doğrusal dalganın dalga boyu yansıma sonrası nasıl olur?","steps":[{"t":"Ortam değişmez","a":"hız aynı","d":"Dalga yine aynı su ortamında ilerlediği için hızı değişmez."},{"t":"Sonuç","a":"dalga boyu aynı","d":"Frekans kaynak tarafından belirlenir, hız sabit olunca dalga boyu da değişmez."}],"ans":"Yansıma sonrası dalga boyu değişmez; çünkü dalga aynı ortamda kaldığından hız ve frekans sabittir."},{"q":"Yankının net duyulabilmesi için sesin engele çarpıp dönmesi yaklaşık ne kadar sürmelidir?","steps":[{"t":"Ayırma eşiği","a":"≈ 0,1 s","d":"İnsan kulağı, ardışık iki sesi ayırt edebilmek için yaklaşık 0,1 saniyelik bir gecikmeye ihtiyaç duyar."},{"t":"Yol koşulu","a":"yeterli uzaklık","d":"Bu süre için engelin yeterince uzakta olması (yaklaşık 17 m'den fazla) gerekir."}],"ans":"Yankının ayrı duyulması için ses ile yankı arasında yaklaşık 0,1 saniyelik gecikme, yani engelin en az ~17 m uzakta olması gerekir."},{"q":"Sabit uçtan ve serbest uçtan yansımayı faz değişimi açısından karşılaştırınız.","steps":[{"t":"Sabit uç","a":"faz değişir","d":"Sabit (sert) uçtan yansıyan darbe ters döner; tepe çukur, çukur tepe olur."},{"t":"Serbest uç","a":"faz değişmez","d":"Serbest uçtan yansıyan darbe aynı yönde kalır; tepe yine tepe olarak döner."}],"ans":"Sabit uçtan yansımada faz değişir (darbe ters döner), serbest uçtan yansımada faz değişmez (aynı yönde döner)."},{"q":"Düzlem bir aynada ışının gelme açısı 20°'den 50°'ye çıkarsa yansıma açısı nasıl değişir?","steps":[{"t":"Yasayı uygula","a":"i = r","d":"Her durumda yansıma açısı gelme açısına eşittir."},{"t":"Sonuç","a":"20° → 50°","d":"Gelme açısı 20°'den 50°'ye çıkınca yansıma açısı da 20°'den 50°'ye çıkar."}],"ans":"Yansıma açısı da 20°'den 50°'ye çıkar; çünkü daima gelme açısına eşittir."},{"q":"Düzgün (parlak) bir yüzey ile pürüzlü bir yüzeydeki yansımanın farkı nedir?","steps":[{"t":"Düzgün yüzey","a":"düzenli","d":"Parlak, pürüzsüz yüzeyde paralel ışınlar paralel olarak yansır; buna düzenli (regüler) yansıma denir."},{"t":"Pürüzlü yüzey","a":"dağınık","d":"Pürüzlü yüzeyde normaller farklı yönlerde olduğundan ışınlar dağılır; buna dağınık (difüz) yansıma denir."}],"ans":"Düzgün yüzeyde düzenli (paralel) yansıma, pürüzlü yüzeyde dağınık yansıma olur; her noktada yansıma yasası yine geçerlidir."},{"q":"Bir radarın gönderdiği dalga bir uçaktan yansıyıp 0,0004 s sonra geri dönüyor. Dalga hızı 3×10⁸ m/s ise uçak kaç km uzaktadır?","steps":[{"t":"Toplam yol","a":"v × t","d":"Toplam yol = hız × süre = 3×10⁸ × 0,0004 = 120000 m'dir."},{"t":"Mesafeyi bul","a":"yol ÷ 2","d":"Yol gidiş-dönüşü kapsadığından mesafe 120000 ÷ 2 = 60000 m'dir."}],"ans":"Uçak 60000 m, yani 60 km uzaktadır."},{"q":"Bir ışın aynaya 60° gelme açısıyla gelir. Ayna 10° döndürülürse yansıyan ışın kaç derece döner?","steps":[{"t":"Kural","a":"2 katı döner","d":"Düzlem ayna belirli bir açı döndürülürse yansıyan ışın bu açının iki katı kadar döner."},{"t":"Uygula","a":"2 × 10°","d":"Ayna 10° döndüğünden yansıyan ışın 2 × 10° = 20° döner."}],"ans":"Yansıyan ışın 20° döner; çünkü ayna döndürülünce yansıyan ışın açının iki katı kadar sapar."},{"q":"Gelme açısı ile yansıma açısının eşitliği hangi temel ilkeyle açıklanır?","steps":[{"t":"İlke","a":"en kısa zaman","d":"Fermat ilkesine göre ışık iki nokta arasında en kısa sürede giden yolu izler."},{"t":"Sonuç","a":"açılar eşit","d":"Bu yolun sağlanması için gelme açısının yansıma açısına eşit olması gerekir."}],"ans":"Açıların eşitliği Fermat'ın en kısa zaman ilkesiyle açıklanır; en kısa süreli yol, gelme açısının yansıma açısına eşit olmasını gerektirir."},{"q":"Bir dalga sabit uçtan yansıyınca frekansı, dalga boyu ve fazı için ne söylenebilir?","steps":[{"t":"Ortam aynı","a":"frekans/boy sabit","d":"Dalga aynı ortamda kaldığından frekans, hız ve dalga boyu değişmez."},{"t":"Faz","a":"ters döner","d":"Sabit uç koşulu nedeniyle yalnızca faz tersine döner (180° faz farkı)."}],"ans":"Sabit uçtan yansımada frekans ve dalga boyu değişmez; yalnızca faz ters döner (180° faz farkı oluşur)."}],"zor":[{"q":"Bir ışın iki dik (90°'lik) ayna arasında, birinci aynaya 30° gelme açısıyla geliyor. İkinci aynadan yansıyan ışının gelme açısı kaç derecedir?","fig":"<svg viewBox='0 0 320 180'><line x1='40' y1='150' x2='250' y2='150' stroke='#1a2b45' stroke-width='4'/><line x1='250' y1='150' x2='250' y2='20' stroke='#1a2b45' stroke-width='4'/><text x='130' y='166' font-size='10' fill='#1a2b45'>1. ayna</text><text x='258' y='90' font-size='10' fill='#1a2b45'>2. ayna</text><line x1='70' y1='90' x2='130' y2='150' stroke='#ffd54a' stroke-width='2.5'/><line x1='130' y1='150' x2='250' y2='90' stroke='#4aa3df' stroke-width='2.5'/><line x1='250' y1='90' x2='120' y2='40' stroke='#e0552b' stroke-width='2.5'/></svg>","steps":[{"t":"Birinci yansıma","a":"r1 = 30°","d":"Birinci aynaya gelme açısı 30° olduğundan yansıma açısı da 30°'dir."},{"t":"İkinci aynaya geliş","a":"60°","d":"İki ayna dik olduğu için ikinci aynanın normaliyle yapılan gelme açısı 90° − 30° = 60° olur."},{"t":"İkinci yansıma","a":"60°","d":"Yansıma yasası gereği ikinci aynadan yansıma açısı da gelme açısına, yani 60°'ye eşittir."}],"ans":"İkinci aynaya gelme açısı 60°'dir (yansıma açısı da 60°); 90°'lik aynalarda gelen ve son yansıyan ışın birbirine paraleldir."},{"q":"Bir gözlemci ile uçurum arasındaki mesafe 510 m'dir. Ses hızı 340 m/s ise gözlemci yankıyı kaç saniye sonra duyar?","steps":[{"t":"Toplam yol","a":"2 × 510","d":"Ses uçuruma gidip geri döndüğü için toplam yol gidiş-dönüş, yani 2 × 510 = 1020 m'dir."},{"t":"Süreyi hesapla","a":"yol ÷ hız","d":"Süre = toplam yol ÷ hız = 1020 ÷ 340'tır."},{"t":"Sonuç","a":"3 s","d":"1020'yi 340'a bölünce 3 saniye bulunur."}],"ans":"Gözlemci yankıyı 3 saniye sonra duyar."},{"q":"Şekildeki gibi ışın aynaya 53° gelme açısıyla geliyor. Ayna, çarpma noktası etrafında 12° döndürülürse yansıyan ışın ile gelen ışın arasındaki açı ilk duruma göre kaç derece değişir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='4'/><line x1='160' y1='150' x2='160' y2='20' stroke='#e0552b' stroke-width='2' stroke-dasharray='5 4'/><line x1='75' y1='60' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><line x1='160' y1='150' x2='245' y2='60' stroke='#4aa3df' stroke-width='3'/><text x='120' y='120' font-size='11' fill='#1a2b45'>53°</text><path d='M120 150 A 45 45 0 0 1 138 120' stroke='#e0552b' fill='none' stroke-width='1.5'/><text x='95' y='140' font-size='9' fill='#e0552b'>12° dön</text></svg>","steps":[{"t":"Kuralı yaz","a":"ışın 2 katı döner","d":"Ayna bir açı döndürülürse yansıyan ışın bu açının iki katı kadar döner."},{"t":"Sapmayı bul","a":"2 × 12°","d":"Ayna 12° döndüğünden yansıyan ışın 24° döner."},{"t":"Açıya etkisi","a":"24°","d":"Gelen ışın sabit kaldığından gelen-yansıyan ışın arasındaki açı 24° değişir."}],"ans":"Yansıyan ışın 24° döner; dolayısıyla gelen ile yansıyan ışın arasındaki açı 24° değişir."},{"q":"Bir kişi bir duvardan 1,5 s, arkasındaki başka bir duvardan 2,5 s sonra yankı duyuyor. Ses hızı 340 m/s ise iki duvar arasındaki mesafe kaç metredir?","steps":[{"t":"İlk duvar uzaklığı","a":"340×1,5÷2","d":"İlk duvar mesafesi = (hız × süre) ÷ 2 = (340 × 1,5) ÷ 2 = 255 m'dir."},{"t":"İkinci duvar uzaklığı","a":"340×2,5÷2","d":"İkinci duvar mesafesi = (340 × 2,5) ÷ 2 = 425 m'dir."},{"t":"Toplam mesafe","a":"255 + 425","d":"Kişi iki duvarın arasında olduğundan duvarlar arası mesafe iki uzaklığın toplamıdır."}],"ans":"İki duvar arasındaki mesafe 680 metredir."},{"q":"Su dalga leğeninde 5 Hz frekanslı doğrusal dalga 0,2 m/s hızla ilerliyor ve düz bir engelden yansıyor. Yansıma sonrası dalga boyu kaç metredir?","steps":[{"t":"Dalga boyunu yaz","a":"λ = v/f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yansımanın etkisi","a":"değişmez","d":"Yansımada hız ve frekans değişmediği için dalga boyu da değişmez."},{"t":"Hesapla","a":"0,2 ÷ 5","d":"λ = 0,2 ÷ 5 = 0,04 m bulunur, bu değer yansımadan sonra da aynıdır."}],"ans":"Yansıma sonrası dalga boyu yine 0,04 m'dir; çünkü yansımada hız ve frekans değişmez."},{"q":"Şekildeki gibi gelen ışınla yansıyan ışın arasındaki açı 70° ölçülüyor. Gelme açısı kaç derecedir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='4'/><line x1='160' y1='150' x2='160' y2='20' stroke='#e0552b' stroke-width='2' stroke-dasharray='5 4'/><text x='166' y='30' font-size='10' fill='#e0552b'>normal</text><line x1='95' y1='60' x2='160' y2='150' stroke='#ffd54a' stroke-width='3'/><line x1='160' y1='150' x2='225' y2='60' stroke='#4aa3df' stroke-width='3'/><text x='150' y='95' font-size='11' fill='#1a2b45'>70°</text></svg>","steps":[{"t":"Açıyı böl","a":"70 ÷ 2","d":"Gelen ve yansıyan ışın normale göre simetrik olduğundan toplam açı, gelme açısının iki katıdır."},{"t":"Sonuç","a":"35°","d":"70°'yi 2'ye bölünce gelme açısı 35° bulunur."}],"ans":"Gelme açısı 35°'dir."},{"q":"Bir ışın yatay zemine paralel ilerliyor. Zemine 30° eğimli bir aynaya çarpınca yansıyan ışın yatayla kaç derece açı yapar?","steps":[{"t":"Gelme açısını bul","a":"60°","d":"Işın yatay, ayna yatayla 30° açılı olduğundan aynanın normaliyle yapılan gelme açısı 90° − 30° = 60°'dir."},{"t":"Toplam sapma","a":"2 × 60°","d":"Bir aynada ışının toplam sapması 2 × gelme açısı = 120°'dir."},{"t":"Yatayla açı","a":"60°","d":"Işın ilk yönüne göre 120° saptığından, yatayla yaptığı açı 180° − 120° = 60° olur."}],"ans":"Yansıyan ışın yatayla 60° açı yapar."},{"q":"İp üzerinde ilerleyen bir tepe darbesi, ipin sabit bağlı ucuna ulaşıyor. Yansıyan darbenin yönünü ve genliğini (kayıpsız durumda) açıklayınız.","fig":"<svg viewBox='0 0 320 160'><line x1='250' y1='20' x2='250' y2='140' stroke='#1a2b45' stroke-width='5'/><text x='258' y='80' font-size='10' fill='#1a2b45'>sabit uç</text><line x1='40' y1='100' x2='250' y2='100' stroke='#1a2b45' stroke-width='1'/><path d='M70 100 Q110 55 150 100' stroke='#e0552b' stroke-width='3' fill='none'/><text x='110' y='125' font-size='10' fill='#1a2b45'>gelen tepe</text><path d='M230 100 Q190 145 150 100' stroke='#4aa3df' stroke-width='3' fill='none'/><text x='190' y='155' font-size='10' fill='#1a2b45'>yansıyan çukur</text></svg>","steps":[{"t":"Faz","a":"ters döner","d":"Sabit uçta tepki kuvveti darbeyi ters çevirir; tepe darbesi çukur olarak yansır (180° faz farkı)."},{"t":"Genlik","a":"aynı","d":"Kayıpsız ortamda enerji korunduğu için yansıyan darbenin genliği gelen darbeyle aynı kalır."}],"ans":"Yansıyan darbe ters döner (tepe çukura döner), kayıpsız durumda genliği gelen darbeyle aynıdır."},{"q":"Bir denizaltı sonar dalgası gönderiyor; dalga deniz tabanından yansıyıp 0,6 s sonra dönüyor. Deniz suyunda ses hızı 1500 m/s ise deniz derinliği kaç metredir?","steps":[{"t":"Toplam yol","a":"v × t","d":"Toplam yol = hız × süre = 1500 × 0,6 = 900 m'dir."},{"t":"Derinliği bul","a":"yol ÷ 2","d":"Dalga aşağı inip yukarı çıktığı için derinlik toplam yolun yarısıdır: 900 ÷ 2."},{"t":"Sonuç","a":"450 m","d":"900'ü 2'ye bölünce derinlik 450 m bulunur."}],"ans":"Deniz derinliği 450 metredir."},{"q":"Düzlem aynaya dik gelen bir ışının yansıma süresince izlediği yol için 'gelme açısı = yansıma açısı = 0' demek hangi fiziksel durumu özetler?","steps":[{"t":"Açı yorumu","a":"normal boyunca","d":"Gelme açısının 0 olması, ışının normalle çakışık, yani yüzeye tam dik geldiğini gösterir."},{"t":"Yansıma yorumu","a":"geri döner","d":"Yansıma açısı da 0 olduğundan ışın aynı doğru üzerinden geri döner."},{"t":"Sonuç","a":"yön tersine","d":"Yön tam tersine döner ama yol değişmez; ışın kaynağına doğru gider."}],"ans":"İki açının da 0 olması, ışının yüzeye tam dik gelip kendi yolu üzerinden geri döndüğü özel durumu özetler."},{"q":"Bir ışın aynaya 45° gelme açısıyla gelirken, ayna ışının çarptığı eksen etrafında 15° döndürülüyor. Yeni gelme açısı kaç derece olur (ışın sabit)?","steps":[{"t":"Normal döner","a":"15°","d":"Ayna 15° döndüğünde yüzeye dik olan normal de 15° döner."},{"t":"Açıya etkisi","a":"45° ∓ 15°","d":"Işın sabit kaldığından gelme açısı, normalin dönme yönüne göre 15° artar ya da azalır."},{"t":"Sonuç","a":"30° veya 60°","d":"Normal ışına yaklaşırsa açı 45° − 15° = 30°, uzaklaşırsa 45° + 15° = 60° olur."}],"ans":"Yeni gelme açısı, aynanın dönme yönüne göre 30° (normal ışına yaklaşırsa) ya da 60° (uzaklaşırsa) olur."},{"q":"Frekansı 250 Hz olan bir ses dalgası havada 340 m/s hızla yayılıyor ve bir duvardan yansıyor. Hem gelen hem yansıyan dalganın dalga boyu ve frekansını karşılaştırınız.","steps":[{"t":"Gelen dalga boyu","a":"λ = v/f","d":"Gelen dalganın dalga boyu = 340 ÷ 250 = 1,36 m'dir."},{"t":"Yansımanın etkisi","a":"değişmez","d":"Yansımada ortam aynı kaldığından hız 340 m/s ve frekans 250 Hz sabit kalır."},{"t":"Karşılaştır","a":"aynı","d":"Hız ve frekans değişmediği için yansıyan dalganın boyu da 1,36 m'dir."}],"ans":"Gelen ve yansıyan dalganın frekansı 250 Hz, dalga boyu 1,36 m'dir; yansıma bu değerleri değiştirmez."},{"q":"Şekildeki düzenekte ışın birbirine paralel iki aynadan sırasıyla yansıyor. İlk aynaya 40° gelme açısıyla gelen ışın, ikinci aynadan yansıdıktan sonra ilk gelen ışına göre nasıl bir doğrultudadır?","fig":"<svg viewBox='0 0 320 180'><line x1='40' y1='40' x2='280' y2='40' stroke='#1a2b45' stroke-width='4'/><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='4'/><text x='250' y='32' font-size='9' fill='#1a2b45'>1. ayna</text><text x='250' y='168' font-size='9' fill='#1a2b45'>2. ayna</text><line x1='60' y1='150' x2='130' y2='40' stroke='#ffd54a' stroke-width='2.5'/><line x1='130' y1='40' x2='210' y2='150' stroke='#4aa3df' stroke-width='2.5'/><line x1='210' y1='150' x2='280' y2='40' stroke='#e0552b' stroke-width='2.5'/></svg>","steps":[{"t":"İlk yansıma","a":"40°","d":"İlk aynaya gelme açısı 40°, yansıma açısı da 40°'dir."},{"t":"İkinci aynaya geliş","a":"40°","d":"Aynalar paralel olduğundan ışın ikinci aynaya da 40° gelme açısıyla ulaşır."},{"t":"Son doğrultu","a":"paralel","d":"İki kez 40° yansıma sonunda son ışın, ilk gelen ışına paralel olur (yalnızca yana kaymıştır)."}],"ans":"İkinci aynadan yansıyan son ışın, ilk gelen ışına paraleldir; sadece yanal olarak ötelenmiştir."},{"q":"Bir gemi 1485 m derinlikteki deniz tabanına sonar dalgası gönderiyor. Suda ses hızı 1485 m/s ise dalganın gidip geri dönme (yankı) süresi kaç saniyedir?","steps":[{"t":"Toplam yol","a":"2 × derinlik","d":"Dalga tabana inip geri çıktığı için toplam yol 2 × 1485 = 2970 m'dir."},{"t":"Süreyi yaz","a":"yol ÷ hız","d":"Süre = toplam yol ÷ hız = 2970 ÷ 1485'tir."},{"t":"Sonuç","a":"2 s","d":"2970'i 1485'e bölünce yankı süresi 2 saniye bulunur."}],"ans":"Dalganın gidip geri dönme süresi 2 saniyedir."},{"q":"Sert ve serbest uçtan yansıyan iki özdeş darbe için yansıyan dalganın matematiksel fazı sırasıyla nasıl ifade edilir ve bu farkın nedeni nedir?","steps":[{"t":"Sabit uç","a":"+π faz","d":"Sabit uçta darbe 180° (π radyan) faz değişimiyle yansır; çünkü uç hareket edemez, sınır koşulu yer değiştirmeyi sıfır tutar."},{"t":"Serbest uç","a":"0 faz","d":"Serbest uçta faz değişimi olmaz (0); çünkü uç serbest hareket eder ve eğim sıfır koşulu sağlanır."},{"t":"Nedeni","a":"sınır koşulu","d":"Fark, uçtaki fiziksel sınır koşulundan (yer değiştirme sıfır mı, kuvvet sıfır mı) kaynaklanır."}],"ans":"Sabit uçta yansıma π (180°) faz değişimiyle, serbest uçta faz değişimi olmadan gerçekleşir; bu fark uçtaki sınır koşulundan kaynaklanır."}]}},"yayDalgasi":{"ilkokul":{"kolay":[{"q":"Bir yayın ucunu elimizle hızlıca yukarı-aşağı sallarsak yayda ne oluşur?","fig":"<svg viewBox='0 0 320 140'><line x1='10' y1='90' x2='80' y2='90' stroke='#1a2b45' stroke-width='2'/><path d='M80 90 q15 -45 30 0 q15 45 30 0' fill='none' stroke='#5b6b85' stroke-width='3'/><line x1='140' y1='90' x2='310' y2='90' stroke='#1a2b45' stroke-width='2'/><text x='95' y='35' font-size='12' text-anchor='middle' fill='#1a2b45'>darbe</text><polygon points='95,42 90,50 100,50' fill='#e0552b'/><text x='40' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>el sallar</text></svg>","steps":[{"t":"Ne yaptık","a":"yayı salladık","d":"Yayın ucunu hızlıca oynatınca yaya bir hareket verdik."},{"t":"Yayda ne olur","a":"dalga ilerler","d":"Bu hareket yay boyunca ilerleyen bir dalga (kıvrım) oluşturur."}],"ans":"Yayı sallayınca yay boyunca ilerleyen bir dalga oluşur."},{"q":"Yayda oluşan dalga ilerlerken yayın kendisi de baştan sona gider mi?","steps":[{"t":"Yaya bak","a":"yerinde titrer","d":"Yayın halkaları sadece olduğu yerde sallanır, baştan sona gitmez."},{"t":"İlerleyen ne","a":"sadece dalga","d":"Yer değiştirip ilerleyen şey dalgadır, yayın maddesi değil."}],"ans":"Hayır; yay yerinde titrer, sadece dalga ilerler."},{"q":"Yayın ucunu bir kez hızlıca sallayıp bırakırsak oluşan tek kıvrıma ne denir?","fig":"<svg viewBox='0 0 320 130'><line x1='10' y1='80' x2='110' y2='80' stroke='#1a2b45' stroke-width='2'/><path d='M110 80 q20 -40 40 0' fill='none' stroke='#5b6b85' stroke-width='3'/><line x1='150' y1='80' x2='310' y2='80' stroke='#1a2b45' stroke-width='2'/><text x='130' y='28' font-size='12' text-anchor='middle' fill='#1a2b45'>tek kıvrım</text><polygon points='200,80 215,75 215,85' fill='#e0552b'/><line x1='180' y1='80' x2='215' y2='80' stroke='#e0552b' stroke-width='2'/></svg>","steps":[{"t":"Kaç kıvrım","a":"bir tane","d":"Yayı bir kez sallarsak yayda tek bir kabarıklık oluşur."},{"t":"Adı","a":"darbe","d":"Tek bir kıvrımdan oluşan bu dalgaya darbe denir."}],"ans":"Tek kıvrımdan oluşan dalgaya darbe denir."},{"q":"Bir yayın halkalarını sıkıştırıp bırakırsak yayda ileri doğru ne gider?","steps":[{"t":"Ne yaptık","a":"sıkıştırdık","d":"Yayın halkalarını birbirine yaklaştırıp bıraktık."},{"t":"Sonuç","a":"sıkışma ilerler","d":"Bu sıkışmış bölge yay boyunca ileri doğru hareket eder."}],"ans":"Yayı sıkıştırıp bırakınca sıkışmış bölge yay boyunca ilerler."},{"q":"Gevşek bir yay ile gergin bir yayda darbeyi gönderirsek hangisinde dalga daha hızlı gider?","steps":[{"t":"Gergin yay","a":"daha hızlı","d":"Yay ne kadar gergin olursa dalga o kadar hızlı ilerler."},{"t":"Karşılaştır","a":"gergin olan","d":"Bu yüzden gergin yayda darbe daha hızlı gider."}],"ans":"Gergin yayda darbe daha hızlı ilerler."}],"zor":[{"q":"Yayı yandan sağa-sola sallarsak halkalar hangi yönde hareket eder: dalganın gittiği yönde mi yoksa ona dik mi?","fig":"<svg viewBox='0 0 320 140'><line x1='10' y1='80' x2='90' y2='80' stroke='#1a2b45' stroke-width='2'/><path d='M90 80 q18 -42 36 0 q18 42 36 0' fill='none' stroke='#5b6b85' stroke-width='3'/><line x1='162' y1='80' x2='310' y2='80' stroke='#1a2b45' stroke-width='2'/><polygon points='250,80 265,75 265,85' fill='#e0552b'/><line x1='225' y1='80' x2='265' y2='80' stroke='#e0552b' stroke-width='2'/><text x='245' y='100' font-size='11' text-anchor='middle' fill='#e0552b'>dalga yönü</text><line x1='108' y1='30' x2='108' y2='65' stroke='#1a2b45' stroke-width='2'/><polygon points='108,30 103,40 113,40' fill='#1a2b45'/><text x='108' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>halka</text></svg>","steps":[{"t":"Hareketi izle","a":"yana titrer","d":"Yayı yandan sallayınca halkalar yana, yani dalganın gittiği yöne dik titrer."},{"t":"İsmi","a":"enine dalga","d":"Titreşim dalga yönüne dik olduğu için buna enine dalga denir."}],"ans":"Halkalar dalga yönüne dik (yana) hareket eder; bu enine dalgadır."},{"q":"Yayı ileri-geri sıkıştırıp gevşeterek dalga gönderirsek halkalar nasıl titrer?","steps":[{"t":"Hareketi izle","a":"ileri-geri","d":"Yayı ileri-geri itince halkalar dalganın gittiği yön boyunca titrer."},{"t":"İsmi","a":"boyuna dalga","d":"Titreşim dalga yönüyle aynı doğrultuda olduğu için buna boyuna dalga denir."}],"ans":"Halkalar dalga yönü boyunca ileri-geri titrer; bu boyuna dalgadır."},{"q":"Boyuna yay dalgasında halkaların sık olduğu bölgeye ve seyrek olduğu bölgeye ne ad verilir?","fig":"<svg viewBox='0 0 320 110'><line x1='20' y1='55' x2='40' y2='55' stroke='#1a2b45' stroke-width='2'/><line x1='48' y1='45' x2='48' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='53' y1='45' x2='53' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='58' y1='45' x2='58' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='63' y1='45' x2='63' y2='65' stroke='#1a2b45' stroke-width='2'/><text x='55' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>sıkışma</text><line x1='90' y1='45' x2='90' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='110' y1='45' x2='110' y2='65' stroke='#1a2b45' stroke-width='2'/><line x1='135' y1='45' x2='135' y2='65' stroke='#1a2b45' stroke-width='2'/><text x='112' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>seyrelme</text><line x1='160' y1='55' x2='300' y2='55' stroke='#1a2b45' stroke-width='1'/></svg>","steps":[{"t":"Sık bölge","a":"sıkışma","d":"Halkaların birbirine yaklaştığı yoğun bölgeye sıkışma denir."},{"t":"Seyrek bölge","a":"seyrelme","d":"Halkaların birbirinden uzaklaştığı bölgeye seyrelme denir."}],"ans":"Sık bölgeye sıkışma, seyrek bölgeye seyrelme denir."},{"q":"Bir ucu duvara sıkıca bağlı yayda gönderdiğimiz darbe duvardan geri döner mi?","steps":[{"t":"Sabit uç","a":"hareket edemez","d":"Yayın ucu duvara bağlı olduğu için orada oynayamaz."},{"t":"Sonuç","a":"geri yansır","d":"Darbe sabit uca çarpınca geri döner, yani yansır."}],"ans":"Evet; darbe sabit uca çarpıp geri yansır."},{"q":"İki çocuk aynı yayı gerdi. Daha çok geren çocuğun ucundan gönderilen darbe neden daha hızlı ilerler?","steps":[{"t":"Gerilim artar","a":"daha gergin","d":"Yayı daha çok germek yaydaki gerilimi artırır."},{"t":"Hıza etkisi","a":"hız artar","d":"Gerilim arttıkça dalganın yayda yayılma hızı da artar."}],"ans":"Daha çok gerilen yayda gerilim büyük olduğu için darbe daha hızlı ilerler."}]},"ortaokul":{"kolay":[{"q":"Enine yay dalgası ile boyuna yay dalgası arasındaki temel fark nedir, kısaca açıklayınız.","steps":[{"t":"Enine dalga","a":"titreşim dik","d":"Enine dalgada yayın titreşimi, dalganın ilerleme yönüne diktir (yana sallama)."},{"t":"Boyuna dalga","a":"titreşim paralel","d":"Boyuna dalgada titreşim, dalga yönüyle aynı doğrultudadır (sıkıştır-bırak)."}],"ans":"Enine dalgada titreşim dalga yönüne dik, boyuna dalgada ise dalga yönüyle aynı doğrultudadır."},{"q":"Yayda bir darbe ilerlerken enerji ve madde için ne söylenebilir?","steps":[{"t":"Madde","a":"yer değiştirmez","d":"Yayın halkaları darbe geçtikten sonra eski yerine döner, baştan sona taşınmaz."},{"t":"Enerji","a":"taşınır","d":"Darbe, kaynaktan aldığı enerjiyi yayın diğer ucuna doğru taşır."}],"ans":"Yay dalgasında madde yer değiştirmez, yalnızca enerji bir uçtan diğerine taşınır."},{"q":"Boyuna yay dalgasında sıkışma ve seyrelme bölgeleri nasıl oluşur?","fig":"<svg viewBox='0 0 320 110'><line x1='15' y1='55' x2='40' y2='55' stroke='#1a2b45' stroke-width='2'/><line x1='50' y1='44' x2='50' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='55' y1='44' x2='55' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='60' y1='44' x2='60' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='55' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>sıkışma</text><line x1='90' y1='44' x2='90' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='115' y1='44' x2='115' y2='66' stroke='#1a2b45' stroke-width='2'/><line x1='145' y1='44' x2='145' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='118' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>seyrelme</text><line x1='160' y1='55' x2='305' y2='55' stroke='#1a2b45' stroke-width='1'/><polygon points='30,30 45,25 45,35' fill='#e0552b'/><line x1='15' y1='30' x2='45' y2='30' stroke='#e0552b' stroke-width='2'/><text x='30' y='20' font-size='10' fill='#e0552b'>itme</text></svg>","steps":[{"t":"İtince","a":"halkalar yaklaşır","d":"Yayı ileri ittiğimizde halkalar birbirine yaklaşır ve sıkışma oluşur."},{"t":"Çekince","a":"halkalar uzaklaşır","d":"Yayı geri çektiğimizde halkalar uzaklaşır ve seyrelme oluşur."}],"ans":"İtince halkalar yaklaşıp sıkışma, çekince uzaklaşıp seyrelme oluşur; bunlar yay boyunca ilerler."},{"q":"Yayda dalganın yayılma hızını artırmak için yayın gerginliğini nasıl değiştirmeliyiz?","steps":[{"t":"İlişki","a":"gerilim ↑ hız ↑","d":"Yayda dalga hızı, yaydaki gerilim arttıkça artar."},{"t":"Sonuç","a":"daha çok ger","d":"Hızı artırmak için yayı daha gergin hale getirmeliyiz."}],"ans":"Yayı daha çok gererek (gerilimi artırarak) dalganın yayılma hızını artırabiliriz."},{"q":"Yayda darbe gönderirken eli ne kadar büyük oynatırsak darbenin neyi değişir?","steps":[{"t":"Büyük sallama","a":"yüksek kıvrım","d":"Eli daha büyük oynatınca darbenin yüksekliği (genliği) artar."},{"t":"Hız değişir mi","a":"hayır","d":"Darbenin hızı yayın gerilimine bağlıdır, sallama büyüklüğüne değil."}],"ans":"Daha büyük sallama darbenin yüksekliğini (genliğini) artırır, hızını değiştirmez."}],"zor":[{"q":"Bir ucu sabit (duvara bağlı) yayda gönderilen yukarı kıvrımlı darbe yansıdığında nasıl döner?","fig":"<svg viewBox='0 0 320 150'><line x1='10' y1='70' x2='90' y2='70' stroke='#1a2b45' stroke-width='2'/><path d='M90 70 q20 -38 40 0' fill='none' stroke='#5b6b85' stroke-width='3'/><line x1='130' y1='70' x2='280' y2='70' stroke='#1a2b45' stroke-width='2'/><line x1='285' y1='30' x2='285' y2='110' stroke='#1a2b45' stroke-width='4'/><text x='295' y='75' font-size='10' fill='#1a2b45'>sabit uç</text><polygon points='160,55 175,50 175,60' fill='#e0552b'/><line x1='145' y1='55' x2='175' y2='55' stroke='#e0552b' stroke-width='2'/><text x='110' y='40' font-size='10' fill='#1a2b45'>gelen (üst)</text></svg>","steps":[{"t":"Sabit uç kuralı","a":"ters döner","d":"Sabit uçta yansıyan darbe ters çevrilerek geri döner."},{"t":"Sonuç","a":"aşağı kıvrım","d":"Yukarı kıvrımlı gelen darbe, aşağı kıvrımlı olarak yansır."}],"ans":"Sabit uçtan yansıyan darbe ters döner; yukarı kıvrım, aşağı kıvrım olarak geri gelir."},{"q":"Bir ucu serbest (halkayla kayabilen) yayda gönderilen yukarı darbe yansıdığında nasıl döner?","steps":[{"t":"Serbest uç kuralı","a":"aynı kalır","d":"Serbest uçta yansıyan darbe ters dönmez, aynı yönde geri gelir."},{"t":"Sonuç","a":"yukarı kıvrım","d":"Yukarı kıvrımlı gelen darbe, yine yukarı kıvrımlı olarak yansır."}],"ans":"Serbest uçtan yansıyan darbe ters dönmez; yukarı kıvrım, yine yukarı kıvrım olarak geri gelir."},{"q":"Bir yayda darbe 4 metrelik mesafeyi 2 saniyede alıyor. Dalganın yayılma hızı kaç m/s'dir?","steps":[{"t":"Bağıntı","a":"hız = yol/zaman","d":"Yayılma hızı, alınan yolun geçen zamana bölünmesiyle bulunur."},{"t":"Yerine koy","a":"4 ÷ 2","d":"Yol 4 m, zaman 2 s değerleri yerine konur."},{"t":"Sonuç","a":"2 m/s","d":"Bölme sonucu 2 m/s bulunur."}],"ans":"Dalganın yayılma hızı 2 m/s'dir."},{"q":"Aynı yayda gerilim artırıldığında, eşit sürede gönderilen darbe daha mı uzağa gider yoksa daha mı yakına?","steps":[{"t":"Gerilim ve hız","a":"hız artar","d":"Gerilim arttığında dalganın yayılma hızı artar."},{"t":"Eşit sürede yol","a":"daha uzağa","d":"Hız büyüdüğü için aynı sürede darbe daha uzağa ilerler."}],"ans":"Gerilim artınca hız büyür; bu yüzden eşit sürede darbe daha uzağa gider."},{"q":"İki ucundan iki kişi aynı anda birer darbe gönderiyor; biri yukarı biri aşağı kıvrımlı. Ortada karşılaştıklarında bir an için ne gözlenir?","steps":[{"t":"Üst üste binme","a":"toplanırlar","d":"İki darbe karşılaştığında genlikleri o noktada toplanır (üst üste binme)."},{"t":"Zıt kıvrımlar","a":"birbirini söndürür","d":"Biri yukarı biri aşağı olduğundan toplam o anda sıfıra yaklaşır, yay düzleşir."}],"ans":"Karşılaşma anında zıt kıvrımlar üst üste binip birbirini söndürür; yay bir an düz görünür, sonra darbeler yollarına devam eder."}]},"lise":{"kolay":[{"q":"Yay (esnek ortam) dalgası tanımı gereği hangi tür dalgalardandır ve neden?","steps":[{"t":"Ortam gerekli mi","a":"evet","d":"Yay dalgası ilerlemek için esnek bir ortama (yayın kendisine) ihtiyaç duyar."},{"t":"Sınıflandırma","a":"mekanik dalga","d":"Maddesel ortamda yayılan dalgalara mekanik dalga denir."}],"ans":"Yay dalgası mekanik dalgadır; çünkü yayılmak için esnek bir maddesel ortam (yay) gerektirir."},{"q":"Enine ve boyuna yay dalgaları, titreşim ile yayılma yönü ilişkisine göre nasıl ayrılır?","steps":[{"t":"Enine","a":"dik","d":"Enine dalgada parçacıkların titreşim doğrultusu yayılma yönüne diktir."},{"t":"Boyuna","a":"paralel","d":"Boyuna dalgada titreşim doğrultusu yayılma yönüne paraleldir."}],"ans":"Enine dalgada titreşim yayılma yönüne dik, boyuna dalgada paraleldir."},{"q":"Boyuna yay dalgasındaki sıkışma ve seyrelme bölgeleri fiziksel olarak neyi temsil eder?","fig":"<svg viewBox='0 0 320 110'><line x1='12' y1='55' x2='35' y2='55' stroke='#1a2b45' stroke-width='2'/><line x1='44' y1='43' x2='44' y2='67' stroke='#1a2b45' stroke-width='2'/><line x1='49' y1='43' x2='49' y2='67' stroke='#1a2b45' stroke-width='2'/><line x1='54' y1='43' x2='54' y2='67' stroke='#1a2b45' stroke-width='2'/><line x1='59' y1='43' x2='59' y2='67' stroke='#1a2b45' stroke-width='2'/><text x='52' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>sıkışma</text><line x1='90' y1='43' x2='90' y2='67' stroke='#1a2b45' stroke-width='2'/><line x1='118' y1='43' x2='118' y2='67' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='43' x2='150' y2='67' stroke='#1a2b45' stroke-width='2'/><text x='120' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>seyrelme</text><line x1='165' y1='55' x2='305' y2='55' stroke='#1a2b45' stroke-width='1'/></svg>","steps":[{"t":"Sıkışma","a":"yüksek yoğunluk","d":"Sıkışma, halkaların yoğunlaştığı, yay yoğunluğunun arttığı bölgedir."},{"t":"Seyrelme","a":"düşük yoğunluk","d":"Seyrelme, halkaların aralandığı, yay yoğunluğunun azaldığı bölgedir."}],"ans":"Sıkışma yüksek yoğunluk (halkaların sık), seyrelme ise düşük yoğunluk (halkaların aralıklı) bölgesini temsil eder."},{"q":"Darbe (pulse) ile sürekli (periyodik) yay dalgası arasındaki fark nedir?","steps":[{"t":"Darbe","a":"tek bozulma","d":"Darbe, yaya bir kez verilen ve tek bir kıvrımdan oluşan kısa süreli bozulmadır."},{"t":"Sürekli dalga","a":"tekrarlı","d":"Ucu sürekli periyodik sallarsak art arda kıvrımlardan oluşan sürekli dalga elde edilir."}],"ans":"Darbe tek bir kıvrımdır; sürekli dalga ise periyodik salınımla oluşan art arda kıvrımlar dizisidir."},{"q":"Yayda dalga hızı, hangi temel niceliğe bağlıdır ve genlik ya da frekanstan etkilenir mi?","steps":[{"t":"Belirleyen nicelik","a":"ortam (gerilim)","d":"Yayda dalga hızı, ortamın özelliği olan gerilime (ve birim uzunluk kütlesine) bağlıdır."},{"t":"Genlik/frekans","a":"etkilemez","d":"Genlik ve frekans değişse de hız aynı kalır; bunlar dalganın hızını belirlemez."}],"ans":"Yayda dalga hızı yalnızca ortama (gerilime) bağlıdır; genlik ve frekanstan bağımsızdır."},{"q":"Bir yayda darbe 6 m yolu 1,5 s'de alıyor. Yayılma hızını hesaplayınız.","steps":[{"t":"Bağıntı","a":"v = x/t","d":"Yayılma hızı, alınan yolun geçen zamana oranıdır."},{"t":"Yerine koy","a":"6 ÷ 1,5","d":"Yol 6 m, zaman 1,5 s yerine konur."},{"t":"Sonuç","a":"4 m/s","d":"Bölme sonucu 4 m/s bulunur."}],"ans":"Dalganın yayılma hızı 4 m/s'dir."},{"q":"Sabit uçtan yansımada darbenin fazı (yönü) neden değişir?","fig":"<svg viewBox='0 0 320 150'><line x1='10' y1='70' x2='90' y2='70' stroke='#1a2b45' stroke-width='2'/><path d='M90 70 q20 -36 40 0' fill='none' stroke='#5b6b85' stroke-width='3'/><line x1='130' y1='70' x2='275' y2='70' stroke='#1a2b45' stroke-width='2'/><line x1='280' y1='32' x2='280' y2='108' stroke='#1a2b45' stroke-width='4'/><text x='292' y='74' font-size='10' fill='#1a2b45'>sabit</text><path d='M180 70 q20 36 40 0' fill='none' stroke='#4aa3df' stroke-width='3' stroke-dasharray='4 3'/><text x='200' y='120' font-size='10' text-anchor='middle' fill='#4aa3df'>yansıyan (ters)</text></svg>","steps":[{"t":"Tepki kuvveti","a":"zıt yönde","d":"Sabit uç hareket edemediği için yaya, gelen darbeye zıt yönde bir tepki kuvveti uygular."},{"t":"Sonuç","a":"180° faz değişimi","d":"Bu zıt tepki, yansıyan darbeyi ters çevirir; faz 180° (yarım dalga) değişir."}],"ans":"Sabit uç zıt yönlü tepki kuvveti uyguladığından yansıyan darbe ters döner; 180° faz değişimi olur."},{"q":"Serbest uçtan yansımada faz değişimi olur mu, açıklayınız.","steps":[{"t":"Serbest uç","a":"serbest hareket","d":"Serbest uç engellenmediği için darbe geldiğinde aynı yönde aşırı hareket eder."},{"t":"Sonuç","a":"faz değişmez","d":"Bu nedenle yansıyan darbe ters dönmez; faz değişimi olmaz (0°)."}],"ans":"Serbest uçtan yansımada faz değişimi olmaz; darbe aynı yönde (dik dönmeden) geri yansır."},{"q":"Yay gerilimi 4 katına çıkarılırsa dalga hızı kaç katına çıkar? (v, gerilimin kareköküyle orantılıdır)","steps":[{"t":"İlişki","a":"v ∝ √T","d":"Yayda dalga hızı, gerilimin kareköküyle doğru orantılıdır."},{"t":"Gerilim 4 katı","a":"√4","d":"Gerilim 4 katına çıkınca hız √4 katına çıkar."},{"t":"Sonuç","a":"2 katı","d":"√4 = 2 olduğundan hız 2 katına çıkar."}],"ans":"Dalga hızı 2 katına çıkar (√4 = 2)."},{"q":"Bir yayda 3 m'lik bölgede aynı anda 2 sıkışma sayılıyorsa boyuna dalganın dalga boyu yaklaşık kaç metredir?","steps":[{"t":"Dalga boyu tanımı","a":"sıkışmalar arası","d":"Boyuna dalgada bir tam dalga boyu, ardışık iki sıkışma arasındaki uzaklıktır."},{"t":"Yerine koy","a":"3 ÷ 2","d":"3 metrelik bölgede 2 sıkışma varsa bunları bölerek ortalama dalga boyunu buluruz."},{"t":"Sonuç","a":"1,5 m","d":"Bölme sonucu 1,5 m bulunur."}],"ans":"Boyuna dalganın dalga boyu yaklaşık 1,5 metredir."},{"q":"Enine yay dalgasında 'genlik' ne anlama gelir?","steps":[{"t":"Tanım","a":"en büyük sapma","d":"Genlik, yay halkalarının denge konumundan yaptığı en büyük yanal yer değiştirmedir."},{"t":"Neyle ilgili","a":"enerji","d":"Genlik arttıkça dalganın taşıdığı enerji de artar."}],"ans":"Genlik, halkaların denge konumundan yaptığı en büyük yanal sapmadır ve dalganın enerjisiyle ilişkilidir."},{"q":"Yayda dalga hızı 5 m/s ve darbe ucu sallama frekansı 2 Hz ise dalga boyu kaç metredir?","steps":[{"t":"Bağıntı","a":"v = λ·f","d":"Dalga hızı, dalga boyu ile frekansın çarpımına eşittir."},{"t":"Düzenle","a":"λ = v/f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Sonuç","a":"5 ÷ 2 = 2,5 m","d":"5 m/s'yi 2 Hz'e bölünce 2,5 m bulunur."}],"ans":"Dalga boyu 2,5 metredir."},{"q":"Yay dalgasının ilerlerken madde değil enerji taşıdığı nasıl gösterilir?","steps":[{"t":"İşaretli halka","a":"yerinde kalır","d":"Yay üzerine işaretlenen bir halka, dalga geçtikten sonra eski konumuna döner; ilerlemez."},{"t":"Uçtaki etki","a":"enerji ulaşır","d":"Buna karşın diğer uca bağlı bir cisim hareketlenir; bu, enerjinin taşındığını gösterir."}],"ans":"İşaretli halka yerinde titreşip kalırken uçtaki cismin hareketlenmesi, dalganın madde değil enerji taşıdığını gösterir."},{"q":"Aynı yayda hem enine hem boyuna dalga gönderildiğinde dalga hızları neye göre belirlenir?","steps":[{"t":"Belirleyen","a":"ortam özellikleri","d":"Her iki dalga türünün hızı da yayın gerilimi ve birim uzunluk kütlesi gibi ortam özelliklerine bağlıdır."},{"t":"Tür etkisi","a":"farklı olabilir","d":"Enine ve boyuna dalgalarda esneklik mekanizması farklı olduğundan hızları birbirinden farklı olabilir."}],"ans":"Her iki dalga hızı da ortamın (yayın) gerilim ve kütle özelliklerine bağlıdır; enine ve boyuna dalga hızları farklı olabilir."},{"q":"Bir darbenin yayda ilerlerken yüksekliğinin (genliğinin) zamanla biraz azalmasının nedeni nedir?","steps":[{"t":"Sürtünme/iç direnç","a":"enerji kaybı","d":"Yayın iç sürtünmesi ve hava direnci darbenin enerjisinin bir kısmını ısıya çevirir."},{"t":"Sonuç","a":"genlik azalır","d":"Enerji azaldıkça darbenin genliği (yüksekliği) yavaşça küçülür; buna sönüm denir."}],"ans":"İç sürtünme ve direnç darbenin enerjisini azalttığı için genliği zamanla küçülür (sönüm)."}],"zor":[{"q":"Bir ucu sabit yayda yukarı kıvrımlı darbe yansıdıktan sonra geri gelirken yön ve kıvrım açısından durumunu açıklayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='10' y1='70' x2='270' y2='70' stroke='#1a2b45' stroke-width='2'/><line x1='275' y1='30' x2='275' y2='110' stroke='#1a2b45' stroke-width='4'/><text x='288' y='74' font-size='10' fill='#1a2b45'>sabit</text><path d='M70 70 q20 -36 40 0' fill='none' stroke='#5b6b85' stroke-width='3'/><polygon points='130,55 145,50 145,60' fill='#e0552b'/><line x1='115' y1='55' x2='145' y2='55' stroke='#e0552b' stroke-width='2'/><path d='M150 70 q20 36 40 0' fill='none' stroke='#4aa3df' stroke-width='3' stroke-dasharray='4 3'/><polygon points='150,95 135,100 135,90' fill='#4aa3df'/><line x1='180' y1='95' x2='135' y2='95' stroke='#4aa3df' stroke-width='2'/></svg>","steps":[{"t":"Yön değişir","a":"geri döner","d":"Darbe sabit uca çarpınca yön değiştirip kaynağa doğru geri ilerler."},{"t":"Kıvrım değişir","a":"ters döner","d":"Sabit uçta 180° faz değişimi olduğundan yukarı kıvrım, aşağı kıvrıma dönüşür."}],"ans":"Yansıyan darbe ters yönde ilerler ve yukarı kıvrımı aşağı kıvrıma dönmüş (ters) haldedir."},{"q":"Bir yayda dalga hızı 8 m/s. Gerilim 4 katına çıkarıldığında hız kaç m/s olur? (v ∝ √T)","steps":[{"t":"İlişki","a":"v ∝ √T","d":"Hız gerilimin kareköküyle orantılı olduğundan gerilim 4 katı olunca hız √4 = 2 katına çıkar."},{"t":"Yerine koy","a":"8 × 2","d":"İlk hız 8 m/s'yi 2 ile çarparız."},{"t":"Sonuç","a":"16 m/s","d":"Çarpım sonucu 16 m/s bulunur."}],"ans":"Yeni dalga hızı 16 m/s'dir."},{"q":"6 m uzunluğundaki bir yayın bir ucundan gönderilen darbe diğer uca 1,5 s'de ulaşıyor. Aynı darbenin gidip sabit uçtan yansıyıp geri dönmesi toplam ne kadar sürer?","steps":[{"t":"Hızı bul","a":"v = 6/1,5 = 4 m/s","d":"Önce yol bölü zamandan yayılma hızını buluruz."},{"t":"Toplam yol","a":"6 + 6 = 12 m","d":"Darbe önce 6 m gider, yansıyıp 6 m geri döner, toplam 12 m yol alır."},{"t":"Süreyi bul","a":"12 ÷ 4","d":"Toplam yolu hıza bölerek toplam süreyi buluruz."}],"ans":"Darbenin gidip yansıyıp geri dönmesi toplam 3 saniye sürer."},{"q":"İki ayrı yayda gerilimler eşit; ancak birinin birim uzunluk kütlesi diğerinin 4 katı. Dalga hızları oranını bulunuz. (v ∝ 1/√μ)","steps":[{"t":"İlişki","a":"v ∝ 1/√μ","d":"Gerilim eşitken hız, birim uzunluk kütlesi μ'nün kareköküyle ters orantılıdır."},{"t":"Oranı kur","a":"√(μ₂/μ₁)","d":"Hafif yayın hızının ağıra oranı √(4) = 2 olur."},{"t":"Sonuç","a":"2/1","d":"Birim kütlesi küçük olan yaydaki hız, diğerinin 2 katıdır."}],"ans":"Birim uzunluk kütlesi küçük olan yaydaki dalga hızı, diğerinin 2 katıdır (oran 2/1)."},{"q":"Bir yayda dalga hızı 10 m/s. Ucu 4 Hz frekansla sürekli sallanıyorsa ardışık iki tepe arası uzaklık (dalga boyu) kaç metredir?","steps":[{"t":"Bağıntı","a":"λ = v/f","d":"Dalga boyu, hızın frekansa bölünmesiyle bulunur."},{"t":"Yerine koy","a":"10 ÷ 4","d":"Hız 10 m/s, frekans 4 Hz yerine konur."},{"t":"Sonuç","a":"2,5 m","d":"Bölme sonucu 2,5 m bulunur."}],"ans":"Ardışık iki tepe arası uzaklık (dalga boyu) 2,5 metredir."},{"q":"Bir ucu serbest yayda yukarı darbe, diğer ucu sabit yayda yukarı darbe gönderiliyor. Her iki yansımadan sonra darbelerin kıvrımları nasıl olur?","steps":[{"t":"Serbest uç","a":"aynı kalır","d":"Serbest uçtan yansımada faz değişmez; yukarı darbe yukarı kalır."},{"t":"Sabit uç","a":"ters döner","d":"Sabit uçtan yansımada 180° faz değişimi olur; yukarı darbe aşağı döner."},{"t":"Karşılaştır","a":"zıt sonuç","d":"Sonuçta serbest uçlu yayda darbe yukarı, sabit uçlu yayda aşağı kıvrımlı olur."}],"ans":"Serbest uçtan yansıyan darbe yukarı (aynı) kalır; sabit uçtan yansıyan darbe aşağı (ters) döner."},{"q":"Yayda iki darbe karşı yönlerden geliyor; biri +3 cm yukarı, diğeri +3 cm yukarı genlikli. Tam üst üste geldikleri anda yayın o noktadaki genliği ne olur?","steps":[{"t":"İlke","a":"üst üste binme","d":"Aynı noktada iki darbenin genlikleri cebirsel olarak toplanır."},{"t":"Topla","a":"+3 + (+3)","d":"İki yukarı darbenin genlikleri aynı işaretli olduğundan toplanır."},{"t":"Sonuç","a":"+6 cm","d":"Toplam genlik +6 cm olur (yapıcı girişim)."}],"ans":"Tam üst üste geldikleri anda yayın genliği +6 cm olur (genlikler toplanır)."},{"q":"4 m'lik yayda darbe 0,8 s'de bir uçtan diğerine geçiyor. Gerilim 9 katına çıkarılırsa darbe aynı mesafeyi kaç saniyede geçer? (v ∝ √T)","steps":[{"t":"İlk hız","a":"v₁ = 4/0,8 = 5 m/s","d":"Önce ilk durumdaki yayılma hızını buluruz."},{"t":"Yeni hız","a":"v₂ = 5 × √9 = 15 m/s","d":"Gerilim 9 katı olunca hız √9 = 3 katına çıkar, yani 15 m/s olur."},{"t":"Yeni süre","a":"4 ÷ 15","d":"Yeni süreyi yol bölü yeni hızdan buluruz."}],"ans":"Darbe aynı mesafeyi yaklaşık 0,27 saniyede (4 ÷ 15 s) geçer."},{"q":"Boyuna yay dalgasında ardışık iki sıkışma arası 0,5 m ve frekans 6 Hz ise yayılma hızını bulunuz.","steps":[{"t":"Dalga boyu","a":"λ = 0,5 m","d":"Ardışık iki sıkışma arası uzaklık bir tam dalga boyuna eşittir."},{"t":"Bağıntı","a":"v = λ·f","d":"Yayılma hızı, dalga boyu ile frekansın çarpımıdır."},{"t":"Sonuç","a":"0,5 × 6","d":"0,5 m ile 6 Hz çarpılır, sonuç 3 m/s bulunur."}],"ans":"Boyuna dalganın yayılma hızı 3 m/s'dir."},{"q":"Bir yayda enine darbenin hızı, genlik iki katına çıkarıldığında nasıl değişir? Gerekçesiyle açıklayınız.","steps":[{"t":"Hızı belirleyen","a":"ortam","d":"Yayda dalga hızı yalnızca gerilim ve birim kütle gibi ortam özelliklerine bağlıdır."},{"t":"Genlik etkisi","a":"yok","d":"Genlik, dalganın enerjisini değiştirir ama yayılma hızını etkilemez."},{"t":"Sonuç","a":"aynı kalır","d":"Bu yüzden genlik 2 katına çıksa da hız değişmez."}],"ans":"Hız değişmez; çünkü yay dalgasının hızı genliğe değil, ortamın (gerilim ve kütle) özelliklerine bağlıdır."},{"q":"İki darbe karşılaşıyor: biri +4 cm yukarı, diğeri 3 cm aşağı (−3 cm) genlikli. Tam üst üste geldikleri anda o noktadaki genlik nedir?","steps":[{"t":"İlke","a":"cebirsel toplam","d":"Üst üste binme ilkesine göre genlikler işaretleriyle toplanır."},{"t":"Topla","a":"+4 + (−3)","d":"Yukarı +4 cm ile aşağı −3 cm cebirsel olarak toplanır."},{"t":"Sonuç","a":"+1 cm","d":"Toplam +1 cm olur; bu yıkıcı (kısmi sönümlü) girişimdir."}],"ans":"Tam üst üste geldikleri anda yayın genliği +1 cm (yukarı) olur."},{"q":"6 m yayda darbe bir uçtan gönderilip sabit uçtan yansıyarak 2,4 s sonra başlangıç noktasına dönüyor. Yayılma hızını bulunuz.","steps":[{"t":"Toplam yol","a":"6 + 6 = 12 m","d":"Darbe gidip yansıyıp döndüğü için 6 m gidiş, 6 m dönüş olmak üzere 12 m yol alır."},{"t":"Bağıntı","a":"v = yol/zaman","d":"Yayılma hızı toplam yolun toplam zamana oranıdır."},{"t":"Sonuç","a":"12 ÷ 2,4","d":"12 m'yi 2,4 s'ye bölünce 5 m/s bulunur."}],"ans":"Dalganın yayılma hızı 5 m/s'dir."},{"q":"Yayda darbenin yüksekliği (genliği), ucu sallarken verilen enerjiyle nasıl ilişkilidir? Niceliksel eğilimi belirtiniz.","steps":[{"t":"Enerji-genlik","a":"E ∝ genlik²","d":"Dalganın taşıdığı enerji, genliğin karesiyle orantılıdır."},{"t":"Eğilim","a":"genlik 2 katı → enerji 4 katı","d":"Genlik 2 katına çıkarsa darbeye verilen enerji 4 katına çıkar."}],"ans":"Darbenin enerjisi genliğin karesiyle orantılıdır; genlik 2 katına çıkınca enerji 4 katına çıkar."},{"q":"Bir yayda gerilim sabit tutulup yayın kütlesi (birim uzunluk kütlesi) 2 katına çıkarılırsa dalga hızı ne olur? (v ∝ 1/√μ)","steps":[{"t":"İlişki","a":"v ∝ 1/√μ","d":"Gerilim sabitken hız, birim uzunluk kütlesinin kareköküyle ters orantılıdır."},{"t":"μ 2 katı","a":"1/√2","d":"μ 2 katına çıkınca hız 1/√2 katına düşer (yaklaşık 0,71)."},{"t":"Sonuç","a":"azalır","d":"Yani dalga hızı yaklaşık 0,71 katına iner, hız azalır."}],"ans":"Dalga hızı 1/√2 ≈ 0,71 katına düşer; yani yay ağırlaştıkça dalga yavaşlar."},{"q":"Bir yayda hem sabit hem serbest uç deneyi yapılıyor. Yansıyan darbenin genliği, sürtünme ihmal edilirse her iki durumda da gelen darbeyle aynı mıdır? Açıklayınız.","steps":[{"t":"Enerji korunumu","a":"kayıp yok","d":"Sürtünme ihmal edilirse yansımada enerji kaybı olmaz, dalga geri döner."},{"t":"Genlik","a":"aynı kalır","d":"Enerji korunduğundan yansıyan darbenin genliği gelen darbeyle aynı büyüklüktedir."},{"t":"Fark","a":"sadece yön/faz","d":"Tek fark fazdadır: sabit uçta ters, serbest uçta aynı kıvrımla döner; genlik değişmez."}],"ans":"Sürtünme yoksa her iki durumda da yansıyan darbenin genliği gelenle aynıdır; yalnızca faz (kıvrım yönü) sabit uçta ters, serbest uçta aynıdır."}]}}};
